  // ═══════════════════════════════════════════════════════════════════════════

  if (context.activeFile) {
    const truncNote = context.activeFile.truncated ? ' ⚠️ TRUNCATED - use read_file for full content' : '';
    parts.push(`
┌─ ⭐ ACTIVE FILE: ${activeRelPath}${truncNote}
