/** Check if a file is already in context */
export function isFileInContext(context: SmartContext, filePath: string): boolean {
  return context.filesInContext.has(filePath);
}

/** Get context statistics */
export function getContextStats(context: SmartContext): {
  totalChars: number;
  fileCount: number;
  symbolCount: number;
  budgetUsed: number;
  intentType: string;
} {
  return {
    totalChars: context.totalSize,
    fileCount: context.filesInContext.size,
    symbolCount: context.symbolIndex.size,
    budgetUsed: context.budgetUsed,
    intentType: context.intent.type,
  };
}

/** Find symbol across all context files */
export function findSymbolInContext(context: SmartContext, symbolName: string): {
  file: string;
  symbol: CodeSymbol;
} | undefined {
  // Exact match
  const exact = context.symbolIndex.get(symbolName);
  if (exact) return exact;

  // Case-insensitive search
  const lowerName = symbolName.toLowerCase();
  for (const [name, entry] of context.symbolIndex.entries()) {
    if (name.toLowerCase() === lowerName) {
      return entry;
    }
  }

  // Partial match
  for (const [name, entry] of context.symbolIndex.entries()) {
    if (name.toLowerCase().includes(lowerName) || lowerName.includes(name.toLowerCase())) {
      return entry;
    }
  }

  return undefined;
}

/** Get files related to a specific symbol */
export function getFilesForSymbol(context: SmartContext, symbolName: string): string[] {
  const files: string[] = [];

  // Check active file
  if (context.activeFile?.symbols.some(s => s.name.includes(symbolName))) {
    files.push(context.activeFile.path);
  }

  // Check related files
  for (const file of context.relatedFiles) {
    if (file.symbols.some(s => s.name.includes(symbolName))) {
      files.push(file.path);
    }
  }

  return files;
}

/** Preload files into cache (call on workspace open) */
export async function preloadContextCache(paths: string[]): Promise<void> {
  const promises = paths
    .filter(p => isCodeFile(p) && !isExcluded(p))
    .slice(0, 50)
    .map(p => getCachedFile(p));

  await Promise.all(promises);
}

/** Get cache statistics */
export function getCacheStats(): { entries: number; totalSize: number } {
  let totalSize = 0;
  for (const entry of fileCache.values()) {
    totalSize += entry.size;
  }
  return { entries: fileCache.size, totalSize };
}

/**
 * Anthropic AI Provider
 * 
 * Docs consulted:
 * - Anthropic API (2026): Claude Opus 4.6 with adaptive thinking & effort controls
 * - API Key: x-api-key header
 * - Anthropic Version: 2023-06-01
 */

import type {
    AIProvider,
    ChatRequest,
    ChatResponse,
    StreamChunk,
    ChatMessage,
    ToolDefinition,
    ToolCall,
    ProviderCapabilities
} from '$core/ai/types';
import { invoke, Channel } from '@tauri-apps/api/core';

const ANTHROPIC_API_BASE = 'https://api.anthropic.com/v1';
const ANTHROPIC_VERSION = '2023-06-01';

const ANTHROPIC_THINKING_SUFFIX = '|thinking';

/**
 * Anthropic API types
 */
interface AnthropicMessage {
    role: 'user' | 'assistant';
    content: string | AnthropicContentPart[];
}

type AnthropicContentPart =
    | { type: 'text'; text: string }
    | { type: 'image'; source: { type: 'base64'; media_type: string; data: string } }
    | { type: 'tool_use'; id: string; name: string; input: Record<string, unknown> }
    | { type: 'tool_result'; tool_use_id: string; content: string }
    | { type: 'thinking'; thinking: string; signature?: string };

interface AnthropicTool {
    name: string;
    description: string;
    input_schema: Record<string, unknown>;
}

interface AnthropicRequest {
    model: string;
    messages: AnthropicMessage[];
    system?: string;
    max_tokens: number;
    temperature?: number;
    stream?: boolean;
    tools?: AnthropicTool[];
    thinking?: {
        type: 'adaptive' | 'disabled';
    };
    output_config?: {
        effort: 'low' | 'medium' | 'high' | 'max';
    };
}

interface AnthropicResponse {
    id: string;
    type: 'message';
    role: 'assistant';
    content: AnthropicContentPart[];
    model: string;
    stop_reason: 'end_turn' | 'max_tokens' | 'stop_sequence' | 'tool_use';
    stop_sequence: string | null;
    usage: {
        input_tokens: number;
        output_tokens: number;
    };
    error?: {
        type: string;
        message: string;
    };
}

/**
 * Mapping help
 */
function toAnthropicMessages(messages: ChatMessage[]): AnthropicMessage[] {
    const anthropicMessages: AnthropicMessage[] = [];

    for (const m of messages) {
        if (m.role === 'system') continue;

        const parts: AnthropicContentPart[] = [];

        if (m.parts && m.parts.length > 0) {
            for (const part of m.parts) {
                if (part.type === 'text') {
                    parts.push({ type: 'text', text: part.text });
                } else if (part.type === 'image') {
                    parts.push({
                        type: 'image',
                        source: {
                            type: 'base64',
                            media_type: part.mimeType,
                            data: part.data
                        }
                    });
                } else if (part.type === 'thinking') {
                    parts.push({
                        type: 'thinking',
                        thinking: part.text
                    });
                } else if (part.type === 'function_call') {
                    parts.push({
                        type: 'tool_use',
                        id: part.id,
                        name: part.name,
                        input: part.arguments
                    });
                } else if (part.type === 'function_response') {
                    parts.push({
                        type: 'tool_result',
                        tool_use_id: part.id,
                        content: JSON.stringify(part.response)
                    });
                }
            }
        } else {
            parts.push({ type: 'text', text: m.content });
        }

        anthropicMessages.push({
            role: m.role === 'assistant' ? 'assistant' : 'user',
            content: parts
        });
    }

    return anthropicMessages;
}

function parseAnthropicModel(model: string): { baseModel: string; effort: 'low' | 'medium' | 'high' | 'max' } {
    if (model.endsWith(ANTHROPIC_THINKING_SUFFIX)) {
        return {
            baseModel: model.slice(0, -ANTHROPIC_THINKING_SUFFIX.length),
            effort: 'max'
        };
    }
    return {
        baseModel: model,
        effort: 'high' // Default effort level for 4.6
    };
}

/**
 * Map Anthropic error
 */
function mapAnthropicError(error: any): string {
    if (!error) return 'Unknown Anthropic error';

    const type = error.type;
    const message = error.message || 'No details provided';

    if (type === 'authentication_error') {
        return 'Invalid Anthropic API key. Tip: Ensure you have a balance of at least $10 in your Anthropic Console (API is separate from Claude Pro).';
    }
    if (type === 'rate_limit_error') {
        return 'Anthropic rate limit exceeded. If you just upgraded, it may take a few hours for limits to refresh.';
    }
    if (type === 'overloaded_error') {
        return 'Anthropic servers are overloaded. Please try again later.';
    }

    return `Anthropic Error (${type}): ${message}`;
}

export async function validateAnthropicKey(apiKey: string): Promise<{ success: boolean; error?: string }> {
    try {
        const result = await invoke<any>('anthropic_proxy', {
            body: {
                model: 'claude-opus-4-6',
                max_tokens: 1,
                messages: [{ role: 'user', content: 'Hi' }]
            },
            apiKey: apiKey.trim(),
            anthropicVersion: ANTHROPIC_VERSION
        });

        // If invoke succeeded without error, but the API returned an error inside JSON
        if (result.error && result.error.type === 'authentication_error') {
            return { success: false, error: 'Invalid API key.' };
        }
        return { success: true };
    } catch (err) {
        // Rust returns the error message as a string
        const errorMsg = String(err);
        if (errorMsg.includes('401') || errorMsg.includes('authentication_error')) {
            return { success: false, error: 'Invalid API key.' };
        }
        return { success: false, error: errorMsg };
    }
}

export const anthropicProvider: AIProvider = {
    id: 'anthropic',
    name: 'Anthropic',
    capabilities: {
        supportsStreaming: true,
        supportsTools: true,
        supportsJsonSchema: true,
        maxContextHint: 1000000
    },

    async sendChat(request: ChatRequest, apiKey: string, signal?: AbortSignal): Promise<ChatResponse> {
        const { baseModel, effort } = parseAnthropicModel(request.model);

        const body: AnthropicRequest = {
            model: baseModel,
            messages: toAnthropicMessages(request.messages),
            max_tokens: request.maxTokens || 4096,
            system: request.systemPrompt,
            output_config: { effort: effort },
            thinking: { type: 'adaptive' }
        };

        if (request.temperature !== undefined) {
            body.temperature = request.temperature;
        }

        if (request.tools && request.tools.length > 0) {
            body.tools = request.tools.map(t => ({
                name: t.name,
                description: t.description,
                input_schema: t.parameters as any
            }));
        }

        const data = await invoke<AnthropicResponse>('anthropic_proxy', {
            body,
            apiKey: apiKey.trim(),
            anthropicVersion: ANTHROPIC_VERSION
        });

        if (data.error) {
            throw new Error(mapAnthropicError(data.error));
        }

        let content = '';
        const toolCalls: ToolCall[] = [];

        for (const part of data.content) {
            if (part.type === 'text') {
                content += part.text;
            } else if (part.type === 'tool_use') {
                toolCalls.push({
                    id: part.id,
                    name: part.name,
                    arguments: part.input
                });
            }
        }

        let finishReason: ChatResponse['finishReason'] = 'stop';
        if (data.stop_reason === 'tool_use') finishReason = 'tool_calls';
        else if (data.stop_reason === 'max_tokens') finishReason = 'length';

        return {
            content,
            toolCalls: toolCalls.length > 0 ? toolCalls : undefined,
            finishReason,
            usage: {
                promptTokens: data.usage.input_tokens,
                completionTokens: data.usage.output_tokens,
                totalTokens: data.usage.input_tokens + data.usage.output_tokens
            }
        };
    },

    async *streamChat(request: ChatRequest, apiKey: string, signal?: AbortSignal): AsyncGenerator<StreamChunk> {
        const { baseModel, effort } = parseAnthropicModel(request.model);

        const body: AnthropicRequest = {
            model: baseModel,
            messages: toAnthropicMessages(request.messages),
            max_tokens: request.maxTokens || 4096,
            system: request.systemPrompt,
            stream: true,
            output_config: { effort: effort },
            thinking: { type: 'adaptive' }
        };

        if (request.temperature !== undefined) {
            body.temperature = request.temperature;
        }

        if (request.tools && request.tools.length > 0) {
            body.tools = request.tools.map(t => ({
                name: t.name,
                description: t.description,
                input_schema: t.parameters as any
            }));
        }

        const channel = new Channel<string>();
        const chunkQueue: string[] = [];
        let resolveNext: ((v: string | null) => void) | null = null;
        let isDone = false;
        let error: any = null;

        channel.onmessage = (chunk: string) => {
            if (resolveNext) {
                resolveNext(chunk);
                resolveNext = null;
            } else {
                chunkQueue.push(chunk);
            }
        };

        const invokePromise = invoke('anthropic_proxy_stream', {
            body,
            apiKey: apiKey.trim(),
            anthropicVersion: ANTHROPIC_VERSION,
            onEvent: channel
        }).then(() => {
            isDone = true;
            if (resolveNext) {
                resolveNext(null);
                resolveNext = null;
            }
        }).catch(err => {
            isDone = true;
            error = err;
            if (resolveNext) {
                resolveNext(null);
                resolveNext = null;
            }
        });

        let buffer = '';
        let activeToolUse: { id: string; name: string; input: string } | null = null;

        while (true) {
            let sseChunk: string | null = null;
            if (chunkQueue.length > 0) {
                sseChunk = chunkQueue.shift()!;
            } else if (!isDone) {
                sseChunk = await new Promise<string | null>(r => { resolveNext = r; });
            } else {
                break;
            }

            if (error) {
                yield { type: 'error', error: mapAnthropicError({ type: 'error', message: String(error) }) };
                return;
            }

            if (sseChunk === null) break;

            buffer += sseChunk;
            const lines = buffer.split('\n');
            buffer = lines.pop() || '';

            for (const line of lines) {
                const trimmed = line.trim();
                if (!trimmed.startsWith('data:')) continue;
                const jsonStr = trimmed.slice(5).trim();
                if (jsonStr === '[DONE]') continue;

                try {
                    const event = JSON.parse(jsonStr);

                    if (event.type === 'content_block_start') {
                        if (event.content_block.type === 'tool_use') {
                            activeToolUse = {
                                id: event.content_block.id,
                                name: event.content_block.name,
                                input: ''
                            };
                        }
                    } else if (event.type === 'content_block_delta') {
                        if (event.delta.type === 'text_delta') {
                            yield { type: 'content', content: event.delta.text };
                        } else if (event.delta.type === 'thinking_delta') {
                            yield { type: 'thinking', thinking: event.delta.thinking };
                        } else if (event.delta.type === 'input_json_delta' && activeToolUse) {
                            activeToolUse.input += event.delta.partial_json;
                        }
                    } else if (event.type === 'content_block_stop') {
                        if (activeToolUse) {
                            try {
                                const args = JSON.parse(activeToolUse.input || '{}');
                                yield {
                                    type: 'tool_call',
                                    toolCall: {
                                        id: activeToolUse.id,
                                        name: activeToolUse.name,
                                        arguments: args
                                    }
                                };
                            } catch (e) {
                                console.error('[Anthropic] Failed to parse tool input JSON:', activeToolUse.input);
                            }
                            activeToolUse = null;
                        }
                    } else if (event.type === 'message_delta') {
                        // Usage and stop reason are here
                    } else if (event.type === 'error') {
                        yield { type: 'error', error: mapAnthropicError(event.error) };
                        return;
                    }
                } catch (e) {
                    // Partial JSON or error parsing
                }
            }
        }
        yield { type: 'done' };
        await invokePromise;
    },

    validateKey: validateAnthropicKey
};

/**
 * Google Gemini AI Provider
 * 
 * Docs consulted:
 * - Gemini API: `x-goog-api-key` auth header
 * - POST https://generativelanguage.googleapis.com/v1beta/models/{model}:generateContent
 * - POST https://generativelanguage.googleapis.com/v1beta/models/{model}:streamGenerateContent (SSE)
 * - Gemini API: multimodal vision with inline base64 data (mimeType + data format)
 * - Gemini API: thinkingConfig for native reasoning (thinkingBudget, includeThoughts)
 * - Gemini 2.5 models support thinking by default, can be configured via thinkingConfig
 */

import type {
  AIProvider,
  ChatRequest,
  ChatResponse,
  StreamChunk,
  ChatMessage,
  ToolDefinition,
  ToolCall,
  ProviderCapabilities
} from '$core/ai/types';
import { invoke, Channel } from '@tauri-apps/api/core';

const GEMINI_API_BASE = 'https://generativelanguage.googleapis.com/v1beta';

const GEMINI_THINKING_SUFFIX = '|thinking';

/**
 * Check if model is Gemini 3 series
 */
function isGemini3Model(model: string): boolean {
  return model.includes('gemini-3');
}

function isGemini3ProModel(model: string): boolean {
  return model.includes('gemini-3-pro');
}

/**
 * Build thinking config based on model series
 * - Gemini 3 Pro: supports LOW/HIGH only (MINIMAL not supported)
 * - Gemini 3 Flash: supports MINIMAL/LOW/MEDIUM/HIGH
 * - Gemini 2.5: uses thinkingBudget (0 to disable, -1 for unlimited)
 */
function buildThinkingConfig(model: string, thinkingEnabled: boolean): GeminiThinkingConfig | undefined {
  if (isGemini3Model(model)) {
    // For Gemini 3, when thinking is "off" in Volt's model selector, omit thinkingConfig.
    // This avoids INVALID_ARGUMENT on models that don't support MINIMAL (e.g. 3 Pro).
    // Gemini will use default dynamic reasoning for the model.
    if (!thinkingEnabled) return undefined;

    // Gemini 3 Pro supports LOW/HIGH only.
    if (isGemini3ProModel(model)) {
      return {
        includeThoughts: true,
        thinkingLevel: 'HIGH'
      };
    }

    // Gemini 3 Flash supports MINIMAL/LOW/MEDIUM/HIGH.
    return {
      includeThoughts: true,
      thinkingLevel: 'HIGH'
    };
  }

  // Gemini 2.5 series: use thinkingBudget (camelCase for REST API)
  return {
    includeThoughts: thinkingEnabled,
    thinkingBudget: thinkingEnabled ? -1 : 0
  };
}

function parseGeminiModel(rawModel: string): { model: string; thinkingEnabled: boolean } {
  const modelWithoutPrefix = rawModel.startsWith('models/') ? rawModel.slice('models/'.length) : rawModel;
  if (modelWithoutPrefix.endsWith(GEMINI_THINKING_SUFFIX)) {
    return {
      model: modelWithoutPrefix.slice(0, -GEMINI_THINKING_SUFFIX.length),
      thinkingEnabled: true
    };
  }
  return { model: modelWithoutPrefix, thinkingEnabled: false };
}

// Gemini API types
interface GeminiContent {
  role: 'user' | 'model';
  parts: GeminiPart[];
}

interface GeminiPart {
  text?: string;
  thought?: boolean; // True if this part is a thinking/reasoning part
  thoughtSignature?: string; // Gemini 3 thought signature - MUST be preserved for function calling
  inlineData?: {
    mimeType: string;
    data: string;
  };
  functionCall?: {
    id?: string; // Optional call ID for parallel calling/Gemini 3
    name: string;
    args: Record<string, unknown>;
  };
  functionResponse?: {
    id?: string; // Must match the functionCall.id
    name: string;
    response: Record<string, unknown>;
  };
}

interface GeminiTool {
  functionDeclarations: GeminiFunctionDeclaration[];
}

interface GeminiFunctionDeclaration {
  name: string;
  description: string;
  parameters: Record<string, unknown>;
}

// CRITICAL: Gemini REST API uses camelCase for thinkingConfig fields!
interface GeminiThinkingConfig {
  includeThoughts?: boolean; // Include thought summaries in response
  thinkingBudget?: number; // 2.5 series: 0 to disable, positive for token budget
  thinkingLevel?: 'HIGH' | 'MEDIUM' | 'LOW' | 'MINIMAL'; // 3 series: dynamic vs explicit
}

interface GeminiFunctionCallingConfig {
  mode: 'AUTO' | 'ANY' | 'NONE';
  allowedFunctionNames?: string[];
}

interface GeminiToolConfig {
  functionCallingConfig: GeminiFunctionCallingConfig;
}

// CRITICAL: Gemini REST API uses camelCase for generationConfig!
interface GeminiRequest {
  contents: GeminiContent[];
  systemInstruction?: GeminiContent; // camelCase for REST API
  tools?: GeminiTool[];
  toolConfig?: GeminiToolConfig;
  generationConfig?: {
    temperature?: number;
    maxOutputTokens?: number;
    stopSequences?: string[];
    topK?: number;
    topP?: number;
    thinkingConfig?: GeminiThinkingConfig;
    responseMimeType?: string; // Force text/plain to prevent JSON output
  };
}

// Streaming response can have partial candidates
interface GeminiStreamCandidate {
  content?: GeminiContent;
  finishReason?: string;
}

interface GeminiStreamResponse {
  candidates?: GeminiStreamCandidate[];
  usageMetadata?: {
    promptTokenCount: number;
    candidatesTokenCount: number;
    totalTokenCount: number;
  };
  error?: {
    code: number;
    message: string;
    status: string;
  };
}

interface GeminiCandidate {
  content: GeminiContent;
  finishReason: string;
}

interface GeminiResponse {
  candidates?: GeminiCandidate[];
  usageMetadata?: {
    promptTokenCount: number;
    candidatesTokenCount: number;
    totalTokenCount: number;
  };
  error?: {
    code: number;
    message: string;
    status: string;
  };
}

/**
 * Convert our message format to Gemini format
 * Supports multimodal content (text + images + function calls/responses)
 * 
 * CRITICAL for multi-turn function calling:
 * - Model's function calls must be in 'model' role with functionCall parts
 * - Function responses must be in 'user' role with functionResponse parts
 * - The sequence must be: user -> model (with functionCall) -> user (with functionResponse) -> model continues
 */
function toGeminiContents(messages: ChatMessage[]): GeminiContent[] {
  const contents: GeminiContent[] = [];

  for (const m of messages) {
    if (m.role === 'system') continue; // System handled separately

    const parts: GeminiPart[] = [];

    // If message has multimodal parts, use them
    if (m.parts && m.parts.length > 0) {
      for (const part of m.parts) {
        if (part.type === 'text') {
          parts.push({ text: part.text });
        } else if (part.type === 'image') {
          parts.push({
            inlineData: {
              mimeType: part.mimeType,
              data: part.data
            }
          });
        } else if (part.type === 'thinking') {
          // Model's previous thinking - send back as thought part
          parts.push({
            text: part.text,
            thought: true
          } as any);
        } else if (part.type === 'function_call') {
          // Model's function call - must go in 'model' role
          // CRITICAL: Include thoughtSignature for Gemini 3 models
          const fcPart: GeminiPart = {
            functionCall: {
              id: part.id, // Include native ID for multi-turn matching
              name: part.name,
              args: part.arguments
            }
          };
          // Preserve thought signature if present (required for Gemini 3)
          if (part.thoughtSignature) {
            fcPart.thoughtSignature = part.thoughtSignature;
          }
          // Preserve native function call ID if present (required for Gemini 3 and 2.5)
          if (part.id) {
            // Note: Gemini API often expects this to be handled via the specific response object structure
            // but we keep it here for our internal state tracking.
          }
          parts.push(fcPart);
        } else if (part.type === 'function_response') {
          // Tool result - must go in 'user' role as functionResponse
          // Gemini expects each functionResponse in its own content block
          // Format: { name: string, response: { result: ... } }

          // If we have accumulated parts, push them first
          if (parts.length > 0) {
            contents.push({
              role: m.role === 'assistant' ? 'model' : 'user',
              parts: [...parts]
            });
            parts.length = 0;
          }

          // Add function response as separate content with 'user' role
          // Wrap the response in 'result' key as per Gemini API spec
          contents.push({
            role: 'user',
            parts: [{
              functionResponse: {
                id: part.id, // Must match original call ID
                name: part.name,
                response: { result: part.response }
              }
            }]
          });
        }
      }
    } else if (m.content && m.content.trim()) {
      // Fallback to text-only content (only if non-empty)
      parts.push({ text: m.content });
    }

    // Push remaining parts if any (and not already handled by function response)
    // Skip empty parts arrays to avoid "Invalid request" errors
    if (parts.length > 0) {
      contents.push({
        role: m.role === 'assistant' ? 'model' : 'user',
        parts
      });
    }
  }

  // Filter out any content blocks with empty parts (safety check)
  const filtered = contents.filter(c => c.parts && c.parts.length > 0);

  // Gemini requires alternating user/model roles
  // Merge consecutive same-role messages to avoid "Invalid request" errors
  const hasFunctionResponsePart = (c: GeminiContent): boolean =>
    c.parts?.some((p) => Boolean((p as GeminiPart).functionResponse));

  const merged: GeminiContent[] = [];
  for (const content of filtered) {
    const last = merged[merged.length - 1];
    if (last && last.role === content.role) {
      const lastHasFnResp = hasFunctionResponsePart(last);
      const currHasFnResp = hasFunctionResponsePart(content);

      // Avoid merging functionResponse parts with normal text/image parts.
      // (Function responses are sensitive to formatting in the Gemini API.)
      if (lastHasFnResp !== currHasFnResp) {
        merged.push(content);
        continue;
      }

      // Merge parts into the previous message with same role
      last.parts = [...last.parts, ...content.parts];
    } else {
      merged.push(content);
    }
  }

  return merged;
}

/**
 * Convert tool definitions to Gemini format
 */
function toGeminiTools(tools: ToolDefinition[]): GeminiTool[] {
  if (tools.length === 0) return [];

  return [{
    functionDeclarations: tools.map(t => ({
      name: t.name,
      description: t.description,
      parameters: t.parameters
    }))
  }];
}

/**
 * Extract tool calls from Gemini response
 */
function extractToolCalls(candidate: GeminiCandidate): ToolCall[] {
  const calls: ToolCall[] = [];

  for (const part of candidate.content.parts) {
    if (part.functionCall) {
      calls.push({
        id: (part as any).id || (part as any).functionCall.id || `call_${Date.now()}_${calls.length}`,
        name: part.functionCall.name,
        arguments: part.functionCall.args
      });
    }
  }

  return calls;
}

/**
 * Map Gemini error to user-friendly message
 * NEVER includes the API key in error messages
 */
function mapGeminiError(error: GeminiResponse['error']): string {
  if (!error) return 'Unknown error';

  const code = error.code;
  const status = error.status;

  // Map common errors
  if (code === 401 || status === 'UNAUTHENTICATED') {
    return 'Invalid API key. Please check your Gemini API key.';
  }
  if (code === 403 || status === 'PERMISSION_DENIED') {
    return 'API key does not have permission. Check your API key settings.';
  }
  if (code === 429 || status === 'RESOURCE_EXHAUSTED') {
    return 'Rate limit exceeded. Please wait a moment and try again.';
  }
  if (code === 400 || status === 'INVALID_ARGUMENT') {
    return 'Invalid request. Please check your input.';
  }
  if (code === 503 || status === 'UNAVAILABLE') {
    return 'Gemini service is temporarily unavailable. Please try again later.';
  }

  // Generic error - redact any potential sensitive data
  const safeMessage = error.message.replace(/[A-Za-z0-9_-]{20,}/g, '[REDACTED]');
  return `Gemini API error: ${safeMessage}`;
}

/**
 * Validate a Gemini API key by making a minimal request
 */
export async function validateGeminiKey(apiKey: string): Promise<{ success: boolean; error?: string }> {
  try {
    const url = `${GEMINI_API_BASE}/models/gemini-2.5-flash:generateContent`;

    const response = await fetch(url, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'x-goog-api-key': apiKey
      },
      body: JSON.stringify({
        contents: [{
          parts: [{ text: 'Hi' }]
        }],
        generationConfig: {
          maxOutputTokens: 5
        }
      })
    });

    if (!response.ok) {
      const data = await response.json() as GeminiResponse;
      return { success: false, error: mapGeminiError(data.error) };
    }

    return { success: true };
  } catch (err) {
    if (err instanceof TypeError && err.message.includes('fetch')) {
      return { success: false, error: 'Network error. Please check your internet connection.' };
    }
    const msg = err instanceof Error ? err.message : 'Unknown error';
    const safeMsg = msg.replace(/[A-Za-z0-9_-]{20,}/g, '[REDACTED]');
    return { success: false, error: safeMsg };
  }
}

