export async function handleLspGetHover(args: Record<string, unknown>): Promise<ToolResult> {
  const path = args.path ? String(args.path) : null;
  let line = typeof args.line === 'number' ? args.line : null;
  let column = typeof args.column === 'number' ? args.column : null;
  const symbol = args.symbol ? String(args.symbol) : null;

  if (!path) {
    return { success: false, error: 'path is required' };
  }

  const absolutePath = resolvePath(path);

  // If no line/column but symbol provided, try to find it in the file
  if ((line === null || column === null) && symbol) {
    const found = await findSymbolInFile(absolutePath, symbol);
    if (found) {
      line = found.line;
      column = found.column;
    } else {
      return {
        success: false,
        error: `Could not find symbol "${symbol}" in ${path}. Provide line and column, or check the symbol name.`
      };
    }
  }

  if (line === null || column === null) {
    return { success: false, error: 'Either (line + column) or symbol is required' };
  }

  // Ensure LSP is running
  const lspType = await ensureLspForFile(absolutePath);
  if (!lspType) {
    return { success: false, error: `LSP not available for ${path}. Supported extensions: .ts, .tsx, .js, .jsx, .svelte, .html, .css, .scss, .json, .dart, .yaml, .xml` };
  }

  // Ensure document is open in LSP
  await ensureDocumentOpen(absolutePath, lspType);

  // Get hover info (LSP uses 0-based)
  const hover = await withTimeout(
    getHover(absolutePath, line - 1, column - 1, lspType),
    20000,
    'Hover lookup timed out'
  );

  if (!hover) {
    return { success: true, output: `No type information available at ${path}:${line}:${column}` };
  }

  // Extract hover content
  let content = '';
  if (typeof hover.contents === 'string') {
    content = hover.contents;
  } else if (Array.isArray(hover.contents)) {
    content = hover.contents.map(c => typeof c === 'string' ? c : c.value).join('\n\n');
  } else if (hover.contents && typeof hover.contents === 'object' && 'value' in hover.contents) {
    content = hover.contents.value;
  }

  if (!content) {
    return { success: true, output: `No type information available at ${path}:${line}:${column}` };
  }

  const lines: string[] = [];
  lines.push(`Type info at ${path}:${line}:${column}:`);
  lines.push('');
  lines.push(content);

  return { success: true, output: lines.join('\n') };
}

// ============================================================================
// TOOL: lsp_rename_symbol
// ============================================================================

export async function handleLspRenameSymbol(args: Record<string, unknown>): Promise<ToolResult> {
  const path = args.path ? String(args.path) : null;
  let line = typeof args.line === 'number' ? args.line : null;
  let column = typeof args.column === 'number' ? args.column : null;
  const newName = args.new_name ? String(args.new_name) : null;
  const oldName = args.old_name ? String(args.old_name) : null;

  if (!path) {
    return { success: false, error: 'path is required' };
  }

  if (!newName) {
    return { success: false, error: 'new_name is required' };
  }

  const absolutePath = resolvePath(path);

  // If no line/column but old_name provided, try to find it in the file
  if ((line === null || column === null) && oldName) {
    const found = await findSymbolInFile(absolutePath, oldName);
    if (found) {
      line = found.line;
      column = found.column;
    } else {
      return {
        success: false,
        error: `Could not find symbol "${oldName}" in ${path}. Provide line and column, or check the symbol name.`
      };
    }
  }

  if (line === null || column === null) {
    return { success: false, error: 'Either (line + column) or old_name is required' };
  }

  // Ensure LSP is running (rename only supported for TypeScript/JavaScript and Dart)
  const lspType = await ensureLspForFile(absolutePath);
  if (!lspType) {
    return { success: false, error: `LSP not available for ${path}. Supported extensions: .ts, .tsx, .js, .jsx, .mts, .cts, .mjs, .cjs, .dart` };
  }

  if (lspType !== 'typescript' && lspType !== 'dart') {
    return { success: false, error: `Rename is only supported for TypeScript/JavaScript and Dart files. Current file type uses ${lspType} LSP.` };
  }

  // Ensure document is open in LSP
  await ensureDocumentOpen(absolutePath, lspType);

  // For Dart, use Dart rename
  if (lspType === 'dart') {
    const workspaceEdit = await withTimeout(
      renameDartSymbol(absolutePath, line - 1, column - 1, newName),
      20000,
      'Rename operation timed out'
    );

    if (!workspaceEdit) {
      return { success: false, error: `Rename failed for symbol at ${path}:${line}:${column} → "${newName}"` };
    }

    // Apply the workspace edit (same format as TypeScript)
    const appliedFiles: string[] = [];
    const errors: string[] = [];
    const changes = (workspaceEdit as WorkspaceEdit).changes || {};

    for (const [uri, edits] of Object.entries(changes)) {
      const filePath = uriToPath(uri);
      try {
        const doc = await fileService.read(filePath, true);
        if (!doc) {
          errors.push(`Failed to read ${filePath}`);
          continue;
        }
        const lines = doc.content.split('\n');

        // Sort edits in reverse order (bottom to top) to preserve line numbers
        const sortedEdits = [...edits].sort((a, b) => {
          if (a.range.start.line !== b.range.start.line) {
            return b.range.start.line - a.range.start.line;
          }
          return b.range.start.character - a.range.start.character;
        });

        // Apply each edit
        for (const edit of sortedEdits) {
          const startLine = edit.range.start.line;
          const startChar = edit.range.start.character;
          const endLine = edit.range.end.line;
          const endChar = edit.range.end.character;

          if (startLine === endLine) {
            const lineContent = lines[startLine] || '';
            lines[startLine] = lineContent.slice(0, startChar) + edit.newText + lineContent.slice(endChar);
          } else {
            const startLineContent = lines[startLine] || '';
            const endLineContent = lines[endLine] || '';
            const newContent = startLineContent.slice(0, startChar) + edit.newText + endLineContent.slice(endChar);
            lines.splice(startLine, endLine - startLine + 1, newContent);
          }
        }

        const newContent = lines.join('\n');
        const result = await fileService.write(filePath, newContent, { source: 'lsp' });
        if (!result.success) {
          errors.push(`Failed to write ${filePath}: ${result.error}`);
          continue;
        }
        appliedFiles.push(getRelativePath(filePath));
      } catch (e) {
        errors.push(`Failed to update ${filePath}: ${extractErrorMessage(e)}`);
      }
    }

    if (errors.length > 0) {
      return {
        success: false,
        error: `Partial rename completed with errors:\n${errors.join('\n')}`
      };
    }

    return {
      success: true,
      data: {
        renamedTo: newName,
        filesModified: appliedFiles.length,
        files: appliedFiles
      }
    };
  }

  // TypeScript rename flow
  // Check if rename is possible at this location
  const prepareResult = await prepareRename(absolutePath, line - 1, column - 1);
  if (!prepareResult) {
    return { success: false, error: `Cannot rename symbol at ${path}:${line}:${column}. Make sure cursor is on a renameable symbol.` };
  }

  const actualOldName = prepareResult.placeholder;

  // Execute rename
  const workspaceEdit = await withTimeout(
    executeRename(absolutePath, line - 1, column - 1, newName),
    20000,
    'Rename operation timed out'
  );

  if (!workspaceEdit) {
    return { success: false, error: `Rename failed for "${actualOldName}" → "${newName}"` };
  }

  // Apply the workspace edit
  const appliedFiles: string[] = [];
  const errors: string[] = [];

  // Handle both formats: changes and documentChanges
  const changes = workspaceEdit.changes || {};

  // Convert documentChanges to changes format if present
  if (workspaceEdit.documentChanges) {
    for (const docChange of workspaceEdit.documentChanges) {
      if ('textDocument' in docChange && 'edits' in docChange) {
        const uri = docChange.textDocument.uri;
        if (!changes[uri]) {
          changes[uri] = [];
        }
        changes[uri].push(...docChange.edits);
      }
    }
  }

  // Apply edits to each file
  for (const [uri, edits] of Object.entries(changes)) {
    const filePath = uriToPath(uri);

    try {
      // Read current content
      const doc = await fileService.read(filePath, true);
      if (!doc) {
        errors.push(`Failed to read ${getRelativePath(filePath)}`);
        continue;
      }
      const lines = doc.content.split('\n');

      // Sort edits in reverse order (bottom to top) to preserve line numbers
      const sortedEdits = [...edits].sort((a, b) => {
        if (a.range.start.line !== b.range.start.line) {
          return b.range.start.line - a.range.start.line;
        }
        return b.range.start.character - a.range.start.character;
      });

      // Apply each edit
      for (const edit of sortedEdits) {
        const startLine = edit.range.start.line;
        const startChar = edit.range.start.character;
        const endLine = edit.range.end.line;
        const endChar = edit.range.end.character;

        if (startLine === endLine) {
          // Single line edit
          const line = lines[startLine] || '';
          lines[startLine] = line.slice(0, startChar) + edit.newText + line.slice(endChar);
        } else {
          // Multi-line edit
          const startLineContent = lines[startLine] || '';
          const endLineContent = lines[endLine] || '';
          const newContent = startLineContent.slice(0, startChar) + edit.newText + endLineContent.slice(endChar);
          lines.splice(startLine, endLine - startLine + 1, newContent);
        }
      }

      // Write back
      const newContent = lines.join('\n');
      const result = await fileService.write(filePath, newContent, { source: 'lsp' });
      if (!result.success) {
        errors.push(`Failed to write ${getRelativePath(filePath)}: ${result.error}`);
        continue;
      }
      appliedFiles.push(getRelativePath(filePath));

    } catch (err) {
      errors.push(`Failed to update ${getRelativePath(filePath)}: ${extractErrorMessage(err)}`);
    }
  }

  // Format result
  const resultLines: string[] = [];
  resultLines.push(`✅ Renamed "${actualOldName}" → "${newName}"`);
  resultLines.push('');
  resultLines.push(`Updated ${appliedFiles.length} file${appliedFiles.length > 1 ? 's' : ''}:`);
  for (const file of appliedFiles) {
    resultLines.push(`  • ${file}`);
  }

  if (errors.length > 0) {
    resultLines.push('');
    resultLines.push('⚠️ Errors:');
    for (const err of errors) {
      resultLines.push(`  • ${err}`);
    }
  }

  return { success: true, output: resultLines.join('\n') };
}

// ============================================================================
// TOOL: lsp_prepare_rename (helper to check if rename is valid)
// ============================================================================

export async function handleLspPrepareRename(args: Record<string, unknown>): Promise<ToolResult> {
  const path = args.path ? String(args.path) : null;
  const line = typeof args.line === 'number' ? args.line : null;
  const column = typeof args.column === 'number' ? args.column : null;

  if (!path) {
    return { success: false, error: 'path is required' };
  }

  if (line === null || column === null) {
    return { success: false, error: 'line and column are required (1-based)' };
  }

  const absolutePath = resolvePath(path);

  // Ensure LSP is running (prepare_rename only for TypeScript)
  const lspType = await ensureLspForFile(absolutePath);
  if (!lspType || lspType !== 'typescript') {
    return { success: false, error: `LSP rename only available for TypeScript/JavaScript files` };
  }

  await ensureDocumentOpen(absolutePath, lspType);

  const result = await prepareRename(absolutePath, line - 1, column - 1);

  if (!result) {
    return {
      success: true,
      output: `Cannot rename at ${path}:${line}:${column}. Position is not on a renameable symbol.`
    };
  }

  return {
    success: true,
    output: `Symbol "${result.placeholder}" at ${path}:${line}:${column} can be renamed.`
  };
}

// ============================================================================
// TOOL: lsp_get_code_actions - Get ESLint code actions (quick fixes)
// ============================================================================

export async function handleLspGetCodeActions(args: Record<string, unknown>): Promise<ToolResult> {
  const path = args.path ? String(args.path) : null;
  const line = typeof args.line === 'number' ? args.line : null;
  const endLine = typeof args.end_line === 'number' ? args.end_line : line;
  const fixAll = args.fix_all === true;

  if (!path) {
    return { success: false, error: 'path is required' };
  }

  const absolutePath = resolvePath(path);
  const relativePath = getRelativePath(absolutePath);

  // Determine if it's a Dart file or ESLint file
  const isDart = isDartFile(absolutePath);
  const isEslint = isEslintFile(absolutePath);

  if (!isDart && !isEslint) {
    return {
      success: false,
      error: `Code actions only available for Dart (.dart) and JS/TS (.ts, .js, etc.) files. Got: ${relativePath}`
    };
  }

  // Handle Dart code actions
  if (isDart) {
    // Ensure document is open in Dart LSP
    await ensureDocumentOpen(absolutePath, 'dart');

    // Get code actions for a specific line or range
    const startLine = line !== null ? line - 1 : 0;
    const endL = endLine !== null ? endLine - 1 : startLine;

    const actions = (await withTimeout(
      getDartCodeActions(absolutePath, startLine, 0, endL, 0),
      20000,
      'Code actions lookup timed out'
    )) as any[];


    if (!actions || actions.length === 0) {
      const rangeInfo = line ? ` at line ${line}${endLine !== line ? `-${endLine}` : ''}` : '';
      return {
        success: true,
        output: `No code actions available for ${relativePath}${rangeInfo}`
      };
    }

    // Format the code actions for the AI
    const resultLines: string[] = [];
    resultLines.push(`Dart code actions for ${relativePath}:`);
    resultLines.push('');

    for (let i = 0; i < actions.length; i++) {
      const action = actions[i];
      resultLines.push(`${i + 1}. ${action.title}`);
      if (action.kind) {
        resultLines.push(`   Kind: ${action.kind}`);
      }
    }

    resultLines.push('');
    resultLines.push('To apply a fix, use lsp_apply_code_action with the action index.');

    return { success: true, output: resultLines.join('\n') };
  }

  // Handle ESLint code actions
  // Open document in ESLint LSP
  try {
    const doc = await fileService.read(absolutePath, true);
    if (!doc) {
      return { success: false, error: `Failed to read file: ${relativePath}` };
    }
    await notifyEslintDocumentOpened(absolutePath, doc.content);

    // Small delay to let ESLint analyze the file
    await new Promise(resolve => setTimeout(resolve, 500));
  } catch (err) {
    return { success: false, error: `Failed to read file: ${extractErrorMessage(err)}` };
  }

  // If fix_all is requested, execute ESLint fix all
  if (fixAll) {
    const edit = await executeEslintFixAll(absolutePath);

    if (!edit) {
      return {
        success: true,
        output: `No ESLint fixes available for ${relativePath}`
      };
    }

    // Apply the edits
    try {
      const filesUpdated = await applyWorkspaceEdit(edit);
      return {
        success: true,
        output: `✅ Applied ESLint fixes to ${filesUpdated} file${filesUpdated > 1 ? 's' : ''}`
      };
    } catch (err) {
      return { success: false, error: `Failed to apply fixes: ${extractErrorMessage(err)}` };
    }
  }

  // Get code actions for a specific line or range
  const startLine = line !== null ? line - 1 : 0;
  const startChar = 0;
  const endL = endLine !== null ? endLine - 1 : startLine;
  const endChar = Number.MAX_SAFE_INTEGER;

  const actions = await getEslintCodeActions(absolutePath, startLine, startChar, endL, endChar, []);

  if (!actions || actions.length === 0) {
    const rangeInfo = line ? ` at line ${line}${endLine !== line ? `-${endLine}` : ''}` : '';
    return {
      success: true,
      output: `No ESLint code actions available for ${relativePath}${rangeInfo}`
    };
  }

  // Format the code actions for the AI
  const resultLines: string[] = [];
  resultLines.push(`ESLint code actions for ${relativePath}:`);
  resultLines.push('');

  for (let i = 0; i < actions.length; i++) {
    const action = actions[i];
    resultLines.push(`${i + 1}. ${action.title}`);
    if (action.kind) {
      resultLines.push(`   Kind: ${action.kind}`);
    }
    if (action.isPreferred) {
      resultLines.push(`   ⭐ Preferred fix`);
    }
  }

  resultLines.push('');
  resultLines.push('To apply a fix, use lsp_apply_code_action with the action index.');
  resultLines.push('To fix all ESLint issues at once, use lsp_get_code_actions with fix_all: true');

  return { success: true, output: resultLines.join('\n') };
}

// ============================================================================
// TOOL: lsp_apply_code_action - Apply a specific ESLint code action
// ============================================================================

export async function handleLspApplyCodeAction(args: Record<string, unknown>): Promise<ToolResult> {
  const path = args.path ? String(args.path) : null;
  const actionIndex = typeof args.action_index === 'number' ? args.action_index : null;
  const line = typeof args.line === 'number' ? args.line : null;
  const endLine = typeof args.end_line === 'number' ? args.end_line : line;

  if (!path) {
    return { success: false, error: 'path is required' };
  }

  if (actionIndex === null || actionIndex < 1) {
    return { success: false, error: 'action_index is required (1-based index from lsp_get_code_actions)' };
  }

  const absolutePath = resolvePath(path);
  const relativePath = getRelativePath(absolutePath);

  const isDart = isDartFile(absolutePath);
  const isEslint = isEslintFile(absolutePath);

  if (!isDart && !isEslint) {
    return {
      success: false,
      error: `Code actions only available for Dart (.dart) and JS/TS (.ts, .js, etc.) files`
    };
  }

  // Handle Dart
  if (isDart) {
    await ensureDocumentOpen(absolutePath, 'dart');
    const startLine = line !== null ? line - 1 : 0;
    const endL = endLine !== null ? endLine - 1 : startLine;

    const actions = (await getDartCodeActions(absolutePath, startLine, 0, endL, 0)) as any[];

    if (!actions || actions.length === 0) {
      return { success: false, error: `No code actions available` };
    }

    if (actionIndex > actions.length) {
      return { success: false, error: `Action index ${actionIndex} out of range. Available: 1-${actions.length}` };
    }

    const action = actions[actionIndex - 1];

    if (!action.edit) {
      return { success: false, error: `Action "${action.title}" has no edit (may require command execution)` };
    }

    try {
      const filesUpdated = await applyWorkspaceEdit(action.edit);
      return {
        success: true,
        output: `✅ Applied Dart action: ${action.title}\nUpdated ${filesUpdated} file${filesUpdated > 1 ? 's' : ''}`
      };
    } catch (err) {
      return { success: false, error: `Failed to apply Dart action: ${extractErrorMessage(err)}` };
    }
  }

  // Handle ESLint
  // Open document
  try {
    const doc = await fileService.read(absolutePath, true);
    if (!doc) {
      return { success: false, error: `Failed to read file` };
    }
    await notifyEslintDocumentOpened(absolutePath, doc.content);
    await new Promise(resolve => setTimeout(resolve, 500));
  } catch (err) {
    return { success: false, error: `Failed to read file: ${extractErrorMessage(err)}` };
  }

  // Get code actions
  const startLine = line !== null ? line - 1 : 0;
  const endL = endLine !== null ? endLine - 1 : (line !== null ? line - 1 : Number.MAX_SAFE_INTEGER);

  const actions = (await getEslintCodeActions(absolutePath, startLine, 0, endL, Number.MAX_SAFE_INTEGER, [])) as any[];

  if (!actions || actions.length === 0) {
    return { success: false, error: `No code actions available` };
  }

  if (actionIndex > actions.length) {
    return {
      success: false,
      error: `Action index ${actionIndex} out of range. Available: 1-${actions.length}`
    };
  }

  const action = actions[actionIndex - 1];

  if (!action.edit) {
    return {
      success: false,
      error: `Action "${action.title}" has no edit (may require command execution)`
    };
  }

  // Apply the edit
  try {
    const filesUpdated = await applyWorkspaceEdit(action.edit);
    return {
      success: true,
      output: `✅ Applied: ${action.title}\nUpdated ${filesUpdated} file${filesUpdated > 1 ? 's' : ''}`
    };
  } catch (err) {
    return { success: false, error: `Failed to apply action: ${extractErrorMessage(err)}` };
  }
}

/**
 * Apply a workspace edit (supports both changes and documentChanges)
 */
async function applyWorkspaceEdit(edit: any): Promise<number> {
  let filesUpdated = 0;

  // Handle changes format
  if (edit.changes) {
    for (const [uri, edits] of Object.entries(edit.changes)) {
      await applyTextEditsToUri(uri, edits as any[]);
      filesUpdated++;
    }
  }

  // Handle documentChanges format
  if (edit.documentChanges) {
    for (const change of edit.documentChanges as any[]) {
      if ('textDocument' in change && 'edits' in change) {
        await applyTextEditsToUri(change.textDocument.uri, change.edits);
        filesUpdated++;
      }
    }
  }

  return filesUpdated;
}

/**
 * Apply text edits to a file by URI
 */
async function applyTextEditsToUri(uri: string, edits: TextEdit[]): Promise<void> {
  // Convert URI to file path
  let filePath = uri.replace('file://', '');
  if (filePath.match(/^\/[a-zA-Z]:/)) {
    filePath = filePath.slice(1);
  }
  filePath = filePath.replace(/%20/g, ' ');

  // Read current content via fileService
  const doc = await fileService.read(filePath, true);
  if (!doc) {
    throw new Error(`Failed to read file: ${filePath}`);
  }
  const lines = doc.content.split('\n');

  // Sort edits in reverse order (bottom to top) to preserve line numbers
  const sortedEdits = [...edits].sort((a, b) => {
    if (a.range.start.line !== b.range.start.line) {
      return b.range.start.line - a.range.start.line;
    }
    return b.range.start.character - a.range.start.character;
  });

  // Apply each edit
  for (const edit of sortedEdits) {
    const startLine = edit.range.start.line;
    const startChar = edit.range.start.character;
    const endLine = edit.range.end.line;
    const endChar = edit.range.end.character;

    if (startLine === endLine) {
      // Single line edit
      const line = lines[startLine] || '';
      lines[startLine] = line.slice(0, startChar) + edit.newText + line.slice(endChar);
    } else {
      // Multi-line edit
      const startLineContent = lines[startLine] || '';
      const endLineContent = lines[endLine] || '';
      const newContent = startLineContent.slice(0, startChar) + edit.newText + endLineContent.slice(endChar);
      lines.splice(startLine, endLine - startLine + 1, newContent);
    }
  }

  // Write back via fileService
  const newContent = lines.join('\n');
  const result = await fileService.write(filePath, newContent, { source: 'lsp' });
  if (!result.success) {
    throw new Error(`Failed to write file: ${result.error}`);
  }
}

/**
 * Read tool handlers - read_file, list_dir, and optional legacy readers
 * 
 * Kiro-style features:
 * - Explanation parameter for intelligent pruning
 * - Line numbers in output
 * - Smart truncation
 */

import { invoke } from '@tauri-apps/api/core';
import { fileService } from '$core/services/file-service';
import { resolvePath, truncateOutput, formatWithLineNumbers, type ToolResult } from '$core/ai/tools/utils';

/**
 * Extract keywords from explanation for content relevance scoring
 */
function extractKeywords(explanation: string): string[] {
  if (!explanation) return [];

  // Remove common words and extract meaningful terms
  const stopWords = new Set([
    'the', 'a', 'an', 'is', 'are', 'was', 'were', 'be', 'been', 'being',
    'have', 'has', 'had', 'do', 'does', 'did', 'will', 'would', 'could', 'should',
    'may', 'might', 'must', 'shall', 'can', 'need', 'dare', 'ought', 'used',
    'to', 'of', 'in', 'for', 'on', 'with', 'at', 'by', 'from', 'as', 'into',
    'through', 'during', 'before', 'after', 'above', 'below', 'between',
    'and', 'but', 'or', 'nor', 'so', 'yet', 'both', 'either', 'neither',
    'not', 'only', 'own', 'same', 'than', 'too', 'very', 'just', 'also',
    'this', 'that', 'these', 'those', 'what', 'which', 'who', 'whom', 'whose',
    'where', 'when', 'why', 'how', 'all', 'each', 'every', 'any', 'some',
    'file', 'code', 'function', 'find', 'look', 'see', 'check', 'read', 'get',
    'i', 'me', 'my', 'we', 'our', 'you', 'your', 'it', 'its', 'they', 'their'
  ]);

  const words = explanation.toLowerCase()
    .replace(/[^a-z0-9_\-]/g, ' ')
    .split(/\s+/)
    .filter(w => w.length > 2 && !stopWords.has(w));

  return [...new Set(words)];
}

/**
 * Score a line's relevance based on keywords
 */
function scoreLineRelevance(line: string, keywords: string[]): number {
  if (keywords.length === 0) return 1;

  const lineLower = line.toLowerCase();
  let score = 0;

  for (const keyword of keywords) {
    if (lineLower.includes(keyword)) {
      score += 2;
      // Bonus for exact word match
      if (new RegExp(`\\b${keyword}\\b`).test(lineLower)) {
        score += 1;
      }
    }
  }

  // Bonus for important code patterns
  if (/^(export|function|class|interface|type|const|let|var)\s/.test(line.trim())) {
    score += 1;
  }

  return score;
}

/**
 * Intelligently prune file content based on explanation
 * Keeps relevant sections + context, removes irrelevant parts
 */
function pruneContent(content: string, explanation: string, maxLines = 300): {
  pruned: string;
  wasPruned: boolean;
  relevantRanges: Array<{ start: number; end: number }>;
} {
  const lines = content.split('\n');

  // If file is small enough, return as-is
  if (lines.length <= maxLines || !explanation) {
    return { pruned: content, wasPruned: false, relevantRanges: [] };
  }

  const keywords = extractKeywords(explanation);
  if (keywords.length === 0) {
    // No keywords - just truncate
    return {
      pruned: lines.slice(0, maxLines).join('\n') + '\n... [truncated]',
      wasPruned: true,
      relevantRanges: []
    };
  }

  // Score each line
  const scores = lines.map((line, i) => ({ line, index: i, score: scoreLineRelevance(line, keywords) }));

  // Find relevant sections (lines with score > 0 + context)
  const contextLines = 5; // Lines before/after relevant code
  const relevantIndices = new Set<number>();
  const relevantRanges: Array<{ start: number; end: number }> = [];

  for (const { index, score } of scores) {
    if (score > 0) {
      const start = Math.max(0, index - contextLines);
      const end = Math.min(lines.length - 1, index + contextLines);

      for (let i = start; i <= end; i++) {
        relevantIndices.add(i);
      }

      // Track ranges for metadata
      if (relevantRanges.length === 0 || relevantRanges[relevantRanges.length - 1].end < start - 1) {
        relevantRanges.push({ start: start + 1, end: end + 1 }); // 1-based
      } else {
        relevantRanges[relevantRanges.length - 1].end = end + 1;
      }
    }
  }

  // Always include first 20 lines (imports, class definition)
  for (let i = 0; i < Math.min(20, lines.length); i++) {
    relevantIndices.add(i);
  }

  // Build pruned output
  const sortedIndices = [...relevantIndices].sort((a, b) => a - b);
  const prunedLines: string[] = [];
  let lastIndex = -1;

  for (const index of sortedIndices) {
    if (prunedLines.length >= maxLines) break;

    // Add ellipsis for gaps
    if (lastIndex >= 0 && index > lastIndex + 1) {
      const gap = index - lastIndex - 1;
      prunedLines.push(`... [${gap} lines omitted]`);
    }

    prunedLines.push(lines[index]);
    lastIndex = index;
  }

  // Add final ellipsis if needed
  if (lastIndex < lines.length - 1) {
    const remaining = lines.length - lastIndex - 1;
    prunedLines.push(`... [${remaining} lines omitted]`);
  }

  return {
    pruned: prunedLines.join('\n'),
    wasPruned: true,
    relevantRanges
  };
}

/**
 * Read a single file with optional line slice
 * Kiro-style: includes line numbers, intelligent pruning based on explanation
 */
export async function handleReadFile(args: Record<string, unknown>): Promise<ToolResult> {
  const relativePath = String(args.path);
  const explanation = args.explanation ? String(args.explanation) : '';
  const path = resolvePath(relativePath);

  let content: string;
  try {
    // Use fileService for consistent file access - always get fresh from disk for AI reads
    const doc = await fileService.read(path, true);
    if (!doc) {
      return { success: false, error: `File not found: ${relativePath}` };
    }
    content = doc.content;
  } catch (err) {
    return { success: false, error: `File not found: ${relativePath}` };
  }

  const totalLines = content.split('\n').length;

  const rawOffset = Number(args.offset);
  const rawLimit = Number(args.limit);
  const offset = Number.isFinite(rawOffset) ? Math.max(0, Math.floor(rawOffset)) : 0;
  const limit = Number.isFinite(rawLimit)
    ? Math.min(2000, Math.max(1, Math.floor(rawLimit)))
    : totalLines;
  const startLine = Math.min(totalLines, offset + 1);
  const endLine = Math.min(totalLines, startLine + limit - 1);

  let output = content;
  let wasPruned = false;
  let relevantRanges: Array<{ start: number; end: number }> = [];

  if (offset > 0 || Number.isFinite(rawLimit)) {
    // Explicit slice requested.
    const lines = content.split('\n');
    output = lines.slice(startLine - 1, endLine).join('\n');
  } else if (explanation) {
    // No line range but has explanation - use intelligent pruning
    const pruneResult = pruneContent(content, explanation);
    output = pruneResult.pruned;
    wasPruned = pruneResult.wasPruned;
    relevantRanges = pruneResult.relevantRanges;
  }

  // Format with line numbers (Kiro-style)
  const formatted = formatWithLineNumbers(output, startLine);

  // Add header
  let header = startLine === 1 && endLine === totalLines
    ? `${relativePath} (${totalLines} lines)`
    : `${relativePath} lines ${startLine}-${endLine} of ${totalLines}`;

  if (wasPruned) {
    header += ' [intelligently pruned]';
  }
  header += '\n';

  const { text, truncated } = truncateOutput(header + formatted);

  return {
    success: true,
    output: text,
    truncated,
    meta: {
      startLine,
      endLine,
      totalLines,
      wasPruned,
      relevantRanges
    }
  };
}

/**
 * Read multiple files at once
 */
export async function handleReadFiles(args: Record<string, unknown>): Promise<ToolResult> {
  const paths = args.paths as string[] | undefined;
  if (!paths || !Array.isArray(paths) || paths.length === 0) {
    return { success: false, error: 'No paths provided' };
  }

  const results: string[] = [];
  let totalLines = 0;

  for (const relativePath of paths) {
    const path = resolvePath(relativePath);
    try {
      // Use fileService for consistent file access - always get fresh from disk
      const doc = await fileService.read(path, true);
      if (!doc) {
        results.push(`── ${relativePath} ──\n[Error: File not found]`);
        continue;
      }
      const content = doc.content;
      const lines = content.split('\n').length;
      totalLines += lines;

      const formatted = formatWithLineNumbers(content);
      results.push(`── ${relativePath} (${lines} lines) ──\n${formatted}`);
    } catch {
      results.push(`── ${relativePath} ──\n[Error: File not found]`);
    }
  }

  const { text, truncated } = truncateOutput(results.join('\n\n'));

  return {
    success: true,
    output: text,
    truncated,
    meta: { totalLines, fileCount: paths.length }
  };
}

/**
 * List directory contents
 */
export async function handleListDir(args: Record<string, unknown>): Promise<ToolResult> {
  const relativePath = String(args.path || '.');
  const path = resolvePath(relativePath);

  try {
    const entries = await invoke<Array<{
      name: string;
      isDir: boolean;
      size: number;
    }>>('list_dir', { path });

    if (entries.length === 0) {
      return { success: true, output: `${relativePath}/ (empty)` };
    }

    // Sort: directories first, then files
    entries.sort((a, b) => {
      if (a.isDir !== b.isDir) return a.isDir ? -1 : 1;
      return a.name.localeCompare(b.name);
    });

    const lines = entries.map(e => {
      const icon = e.isDir ? '📁' : '📄';
      const size = e.isDir ? '' : ` (${formatSize(e.size)})`;
      return `${icon} ${e.name}${size}`;
    });

    return {
      success: true,
      output: `${relativePath}/\n${lines.join('\n')}`
    };
  } catch (err) {
    return { success: false, error: `Cannot list: ${relativePath}` };
  }
}

/**
 * Get file tree structure (recursive directory listing)
 * BETTER than Kiro's listDirectory:
 * - Shows file type icons/emojis
 * - Shows file counts per directory
 * - Smarter directory skipping
 * - Shows project type detection (React, Svelte, etc.)
 * - LARGE PROJECT SAFE: Caps total entries to prevent context overflow
 */
export async function handleGetFileTree(args: Record<string, unknown>): Promise<ToolResult> {
  const relativePath = String(args.path || '.');
  const maxDepth = Math.min(Number(args.depth) || 3, 4); // Cap at 4 for safety
  const path = resolvePath(relativePath);

  try {
    const { tree, stats, wasTruncated } = await buildFileTreeWithStats(path, relativePath, 0, maxDepth);
    const output = formatFileTreeBetter(tree, relativePath, stats, wasTruncated);
    const { text, truncated } = truncateOutput(output);
    return { success: true, output: text, truncated: truncated || wasTruncated };
  } catch (err) {
    return { success: false, error: `Cannot get tree: ${relativePath}` };
  }
}

interface TreeEntry {
  name: string;
  isDir: boolean;
  children?: TreeEntry[];
  fileCount?: number; // For directories
}

interface TreeStats {
  totalFiles: number;
  totalDirs: number;
  fileTypes: Map<string, number>;
  projectType?: string;
}

// Global limit to prevent context overflow on huge projects
const MAX_TREE_ENTRIES = 200;

/**
 * Recursively build file tree with statistics
 * LARGE PROJECT SAFE: Stops after MAX_TREE_ENTRIES
 */
async function buildFileTreeWithStats(
  absolutePath: string,
  relativePath: string,
  currentDepth: number,
  maxDepth: number
): Promise<{ tree: TreeEntry[]; stats: TreeStats; wasTruncated: boolean }> {
  const stats: TreeStats = {
    totalFiles: 0,
    totalDirs: 0,
    fileTypes: new Map(),
  };

  let entryCount = 0;
  let wasTruncated = false;

  const tree = await buildFileTreeRecursive(absolutePath, relativePath, currentDepth, maxDepth, stats,
    () => entryCount++,
    () => entryCount >= MAX_TREE_ENTRIES,
    () => { wasTruncated = true; }
  );

  // Detect project type from file types
  if (stats.fileTypes.has('svelte')) stats.projectType = 'Svelte';
  else if (stats.fileTypes.has('tsx') || stats.fileTypes.has('jsx')) stats.projectType = 'React';
  else if (stats.fileTypes.has('vue')) stats.projectType = 'Vue';
  else if (stats.fileTypes.has('py')) stats.projectType = 'Python';
  else if (stats.fileTypes.has('rs')) stats.projectType = 'Rust';
  else if (stats.fileTypes.has('go')) stats.projectType = 'Go';
  else if (stats.fileTypes.has('ts') || stats.fileTypes.has('js')) stats.projectType = 'Node.js';

  return { tree, stats, wasTruncated };
}

async function buildFileTreeRecursive(
  absolutePath: string,
  relativePath: string,
  currentDepth: number,
  maxDepth: number,
  stats: TreeStats,
  incrementCount: () => void,
  shouldStop: () => boolean,
  markTruncated: () => void
): Promise<TreeEntry[]> {
  if (currentDepth >= maxDepth || shouldStop()) return [];

  try {
    const entries = await invoke<Array<{ name: string; isDir: boolean; path: string }>>('list_dir', { path: absolutePath });

    // Sort: directories first, then alphabetically
    entries.sort((a, b) => {
      if (a.isDir && !b.isDir) return -1;
      if (!a.isDir && b.isDir) return 1;
      return a.name.toLowerCase().localeCompare(b.name.toLowerCase());
    });

    // Skip common non-essential directories
    const skipDirs = ['node_modules', '.git', 'dist', 'build', '.svelte-kit', '__pycache__', '.next', 'coverage', '.turbo', '.cache', 'vendor', 'target', '.pnpm', '.yarn'];

    const result: TreeEntry[] = [];
    for (const entry of entries) {
      // Check if we should stop
      if (shouldStop()) {
        markTruncated();
        break;
      }

      // Skip hidden files at root level (except important ones)
      if (entry.name.startsWith('.') && currentDepth === 0) {
        if (!['env', '.env', '.env.local', '.gitignore', '.eslintrc', '.prettierrc'].some(f => entry.name.includes(f))) {
          continue;
        }
      }
      if (skipDirs.includes(entry.name)) continue;

      incrementCount();

      const treeEntry: TreeEntry = {
        name: entry.name,
        isDir: entry.isDir,
      };

      if (entry.isDir) {
        stats.totalDirs++;
        if (currentDepth < maxDepth - 1 && !shouldStop()) {
          treeEntry.children = await buildFileTreeRecursive(
            entry.path,
            `${relativePath}/${entry.name}`,
            currentDepth + 1,
            maxDepth,
            stats,
            incrementCount,
            shouldStop,
            markTruncated
          );
          treeEntry.fileCount = treeEntry.children.filter(c => !c.isDir).length;
        }
      } else {
        stats.totalFiles++;
        // Track file types
        const ext = entry.name.split('.').pop()?.toLowerCase() || '';
        if (ext) {
          stats.fileTypes.set(ext, (stats.fileTypes.get(ext) || 0) + 1);
        }
      }

      result.push(treeEntry);
    }

    return result;
  } catch {
    return [];
  }
}

/**
 * Format tree with icons and better structure
 */
function formatFileTreeBetter(entries: TreeEntry[], rootPath: string, stats: TreeStats, wasTruncated: boolean): string {
  const lines: string[] = [];

  // Header with project info
  lines.push(`📂 ${rootPath}/`);
  if (stats.projectType) {
    lines.push(`   Project: ${stats.projectType} | ${stats.totalFiles} files, ${stats.totalDirs} directories`);
  } else {
    lines.push(`   ${stats.totalFiles} files, ${stats.totalDirs} directories`);
  }

  if (wasTruncated) {
    lines.push(`   ⚠️ Large project - showing first ${MAX_TREE_ENTRIES} entries. Use find_files or workspace_search for specific files.`);
  }
  lines.push('');

  // Tree
  lines.push(formatTreeRecursive(entries, ''));

  if (wasTruncated) {
    lines.push('');
    lines.push('... (truncated for large project)');
  }

  return lines.join('\n');
}

function formatTreeRecursive(entries: TreeEntry[], prefix: string): string {
  let output = '';

  for (let i = 0; i < entries.length; i++) {
    const entry = entries[i];
    const isLast = i === entries.length - 1;
    const connector = isLast ? '└── ' : '├── ';
    const childPrefix = isLast ? '    ' : '│   ';

    if (entry.isDir) {
      const countInfo = entry.fileCount !== undefined ? ` (${entry.fileCount})` : '';
      output += `${prefix}${connector}📁 ${entry.name}/${countInfo}\n`;
    } else {
      const icon = getFileTypeIcon(entry.name);
      output += `${prefix}${connector}${icon} ${entry.name}\n`;
    }

    if (entry.children && entry.children.length > 0) {
      output += formatTreeRecursive(entry.children, prefix + childPrefix);
    }
  }

  return output;
}

/**
 * Get icon for file type
 */
function getFileTypeIcon(filename: string): string {
  const ext = filename.split('.').pop()?.toLowerCase() || '';

  const icons: Record<string, string> = {
    'ts': '📘', 'tsx': '⚛️', 'js': '📒', 'jsx': '⚛️',
    'svelte': '🔶', 'vue': '💚', 'py': '🐍', 'rs': '🦀',
    'go': '🐹', 'java': '☕', 'rb': '💎', 'php': '🐘',
    'html': '🌐', 'css': '🎨', 'scss': '🎨', 'sass': '🎨',
    'json': '📋', 'yaml': '📋', 'yml': '📋', 'toml': '📋',
    'md': '📝', 'txt': '📄', 'sql': '🗃️',
    'png': '🖼️', 'jpg': '🖼️', 'svg': '🎨', 'ico': '🖼️',
    'lock': '🔒', 'env': '🔐',
  };

  return icons[ext] || '📄';
}

/**
 * Get file info (size, modified date, etc.)
 */
export async function handleGetFileInfo(args: Record<string, unknown>): Promise<ToolResult> {
  const relativePath = String(args.path);
  const path = resolvePath(relativePath);

  try {
    const info = await invoke<{
      name: string;
      isDir: boolean;
      isFile: boolean;
      isReadonly: boolean;
      size: number;
      modified: number | null;
    }>('get_file_info', { path });

    const output = [
      `Name: ${info.name}`,
      `Type: ${info.isDir ? 'Directory' : 'File'}`,
      `Size: ${formatSize(info.size)}`,
      info.modified ? `Modified: ${new Date(info.modified).toLocaleString()}` : null
    ].filter(Boolean).join('\n');

    return { success: true, output };
  } catch (err) {
    return { success: false, error: `File not found: ${relativePath}` };
  }
}

/**
 * Format file size in human readable format
 */
function formatSize(bytes: number): string {
  if (bytes < 1024) return `${bytes} B`;
  if (bytes < 1024 * 1024) return `${(bytes / 1024).toFixed(1)} KB`;
  return `${(bytes / (1024 * 1024)).toFixed(1)} MB`;
}


/**
 * Read code file with smart structure analysis
 * VOLT EXCLUSIVE - Better than Kiro's readFile:
 * - Shows file structure (functions, classes, exports)
 * - Can read specific symbol by name
 * - Auto-detects and highlights important sections
 * - LARGE FILE SAFE: Skips structure analysis for huge files
 */
export async function handleReadCode(args: Record<string, unknown>): Promise<ToolResult> {
  const relativePath = String(args.path);
  const symbolName = args.symbol ? String(args.symbol) : '';
  const showStructure = args.structure !== false; // Default true
  const path = resolvePath(relativePath);

  let content: string;
  try {
    const doc = await fileService.read(path, true);
    if (!doc) {
      return { success: false, error: `File not found: ${relativePath}` };
    }
    content = doc.content;
  } catch (err) {
    return { success: false, error: `File not found: ${relativePath}` };
  }

  const lines = content.split('\n');
  const totalLines = lines.length;
  const ext = relativePath.split('.').pop()?.toLowerCase() || '';

  // Skip structure analysis for huge files (>2000 lines) to prevent slowdown
  const isHugeFile = totalLines > 2000;

  // Analyze code structure (skip for huge files unless symbol requested)
  const structure = (isHugeFile && !symbolName)
    ? { symbols: [], imports: [] }
    : analyzeCodeStructure(content, ext);

  // If symbol requested, find and return just that symbol
  if (symbolName) {
    const symbol = structure.symbols.find(s =>
      s.name.toLowerCase() === symbolName.toLowerCase() ||
      s.name.toLowerCase().includes(symbolName.toLowerCase())
    );

    if (symbol) {
      const symbolContent = lines.slice(symbol.startLine - 1, symbol.endLine).join('\n');
      const formatted = formatWithLineNumbers(symbolContent, symbol.startLine);

      return {
        success: true,
        output: `${relativePath} - ${symbol.kind}: ${symbol.name} (lines ${symbol.startLine}-${symbol.endLine})\n\n${formatted}`,
        meta: { symbol, totalLines }
      };
    } else {
      const availableSymbols = structure.symbols.length > 0
        ? structure.symbols.slice(0, 20).map(s => s.name).join(', ')
        : '(file too large for full analysis - try workspace_search)';
      return {
        success: false,
        error: `Symbol "${symbolName}" not found. Available: ${availableSymbols}`
      };
    }
  }

  // Build output with structure header
  const outputLines: string[] = [];

  // Header
  outputLines.push(`📄 ${relativePath} (${totalLines} lines)`);

  if (isHugeFile) {
    outputLines.push(`⚠️ Large file - structure analysis skipped. Use symbol parameter to read specific functions.`);
  }

  // Structure summary if requested and file has structure
  if (showStructure && structure.symbols.length > 0 && !isHugeFile) {
    outputLines.push('');
    outputLines.push('📋 Structure:');

    // Group by kind
    const byKind = new Map<string, typeof structure.symbols>();
    for (const sym of structure.symbols) {
      if (!byKind.has(sym.kind)) byKind.set(sym.kind, []);
      byKind.get(sym.kind)!.push(sym);
    }

    for (const [kind, syms] of byKind) {
      const icon = kind === 'function' ? '⚡' : kind === 'class' ? '🏛️' : kind === 'interface' ? '📐' : kind === 'type' ? '📝' : '•';
      for (const sym of syms.slice(0, 15)) { // Cap at 15 per kind
        const exported = sym.exported ? '↗️' : '  ';
        outputLines.push(`   ${exported} ${icon} ${sym.name} (L${sym.startLine})`);
      }
      if (syms.length > 15) {
        outputLines.push(`   ... +${syms.length - 15} more ${kind}s`);
      }
    }
    outputLines.push('');
  }

  // File content with line numbers
  const formatted = formatWithLineNumbers(content);
  const { text, truncated } = truncateOutput(outputLines.join('\n') + '\n' + formatted);

  return {
    success: true,
    output: text,
    truncated,
    meta: { totalLines, structure: isHugeFile ? null : structure }
  };
}

interface CodeSymbol {
  name: string;
  kind: 'function' | 'class' | 'interface' | 'type' | 'const' | 'variable';
  startLine: number;
  endLine: number;
  exported: boolean;
}

interface CodeStructure {
  symbols: CodeSymbol[];
  imports: string[];
}

/**
 * Analyze code structure using regex patterns
 * Works for TS/JS/Svelte - no LSP needed
 */
function analyzeCodeStructure(content: string, ext: string): CodeStructure {
  const lines = content.split('\n');
  const symbols: CodeSymbol[] = [];
  const imports: string[] = [];

  // Patterns for different constructs
  const patterns = {
    function: /^(export\s+)?(async\s+)?function\s+(\w+)/,
    arrowFunction: /^(export\s+)?(const|let)\s+(\w+)\s*=\s*(async\s*)?\([^)]*\)\s*(:\s*\w+)?\s*=>/,
    class: /^(export\s+)?class\s+(\w+)/,
    interface: /^(export\s+)?interface\s+(\w+)/,
    type: /^(export\s+)?type\s+(\w+)/,
    constExport: /^export\s+const\s+(\w+)/,
    import: /^import\s+/,
  };

  let braceDepth = 0;
  let currentSymbol: CodeSymbol | null = null;

  for (let i = 0; i < lines.length; i++) {
    const line = lines[i];
    const trimmed = line.trim();
    const lineNum = i + 1;

    // Track imports
    if (patterns.import.test(trimmed)) {
      imports.push(trimmed);
      continue;
    }

    // Skip if inside a symbol body
    if (currentSymbol) {
      // Count braces
      for (const char of line) {
        if (char === '{') braceDepth++;
        if (char === '}') braceDepth--;
      }

      if (braceDepth === 0) {
        currentSymbol.endLine = lineNum;
        symbols.push(currentSymbol);
        currentSymbol = null;
      }
      continue;
    }

    // Check for new symbols
    let match: RegExpMatchArray | null;

    if ((match = trimmed.match(patterns.function))) {
      currentSymbol = {
        name: match[3],
        kind: 'function',
        startLine: lineNum,
        endLine: lineNum,
        exported: !!match[1]
      };
      braceDepth = (line.match(/{/g) || []).length - (line.match(/}/g) || []).length;
      if (braceDepth === 0 && line.includes('{') && line.includes('}')) {
        symbols.push(currentSymbol);
        currentSymbol = null;
      }
    } else if ((match = trimmed.match(patterns.arrowFunction))) {
      currentSymbol = {
        name: match[3],
        kind: 'function',
        startLine: lineNum,
        endLine: lineNum,
        exported: !!match[1]
      };
      braceDepth = (line.match(/{/g) || []).length - (line.match(/}/g) || []).length;
      if (braceDepth <= 0) {
        // Single line arrow function
        symbols.push(currentSymbol);
        currentSymbol = null;
        braceDepth = 0;
      }
    } else if ((match = trimmed.match(patterns.class))) {
      currentSymbol = {
        name: match[2],
        kind: 'class',
        startLine: lineNum,
        endLine: lineNum,
        exported: !!match[1]
      };
      braceDepth = (line.match(/{/g) || []).length - (line.match(/}/g) || []).length;
    } else if ((match = trimmed.match(patterns.interface))) {
      currentSymbol = {
        name: match[2],
        kind: 'interface',
        startLine: lineNum,
        endLine: lineNum,
        exported: !!match[1]
      };
      braceDepth = (line.match(/{/g) || []).length - (line.match(/}/g) || []).length;
      if (braceDepth === 0) {
        symbols.push(currentSymbol);
        currentSymbol = null;
      }
    } else if ((match = trimmed.match(patterns.type))) {
      currentSymbol = {
        name: match[2],
        kind: 'type',
        startLine: lineNum,
        endLine: lineNum,
        exported: !!match[1]
      };
      // Types usually end with ; on same or next line
      if (trimmed.endsWith(';') || trimmed.endsWith('}')) {
        symbols.push(currentSymbol);
        currentSymbol = null;
      } else {
        braceDepth = (line.match(/{/g) || []).length - (line.match(/}/g) || []).length;
      }
    } else if ((match = trimmed.match(patterns.constExport))) {
      // Simple exported const (not arrow function)
      symbols.push({
        name: match[1],
        kind: 'const',
        startLine: lineNum,
        endLine: lineNum,
        exported: true
      });
    }
  }

  // Close any unclosed symbol
  if (currentSymbol) {
    currentSymbol.endLine = lines.length;
    symbols.push(currentSymbol);
  }

  return { symbols, imports };
}

// ============================================================================
// FILE OUTLINE - Structure only, no content (token-efficient)
// ============================================================================

/**
 * Get file structure outline without loading content.
 * Returns classes, functions, interfaces, types with line ranges.
 * Works on large files (no content = no size limit concerns).
 * ~100x more token-efficient than read_code for understanding file structure.
 */
export async function handleFileOutline(args: Record<string, unknown>): Promise<ToolResult> {
  const relativePath = String(args.path);
  const path = resolvePath(relativePath);

  let content: string;
  try {
    const doc = await fileService.read(path, true);
    if (!doc) {
      return { success: false, error: `File not found: ${relativePath}` };
    }
    content = doc.content;
  } catch {
    return { success: false, error: `File not found: ${relativePath}` };
  }

  const lines = content.split('\n');
  const totalLines = lines.length;
  const ext = relativePath.split('.').pop()?.toLowerCase() || '';

  // Analyze structure — no size limit since we're not returning content
  const structure = analyzeCodeStructure(content, ext);

  // Build compact outline
  const outputLines: string[] = [];
  outputLines.push(`📄 ${relativePath} (${totalLines} lines)`);

  // Import summary
  if (structure.imports.length > 0) {
    outputLines.push(`\nImports: ${structure.imports.length} imports`);
  }

  // Symbols grouped by kind
  if (structure.symbols.length === 0) {
    outputLines.push('\nNo symbols detected (may be a config, data, or markup file)');
  } else {
    outputLines.push('\nSymbols:');

    // Group by kind
    const byKind = new Map<string, typeof structure.symbols>();
    for (const sym of structure.symbols) {
      if (!byKind.has(sym.kind)) byKind.set(sym.kind, []);
      byKind.get(sym.kind)!.push(sym);
    }

    for (const [kind, syms] of byKind) {
      const icon = kind === 'function' ? '⚡' : kind === 'class' ? '🏛️' : kind === 'interface' ? '📐' : kind === 'type' ? '📝' : kind === 'const' ? '📦' : '•';
      for (const sym of syms.slice(0, 30)) {
        const exported = sym.exported ? '↗️ ' : '   ';
        const range = sym.endLine > sym.startLine ? `L${sym.startLine}-L${sym.endLine}` : `L${sym.startLine}`;
        outputLines.push(`  ${exported}${icon} ${sym.name} (${range})`);
      }
      if (syms.length > 30) {
        outputLines.push(`  ... +${syms.length - 30} more ${kind}s`);
      }
    }
  }

  return {
    success: true,
    output: outputLines.join('\n'),
    meta: {
      totalLines,
      symbolCount: structure.symbols.length,
      importCount: structure.imports.length,
    }
  };
}

/**
 * Search tool handlers - workspace_search and optional legacy search helpers
 * 
 * BETTER than Kiro:
 * - Smart result grouping by relevance
 * - Code-aware context (shows full function when match is inside)
 * - Deduplication of overlapping matches
 * - Clear file:line format for easy navigation
 */

import { invoke } from '@tauri-apps/api/core';
import { fileService } from '$core/services/file-service';
import { getIndexAge, indexProject, isIndexReady, searchFiles } from '$core/services/file-index';
import { projectStore } from '$shared/stores/project.svelte';
import { truncateOutput, resolvePath, type ToolResult } from '$core/ai/tools/utils';
import { getWorkspaceSymbols as getTsWorkspaceSymbols, isTsLspConnected, ensureTsLspStarted } from '$core/lsp/typescript-sidecar';
import { getWorkspaceSymbols as getDartWorkspaceSymbols, isDartLspRunning } from '$core/lsp/dart-sidecar';

/**
 * Search workspace for text/regex patterns
 * BETTER than Kiro's grepSearch:
 * - Shows 2 lines context (same as Kiro)
 * - Groups results by file with clear formatting
 * - Deduplicates overlapping context
 * - Shows file:line format for easy navigation
 * - Caps at 50 matches (same as Kiro)
 * - Truncates long lines at 120 chars
 */
export async function handleWorkspaceSearch(args: Record<string, unknown>): Promise<ToolResult> {
  const query = String(args.query);
  const includePattern = args.includePattern ? String(args.includePattern) : '';
  const excludePattern = args.excludePattern ? String(args.excludePattern) : '';
  const caseSensitive = Boolean(args.caseSensitive);
  const explanation = args.explanation ? String(args.explanation) : '';
  const workspaceRoot = projectStore.rootPath || '';

  if (!query.trim()) {
    return { success: false, error: 'Search query cannot be empty' };
  }

  // Smart query enhancement based on explanation
  // If explanation mentions specific file types, auto-add include pattern
  let smartIncludePattern = includePattern;
  if (!includePattern && explanation) {
    const expLower = explanation.toLowerCase();
    if (expLower.includes('component') || expLower.includes('svelte')) {
      smartIncludePattern = '**/*.svelte';
    } else if (expLower.includes('react') || expLower.includes('jsx')) {
      smartIncludePattern = '**/*.{tsx,jsx}';
    } else if (expLower.includes('style') || expLower.includes('css')) {
      smartIncludePattern = '**/*.{css,scss,sass,less}';
    } else if (expLower.includes('test') || expLower.includes('spec')) {
      smartIncludePattern = '**/*.{test,spec}.{ts,tsx,js,jsx}';
    } else if (expLower.includes('config')) {
      smartIncludePattern = '**/*.{json,yaml,yml,toml,config.*}';
    }
  }

  try {
    const result = await invoke<{
      files: Array<{
        path: string;
        matches: Array<{ line: number; lineContent: string }>;
      }>;
      totalMatches: number;
      truncated: boolean;
      telemetry?: {
        requestedEngine: string;
        engine: string;
        fallbackUsed: boolean;
        fallbackReason?: string | null;
        elapsedMs: number;
        rgSource?: string;
        rgPath?: string | null;
      };
    }>('workspace_search', {
      options: {
        query,
        rootPath: workspaceRoot,
        useRegex: true,
        caseSensitive,
        includePatterns: smartIncludePattern ? [smartIncludePattern] : [],
        excludePatterns: excludePattern
          ? [excludePattern, 'node_modules/**', '.git/**', 'target/**', 'dist/**', 'build/**', '.svelte-kit/**']
          : ['node_modules/**', '.git/**', 'target/**', 'dist/**', 'build/**', '.svelte-kit/**'],
        maxResults: 50,
        requestId: Date.now()
      }
    });

    if (result.totalMatches === 0) {
      // Helpful message with suggestions
      let msg = `No matches for "${query}"`;
      if (caseSensitive) {
        msg += '\nTip: Try with caseSensitive: false';
      }
      if (includePattern) {
        msg += `\nSearched in: ${includePattern}`;
      }
      return { success: true, output: msg };
    }

    // Format output - clean, scannable format like Kiro but better
    const lines: string[] = [];
    const fileCount = result.files.length;
    const matchCount = result.totalMatches;

    lines.push(`Found ${matchCount} match${matchCount > 1 ? 'es' : ''} in ${fileCount} file${fileCount > 1 ? 's' : ''}`);
    if (result.telemetry) {
      const fallback = result.telemetry.fallbackUsed && result.telemetry.fallbackReason
        ? `, fallback: ${result.telemetry.fallbackReason}`
        : result.telemetry.fallbackUsed
          ? ', fallback used'
          : '';
      const source = result.telemetry.rgSource ? `, source: ${result.telemetry.rgSource}` : '';
      lines.push(`Engine: ${result.telemetry.engine} (${result.telemetry.elapsedMs}ms${source}${fallback})`);
    }
    if (result.truncated) {
      lines.push('(results truncated)');
    }
    lines.push('');

    // Process each file - limit to 10 files to prevent context overflow
    const maxFilesToShow = 10;
    for (const file of result.files.slice(0, maxFilesToShow)) {
      const relativePath = file.path.replace(workspaceRoot, '').replace(/^[/\\]/, '');

      // Get file content for context (skip for very large match counts to save time)
      let fileLines: string[] = [];
      if (file.matches.length <= 10) {
        try {
          const doc = await fileService.read(file.path, true);
          if (doc) {
            fileLines = doc.content.split('\n');
          }
        } catch {
          // Continue without context
        }
      }

      lines.push(`── ${relativePath} (${file.matches.length} match${file.matches.length > 1 ? 'es' : ''}) ──`);

      // Track which lines we've shown to avoid duplicates
      const shownLines = new Set<number>();

      for (const match of file.matches.slice(0, 5)) {
        const lineNum = match.line;

        // Skip if we already showed this line in previous context
        if (shownLines.has(lineNum)) continue;

        if (fileLines.length > 0) {
          // Calculate context range (2 lines before and after)
          const contextStart = Math.max(0, lineNum - 3);
          const contextEnd = Math.min(fileLines.length - 1, lineNum + 1);

          // Show context, skipping already-shown lines
          for (let i = contextStart; i <= contextEnd; i++) {
            if (shownLines.has(i + 1)) continue;
            shownLines.add(i + 1);

            const num = String(i + 1).padStart(4, ' ');
            const content = truncateLine(fileLines[i] || '', 120);
            const isMatch = i + 1 === lineNum;

            if (isMatch) {
              lines.push(`${num} │ ${content}  ◀── MATCH`);
            } else {
              lines.push(`${num} │ ${content}`);
            }
          }
          lines.push('');
        } else {
          // No file content available - show just the match
          const num = String(lineNum).padStart(4, ' ');
          lines.push(`${num} │ ${truncateLine(match.lineContent.trim(), 120)}`);
        }
      }

      if (file.matches.length > 5) {
        lines.push(`     ... +${file.matches.length - 5} more matches in this file`);
        lines.push('');
      }
    }

    if (result.files.length > maxFilesToShow) {
      lines.push(`\n... and ${result.files.length - maxFilesToShow} more files with matches`);
      lines.push('Tip: Use includePattern to narrow search, e.g. "**/*.svelte"');
    }

    // Add navigation hint
    lines.push('');
    lines.push('Use read_file with offset/limit to see focused context.');

    const { text, truncated } = truncateOutput(lines.join('\n'));
    return {
      success: true,
      output: text,
      truncated,
      meta: result.telemetry
        ? {
            searchTelemetry: {
              engine: result.telemetry.engine,
              rgSource: result.telemetry.rgSource ?? 'none',
              rgPath: result.telemetry.rgPath ?? null,
              fallbackUsed: result.telemetry.fallbackUsed,
              fallbackReason: result.telemetry.fallbackReason ?? null,
              elapsedMs: result.telemetry.elapsedMs,
            },
          }
        : undefined,
    };

  } catch (err) {
    const message = err instanceof Error
      ? err.message
      : typeof err === 'object' && err !== null
        ? JSON.stringify(err)
        : String(err);
    return { success: false, error: `Search failed: ${message}` };
  }
}

/**
 * Truncate a line to max length, preserving word boundaries
 */
function truncateLine(line: string, maxLen: number): string {
  if (line.length <= maxLen) return line;

  // Try to break at a word boundary
  const truncated = line.slice(0, maxLen);
  const lastSpace = truncated.lastIndexOf(' ');

  if (lastSpace > maxLen * 0.7) {
    return truncated.slice(0, lastSpace) + '...';
  }

  return truncated + '...';
}

/**
 * Find files by name (fuzzy search)
 * BETTER than Kiro's fileSearch:
 * - Shows file type with icon/emoji
 * - Groups by directory for easier scanning
 * - Shows file size for context
 * - Highlights why it matched (name vs path)
 */
export async function handleFindFiles(args: Record<string, unknown>): Promise<ToolResult> {
  const query = String(args.query);

  if (!query.trim()) {
    return { success: false, error: 'Search query cannot be empty' };
  }

  const workspaceRoot = projectStore.rootPath || '';
  const includePattern = args.includePattern ? String(args.includePattern) : '';
  const excludePattern = args.excludePattern ? String(args.excludePattern) : '';
  const includeHidden = Boolean(args.includeHidden);

  try {
    let results: Array<{ name: string; relativePath: string }>;
    let engineLabel = 'legacy-index';
    let rgSource: string | null = null;
    let rgPath: string | null = null;
    let elapsedMs = 0;
    let fallbackNote = '';

    try {
      const rgResult = await invoke<{
        files: string[];
        totalFiles: number;
        truncated: boolean;
        engine: string;
        fallbackUsed: boolean;
        fallbackReason?: string | null;
        elapsedMs: number;
        rgSource?: string | null;
        rgPath?: string | null;
      }>('find_files_by_name', {
        options: {
          query,
          rootPath: workspaceRoot,
          includeHidden,
          includePatterns: includePattern ? [includePattern] : [],
          excludePatterns: excludePattern
            ? [excludePattern, 'node_modules/**', '.git/**', 'target/**', 'dist/**', 'build/**', '.svelte-kit/**']
            : ['node_modules/**', '.git/**', 'target/**', 'dist/**', 'build/**', '.svelte-kit/**'],
          maxResults: 25,
        }
      });
      engineLabel = rgResult.engine;
      rgSource = rgResult.rgSource ?? null;
      rgPath = rgResult.rgPath ?? null;
      elapsedMs = rgResult.elapsedMs ?? 0;
      if (rgResult.fallbackUsed && rgResult.fallbackReason) {
        fallbackNote = ` (fallback: ${rgResult.fallbackReason})`;
      }
      results = rgResult.files.map((relativePath) => ({
        relativePath,
        name: relativePath.split('/').pop() || relativePath,
      }));
    } catch {
      // Ensure index is ready and fresh (re-index if older than 5 minutes)
      const maxAgeMs = 5 * 60 * 1000; // 5 minutes
      const indexAge = getIndexAge();
      const isStale = indexAge > maxAgeMs;

      if (!isIndexReady() || isStale) {
        if (workspaceRoot) {
          await indexProject(workspaceRoot, true);
        }
      }
      results = searchFiles(query, [], 25);
      engineLabel = 'legacy-index';
      fallbackNote = ' (fallback: file index)';
    }

    if (results.length === 0) {
      // Helpful suggestions
      let msg = `No files matching "${query}"`;
      if (query.includes('.')) {
        msg += `\nTip: Try without extension, e.g. "${query.split('.')[0]}"`;
      }
      if (query.length < 3) {
        msg += '\nTip: Try a longer search term';
      }
      return { success: true, output: msg };
    }

    // Format with file type indicators and grouping
    const lines: string[] = [];
    lines.push(`Found ${results.length} file${results.length > 1 ? 's' : ''} matching "${query}":`);
    lines.push(`Engine: ${engineLabel}${fallbackNote}`);
    lines.push('');

    // Group by parent directory for easier scanning
    const byDir = new Map<string, typeof results>();
    for (const file of results) {
      const parts = file.relativePath.split('/');
      const dir = parts.length > 1 ? parts.slice(0, -1).join('/') : '.';
      if (!byDir.has(dir)) byDir.set(dir, []);
      byDir.get(dir)!.push(file);
    }

    // If all in same dir or few results, show flat list
    if (byDir.size <= 2 || results.length <= 8) {
      for (const file of results) {
        const icon = getFileIcon(file.name);
        lines.push(`${icon} ${file.relativePath}`);
      }
    } else {
      // Group by directory
      for (const [dir, files] of byDir) {
        if (files.length === 0) continue;
        lines.push(`📁 ${dir}/`);
        for (const file of files) {
          const icon = getFileIcon(file.name);
          lines.push(`   ${icon} ${file.name}`);
        }
      }
    }

    // Smart suggestions - find related files
    const relatedSuggestions = getRelatedFileSuggestions(results, query);
    if (relatedSuggestions.length > 0) {
      lines.push('');
      lines.push('💡 Related files you might want:');
      for (const suggestion of relatedSuggestions) {
        lines.push(`   ${suggestion}`);
      }
    }

    // Add helpful hint
    lines.push('');
    lines.push('Use read_file to view contents.');

    return {
      success: true,
        output: lines.join('\n'),
        meta: {
          searchTelemetry: {
            engine: engineLabel,
            rgSource: rgSource ?? (engineLabel === 'rg' ? 'unknown' : 'none'),
            rgPath,
            fallbackUsed: fallbackNote.length > 0,
            fallbackReason: fallbackNote || null,
            elapsedMs,
          },
        },
      };

  } catch (err) {
    const message = err instanceof Error
      ? err.message
      : typeof err === 'object' && err !== null
        ? JSON.stringify(err)
        : String(err);
    return { success: false, error: `Find failed: ${message}` };
  }
}

/**
 * Get icon/emoji for file type
 */
function getFileIcon(filename: string): string {
  const ext = filename.split('.').pop()?.toLowerCase() || '';

  const icons: Record<string, string> = {
    // Code
    'ts': '📘', 'tsx': '⚛️', 'js': '📒', 'jsx': '⚛️',
    'svelte': '🔶', 'vue': '💚', 'py': '🐍', 'rs': '🦀',
    'go': '🐹', 'java': '☕', 'rb': '💎', 'php': '🐘',
    // Web
    'html': '🌐', 'css': '🎨', 'scss': '🎨', 'sass': '🎨', 'less': '🎨',
    // Config
    'json': '📋', 'yaml': '📋', 'yml': '📋', 'toml': '📋',
    'xml': '📋', 'env': '🔐',
    // Docs
    'md': '📝', 'txt': '📄', 'pdf': '📕',
    // Data
    'sql': '🗃️', 'db': '🗃️', 'csv': '📊',
    // Assets
    'png': '🖼️', 'jpg': '🖼️', 'jpeg': '🖼️', 'gif': '🖼️', 'svg': '🎨',
    'ico': '🖼️', 'webp': '🖼️',
    // Other
    'lock': '🔒', 'gitignore': '🙈',
  };

  return icons[ext] || '📄';
}

/**
 * Get smart suggestions for related files
 * VOLT EXCLUSIVE - Kiro doesn't have this!
 */
function getRelatedFileSuggestions(results: Array<{ name: string; relativePath: string }>, query: string): string[] {
  const suggestions: string[] = [];

  if (results.length === 0) return suggestions;

  // Check if searching for a component - suggest test/story files
  const firstResult = results[0];
  const baseName = firstResult.name.replace(/\.[^.]+$/, '');
  const ext = firstResult.name.split('.').pop()?.toLowerCase() || '';

  // Component file patterns
  const componentExts = ['svelte', 'tsx', 'jsx', 'vue'];
  if (componentExts.includes(ext)) {
    suggestions.push(`${baseName}.test.${ext === 'svelte' ? 'ts' : ext} (test file)`);
    suggestions.push(`${baseName}.stories.${ext === 'svelte' ? 'ts' : ext} (storybook)`);
  }

  // If searching for a store, suggest related components
  if (query.toLowerCase().includes('store') || firstResult.relativePath.includes('store')) {
    suggestions.push(`Components using this store`);
  }

  // If searching for types/interfaces, suggest implementations
  if (firstResult.relativePath.includes('types') || query.toLowerCase().includes('type')) {
    suggestions.push(`Files importing these types`);
  }

  return suggestions.slice(0, 3); // Max 3 suggestions
}

/**
 * Search for symbols (functions, classes, variables) using LSP
 * Like Kiro's symbol search - finds definitions across the codebase
 */
export async function handleSearchSymbols(args: Record<string, unknown>): Promise<ToolResult> {
  const query = String(args.query);
  const kindFilter = args.kind ? String(args.kind).toLowerCase() : null;
  const workspaceRoot = projectStore.rootPath || '';

  if (!workspaceRoot) {
    return { success: false, error: 'No workspace open' };
  }

  try {
    // Use workspace symbol search from LSP - query all active LSPs
    let symbols: any[] = [];

    // Query TypeScript LSP if connected
    if (isTsLspConnected()) {
      const tsSymbols = await getTsWorkspaceSymbols(query);
      if (tsSymbols) symbols = symbols.concat(tsSymbols);
    }

    // Query Dart LSP if running
    if (isDartLspRunning()) {
      const dartSymbols = await getDartWorkspaceSymbols(query);
      if (dartSymbols) symbols = symbols.concat(dartSymbols);
    }

    // If no symbols from active LSPs, try to start them if they should be there
    if (symbols.length === 0) {
      // Logic to bootstrap LSP for symbol search if needed
      // (Simplified for now: if no symbols, proceed to fallback)
    }

    if (!symbols || symbols.length === 0) {
      // Fallback: use text search for the symbol name
      const fallbackResult = await handleWorkspaceSearch({
        query: `\\b${query}\\b`,
        includePattern: '**/*.{ts,tsx,js,jsx,svelte,vue,dart}',
        caseSensitive: true
      });

      if (fallbackResult.success && fallbackResult.output) {
        return {
          success: true,
          output: `No LSP symbols found. Text search results:\n${fallbackResult.output}`
        };
      }

      return { success: true, output: `No symbols matching "${query}"` };
    }

    // Map LSP symbol kinds to readable names
    const kindNames: Record<number, string> = {
      1: 'file', 2: 'module', 3: 'namespace', 4: 'package',
      5: 'class', 6: 'method', 7: 'property', 8: 'field',
      9: 'constructor', 10: 'enum', 11: 'interface', 12: 'function',
      13: 'variable', 14: 'constant', 15: 'string', 16: 'number',
      17: 'boolean', 18: 'array', 19: 'object', 20: 'key',
      21: 'null', 22: 'enum_member', 23: 'struct', 24: 'event',
      25: 'operator', 26: 'type_parameter'
    };

    // Filter by kind if specified
    let filtered = symbols;
    if (kindFilter) {
      const kindMap: Record<string, number[]> = {
        'function': [6, 12], // method, function
        'class': [5],
        'variable': [13, 14], // variable, constant
        'type': [11, 26], // interface, type_parameter
        'interface': [11],
        'enum': [10],
        'property': [7, 8], // property, field
      };
      const allowedKinds = kindMap[kindFilter] || [];
      if (allowedKinds.length > 0) {
        filtered = symbols.filter(s => allowedKinds.includes(s.kind));
      }
    }

    // Format results
    const results = filtered.slice(0, 20).map(s => {
      const kindName = kindNames[s.kind] || 'symbol';
      const filePath = s.location.uri.replace('file://', '').replace(workspaceRoot, '').replace(/^[/\\]/, '');
      const line = s.location.range.start.line + 1;
      const container = s.containerName ? ` (in ${s.containerName})` : '';
      return `${s.name} [${kindName}] - ${filePath}:${line}${container}`;
    });

    const { text } = truncateOutput(
      `Found ${filtered.length} symbols:\n${results.join('\n')}`
    );

    return { success: true, output: text };

  } catch (err) {
    // LSP not available - fallback to text search
    const fallbackResult = await handleWorkspaceSearch({
      query: `(function|class|const|let|var|interface|type|enum|void|final|late|dynamic|bool|int|double|String)\\s+${query}\\b`,
      includePattern: '**/*.{ts,tsx,js,jsx,svelte,vue,dart}',
      caseSensitive: false
    });

    if (fallbackResult.success && fallbackResult.output) {
      return {
        success: true,
        output: `Symbol search (text fallback):\n${fallbackResult.output}`
      };
    }

    return { success: false, error: `Symbol search failed: ${err}` };
  }
}

/**
 * Terminal tool handlers - Kiro-style with background process management
 * 
 * Tools:
 * - run_command: Execute command and wait for completion
 * - start_process: Start background process (dev servers, watchers)
 * - stop_process: Stop a background process
 * - list_processes: List all running background processes
 * - get_process_output: Read output from a specific process
 * - read_terminal: Read recent terminal output (legacy)
 */

import { terminalStore } from '$features/terminal/stores/terminal.svelte';
import { projectStore } from '$shared/stores/project.svelte';
import { projectDiagnostics } from '$core/services/project-diagnostics';
import { uiStore } from '$shared/stores/ui.svelte';
import { logOutput } from '$features/terminal/stores/output.svelte';
import type { TerminalSession } from '$features/terminal/services/terminal-client';
import { truncateOutput, extractErrorMessage, type ToolResult } from '$core/ai/tools/utils';

let aiCommandQueue: Promise<ToolResult> = Promise.resolve({ success: true, output: '' });
const recentAiCommands = new Map<string, { command: string; timestamp: number }>();
const AI_QUEUE_WAIT_TIMEOUT_MS = 45_000;
const AI_COMMAND_HARD_CAP_MS = 120_000;

function withTimeout<T>(promise: Promise<T>, timeoutMs: number, fallback: T): Promise<T> {
  if (!Number.isFinite(timeoutMs) || timeoutMs <= 0) return promise;
  let timer: ReturnType<typeof setTimeout> | null = null;
  return Promise.race([
    promise.finally(() => {
      if (timer) clearTimeout(timer);
    }),
    new Promise<T>((resolve) => {
      timer = setTimeout(() => resolve(fallback), timeoutMs);
    })
  ]);
}

function isLikelyDevServer(command: string): boolean {
  const cmd = command.trim().toLowerCase();
  if (!cmd) return false;

  const npmRun = /\b(npm|pnpm|yarn)\s+(run\s+)?(dev|serve|start|preview|watch)\b/i;
  const common = /\b(vite|next\s+dev|nuxt\s+dev|astro\s+dev|svelte-kit\s+dev|react-scripts\s+start|ng\s+serve|nx\s+serve|bun\s+run\s+dev|deno\s+task\s+dev)\b/i;
  const avoid = /\b(npm|pnpm|yarn)\s+install\b/i;

  if (avoid.test(cmd)) return false;
  return npmRun.test(cmd) || common.test(cmd);
}

function normalizeCommand(command: string): string {
  return command.trim().replace(/\s+/g, ' ').toLowerCase();
}

function getBlockedCommandReason(command: string): string | null {
  const normalized = normalizeCommand(command);

  // Protect Volt metadata/project control directory from AI shell mutations.
  const mutatingShellVerb =
    /\b(move-item|rename-item|remove-item|del|erase|rmdir|rd|rm|mv|ren)\b/i;
  const touchesVoltDir = /(^|[\s"'`\\\/])\.volt([\\\/\s"'`]|$)/i.test(command);
  if (touchesVoltDir && mutatingShellVerb.test(command)) {
    return 'Blocked unsafe command: modifying `.volt` is not allowed because it can break plans/chat state.';
  }

  // Common failure mode: create-next-app in current directory conflicts with `.volt`.
  // Force safer scaffolding flow in a temp/sub folder.
  if (
    /\bcreate-next-app(?:@[\w.-]+)?\b/i.test(normalized) &&
    /(?:^|\s)\.(?:\s|$)/.test(normalized)
  ) {
    return 'Blocked unsafe scaffold target: do not run create-next-app in `.`. Scaffold into a temp/subfolder and move app files instead.';
  }

  return null;
}

function extractPort(command: string): number | null {
  const direct = command.match(/(?:--port|-p)\s*=?\s*(\d{2,5})/i);
  if (direct) return Number(direct[1]);
  const env = command.match(/\bPORT\s*=\s*(\d{2,5})/i);
  if (env) return Number(env[1]);
  return null;
}

function normalizeLoopbackHost(url: string): string {
  return url
    .replace('0.0.0.0', 'localhost')
    .replace('[::]', 'localhost')
    .replace('::1', 'localhost');
}

function extractLocalhostUrls(text: string): string[] {
  if (!text) return [];
  const urls = new Set<string>();

  const direct = text.match(/https?:\/\/(?:localhost|127\.0\.0\.1|0\.0\.0\.0|\[::\]|::1)(?::\d{2,5})?(?:\/[^\s"'<>]*)?/gi) || [];
  for (const url of direct) urls.add(normalizeLoopbackHost(url));

  const hostPort = text.match(/\b(?:localhost|127\.0\.0\.1|0\.0\.0\.0|\[::\]|::1):\d{2,5}(?:\/[^\s"'<>]*)?/gi) || [];
  for (const hp of hostPort) urls.add(normalizeLoopbackHost(`http://${hp}`));

  return [...urls];
}

function inferDefaultDevPort(command: string): number | null {
  const cmd = command.toLowerCase();
  if (/\bnext\s+dev\b/.test(cmd)) return 3000;
  if (/\breact-scripts\s+start\b/.test(cmd)) return 3000;
  if (/\bng\s+serve\b/.test(cmd)) return 4200;
  if (/\bnuxt\s+dev\b/.test(cmd)) return 3000;
  if (/\bastro\s+dev\b/.test(cmd)) return 4321;
  if (/\bvite\b/.test(cmd) || /\b(?:npm|pnpm|yarn)\s+(run\s+)?dev\b/.test(cmd)) return 5173;
  return null;
}

function inferDevServerUrl(command: string): string | null {
  const explicit = extractPort(command);
  if (explicit) return `http://localhost:${explicit}`;
  const inferred = inferDefaultDevPort(command);
  return inferred ? `http://localhost:${inferred}` : null;
}

function updateProcessDetectedUrl(process: BackgroundProcess, output: string): BackgroundProcess {
  const detectedFromOutput = extractLocalhostUrls(output)[0];
  const detectedUrl =
    detectedFromOutput ||
    process.detectedUrl ||
    inferDevServerUrl(process.command) ||
    undefined;

  const next: BackgroundProcess = { ...process, detectedUrl };
  processStore.set(process.processId, next);
  return next;
}

function findRunningDevServer(command: string, cwd?: string): BackgroundProcess | null {
  const normalized = normalizeCommand(command);
  const desiredPort = extractPort(command);
  for (const proc of processes.values()) {
    if (proc.status !== 'running') continue;
    if (normalizeCommand(proc.command) !== normalized) continue;
    if (cwd && proc.cwd && proc.cwd !== cwd) continue;
    if (desiredPort && proc.port && proc.port !== desiredPort) continue;
    if (!proc.terminalId) continue;
    const session = terminalStore.sessions.find(s => s.id === proc.terminalId);
    if (!session) continue;
    return proc;
  }
  return null;
}

function trackDetachedProcess(command: string, cwd: string | undefined, terminalId: string): BackgroundProcess {
  const processId = processStore.nextProcessId();
  const proc: BackgroundProcess = {
    processId,
    command,
    cwd,
    startTime: Date.now(),
    status: 'running',
    terminalId,
    port: extractPort(command) ?? undefined,
    detectedUrl: inferDevServerUrl(command) ?? undefined,
  };
  processes.set(processId, proc);

  const session = terminalStore.sessions.find(s => s.id === terminalId);
  if (session) {
    session.onExit(() => {
      const p = processStore.get(processId);
      if (p) {
        p.status = 'stopped';
        processStore.set(processId, p);
      }
    });
  }

  return proc;
}

/**
 * Get or create a dedicated terminal for a background process.
 */
async function getProcessTerminal(processId: number, cwd?: string): Promise<TerminalSession> {
  const proc = processes.get(processId);
  if (proc?.terminalId) {
    const session = terminalStore.sessions.find(s => s.id === proc.terminalId);
    if (session) {
      terminalStore.setActive(session.id);
      return session;
    }
  }

  // Create a new one if not found
  const session = await terminalStore.createTerminal(cwd);
  if (!session) {
    throw new Error('Failed to create process terminal session');
  }

  terminalStore.setSessionLabel(session.id, `Volt Proc: ${processId}`);
  terminalStore.setActive(session.id);

  await session.waitForReady(3000);
  return session;
}

// ============================================
// Background Process Tracking
// ============================================

interface BackgroundProcess {
  processId: number;
  command: string;
  cwd: string | undefined;
  startTime: number;
  status: 'running' | 'stopped' | 'unknown';
  terminalId?: string;
  port?: number;
  detectedUrl?: string;
}

const STORAGE_KEY = 'volt.ai.processes';
const STALE_ORPHAN_PROCESS_AGE_MS = 2 * 60 * 60 * 1000; // 2h
const STOPPED_PROCESS_RETENTION_MS = 24 * 60 * 60 * 1000; // 24h
const MAX_TRACKED_PROCESSES = 200;

class ProcessStore {
  private _processes = new Map<number, BackgroundProcess>();
  private _nextProcessId = 1;

  constructor() {
    this.load();
  }

  private load(): void {
    if (typeof localStorage === 'undefined') return;

    try {
      const data = localStorage.getItem(STORAGE_KEY);
      if (!data) return;

      const parsed = JSON.parse(data) as { processes: BackgroundProcess[]; nextId: number };
      this._nextProcessId = parsed.nextId || 1;

      for (const proc of parsed.processes) {
        // Do not infer unknown/running here because terminal sessions may not be
        // hydrated yet at module init; reconciliation is done lazily per tool call.
        this._processes.set(proc.processId, { ...proc });
      }
    } catch {
      // Ignore parse errors, start fresh
    }
  }

  private save(): void {
    if (typeof localStorage === 'undefined') return;

    try {
      const data = {
        processes: Array.from(this._processes.values()),
        nextId: this._nextProcessId
      };
      localStorage.setItem(STORAGE_KEY, JSON.stringify(data));
    } catch {
      // Ignore storage errors
    }
  }

  get(processId: number): BackgroundProcess | undefined {
    return this._processes.get(processId);
  }

  set(processId: number, process: BackgroundProcess): void {
    this._processes.set(processId, process);
    this.save();
  }

  delete(processId: number): boolean {
    const result = this._processes.delete(processId);
    if (result) this.save();
    return result;
  }

  getAll(): BackgroundProcess[] {
    return Array.from(this._processes.values());
  }

  getRunningCount(): number {
    return this.getAll().filter(p => p.status === 'running').length;
  }

  get size(): number {
    return this._processes.size;
  }

  values(): IterableIterator<BackgroundProcess> {
    return this._processes.values();
  }

  entries(): IterableIterator<[number, BackgroundProcess]> {
    return this._processes.entries();
  }

  nextProcessId(): number {
    const id = this._nextProcessId++;
    this.save();
    return id;
  }
}

const processStore = new ProcessStore();

// Backward compatibility: expose Map-like interface
const processes = {
  get: (id: number) => processStore.get(id),
  set: (id: number, proc: BackgroundProcess) => { processStore.set(id, proc); return processes; },
  delete: (id: number) => processStore.delete(id),
  get size() { return processStore.size; },
  values: () => processStore.values()
};

async function reconcileTrackedProcesses(): Promise<void> {
  await terminalStore.syncWithBackend();

  const now = Date.now();
  const all = processStore.getAll();
  const liveTerminalIds = new Set(terminalStore.sessions.map((s) => s.id));

  for (const proc of all) {
    const hasTerminal = proc.terminalId ? liveTerminalIds.has(proc.terminalId) : false;
    const ageMs = now - proc.startTime;

    if (proc.status === 'running' && !hasTerminal) {
      // Orphaned running process: likely stale persisted state after reload/crash.
      // Keep briefly as unknown, then auto-stop.
      if (ageMs > STALE_ORPHAN_PROCESS_AGE_MS) {
        processStore.set(proc.processId, { ...proc, status: 'stopped' });
      } else {
        processStore.set(proc.processId, { ...proc, status: 'unknown' });
      }
      continue;
    }

    if (proc.status === 'unknown' && hasTerminal) {
      processStore.set(proc.processId, { ...proc, status: 'running' });
    }
  }

  // Prune old stopped entries so the list doesn't grow forever.
  const sorted = processStore
    .getAll()
    .sort((a, b) => b.startTime - a.startTime);

  const keep = new Set<number>();
  for (const proc of sorted) {
    const ageMs = now - proc.startTime;
    const keepByAge =
      proc.status === 'running' ||
      proc.status === 'unknown' ||
      ageMs <= STOPPED_PROCESS_RETENTION_MS;
    if (keepByAge && keep.size < MAX_TRACKED_PROCESSES) {
      keep.add(proc.processId);
    }
  }

  for (const [id] of processStore.entries()) {
    if (!keep.has(id)) {
      processStore.delete(id);
    }
  }
}

