/**
 * Format a file using Prettier
 */
export async function handleFormatFile(args: Record<string, unknown>): Promise<ToolResult> {
  const relativePath = String(args.path);
  const absolutePath = resolvePath(relativePath);

  // Import Prettier service
  const { formatWithPrettier, isPrettierFile } = await import('$core/services/prettier');

  // Check if file type is supported
  if (!isPrettierFile(absolutePath)) {
    const ext = absolutePath.split('.').pop() || '';
    return {
      success: false,
      error: `Unsupported file type: .${ext}. Prettier supports: ts, tsx, js, jsx, json, css, scss, less, html, md, svelte, vue, yaml`
    };
  }

  // Read current content
  let content: string;
  try {
    const doc = await fileService.read(absolutePath, true);
    if (!doc) {
      return { success: false, error: `File not found: ${relativePath}` };
    }
    content = doc.content;
  } catch (err) {
    return { success: false, error: `File not found: ${relativePath}` };
  }

  // Format with Prettier
  const formatted = await formatWithPrettier(content, absolutePath);

  if (formatted === null) {
    return {
      success: false,
      error: `Formatting failed. Make sure Prettier is installed: npm install -D prettier`
    };
  }

  // Check if content changed
  if (formatted === content) {
    return { success: true, output: `✓ ${relativePath} already formatted` };
  }

  // Write formatted content
  try {
    const result = await fileService.write(absolutePath, formatted, { source: 'ai' });
    if (!result.success) {
      return { success: false, error: `Failed to write: ${result.error}` };
    }

    // Update editor if file is open
    const openFiles = editorStore.openFiles.filter(f =>
      f.path === absolutePath ||
      f.path.endsWith('/' + relativePath) ||
      f.path.endsWith('\\' + relativePath)
    );

    if (openFiles.length > 0) {
      editorStore.updateContent(openFiles[0].path, formatted);
    }

    const linesBefore = content.split('\n').length;
    const linesAfter = formatted.split('\n').length;
    const lineDiff = linesAfter - linesBefore;
    const lineDiffStr = lineDiff === 0 ? '' : lineDiff > 0 ? ` (+${lineDiff} lines)` : ` (${lineDiff} lines)`;

    return {
      success: true,
      output: `✓ Formatted ${relativePath}${lineDiffStr}`
    };
  } catch (err) {
    return { success: false, error: `Failed to write formatted file: ${extractErrorMessage(err)}` };
  }
}

/**
 * AI Tool Router
 * 
 * Clean architecture:
 * - router.ts: validation + dispatch (this file)
 * - definitions.ts: tool schemas
 * - utils.ts: shared helpers
 * - handlers/: individual tool implementations
 */

import { projectStore } from '$shared/stores/project.svelte';
import { assistantStore } from '$features/assistant/stores/assistant.svelte';
import {
  getAllToolsForMode,
  getToolByName,
  isToolAllowed,
  RETIRED_TOOL_NAMES,
} from '$core/ai/tools/definitions';
import { isBrowserToolBlocked } from '$core/ai/tools/browser-gate';
import {
  normalizeToolOutputBudget,
  validatePathInWorkspace,
  type ToolResult,
  type CanonicalToolResult,
} from '$core/ai/tools/utils';
import { toolHandlers } from '$core/ai/tools/handlers';
import { isMcpTool, executeMcpTool, isMcpToolAutoApproved, getMcpToolInfo } from '$core/ai/tools/handlers/mcp';
import type { AIMode } from '$features/assistant/stores/ai.svelte';
import { getToolCapabilities } from '$core/ai/tools/capabilities';
import { toolObservabilityStore } from '$features/assistant/stores/tool-observability.svelte';
import { agentTelemetryStore } from '$features/assistant/stores/agent-telemetry.svelte';
import { afterToolHook, beforeToolHook } from '$core/ai/tools/hooks';

// Timeout for tool operations (30 seconds default)
const DEFAULT_TIMEOUT_MS = 30000;
const MAX_TIMEOUT_MS = 5 * 60 * 1000; // 5 minutes max
const TERMINAL_TOOL_DEFAULT_TIMEOUT_MS = MAX_TIMEOUT_MS;
const HIDDEN_HANDLER_NAMES = new Set([
  'lsp_go_to_definition',
  'lsp_find_references',
  'lsp_get_hover',
  'lsp_rename_symbol',
]);
const TOOL_MAX_ATTEMPTS: Record<string, number> = {
  browser_get_console_logs: 3,
  browser_get_errors: 3,
  browser_get_network_requests: 3,
  browser_get_network_request_details: 3,
  browser_get_performance: 3,
  browser_get_summary: 3,
  browser_get_application_storage: 3,
  browser_get_security_report: 3,
};
const TOOL_NAME_ALIASES: Record<string, string> = {
  shell_command: 'run_command',
};

export function normalizeToolName(toolName: string): string {
  const trimmed = toolName.trim();
  return TOOL_NAME_ALIASES[trimmed] ?? trimmed;
}

/**
 * Tool execution options
 */
export interface ToolExecutionOptions {
  signal?: AbortSignal;
  idempotencyKey?: string;
}

/**
 * Tool validation result
 */
export interface ToolValidation {
  valid: boolean;
  error?: string;
  requiresApproval: boolean;
}

// Re-export ToolResult types for convenience
export type { ToolResult, CanonicalToolResult } from '$core/ai/tools/utils';

const IDEMPOTENCY_RESULT_TTL_MS = 2 * 60 * 1000;
const idempotentResultCache = new Map<string, { result: CanonicalToolResult; expiresAt: number }>();
const idempotentInFlight = new Map<string, Promise<CanonicalToolResult>>();

/**
 * Validate a tool call before execution
 */
export function validateToolCall(
  toolName: string,
  args: Record<string, unknown>,
  mode: AIMode
): ToolValidation {
  const canonicalToolName = normalizeToolName(toolName);
  if (isBrowserToolBlocked(canonicalToolName, assistantStore.browserToolsEnabled)) {
    return {
      valid: false,
      error:
        'Browser tools are disabled. Enable Browser tools in chat (globe toggle) to use this tool.',
      requiresApproval: false,
    };
  }

  // Check if it's an MCP tool
  if (isMcpTool(canonicalToolName)) {
    // MCP tools are allowed in agent mode only
    if (mode !== 'agent') {
      return {
        valid: false,
        error: `MCP tools are only available in agent mode`,
        requiresApproval: false
      };
    }

    // Check if auto-approved
    const requiresApproval = !isMcpToolAutoApproved(canonicalToolName);
    return { valid: true, requiresApproval };
  }

  // Check if tool exists
  const tool = getToolByName(canonicalToolName);
  if (!tool) {
    if (RETIRED_TOOL_NAMES.has(canonicalToolName)) {
      return {
        valid: false,
        error: `Tool "${canonicalToolName}" was removed from strict profile. Use read_file/workspace_search/apply_patch/run_command equivalents.`,
        requiresApproval: false,
      };
    }
    const suggestion = suggestToolName(canonicalToolName, mode);
    const suffix = suggestion ? ` Did you mean "${suggestion}"?` : '';
    return { valid: false, error: `Unknown tool: ${canonicalToolName}.${suffix}`, requiresApproval: false };
  }
  if (RETIRED_TOOL_NAMES.has(canonicalToolName)) {
    return {
      valid: false,
      error: `Tool "${canonicalToolName}" was removed from strict profile. Use read_file/workspace_search/apply_patch/run_command equivalents.`,
      requiresApproval: false,
    };
  }

  // Check if tool is allowed in current mode
  if (!isToolAllowed(canonicalToolName, mode)) {
    return {
      valid: false,
      error: `Tool "${canonicalToolName}" not allowed in ${mode} mode`,
      requiresApproval: false
    };
  }

  // Validate required parameters
  const paramError = validateRequiredParams(canonicalToolName, args);
  if (paramError) {
    return { valid: false, error: paramError, requiresApproval: false };
  }
  if (
    canonicalToolName === 'read_file' &&
    (typeof args.start_line === 'number' ||
      typeof args.end_line === 'number' ||
      typeof args.startLine === 'number' ||
      typeof args.endLine === 'number')
  ) {
    return {
      valid: false,
      error: 'read_file now requires Codex-style slice args: use "offset" and "limit" (line-based).',
      requiresApproval: false,
    };
  }

  // Validate path is within workspace (if path param exists)
  const workspaceRoot = projectStore.rootPath;
  const capabilities = getToolCapabilities(canonicalToolName);
  if (workspaceRoot && capabilities.requiresWorkspacePathValidation) {
    const pathsToValidate = collectPaths(args);
    for (const path of pathsToValidate) {
      const pathValidation = validatePathInWorkspace(path, workspaceRoot);
      if (!pathValidation.valid) {
        return { valid: false, error: pathValidation.error, requiresApproval: false };
      }
    }
  }

  return {
    valid: true,
    requiresApproval: capabilities.requiresApproval
  };
}

function collectPaths(args: Record<string, unknown>): string[] {
  const paths: string[] = [];
  const addPath = (value: unknown): void => {
    if (typeof value === 'string' && value.trim().length > 0) {
      paths.push(value);
    }
  };

  addPath(args.path);
  addPath(args.oldPath);
  addPath(args.newPath);
  addPath(args.cwd);

  if (Array.isArray(args.paths)) {
    for (const value of args.paths) {
      addPath(value);
    }
  }

  return paths;
}

/**
 * Validate required parameters for each tool
 */
function validateRequiredParams(toolName: string, args: Record<string, unknown>): string | null {
  const requireString = (key: string, altKey?: string): string | null => {
    const val = args[key] ?? (altKey ? args[altKey] : undefined);
    if (typeof val === 'string' && val.trim().length > 0) return null;
    return `Missing "${key}"`;
  };

  switch (toolName) {
    // Read tools
    case 'list_dir':
    case 'read_file':
    case 'get_file_info':
      return requireString('path');

    case 'workspace_search':
      return requireString('query');

    // Write tools
    case 'apply_patch': {
      const pathErr = requireString('path');
      if (pathErr) return pathErr;
      return requireString('patch');
    }

    // Terminal tools
    case 'run_command':
      return requireString('command');

    // Browser tools - read-only
    // No required params
    case 'get_diagnostics':
      return null;

    case 'attempt_completion':
      return requireString('result');

    default:
      return validateRequiredParamsFromSchema(toolName, args);
  }
}

function validateRequiredParamsFromSchema(
  toolName: string,
  args: Record<string, unknown>,
): string | null {
  const tool = getToolByName(toolName);
  if (!tool) return null;

  const schema = tool.parameters as Record<string, unknown>;
  const required = schema.required;
  if (!Array.isArray(required) || required.length === 0) return null;

  for (const key of required) {
    if (typeof key !== 'string') continue;
    const value = args[key];
    const missingString = typeof value === 'string' && value.trim().length === 0;
    if (value === undefined || value === null || missingString) {
      return `Missing "${key}"`;
    }
  }

  return null;
}

export function getToolContractParity(): {
  missingHandlers: string[];
  orphanHandlers: string[];
} {
  const definedTools = new Set([
    ...getAllToolsForMode('ask').map((tool) => tool.name),
    ...getAllToolsForMode('plan').map((tool) => tool.name),
    ...getAllToolsForMode('agent').map((tool) => tool.name),
  ]);
  const handlerTools = new Set(Object.keys(toolHandlers));

  const missingHandlers = [...definedTools]
    .filter((name) => !handlerTools.has(name) && !isMcpTool(name))
    .sort();

  const orphanHandlers = [...handlerTools]
    .filter(
      (name) =>
        !definedTools.has(name) &&
        !getToolByName(name) &&
        !HIDDEN_HANDLER_NAMES.has(name) &&
        !RETIRED_TOOL_NAMES.has(name) &&
        !isMcpTool(name),
    )
    .sort();

  return { missingHandlers, orphanHandlers };
}

function normalizeToolToken(value: string): string {
  return value.toLowerCase().replace(/[-_\s]+/g, '');
}

function suggestToolName(toolName: string, mode: AIMode): string | null {
  const available = getAllToolsForMode(mode).map((tool) => tool.name);
  if (available.length === 0) return null;

  const normalized = normalizeToolToken(toolName);
  const exactNormalized = available.find((name) => normalizeToolToken(name) === normalized);
  if (exactNormalized) return exactNormalized;

  const prefixMatch = available.find((name) => name.startsWith(toolName) || toolName.startsWith(name));
  if (prefixMatch) return prefixMatch;

  let best: { name: string; distance: number } | null = null;
  for (const candidate of available) {
    const distance = levenshteinDistance(normalizeToolToken(candidate), normalized);
    if (!best || distance < best.distance) {
      best = { name: candidate, distance };
    }
  }

  if (!best) return null;
  return best.distance <= 6 ? best.name : null;
}

function levenshteinDistance(a: string, b: string): number {
  if (a === b) return 0;
  if (a.length === 0) return b.length;
  if (b.length === 0) return a.length;

  const rows = a.length + 1;
  const cols = b.length + 1;
  const matrix: number[][] = Array.from({ length: rows }, () => Array(cols).fill(0));

  for (let i = 0; i < rows; i++) matrix[i][0] = i;
  for (let j = 0; j < cols; j++) matrix[0][j] = j;

  for (let i = 1; i < rows; i++) {
    for (let j = 1; j < cols; j++) {
      const cost = a[i - 1] === b[j - 1] ? 0 : 1;
      matrix[i][j] = Math.min(
        matrix[i - 1][j] + 1,
        matrix[i][j - 1] + 1,
        matrix[i - 1][j - 1] + cost,
      );
    }
  }

  return matrix[rows - 1][cols - 1];
}

/**
 * Execute a tool call
 */
export async function executeToolCall(
  toolName: string,
  args: Record<string, unknown>,
  options: ToolExecutionOptions = {}
): Promise<CanonicalToolResult> {
  const canonicalToolName = normalizeToolName(toolName);
  const { signal, idempotencyKey } = options;
  const signature = createToolSignature(canonicalToolName, args);

  purgeExpiredIdempotencyCache();

  if (idempotencyKey) {
    const cached = idempotentResultCache.get(idempotencyKey);
    if (cached && cached.expiresAt > Date.now()) {
      const replayMeta: Record<string, any> = {
        ...(cached.result.meta ?? {}),
        replayed: true,
        idempotencyKey,
        signature,
      };
      const replayResult = {
        ...cached.result,
        timestamp: Date.now(),
        meta: replayMeta,
      };
      toolObservabilityStore.record({
        timestamp: Date.now(),
        toolName: canonicalToolName,
        signature,
        idempotencyKey,
        durationMs: 0,
        success: replayResult.success,
        code: replayResult.code,
        retryable: replayResult.retryable,
        attempt: Number(replayMeta.attempts ?? 1),
        maxAttempts: Number(replayMeta.maxAttempts ?? 1),
        replayed: true,
      });
      return replayResult;
    }

    const inFlight = idempotentInFlight.get(idempotencyKey);
    if (inFlight) {
      toolObservabilityStore.record({
        timestamp: Date.now(),
        toolName: canonicalToolName,
        signature,
        idempotencyKey,
        durationMs: 0,
        success: true,
        code: 'IDEMPOTENT_IN_FLIGHT',
        retryable: false,
        attempt: 1,
        maxAttempts: 1,
        replayed: true,
      });
      return inFlight;
    }
  }

  const executionPromise = executeToolCallInternal(canonicalToolName, args, {
    signal,
    idempotencyKey,
    signature,
  });

  if (idempotencyKey) {
    idempotentInFlight.set(idempotencyKey, executionPromise);
  }

  try {
    const result = await executionPromise;
    if (idempotencyKey) {
      idempotentResultCache.set(idempotencyKey, {
        result,
        expiresAt: Date.now() + IDEMPOTENCY_RESULT_TTL_MS,
      });
    }
    return result;
  } finally {
    if (idempotencyKey) {
      idempotentInFlight.delete(idempotencyKey);
    }
  }
}

async function executeToolCallInternal(
  toolName: string,
  args: Record<string, unknown>,
  options: ToolExecutionOptions & { signature: string }
): Promise<CanonicalToolResult> {
  const { signal, idempotencyKey, signature } = options;
  if (RETIRED_TOOL_NAMES.has(toolName)) {
    return normalizeToolResult(
      toolName,
      {
        success: false,
        error: `Tool "${toolName}" was removed from strict profile. Use read_file/workspace_search/apply_patch/run_command equivalents.`,
      },
      {
        idempotencyKey,
        signature,
        attempt: 1,
        maxAttempts: 1,
      },
    );
  }

  if (isMcpTool(toolName)) {
    const startedAt = Date.now();
    const result = await executeMcpTool(toolName, args);
    const normalized = normalizeToolResult(toolName, result, {
      idempotencyKey,
      signature,
      attempt: 1,
      maxAttempts: 1,
    });
    recordExecutionTelemetry(toolName, signature, idempotencyKey, normalized, Date.now() - startedAt, 1, 1, false);
    return normalized;
  }

  const capabilities = getToolCapabilities(toolName);
  const defaultTimeout = capabilities.isLongRunning ? TERMINAL_TOOL_DEFAULT_TIMEOUT_MS : DEFAULT_TIMEOUT_MS;
  const requestedTimeout = typeof args.timeout === 'number' ? args.timeout : defaultTimeout;
  const timeoutMs = Math.min(Math.max(0, requestedTimeout), MAX_TIMEOUT_MS);

  const handler = toolHandlers[toolName];
  if (!handler) {
    const normalized = normalizeToolResult(toolName, { success: false, error: `No handler for tool: ${toolName}` }, {
      idempotencyKey,
      signature,
      attempt: 1,
      maxAttempts: 1,
    });
    recordExecutionTelemetry(toolName, signature, idempotencyKey, normalized, 0, 1, 1, false);
    return normalized;
  }

  const toolDef = getToolByName(toolName);
  const maxAttempts = getToolMaxAttempts(toolName, toolDef);
  let attempt = 0;
  const execStarted = Date.now();

  while (attempt < maxAttempts) {
    let timeoutId: ReturnType<typeof setTimeout> | undefined;
    const timeoutPromise = timeoutMs === 0
      ? new Promise<ToolResult>(() => undefined)
      : new Promise<ToolResult>((resolve) => {
        timeoutId = setTimeout(() => {
          resolve({ success: false, error: 'Tool execution timed out' });
        }, timeoutMs);
      });

    let abortHandler: (() => void) | undefined;
    const abortPromise = new Promise<ToolResult>((resolve) => {
      if (!signal) return;
      abortHandler = () => resolve({ success: false, error: 'Tool execution cancelled' });
      signal.addEventListener('abort', abortHandler, { once: true });
    });

    try {
      beforeToolHook({
        toolName,
        args,
        attempt: attempt + 1,
        maxAttempts,
        startedAt: execStarted,
      });
      const result = await Promise.race([
        handler(args),
        timeoutPromise,
        ...(signal ? [abortPromise] : [])
      ]);

      const normalized = normalizeToolResult(toolName, result, {
        idempotencyKey,
        signature,
        attempt: attempt + 1,
        maxAttempts,
      });
      const hookOutcome = afterToolHook(
        {
          toolName,
          args,
          attempt: attempt + 1,
          maxAttempts,
          startedAt: execStarted,
        },
        normalized,
      );
      agentTelemetryStore.record({
        type: 'agent.tool.hook',
        timestamp: Date.now(),
        toolName,
        parseCategory: hookOutcome.parseCategory ?? 'none',
        attempt: attempt + 1,
        maxAttempts,
      });
      recordExecutionTelemetry(toolName, signature, idempotencyKey, normalized, Date.now() - execStarted, attempt + 1, maxAttempts, false);
      if (normalized.success || !shouldRetryResult(toolName, toolDef, normalized, attempt, maxAttempts)) {
        return normalized;
      }
    } catch (err) {
      const message = err instanceof Error ? err.message : String(err);
      const normalized = normalizeToolResult(toolName, { success: false, error: message }, {
        idempotencyKey,
        signature,
        attempt: attempt + 1,
        maxAttempts,
      });
      recordExecutionTelemetry(toolName, signature, idempotencyKey, normalized, Date.now() - execStarted, attempt + 1, maxAttempts, false);
      if (!shouldRetryResult(toolName, toolDef, normalized, attempt, maxAttempts)) {
        return normalized;
      }
    } finally {
      if (timeoutId) clearTimeout(timeoutId);
      if (signal && abortHandler) {
        signal.removeEventListener('abort', abortHandler);
      }
    }

    attempt++;
    await delay(200 * attempt);
  }

  const finalFailure = normalizeToolResult(toolName, { success: false, error: 'Tool execution failed' }, {
    idempotencyKey,
    signature,
    attempt: maxAttempts,
    maxAttempts,
  });
  recordExecutionTelemetry(toolName, signature, idempotencyKey, finalFailure, Date.now() - execStarted, maxAttempts, maxAttempts, false);
  return finalFailure;
}

function normalizeToolResult(
  toolName: string,
  result: ToolResult,
  context: {
    idempotencyKey?: string;
    signature: string;
    attempt: number;
    maxAttempts: number;
  }
): CanonicalToolResult {
  const baseOutput = typeof result.output === 'string'
    ? result.output
    : result.output == null
      ? ''
      : JSON.stringify(result.output, null, 2);

  const baseError = typeof result.error === 'string'
    ? result.error
    : result.error == null
      ? ''
      : String(result.error);

  const success = Boolean(result.success);
  const error = success
    ? (baseError || '')
    : (baseError || baseOutput || 'Tool execution failed');
  const output = baseOutput || (success ? '[ok]' : '');
  const budgeted = normalizeToolOutputBudget(toolName, output);
  const code = success ? 'OK' : mapErrorCode(error);
  const retryable = success ? false : isRetryableError(error);
  const warnings = Array.isArray(result.warnings)
    ? result.warnings.filter((item): item is string => typeof item === 'string')
    : [];
  return {
    success,
    output: budgeted.output,
    error,
    data: result.data ?? null,
    warnings,
    meta: {
      ...(result.meta ?? {}),
      idempotencyKey: context.idempotencyKey,
      signature: context.signature,
      attempts: context.attempt,
      maxAttempts: context.maxAttempts,
    },
    tool: toolName,
    code,
    retryable,
    timestamp: Date.now(),
    truncated: result.truncated || budgeted.truncated,
  };
}

function mapErrorCode(error?: string): string {
  const message = (error ?? '').toLowerCase();
  if (!message) return 'ERROR';
  if (message.includes('completion blocked by diagnostics')) return 'COMPLETION_BLOCKED_BY_DIAGNOSTICS';
  if (message.includes('retry exhausted')) return 'EDIT_RETRY_EXHAUSTED';
  if (message.includes('content changed on disk')) return 'EDIT_STALE_CONTENT';
  if (message.includes('timed out')) return 'TIMEOUT';
  if (message.includes('cancelled')) return 'CANCELLED';
  if (message.includes('no handler') || message.includes('unknown tool')) return 'TOOL_NOT_FOUND';
  if (message.includes('removed from strict profile')) return 'TOOL_DEPRECATED';
  if (message.includes('missing')) return 'MISSING_PARAM';
  if (message.includes('read-before-edit guard') || message.includes('read before edit')) {
    return 'READ_REQUIRED_BEFORE_EDIT';
  }
  if (message.includes('outside workspace')) return 'PATH_OUTSIDE_WORKSPACE';
  if (message.includes('not found')) return 'NOT_FOUND';
  if (message.includes('permission') || message.includes('denied')) return 'PERMISSION_DENIED';
  if (message.includes('invalid line range') || message.includes('exceeds file length')) return 'INVALID_RANGE';
  if (message.includes('syntax')) return 'SYNTAX_ERROR';
  return 'ERROR';
}

function isRetryableError(error?: string): boolean {
  const message = (error ?? '').toLowerCase();
  if (!message) return false;
  if (message.includes('timed out')) return true;
  if (message.includes('temporarily') || message.includes('transient')) return true;
  if (message.includes('network') || message.includes('econn') || message.includes('connection')) return true;
  return false;
}

function shouldRetryTool(toolName: string, toolDef: ReturnType<typeof getToolByName>): boolean {
  if (toolName.startsWith('lsp_')) return false;
  const category = toolDef?.category;
  return category === 'workspace_read' ||
    category === 'workspace_search' ||
    category === 'diagnostics' ||
    category === 'editor_context' ||
    category === 'browser';
}

function getToolMaxAttempts(
  toolName: string,
  toolDef: ReturnType<typeof getToolByName>,
): number {
  if (!shouldRetryTool(toolName, toolDef)) return 1;
  const configured = TOOL_MAX_ATTEMPTS[toolName];
  if (typeof configured === 'number' && configured > 0) return configured;
  return 2;
}

function shouldRetryResult(
  toolName: string,
  toolDef: ReturnType<typeof getToolByName>,
  result: CanonicalToolResult,
  attempt: number,
  maxAttempts: number
): boolean {
  if (attempt >= maxAttempts - 1) return false;
  if (!shouldRetryTool(toolName, toolDef)) return false;
  if (!result.retryable) return false;
  return true;
}

function stableStringify(value: unknown): string {
  if (value == null || typeof value !== 'object') {
    return JSON.stringify(value);
  }
  if (Array.isArray(value)) {
    return `[${value.map((v) => stableStringify(v)).join(',')}]`;
  }
  const obj = value as Record<string, unknown>;
  const keys = Object.keys(obj).sort();
  return `{${keys.map((k) => `${JSON.stringify(k)}:${stableStringify(obj[k])}`).join(',')}}`;
}

function createToolSignature(toolName: string, args: Record<string, unknown>): string {
  return `${toolName}:${stableStringify(args)}`;
}

function purgeExpiredIdempotencyCache(): void {
  const now = Date.now();
  for (const [key, entry] of idempotentResultCache) {
    if (entry.expiresAt <= now) {
      idempotentResultCache.delete(key);
    }
  }
}

function recordExecutionTelemetry(
  toolName: string,
  signature: string,
  idempotencyKey: string | undefined,
  result: CanonicalToolResult,
  durationMs: number,
  attempt: number,
  maxAttempts: number,
  replayed: boolean
): void {
  toolObservabilityStore.record({
    timestamp: Date.now(),
    toolName,
    signature,
    idempotencyKey,
    durationMs,
    success: result.success,
    code: result.code,
    retryable: result.retryable,
    attempt,
    maxAttempts,
    replayed,
  });
  agentTelemetryStore.record({
    type: 'agent.tool.call',
    timestamp: Date.now(),
    toolName,
    success: result.success,
    durationMs,
    code: result.code,
    retryable: result.retryable,
    signature,
  });
  if (!result.success) {
    agentTelemetryStore.record({
      type: 'agent.tool.failure_signature',
      timestamp: Date.now(),
      toolName,
      signature,
    });
  }
}

function delay(ms: number): Promise<void> {
  return new Promise(resolve => setTimeout(resolve, ms));
}

if (typeof window !== 'undefined' && import.meta.env.DEV) {
  const parity = getToolContractParity();
  if (parity.missingHandlers.length > 0 || parity.orphanHandlers.length > 0) {
    console.warn('[Tools] Contract parity warning', parity);
  }
}

/**
 * Format tool call for display (used in UI)
 */
export function formatToolCallForDisplay(toolCall: { name: string; arguments: Record<string, unknown> }): string {
  const args = { ...toolCall.arguments };
  delete args.meta; // Don't show meta in display

  const argStr = Object.entries(args)
    .filter(([_, v]) => v !== undefined)
    .map(([k, v]) => {
      const val = typeof v === 'string' && v.length > 50
        ? v.slice(0, 50) + '...'
        : JSON.stringify(v);
      return `${k}=${val}`;
    })
    .join(', ');

  return `${toolCall.name}(${argStr})`;
}

/**
 * Shared utilities for tool handlers
 */

import { projectStore } from '$shared/stores/project.svelte';
import { isFileError, getFileErrorMessage } from '$core/types/files';

// Maximum output size (100KB)
export const MAX_OUTPUT_SIZE = 100 * 1024;
const DEFAULT_TOOL_OUTPUT_CAP = 24 * 1024;
const TOOL_OUTPUT_CAPS: Record<string, number> = {
  read_file: 48 * 1024,
  workspace_search: 40 * 1024,
  run_command: 40 * 1024,
  apply_patch: 24 * 1024,
};

/**
 * Truncate output if too large
 */
export function truncateOutput(output: string): { text: string; truncated: boolean } {
  if (output.length <= MAX_OUTPUT_SIZE) {
    return { text: output, truncated: false };
  }
  return {
    text: output.slice(0, MAX_OUTPUT_SIZE) + '\n\n[Output truncated - exceeded 100KB]',
    truncated: true
  };
}

/**
 * Extract error message from unknown error
 */
export function extractErrorMessage(err: unknown): string {
  if (err instanceof Error) return err.message;
  if (typeof err === 'string') return err;
  if (isFileError(err)) return getFileErrorMessage(err);
  if (err && typeof err === 'object' && 'message' in err) return String(err.message);
  return 'Unknown error';
}

/**
 * Calculate simple line-based diff statistics (added/removed)
 * This is used for the green/red indicators in the chat UI
 */
export function calculateDiffStats(before: string, after: string): { added: number; removed: number } {
  if (before === after) return { added: 0, removed: 0 };
  
  const beforeLines = before.split('\n');
  const afterLines = after.split('\n');
  
  // Use a simple map to track line occurrences for counting
  const beforeMap = new Map<string, number>();
  for (const line of beforeLines) {
    beforeMap.set(line, (beforeMap.get(line) || 0) + 1);
  }
  
  let added = 0;
  const afterMap = new Map<string, number>();
  for (const line of afterLines) {
    const count = beforeMap.get(line) || 0;
    if (count > 0) {
      beforeMap.set(line, count - 1);
    } else {
      added++;
    }
  }
  
  // Remaining lines in beforeMap are removed lines
  let removed = 0;
  for (const count of beforeMap.values()) {
    removed += count;
  }
  
  return { added, removed };
}

/**
 * Resolve relative path to absolute using workspace root
 */
export function resolvePath(relativePath: string): string {
  const root = projectStore.rootPath;
  if (!root) return relativePath;

  // Already absolute
  if (relativePath.startsWith('/') || /^[A-Za-z]:/.test(relativePath)) {
    return relativePath;
  }

  // Join with root
  const separator = root.includes('\\') ? '\\' : '/';
  return root.endsWith(separator) ? root + relativePath : root + separator + relativePath;
}

/**
 * Validate path is within workspace
 */
export function validatePathInWorkspace(path: string, workspaceRoot: string): { valid: boolean; absolutePath: string; error?: string } {
  if (!workspaceRoot) {
    return { valid: false, absolutePath: '', error: 'No workspace is open' };
  }

  const normalizedPath = path.replace(/\\/g, '/');
  const normalizedRoot = workspaceRoot.replace(/\\/g, '/');

  // Build absolute path
  let absolutePath: string;
  if (normalizedPath.startsWith('/') || /^[A-Za-z]:/.test(normalizedPath)) {
    absolutePath = normalizedPath;
  } else {
    absolutePath = normalizedRoot.endsWith('/')
      ? normalizedRoot + normalizedPath
      : normalizedRoot + '/' + normalizedPath;
  }

  // Normalize (resolve . and ..)
  const parts = absolutePath.split('/').filter(p => p !== '');
  const resolved: string[] = [];

  for (const part of parts) {
    if (part === '.') continue;
    else if (part === '..') {
      if (resolved.length > 0) resolved.pop();
    } else {
      resolved.push(part);
    }
  }

  let finalPath: string;
  if (/^[A-Za-z]:$/.test(parts[0] || '')) {
    finalPath = resolved.join('/');
  } else {
    finalPath = '/' + resolved.join('/');
  }

  // Check if within workspace
  const normalizedFinal = finalPath.toLowerCase();
  const normalizedRootLower = normalizedRoot.toLowerCase();
  const rootWithSlash = normalizedRootLower.endsWith('/') ? normalizedRootLower : normalizedRootLower + '/';
  const isWithin = normalizedFinal === normalizedRootLower || normalizedFinal.startsWith(rootWithSlash);

  if (!isWithin) {
    return { valid: false, absolutePath: finalPath, error: `Path "${path}" is outside workspace` };
  }

  return { valid: true, absolutePath: finalPath };
}

/**
 * Compare paths for equality (handles different separators)
 */
export function isSameOrSuffixPath(openPath: string, absPath: string, relPath: string): boolean {
  const normalize = (p: string) => p.replace(/\\/g, '/').toLowerCase();
  const openNorm = normalize(openPath);
  const absNorm = normalize(absPath);
  const relNorm = normalize(relPath);

  if (openNorm === absNorm || openNorm === relNorm) return true;

  const relSuffix = '/' + relNorm.replace(/^\/+/, '');
  if (openNorm.endsWith(relSuffix)) return true;
  if (openNorm.endsWith(relNorm) && (openNorm.length === relNorm.length || openNorm[openNorm.length - relNorm.length - 1] === '/')) {
    return true;
  }

  return false;
}

/**
 * Format file content with line numbers
 */
export function formatWithLineNumbers(content: string, startLine: number = 1): string {
  const lines = content.split('\n');
  const maxLineNum = startLine + lines.length - 1;
  const padding = String(maxLineNum).length;

  return lines
    .map((line, i) => {
      const lineNum = String(startLine + i).padStart(padding, ' ');
      return `${lineNum}│${line}`;
    })
    .join('\n');
}

/**
 * Tool result type
 */
export interface ToolResult {
  success: boolean;
  output?: string;
  error?: string;
  truncated?: boolean;
  meta?: Record<string, any>;
  data?: any;
  warnings?: string[];
  tool?: string;
  code?: string;
  retryable?: boolean;
  timestamp?: number;
}

export interface CanonicalToolResult {
  success: boolean;
  output: string;
  error: string;
  data: any;
  meta: Record<string, any>;
  warnings: string[];
  tool: string;
  code: string;
  retryable: boolean;
  timestamp: number;
  truncated?: boolean;
}

export function normalizeToolOutputBudget(
  toolName: string,
  output: string,
): { output: string; truncated: boolean } {
  const limit = TOOL_OUTPUT_CAPS[toolName] ?? DEFAULT_TOOL_OUTPUT_CAP;
  if (output.length <= limit) {
    return { output, truncated: false };
  }
  return {
    output: `${output.slice(0, limit)}\n\n[Output truncated by tool output policy]`,
    truncated: true,
  };
}

/**
 * LSP Client - Monaco Editor Diagnostics Integration
 * 
 * Monaco Editor has built-in language support through its web workers:
 * - TypeScript/JavaScript
 * - HTML
 * - CSS/SCSS/LESS
 * - JSON
 * 
 * This module:
 * 1. Configures language defaults (TypeScript, HTML, CSS)
 * 2. Registers custom languages (Svelte)
 * 3. Listens for marker (diagnostic) changes
 * 4. Pipes diagnostics to the problems store
 * 5. Implements low-RAM strategy (single LSP at a time when RAM < 4GB)
 */

import type * as Monaco from 'monaco-editor';
import { getMonaco, isMonacoLoaded } from '$core/services/monaco-loader';
import { problemsStore, type Problem, type ProblemSeverity } from '$shared/stores/problems.svelte';
import { configureHtmlDefaults, configureCssDefaults } from './html-css';
import { registerSvelteLanguage } from './svelte';

// Track if LSP client is initialized
let initialized = false;

// Track which language services are active
let activeLanguageServices = new Set<string>();

// Debounce timer for marker updates
let markerUpdateTimer: ReturnType<typeof setTimeout> | null = null;
const MARKER_UPDATE_DEBOUNCE = 150;

// Idle timeout for cleanup (5 minutes)
let idleTimer: ReturnType<typeof setTimeout> | null = null;
const IDLE_TIMEOUT = 5 * 60 * 1000;

// Track active file types
const activeLanguages = new Set<string>();

// Disposables for cleanup
const disposables: Monaco.IDisposable[] = [];

// Low RAM threshold (4GB in bytes)
const LOW_RAM_THRESHOLD = 4 * 1024 * 1024 * 1024;

// Estimated system RAM (will be updated if system info is available)
let estimatedRamBytes = 8 * 1024 * 1024 * 1024; // Default to 8GB

/**
 * Check if system is in low RAM mode
 */
function isLowRamMode(): boolean {
  return estimatedRamBytes < LOW_RAM_THRESHOLD;
}

/**
 * Set estimated RAM (can be called from system detection)
 */
export function setEstimatedRam(ramBytes: number): void {
  estimatedRamBytes = ramBytes;
}

/**
 * Language service categories for low-RAM mode
 */
type LanguageServiceCategory = 'typescript' | 'html' | 'css' | 'svelte';

/**
 * Get the language service category for a language
 */
function getLanguageServiceCategory(language: string): LanguageServiceCategory | null {
  switch (language) {
    case 'typescript':
    case 'javascript':
    case 'typescriptreact':
    case 'javascriptreact':
      return 'typescript';
    case 'html':
    case 'handlebars':
    case 'razor':
      return 'html';
    case 'css':
    case 'scss':
    case 'less':
      return 'css';
    case 'svelte':
      return 'svelte';
    default:
      return null;
  }
}

/**
 * Map Monaco MarkerSeverity to our ProblemSeverity
 */
function mapSeverity(monaco: typeof Monaco, severity: Monaco.MarkerSeverity): ProblemSeverity {
  switch (severity) {
    case monaco.MarkerSeverity.Error:
      return 'error';
    case monaco.MarkerSeverity.Warning:
      return 'warning';
    case monaco.MarkerSeverity.Info:
      return 'info';
    case monaco.MarkerSeverity.Hint:
      return 'hint';
    default:
      return 'info';
  }
}

/**
 * Extract file path from Monaco URI
 */
function getFilePathFromUri(uri: Monaco.Uri): string {
  // Our URIs are in format: inmemory://model/{encodedPath}
  const path = uri.path;
  if (path.startsWith('/')) {
    return decodeURIComponent(path.slice(1));
  }
  return decodeURIComponent(path);
}

/**
 * Check if a file is a TypeScript/JavaScript file
 * These files are handled by the TypeScript sidecar, not Monaco markers
 */
function isTsJsFile(filepath: string): boolean {
  const ext = filepath.split('.').pop()?.toLowerCase() || '';
  return ['ts', 'tsx', 'js', 'jsx', 'mts', 'cts', 'mjs', 'cjs'].includes(ext);
}

/**
 * Extract file name from path
 */
function getFileName(filePath: string): string {
  return filePath.split(/[/\\]/).pop() || filePath;
}

/**
 * Process markers from Monaco and update problems store
 * 
 * NOTE: TypeScript/JavaScript files are handled by the TypeScript sidecar,
 * so we skip Monaco markers for those files to avoid conflicts.
 */
function processMarkers(monaco: typeof Monaco): void {
  // Get all markers from Monaco
  const allMarkers = monaco.editor.getModelMarkers({});

  // Group markers by file (excluding TS/JS files which are handled by sidecar)
  const markersByFile = new Map<string, Monaco.editor.IMarker[]>();

  for (const marker of allMarkers) {
    const filePath = getFilePathFromUri(marker.resource);

    // Skip TS/JS files - they're handled by the TypeScript sidecar
    // Also skip markers we've set ourselves to avoid loops
    if (isTsJsFile(filePath) || marker.owner === 'volt-problems') {
      continue;
    }

    const existing = markersByFile.get(filePath) || [];
    existing.push(marker);
    markersByFile.set(filePath, existing);
  }

  // Get all files that currently have problems (excluding TS/JS files)
  const currentFiles = new Set(
    problemsStore.filesWithProblems.filter(f => !isTsJsFile(f))
  );

  // Update problems for each file with markers
  for (const [filePath, markers] of markersByFile) {
    const problems: Problem[] = markers.map((marker, index) => ({
      id: `${filePath}:${marker.startLineNumber}:${marker.startColumn}:${index}`,
      file: filePath,
      fileName: getFileName(filePath),
      line: marker.startLineNumber,
      column: marker.startColumn,
      endLine: marker.endLineNumber,
      endColumn: marker.endColumn,
      message: marker.message,
      severity: mapSeverity(monaco, marker.severity),
      source: 'monaco',
      code: marker.code?.toString()
    }));

    problemsStore.setProblemsForFile(filePath, problems, 'monaco');
    currentFiles.delete(filePath);
  }

  // Clear problems for non-TS/JS files that no longer have markers
  for (const filePath of currentFiles) {
    problemsStore.clearProblemsForFile(filePath, 'monaco');
  }
}

/**
 * Debounced marker update
 */
function scheduleMarkerUpdate(monaco: typeof Monaco): void {
  if (markerUpdateTimer) {
    clearTimeout(markerUpdateTimer);
  }

  markerUpdateTimer = setTimeout(() => {
    processMarkers(monaco);
    markerUpdateTimer = null;
  }, MARKER_UPDATE_DEBOUNCE);
}

/**
 * Reset idle timer
 */
function resetIdleTimer(): void {
  if (idleTimer) {
    clearTimeout(idleTimer);
  }

  idleTimer = setTimeout(() => {
    // Could implement cleanup here if needed
    // For now, we keep the LSP active as long as Monaco is loaded
  }, IDLE_TIMEOUT);
}

/**
 * Configure TypeScript compiler options for better IDE experience
 * Uses dynamic access to avoid TypeScript type issues with Monaco's deprecated namespace
 * 
 * NOTE: We DISABLE Monaco's built-in TS diagnostics because we use the real
 * typescript-language-server sidecar for diagnostics. This prevents conflicts
 * where Monaco squiggles show different errors than the Problems panel.
 */
function configureTypeScript(monaco: typeof Monaco): void {
  // Access TypeScript defaults through dynamic property access
  // This is needed because Monaco's types mark these as deprecated
  const languages = monaco.languages as Record<string, unknown>;
  const typescript = languages['typescript'] as {
    typescriptDefaults?: {
      setCompilerOptions: (options: Record<string, unknown>) => void;
      setDiagnosticsOptions: (options: Record<string, unknown>) => void;
    };
    javascriptDefaults?: {
      setCompilerOptions: (options: Record<string, unknown>) => void;
      setDiagnosticsOptions: (options: Record<string, unknown>) => void;
    };
    ScriptTarget?: Record<string, number>;
    ModuleKind?: Record<string, number>;
    ModuleResolutionKind?: Record<string, number>;
    JsxEmit?: Record<string, number>;
  };

  if (!typescript?.typescriptDefaults || !typescript?.javascriptDefaults) {
    return;
  }

  const compilerOptions: Record<string, unknown> = {
    target: typescript.ScriptTarget?.ESNext ?? 99,
    module: typescript.ModuleKind?.ESNext ?? 99,
    moduleResolution: typescript.ModuleResolutionKind?.NodeJs ?? 2,
    jsx: typescript.JsxEmit?.React ?? 2,
    allowNonTsExtensions: true,
    allowJs: true,
    checkJs: true,
    strict: true,
    noEmit: true,
    esModuleInterop: true,
    skipLibCheck: true,
    forceConsistentCasingInFileNames: true,
    resolveJsonModule: true,
    isolatedModules: true,
    noUnusedLocals: false,
    noUnusedParameters: false,
    noImplicitReturns: true,
    noFallthroughCasesInSwitch: true
  };

  // Apply to both TypeScript and JavaScript
  typescript.typescriptDefaults.setCompilerOptions(compilerOptions);
  typescript.javascriptDefaults.setCompilerOptions(compilerOptions);

  // DISABLE Monaco's built-in TS diagnostics - we use the real TS server sidecar instead
  // This prevents conflicts between Monaco squiggles and Problems panel
  const diagnosticsOptions = {
    noSemanticValidation: true,  // Disable - handled by TS sidecar
    noSyntaxValidation: true,    // Disable - handled by TS sidecar
    noSuggestionDiagnostics: true // Disable - handled by TS sidecar
  };

  typescript.typescriptDefaults.setDiagnosticsOptions(diagnosticsOptions);
  typescript.javascriptDefaults.setDiagnosticsOptions(diagnosticsOptions);

  activeLanguageServices.add('typescript');
}

/**
 * Configure all language services
 */
function configureAllLanguages(monaco: typeof Monaco): void {
  // Configure TypeScript/JavaScript
  configureTypeScript(monaco);

  // Configure HTML
  configureHtmlDefaults(monaco);
  activeLanguageServices.add('html');

  // Configure CSS/SCSS/LESS
  configureCssDefaults(monaco);
  activeLanguageServices.add('css');

  // Register Svelte language
  registerSvelteLanguage(monaco);
  activeLanguageServices.add('svelte');
}

/**
 * Initialize the LSP client
 * Should be called when Monaco is loaded
 */
export function initializeLspClient(): void {
  if (initialized) return;

  const monaco = getMonaco();
  if (!monaco) return;

  // Configure all language services
  configureAllLanguages(monaco);

  // Listen for marker changes
  const markerDisposable = monaco.editor.onDidChangeMarkers(() => {
    scheduleMarkerUpdate(monaco);
    resetIdleTimer();
  });
  disposables.push(markerDisposable);

  // Initial marker processing
  processMarkers(monaco);

  initialized = true;
  resetIdleTimer();
}

/**
 * Check if a language should trigger LSP initialization
 */
export function isLspLanguage(language: string): boolean {
  const lspLanguages = [
    // TypeScript/JavaScript
    'typescript', 'javascript', 'typescriptreact', 'javascriptreact',
    // HTML
    'html', 'handlebars', 'razor',
    // CSS
    'css', 'scss', 'less',
    // Svelte
    'svelte'
  ];
  return lspLanguages.includes(language);
}

/**
 * Get active language services
 */
export function getActiveLanguageServices(): string[] {
  return Array.from(activeLanguageServices);
}

/**
 * Check if running in low RAM mode
 */
export function isInLowRamMode(): boolean {
  return isLowRamMode();
}

/**
 * Notify that a file with a specific language was opened
 * This triggers LSP initialization if needed
 */
export function notifyFileOpened(language: string): void {
  if (!isLspLanguage(language)) return;

  activeLanguages.add(language);

  // Initialize LSP if Monaco is loaded
  if (isMonacoLoaded() && !initialized) {
    initializeLspClient();
  }

  resetIdleTimer();
}

/**
 * Notify that a file was closed
 */
export function notifyFileClosed(language: string): void {
  activeLanguages.delete(language);
}

/**
 * Dispose the LSP client
 */
export function disposeLspClient(): void {
  if (markerUpdateTimer) {
    clearTimeout(markerUpdateTimer);
    markerUpdateTimer = null;
  }

  if (idleTimer) {
    clearTimeout(idleTimer);
    idleTimer = null;
  }

  for (const disposable of disposables) {
    disposable.dispose();
  }
  disposables.length = 0;

  activeLanguages.clear();
  problemsStore.clearAll();
  initialized = false;
}

/**
 * Check if LSP client is initialized
 */
export function isLspInitialized(): boolean {
  return initialized;
}

/**
 * CSS LSP Sidecar Service
 * 
 * Provides CSS/SCSS/LESS language intelligence using vscode-css-language-server:
 * - Completions (properties, values, selectors)
 * - Hover information (property docs)
 * - Go to definition (variables, mixins)
 * - Color picker
 * - Diagnostics
 * 
 * Strategy:
 * - Start server when opening a CSS/SCSS/LESS file
 * - Workspace root = projectStore.rootPath
 */

import { getLspRegistry, type LspTransport, type JsonRpcMessage } from './sidecar';
import { problemsStore, type Problem, type ProblemSeverity } from '$shared/stores/problems.svelte';
import { projectStore } from '$shared/stores/project.svelte';
import { readFileQuiet } from '$core/services/file-system';
import { getAllFiles } from '$core/services/file-index';

// Server instance tracking
let cssServerTransport: LspTransport | null = null;
let cssServerInitialized = false;
let initializationPromise: Promise<void> | null = null;

// Document tracking
const openDocuments = new Map<string, { version: number; content: string }>();

/**
 * Check if a file is a CSS file
 */
export function isCssFile(filepath: string): boolean {
  const ext = filepath.split('.').pop()?.toLowerCase() || '';
  return ['css', 'scss', 'sass', 'less'].includes(ext);
}

/**
 * Get the language ID for LSP
 */
function getLanguageId(filepath: string): string {
  const ext = filepath.split('.').pop()?.toLowerCase() || '';
  switch (ext) {
    case 'scss': return 'scss';
    case 'sass': return 'sass';
    case 'less': return 'less';
    default: return 'css';
  }
}

/**
 * Convert file path to URI
 */
function pathToUri(filepath: string): string {
  // Handle Windows paths
  let normalizedPath = filepath.replace(/\\/g, '/');
  // Normalize drive letter to lowercase for consistency
  if (normalizedPath.match(/^[a-zA-Z]:/)) {
    normalizedPath = normalizedPath[0].toLowerCase() + normalizedPath.slice(1);
  }
  const encodedPath = encodeURI(normalizedPath);
  if (normalizedPath.match(/^[a-zA-Z]:/)) {
    return `file:///${encodedPath}`;
  }
  return `file://${encodedPath}`;
}

/**
 * Convert URI to file path
 */
function uriToPath(uri: string): string {
  let path = uri.replace('file://', '');
  // Handle Windows paths (file:///C:/...)
  if (path.match(/^\/[a-zA-Z]:/)) {
    path = path.slice(1);
  }
  // Normalize drive letter to lowercase for consistency
  if (path.match(/^[a-zA-Z]:/)) {
    path = path[0].toLowerCase() + path.slice(1);
  }
  // Normalize to forward slashes for consistency with editorStore
  return path.replace(/\\/g, '/');
}

/**
 * Map LSP severity to our severity
 */
function mapSeverity(lspSeverity: number): ProblemSeverity {
  switch (lspSeverity) {
    case 1: return 'error';
    case 2: return 'warning';
    case 3: return 'info';
    case 4: return 'hint';
    default: return 'info';
  }
}

interface Diagnostic {
  range: {
    start: { line: number; character: number };
    end: { line: number; character: number };
  };
  message: string;
  severity?: number;
  code?: number | string;
  source?: string;
}

interface PublishDiagnosticsParams {
  uri: string;
  diagnostics: Diagnostic[];
}

/**
 * Handle incoming LSP messages
 */
function handleLspMessage(message: JsonRpcMessage): void {
  // Handle server requests that require a response
  if ('id' in message && 'method' in message && message.id !== null) {
    const id = message.id;
    if (message.method === 'workspace/configuration') {
      const items = (message.params as any)?.items || [];
      const result = items.map(() => ({}));
      cssServerTransport?.sendResponse(id, result);
    } else {
      cssServerTransport?.sendResponse(id, null);
    }
    return;
  }

  // Handle notifications
  if ('method' in message && !('id' in message)) {
    if (message.method === 'textDocument/publishDiagnostics') {
      handleDiagnostics(message.params as PublishDiagnosticsParams);
    }
  }
}

/**
 * Handle diagnostics from the LSP server
 */
function handleDiagnostics(params: PublishDiagnosticsParams): void {
  const filePath = uriToPath(params.uri);
  const fileName = filePath.split(/[/\\]/).pop() || filePath;

  const problems: Problem[] = params.diagnostics.map((diag, index) => ({
    id: `css:${filePath}:${diag.range.start.line}:${diag.range.start.character}:${index}`,
    file: filePath,
    fileName,
    line: diag.range.start.line + 1,
    column: diag.range.start.character + 1,
    endLine: diag.range.end.line + 1,
    endColumn: diag.range.end.character + 1,
    message: diag.message,
    severity: mapSeverity(diag.severity ?? 1),
    source: diag.source || 'css',
    code: diag.code?.toString()
  }));

  problemsStore.setProblemsForFile(filePath, problems, 'css');
}

/**
 * Initialize the CSS language server
 */
async function initializeServer(): Promise<void> {
  if (!projectStore.rootPath) return;
  if (cssServerInitialized) return;
  if (initializationPromise) return initializationPromise;

  initializationPromise = (async () => {
    try {
      const registry = getLspRegistry();

      cssServerTransport = await registry.startServer('css', {
        serverId: 'css-main',
        cwd: projectStore.rootPath ?? undefined
      });

      cssServerTransport.onMessage(handleLspMessage);
      cssServerTransport.onError((error) => {
        console.error('[CSS LSP] Server error:', error);
      });
      cssServerTransport.onExit(() => {
        console.log('[CSS LSP] Server exited');
        cssServerTransport = null;
        cssServerInitialized = false;
        initializationPromise = null;
        openDocuments.clear();
      });

      const rootUri = pathToUri(projectStore.rootPath!);

      await cssServerTransport.sendRequest('initialize', {
        processId: null,
        rootUri,
        rootPath: projectStore.rootPath,
        capabilities: {
          textDocument: {
            synchronization: {
              dynamicRegistration: true,
              willSave: false,
              willSaveWaitUntil: false,
              didSave: true
            },
            completion: {
              dynamicRegistration: true,
              completionItem: {
                snippetSupport: true,
                documentationFormat: ['markdown', 'plaintext']
              }
            },
            hover: {
              dynamicRegistration: true,
              contentFormat: ['markdown', 'plaintext']
            },
            definition: {
              dynamicRegistration: true
            },
            references: {
              dynamicRegistration: true
            },
            colorProvider: {
              dynamicRegistration: true
            },
            formatting: {
              dynamicRegistration: true
            },
            publishDiagnostics: {
              relatedInformation: true
            }
          },
          workspace: {
            applyEdit: true,
            workspaceEdit: { documentChanges: true },
            configuration: true,
            workspaceFolders: true
          }
        },
        workspaceFolders: [
          { uri: rootUri, name: projectStore.projectName }
        ]
      });

      await cssServerTransport.sendNotification('initialized', {});
      cssServerInitialized = true;
      console.log('[CSS LSP] Server initialized');
    } catch (error) {
      console.error('[CSS LSP] Failed to initialize:', error);
      cssServerTransport = null;
      initializationPromise = null;
      throw error;
    }
  })();

  return initializationPromise;
}

/**
 * Notify the server that a document was opened
 */
export async function notifyCssDocumentOpened(filepath: string, content: string): Promise<void> {
  if (!isCssFile(filepath)) return;
  if (!projectStore.rootPath) return;

  // Initialize server if needed
  await initializeServer();

  // Don't reopen if already open and content is the same
  const existing = openDocuments.get(filepath);
  if (existing && existing.content === content) return;

  if (!cssServerTransport || !cssServerInitialized) return;

  const uri = pathToUri(filepath);
  const languageId = getLanguageId(filepath);

  // Track document
  openDocuments.set(filepath, { version: existing ? existing.version + 1 : 1, content });

  if (existing) {
    // If it's already open but content changed, send didChange instead
    await cssServerTransport.sendNotification('textDocument/didChange', {
      textDocument: {
        uri,
        version: existing.version + 1
      },
      contentChanges: [{ text: content }]
    });
    return;
  }

  // Send didOpen notification
  await cssServerTransport.sendNotification('textDocument/didOpen', {
    textDocument: {
      uri,
      languageId,
      version: 1,
      text: content
    }
  });
}

/**
 * Notify the server that a document was changed
 */
export async function notifyCssDocumentChanged(filepath: string, content: string): Promise<void> {
  if (!isCssFile(filepath)) return;
  if (!cssServerTransport || !cssServerInitialized) return;

  const existing = openDocuments.get(filepath);
  if (!existing) {
    await notifyCssDocumentOpened(filepath, content);
    return;
  }

  existing.version++;
  existing.content = content;

  await cssServerTransport.sendNotification('textDocument/didChange', {
    textDocument: { uri: pathToUri(filepath), version: existing.version },
    contentChanges: [{ text: content }]
  });
}

/**
 * Notify the server that a document was closed
 */
export async function notifyCssDocumentClosed(filepath: string): Promise<void> {
  if (!cssServerTransport || !cssServerInitialized) return;
  if (!openDocuments.has(filepath)) return;

  openDocuments.delete(filepath);
  await cssServerTransport.sendNotification('textDocument/didClose', {
    textDocument: { uri: pathToUri(filepath) }
  });
}

export interface Location {
  uri: string;
  range: {
    start: { line: number; character: number };
    end: { line: number; character: number };
  };
}

/**
 * Request hover information
 */
export async function getCssHover(
  filepath: string,
  line: number,
  character: number
): Promise<{ contents: unknown; range?: unknown } | null> {
  if (!isCssFile(filepath)) return null;
  if (!cssServerTransport || !cssServerInitialized) return null;

  try {
    const result = await cssServerTransport.sendRequest('textDocument/hover', {
      textDocument: { uri: pathToUri(filepath) },
      position: { line, character }
    });
    return result as { contents: unknown; range?: unknown } | null;
  } catch (error) {
    console.error('[CSS LSP] Hover error:', error);
    return null;
  }
}

/**
 * Request definition location (for CSS variables, mixins, etc.)
 */
export async function getCssDefinition(
  filepath: string,
  line: number,
  character: number
): Promise<Location[] | null> {
  if (!isCssFile(filepath)) return null;
  if (!cssServerTransport || !cssServerInitialized) return null;

  try {
    const result = await cssServerTransport.sendRequest<Location | Location[] | null>(
      'textDocument/definition',
      {
        textDocument: { uri: pathToUri(filepath) },
        position: { line, character }
      }
    );
    if (!result) return null;
    return Array.isArray(result) ? result : [result];
  } catch (error) {
    console.error('[CSS LSP] Definition error:', error);
    return null;
  }
}

/**
 * Request references (for CSS variables, classes, etc.)
 */
export async function getCssReferences(
  filepath: string,
  line: number,
  character: number,
  includeDeclaration = true
): Promise<Location[] | null> {
  if (!isCssFile(filepath)) return null;
  if (!cssServerTransport || !cssServerInitialized) return null;

  try {
    const result = await cssServerTransport.sendRequest<Location[] | null>(
      'textDocument/references',
      {
        textDocument: { uri: pathToUri(filepath) },
        position: { line, character },
        context: { includeDeclaration }
      }
    );
    return result;
  } catch (error) {
    console.error('[CSS LSP] References error:', error);
    return null;
  }
}

/**
 * Check if CSS LSP is initialized
 */
export function isCssLspInitialized(): boolean {
  return cssServerInitialized;
}

/**
 * Check if CSS LSP is connected
 */
export function isCssLspConnected(): boolean {
  return cssServerTransport !== null && cssServerInitialized;
}

/**
 * Ensure CSS LSP is started
 */
export async function ensureCssLspStarted(): Promise<void> {
  if (!cssServerInitialized) {
    await initializeServer();
  }
}

/**
 * Stop the CSS LSP server
 */
export async function stopCssLsp(): Promise<void> {
  if (!cssServerTransport) return;

  try {
    await cssServerTransport.sendRequest('shutdown', null);
    await cssServerTransport.sendNotification('exit', null);
  } catch {
    // Ignore errors during shutdown
  }

  cssServerTransport = null;
  cssServerInitialized = false;
  initializationPromise = null;
  openDocuments.clear();
}

/**
 * Perform background analysis of all CSS files in the project
 */
export async function startProjectWideAnalysis(): Promise<void> {
  if (!projectStore.rootPath) return;

  const allFiles = getAllFiles();
  const cssFiles = allFiles.filter(f => isCssFile(f.path));

  if (cssFiles.length === 0) {
    console.log('[CSS LSP] No CSS/SCSS files found for background analysis.');
    return;
  }

  console.log(`[CSS LSP] Starting project-wide analysis of ${cssFiles.length} files...`);

  // Process in small batches to avoid blocking
  for (const file of cssFiles) {
    console.log(`[CSS LSP] Background analyzing: ${file.path}`);
    // Only open if not already open (prevent double-counting)
    if (openDocuments.has(file.path)) continue;

    const content = await readFileQuiet(file.path);
    if (content) {
      // This will automatically initialize server if needed
      await notifyCssDocumentOpened(file.path, content);
      console.log(`[CSS LSP] Sent ${file.path} to server`);

      // If we've opened many files, yield to event loop
      if (cssFiles.indexOf(file) % 5 === 0) {
        await new Promise(r => setTimeout(r, 0));
      }
    }
  }
}

/**
 * Dart SDK Detection Service
 * 
 * Detects the Dart/Flutter SDK installation on the user's system.
 * Searches PATH, environment variables, and common installation locations.
 */

import { invoke } from '@tauri-apps/api/core';
import { platform } from '@tauri-apps/plugin-os';
import { homeDir } from '@tauri-apps/api/path';

/** Dart SDK information */
export interface DartSdkInfo {
  /** Full path to the dart executable */
  dartPath: string;
  /** Dart SDK version (e.g., "3.3.0") */
  version: string;
  /** Whether this is part of a Flutter SDK */
  isFlutterSdk: boolean;
  /** Path to Flutter executable (if available) */
  flutterPath?: string;
  /** Flutter SDK version (if available) */
  flutterVersion?: string;
}

/** Cached SDK info */
let cachedSdkInfo: DartSdkInfo | null = null;

/**
 * Detect Dart SDK installation
 * Returns null if Dart is not installed
 */
export async function detectDartSdk(): Promise<DartSdkInfo | null> {
  if (cachedSdkInfo) {
    return cachedSdkInfo;
  }

  try {
    // Try to get Dart version via command
    const dartPath = await findDartExecutable();
    if (!dartPath) {
      return null;
    }

    const version = await getDartVersion(dartPath);
    if (!version) {
      return null;
    }

    // Check if this is part of a Flutter SDK
    const flutterInfo = await detectFlutterSdk();

    cachedSdkInfo = {
      dartPath,
      version,
      isFlutterSdk: !!flutterInfo,
      flutterPath: flutterInfo?.flutterPath,
      flutterVersion: flutterInfo?.version,
    };

    console.log('[Dart SDK] Detected:', cachedSdkInfo);
    return cachedSdkInfo;
  } catch (error) {
    console.error('[Dart SDK] Detection failed:', error);
    return null;
  }
}

/**
 * Find the dart executable in PATH or common locations
 */
async function findDartExecutable(): Promise<string | null> {
  const os = await platform();
  const isWindows = os === 'windows';
  const dartCmd = isWindows ? 'dart.bat' : 'dart';

  // First, try PATH via 'where' (Windows) or 'which' (Unix)
  try {
    const result = await runCommand(isWindows ? 'where' : 'which', [isWindows ? 'dart' : 'dart']);
    if (result.exitCode === 0 && result.stdout.trim()) {
      const path = result.stdout.trim().split('\n')[0].trim();
      if (path) return path;
    }
  } catch {
    // Continue to check common locations
  }

  // Check common installation locations
  const home = await homeDir();
  const commonPaths = isWindows
    ? [
        // Flutter SDK locations
        `${home}\\flutter\\bin\\dart.bat`,
        `${home}\\flutter\\bin\\cache\\dart-sdk\\bin\\dart.bat`,
        `C:\\flutter\\bin\\dart.bat`,
        `C:\\flutter\\bin\\cache\\dart-sdk\\bin\\dart.bat`,
        // Standalone Dart SDK
        `C:\\tools\\dart-sdk\\bin\\dart.bat`,
        `${home}\\.dart\\bin\\dart.bat`,
        // Chocolatey
        `C:\\ProgramData\\chocolatey\\bin\\dart.bat`,
      ]
    : [
        // Flutter SDK locations
        `${home}/flutter/bin/dart`,
        `${home}/flutter/bin/cache/dart-sdk/bin/dart`,
        '/usr/local/flutter/bin/dart',
        // Standalone Dart SDK
        '/usr/local/dart/bin/dart',
        '/usr/lib/dart/bin/dart',
        `${home}/.dart/bin/dart`,
        // Homebrew (macOS)
        '/opt/homebrew/bin/dart',
        '/usr/local/bin/dart',
      ];

  // Check FLUTTER_ROOT environment variable
  const flutterRoot = await getEnvVar('FLUTTER_ROOT');
  if (flutterRoot) {
    commonPaths.unshift(
      isWindows
        ? `${flutterRoot}\\bin\\dart.bat`
        : `${flutterRoot}/bin/dart`
    );
  }

  // Check DART_SDK environment variable
  const dartSdk = await getEnvVar('DART_SDK');
  if (dartSdk) {
    commonPaths.unshift(
      isWindows
        ? `${dartSdk}\\bin\\dart.bat`
        : `${dartSdk}/bin/dart`
    );
  }

  for (const path of commonPaths) {
    if (await fileExists(path)) {
      return path;
    }
  }

  return null;
}

/**
 * Get Dart version from executable
 */
async function getDartVersion(dartPath: string): Promise<string | null> {
  try {
    const result = await runCommand(dartPath, ['--version']);
    const output = `${result.stdout}\n${result.stderr}`;
    // Output format: "Dart SDK version: 3.3.0 (stable) ..."
    const match = output.match(/Dart SDK version:\s*(\d+\.\d+\.\d+)/);
    return match ? match[1] : null;
  } catch {
    return null;
  }
}

/**
 * Detect Flutter SDK (optional, used to enrich Dart SDK info)
 */
async function detectFlutterSdk(): Promise<{ flutterPath: string; version: string } | null> {
  const os = await platform();
  const isWindows = os === 'windows';

  try {
    const result = await runCommand(isWindows ? 'where' : 'which', ['flutter']);
    if (result.exitCode === 0 && result.stdout.trim()) {
      const flutterPath = result.stdout.trim().split('\n')[0].trim();
      
      // Get Flutter version
      const versionResult = await runCommand(flutterPath, ['--version', '--machine']);
      if (versionResult.exitCode === 0) {
        try {
          const info = JSON.parse(versionResult.stdout);
          return {
            flutterPath,
            version: info.frameworkVersion || info.version,
          };
        } catch {
          // Try parsing plain text output
          const match = versionResult.stdout.match(/Flutter\s+(\d+\.\d+\.\d+)/);
          if (match) {
            return { flutterPath, version: match[1] };
          }
        }
      }
    }
  } catch {
    // Flutter not found, that's okay
  }

  return null;
}

/**
 * Run a command and capture output
 */
async function runCommand(cmd: string, args: string[]): Promise<{ exitCode: number; stdout: string; stderr: string }> {
