      contentChanges: [{ text: content }]
    });
    return;
  }

  // Send didOpen notification
  await jsonServerTransport.sendNotification('textDocument/didOpen', {
    textDocument: {
      uri,
      languageId,
      version: 1,
      text: content
    }
  });
}

/**
 * Notify the server that a document was changed
 */
export async function notifyJsonDocumentChanged(filepath: string, content: string): Promise<void> {
  if (!isJsonFile(filepath)) return;
  if (!jsonServerTransport || !jsonServerInitialized) return;

  const existing = openDocuments.get(filepath);
  if (!existing) {
    await notifyJsonDocumentOpened(filepath, content);
    return;
  }

  existing.version++;
  existing.content = content;

  await jsonServerTransport.sendNotification('textDocument/didChange', {
    textDocument: { uri: pathToUri(filepath), version: existing.version },
    contentChanges: [{ text: content }]
  });
}

/**
 * Notify the server that a document was closed
 */
export async function notifyJsonDocumentClosed(filepath: string): Promise<void> {
  if (!jsonServerTransport || !jsonServerInitialized) return;
  if (!openDocuments.has(filepath)) return;

  openDocuments.delete(filepath);
  await jsonServerTransport.sendNotification('textDocument/didClose', {
    textDocument: { uri: pathToUri(filepath) }
  });
}

/**
 * Request hover information
 */
export async function getJsonHover(
  filepath: string,
  line: number,
  character: number
): Promise<{ contents: unknown; range?: unknown } | null> {
  if (!isJsonFile(filepath)) return null;
  if (!jsonServerTransport || !jsonServerInitialized) return null;

  try {
    const result = await jsonServerTransport.sendRequest('textDocument/hover', {
      textDocument: { uri: pathToUri(filepath) },
      position: { line, character }
    });
    return result as { contents: unknown; range?: unknown } | null;
  } catch (error) {
    console.error('[JSON LSP] Hover error:', error);
    return null;
  }
}

/**
 * Check if JSON LSP is initialized
 */
export function isJsonLspInitialized(): boolean {
  return jsonServerInitialized;
}

/**
 * Check if JSON LSP is connected
 */
export function isJsonLspConnected(): boolean {
  return jsonServerTransport !== null && jsonServerInitialized;
}

/**
 * Ensure JSON LSP is started
 */
export async function ensureJsonLspStarted(): Promise<void> {
  if (!jsonServerInitialized) {
    await initializeServer();
  }
}

/**
 * Stop the JSON LSP server
 */
export async function stopJsonLsp(): Promise<void> {
  if (!jsonServerTransport) return;

  try {
    await jsonServerTransport.sendRequest('shutdown', null);
    await jsonServerTransport.sendNotification('exit', null);
  } catch {
    // Ignore errors during shutdown
  }

  jsonServerTransport = null;
  jsonServerInitialized = false;
  initializationPromise = null;
  openDocuments.clear();
}

/**
 * LSP Sidecar Transport
 * 
 * Handles communication between the frontend and LSP server sidecars
 * running in the Rust backend via Tauri commands and events.
 * Also supports external LSP servers from user's PATH (e.g., Dart, Rust Analyzer).
 */

import { invoke } from '@tauri-apps/api/core';
import { listen, type UnlistenFn } from '@tauri-apps/api/event';
import type {
  LspServerConfig,
  ExternalLspConfig,
  LspServerInfo,
  JsonRpcMessage,
  JsonRpcRequest,
  JsonRpcNotification,
  JsonRpcResponse,
  MessageHandler,
  ErrorHandler,
  ExitHandler,
  HealthHandler,
  HealthConfig,
  HealthStatus,
} from './types';
import { DEFAULT_HEALTH_CONFIG } from './types';

/** Pending request tracking */
interface PendingRequest {
  resolve: (result: unknown) => void;
  reject: (error: Error) => void;
  method: string;
  timestamp: number;
}

type StartMode = 'sidecar' | 'external';

/**
 * LSP Transport - manages communication with a single LSP server sidecar
 */
export class LspTransport {
  private serverId: string;
  private serverType: string;
  private messageHandlers: Set<MessageHandler> = new Set();
  private errorHandlers: Set<ErrorHandler> = new Set();
  private exitHandlers: Set<ExitHandler> = new Set();
  private healthHandlers: Set<HealthHandler> = new Set();
  private pendingRequests: Map<number | string, PendingRequest> = new Map();
  private nextRequestId = 1;
  private unlisteners: UnlistenFn[] = [];
  private isConnected = false;
  private startMode: StartMode | null = null;
  private startConfig: Omit<LspServerConfig, 'serverId' | 'serverType'> | Omit<ExternalLspConfig, 'serverId' | 'serverType'> | null = null;
  private isRestarting = false;

  // Health monitoring state
  private healthConfig: Required<HealthConfig>;
  private healthCheckTimer: ReturnType<typeof setInterval> | null = null;
  private healthStatus: HealthStatus = {
    healthy: true,
    lastResponseAt: null,
    consecutiveFailures: 0,
    lastCheckAt: null,
    avgResponseTimeMs: null,
    message: 'Not started',
  };
  private responseTimes: number[] = []; // Rolling window for avg calculation
  private static readonly RESPONSE_TIME_WINDOW = 10; // Keep last 10 response times

  constructor(serverId: string, serverType: string, healthConfig?: HealthConfig) {
    this.serverId = serverId;
    this.serverType = serverType;
    this.healthConfig = { ...DEFAULT_HEALTH_CONFIG, ...healthConfig };
  }

  /** Get the server ID */
  get id(): string {
    return this.serverId;
  }

  /** Get the server type */
  get type(): string {
    return this.serverType;
  }

  /** Check if connected */
  get connected(): boolean {
    return this.isConnected;
  }

  /** Get current health status */
  get health(): HealthStatus {
    return { ...this.healthStatus };
  }

  /** Check if server is healthy */
  get healthy(): boolean {
    return this.healthStatus.healthy;
  }

  /** Lightweight runtime metrics for leak/perf monitoring */
  getRuntimeSnapshot(): {
    id: string;
    type: string;
    connected: boolean;
    healthy: boolean;
    pendingRequests: number;
    eventListeners: number;
    messageHandlers: number;
    errorHandlers: number;
    exitHandlers: number;
    healthHandlers: number;
  } {
    return {
      id: this.serverId,
      type: this.serverType,
      connected: this.isConnected,
      healthy: this.healthStatus.healthy,
      pendingRequests: this.pendingRequests.size,
      eventListeners: this.unlisteners.length,
      messageHandlers: this.messageHandlers.size,
      errorHandlers: this.errorHandlers.size,
      exitHandlers: this.exitHandlers.size,
      healthHandlers: this.healthHandlers.size,
    };
  }


  /**
   * Start the LSP server sidecar and set up event listeners
   */
  async start(config: Omit<LspServerConfig, 'serverId' | 'serverType'>): Promise<LspServerInfo> {
    // Start the server via Tauri command
    const info = await invoke<LspServerInfo>('lsp_start_server', {
      serverId: this.serverId,
      serverType: this.serverType,
      sidecarName: config.sidecarName,
      entrypoint: config.entrypoint,
      args: config.args,
      cwd: config.cwd,
      env: config.env,
    });

    // Set up event listeners
    await this.setupEventListeners();
    this.isConnected = true;
    this.startMode = 'sidecar';
    this.startConfig = { ...config };

    // Start health monitoring
    this.startHealthMonitoring();

    return info;
  }

  /**
   * Start an external LSP server (from user's PATH) and set up event listeners
   */
  async startExternal(config: Omit<ExternalLspConfig, 'serverId' | 'serverType'>): Promise<LspServerInfo> {
    // Start the external server via Tauri command
    const info = await invoke<LspServerInfo>('lsp_start_external_server', {
      serverId: this.serverId,
      serverType: this.serverType,
      command: config.command,
      args: config.args,
      cwd: config.cwd,
      env: config.env,
    });

    // Set up event listeners (same as sidecar)
    await this.setupEventListeners();
    this.isConnected = true;
    this.startMode = 'external';
    this.startConfig = { ...config };

    // Start health monitoring
    this.startHealthMonitoring();

    return info;
  }

  /**
   * Set up Tauri event listeners for this server
   */
  private async setupEventListeners(): Promise<void> {
    // Defensive cleanup in case listeners were left over from a prior lifecycle.
    for (const unlisten of this.unlisteners) {
      unlisten();
    }
    this.unlisteners = [];

    // Listen for JSON-RPC messages from the server
    const messageUnlisten = await listen<JsonRpcMessage>(
      `lsp://${this.serverId}//message`,
      (event) => {
        this.handleIncomingMessage(event.payload);
      }
    );
    this.unlisteners.push(messageUnlisten);

    // Listen for stderr output (logging)
    const stderrUnlisten = await listen<string>(
      `lsp://${this.serverId}//stderr`,
      (event) => {
        this.notifyError(event.payload);
      }
    );
    this.unlisteners.push(stderrUnlisten);

    // Listen for errors
    const errorUnlisten = await listen<string>(
      `lsp://${this.serverId}//error`,
      (event) => {
        this.notifyError(event.payload);
      }
    );
    this.unlisteners.push(errorUnlisten);

    // Listen for server exit
    const exitUnlisten = await listen(
      `lsp://${this.serverId}//exit`,
      () => {
        this.handleServerExit();
      }
    );
    this.unlisteners.push(exitUnlisten);

    // Listen for server stopped
    const stoppedUnlisten = await listen(
      `lsp://${this.serverId}//stopped`,
      () => {
        this.handleServerExit();
      }
    );
    this.unlisteners.push(stoppedUnlisten);
  }

  /**
   * Handle incoming JSON-RPC message from the server
   */
  private handleIncomingMessage(message: JsonRpcMessage): void {
    // Check if this is a response to a pending request
    if ('id' in message && message.id !== null) {
      const pending = this.pendingRequests.get(message.id);
      if (pending) {
        this.pendingRequests.delete(message.id);

        if ('error' in message && message.error) {
          pending.reject(new Error(message.error.message));
        } else if ('result' in message) {
          pending.resolve(message.result);
        } else {
          pending.resolve(undefined);
        }
        return;
      }
    }

    // Notify all message handlers
    for (const handler of this.messageHandlers) {
      try {
        handler(message);
      } catch (e) {
        console.error('[LSP Transport] Message handler error:', e);
      }
    }
  }

  /**
   * Handle server exit
   */
  private handleServerExit(): void {
    this.isConnected = false;

    // Reject all pending requests
    for (const [id, pending] of this.pendingRequests) {
      pending.reject(new Error('Server exited'));
      this.pendingRequests.delete(id);
    }

    // Notify exit handlers
    for (const handler of this.exitHandlers) {
      try {
        handler();
      } catch (e) {
        console.error('[LSP Transport] Exit handler error:', e);
      }
    }
  }

  /**
   * Notify error handlers
   */
  private notifyError(error: string): void {
    for (const handler of this.errorHandlers) {
      try {
        handler(error);
      } catch (e) {
        console.error('[LSP Transport] Error handler error:', e);
      }
    }
  }

  // ============================================================
  // Health Monitoring Methods
  // ============================================================

  /**
   * Start periodic health monitoring
   */
  private startHealthMonitoring(): void {
    if (!this.healthConfig.enabled) {
      this.updateHealthStatus({
        healthy: true,
        message: 'Health monitoring disabled',
      });
      return;
    }

    // Clear any existing timer
    this.stopHealthMonitoring();

    // Update initial status
    this.updateHealthStatus({
      healthy: true,
      lastResponseAt: Date.now(),
      consecutiveFailures: 0,
      message: 'Server started',
    });

    // Start periodic health checks
    this.healthCheckTimer = setInterval(() => {
      this.performHealthCheck();
    }, this.healthConfig.intervalMs);

    console.log(`[LSP Health] Started monitoring for ${this.serverId} (interval: ${this.healthConfig.intervalMs}ms)`);
  }

  /**
   * Stop health monitoring
   */
  private stopHealthMonitoring(): void {
    if (this.healthCheckTimer) {
      clearInterval(this.healthCheckTimer);
      this.healthCheckTimer = null;
    }
  }

  /**
   * Perform a single health check
   */
  private async performHealthCheck(): Promise<void> {
    if (!this.isConnected) {
      this.updateHealthStatus({
        healthy: false,
        consecutiveFailures: this.healthStatus.consecutiveFailures + 1,
        lastCheckAt: Date.now(),
        message: 'Server disconnected',
      });
      return;
    }

    const startTime = Date.now();

    try {
      // Use a simple request that most LSP servers support
      // We use $/cancelRequest with an invalid ID which should return quickly
      // or textDocument/hover with null params (will error but confirms server is alive)
      await this.sendHealthPing();

      // Success - record response time
      const responseTime = Date.now() - startTime;
      this.recordResponseTime(responseTime);

      this.updateHealthStatus({
        healthy: true,
        lastResponseAt: Date.now(),
        consecutiveFailures: 0,
        lastCheckAt: Date.now(),
        avgResponseTimeMs: this.calculateAvgResponseTime(),
        message: `Healthy (${responseTime}ms)`,
      });

    } catch (error) {
      const failures = this.healthStatus.consecutiveFailures + 1;
      const isUnhealthy = failures >= this.healthConfig.failureThreshold;
      const wasHealthy = this.healthStatus.healthy;

      this.updateHealthStatus({
        healthy: !isUnhealthy,
        consecutiveFailures: failures,
        lastCheckAt: Date.now(),
        message: isUnhealthy
          ? `Unhealthy: ${failures} consecutive failures`
          : `Warning: ${failures}/${this.healthConfig.failureThreshold} failures`,
      });

      // Only log on state transition (healthy → unhealthy) to reduce noise
      if (wasHealthy && isUnhealthy) {
        console.warn(`[LSP Health] ${this.serverId} became unhealthy after ${failures} failures`);
      }

      // Stop monitoring once threshold is reached (no infinite loop)
      if (isUnhealthy) {
        console.log(`[LSP Health] Stopping monitoring for ${this.serverId} (unhealthy)`);
        this.stopHealthMonitoring();

        // Auto-restart if configured
        if (this.healthConfig.autoRestart) {
          console.log(`[LSP Health] Auto-restarting unhealthy server: ${this.serverId}`);
          this.notifyError(`Server unhealthy, attempting restart...`);
          await this.restartFromSavedConfig();
        }
      }
    }
  }

  /**
   * Send a health ping to the server
   * Uses backend process-level liveness check to avoid false negatives from
   * language-specific request errors (e.g. unsupported workspace/symbol).
   */
  private async sendHealthPing(): Promise<void> {
    const running = await invoke<boolean>('lsp_is_server_running', {
      serverId: this.serverId,
    });
    if (!running) {
      throw new Error(`LSP server not running: ${this.serverId}`);
    }
  }

  /**
   * Record a response time for average calculation
   */
  private recordResponseTime(timeMs: number): void {
    this.responseTimes.push(timeMs);
    // Keep only the last N response times.
    if (this.responseTimes.length > LspTransport.RESPONSE_TIME_WINDOW) {
      this.responseTimes.shift();
    }
  }

  /**
   * Calculate average response time from recorded times
   */
  private calculateAvgResponseTime(): number | null {
    if (this.responseTimes.length === 0) return null;
    const sum = this.responseTimes.reduce((a, b) => a + b, 0);
    return Math.round(sum / this.responseTimes.length);
  }

  /**
   * Update health status and notify handlers
   */
  private updateHealthStatus(partial: Partial<HealthStatus>): void {
    const previousHealthy = this.healthStatus.healthy;
    const hadPreviousCheck = this.healthStatus.lastCheckAt !== null;
    this.healthStatus = { ...this.healthStatus, ...partial };

    // Notify on health transitions and first completed check.
    const healthChanged = previousHealthy !== this.healthStatus.healthy;
    const isFirstCheck = !hadPreviousCheck && this.healthStatus.lastCheckAt !== null;

    if (healthChanged || isFirstCheck) {
      for (const handler of this.healthHandlers) {
        try {
          handler(this.health);
        } catch (e) {
          console.error('[LSP Transport] Health handler error:', e);
        }
      }
    }
  }

  /**
   * Manually trigger a health check (useful for testing or on-demand verification)
   */
  async checkHealth(): Promise < HealthStatus > {
  await this.performHealthCheck();
  return this.health;
}

/**
 * Update health configuration at runtime
 */
configureHealth(config: HealthConfig): void {
  this.healthConfig = { ...this.healthConfig, ...config };

  // Restart monitoring if enabled state changed
  if(this.isConnected) {
  this.stopHealthMonitoring();
  if (this.healthConfig.enabled) {
    this.startHealthMonitoring();
  }
}
  }

  /**
   * Send a JSON-RPC request and wait for response
   */
  async sendRequest < T = unknown > (method: string, params ?: unknown): Promise < T > {
    return this.sendRequestWithTimeout<T>(method, params);
  }

  private async sendRequestWithTimeout<T = unknown>(
    method: string,
    params?: unknown,
    timeoutMs?: number
  ): Promise<T> {
    if (!this.isConnected) {
      throw new Error('Transport not connected');
    }

    const id = this.nextRequestId++;
    const request: JsonRpcRequest = {
      jsonrpc: '2.0',
      id,
      method,
      params,
    };

    // Create promise for the response
    const responsePromise = new Promise<T>((resolve, reject) => {
      this.pendingRequests.set(id, {
        resolve: resolve as (result: unknown) => void,
        reject,
        method,
        timestamp: Date.now(),
      });
    });

    // Send the request
    const message = JSON.stringify(request);
    try {
      await invoke('lsp_send_message', {
        serverId: this.serverId,
        message,
      });
    } catch (error) {
      this.pendingRequests.delete(id);
      throw error;
    }

    if (!timeoutMs || timeoutMs <= 0) {
      return responsePromise;
    }

    return new Promise<T>((resolve, reject) => {
      const timeoutId = setTimeout(() => {
        this.pendingRequests.delete(id);
        reject(new Error(`LSP request timed out: ${method}`));
      }, timeoutMs);

      responsePromise
        .then((value) => {
          clearTimeout(timeoutId);
          resolve(value);
        })
        .catch((error) => {
          clearTimeout(timeoutId);
          reject(error);
        });
    });
  }

  /**
   * Send a JSON-RPC notification (no response expected)
   */
  async sendNotification(method: string, params ?: unknown): Promise < void> {
  if(!this.isConnected) {
  throw new Error('Transport not connected');
}

const notification: JsonRpcNotification = {
  jsonrpc: '2.0',
  method,
  params,
};

const message = JSON.stringify(notification);
await invoke('lsp_send_message', {
  serverId: this.serverId,
  message,
});
  }

  /**
   * Send a JSON-RPC response to a server request
   */
  async sendResponse(id: number | string, result: unknown): Promise < void> {
  if(!this.isConnected) {
  throw new Error('Transport not connected');
}

const response: JsonRpcResponse = {
  jsonrpc: '2.0',
  id,
  result,
};

const message = JSON.stringify(response);
await invoke('lsp_send_message', {
  serverId: this.serverId,
  message,
});
  }

/**
 * Register a message handler
 */
onMessage(handler: MessageHandler): () => void {
  this.messageHandlers.add(handler);
  return() => this.messageHandlers.delete(handler);
}

/**
 * Register an error handler
 */
onError(handler: ErrorHandler): () => void {
  this.errorHandlers.add(handler);
  return() => this.errorHandlers.delete(handler);
}

/**
 * Register an exit handler
 */
onExit(handler: ExitHandler): () => void {
  this.exitHandlers.add(handler);
  return() => this.exitHandlers.delete(handler);
}

/**
 * Register a health status change handler
 */
onHealth(handler: HealthHandler): () => void {
  this.healthHandlers.add(handler);
  return() => this.healthHandlers.delete(handler);
}

  /**
   * Stop the server and clean up
   */
  async stop(): Promise < void> {
  // Stop health monitoring first
  this.stopHealthMonitoring();

  // Remove all event listeners
  for(const unlisten of this.unlisteners) {
  unlisten();
}
this.unlisteners = [];

// Stop the server
if (this.isConnected) {
  try {
    await invoke('lsp_stop_server', { serverId: this.serverId });
  } catch (e) {
    console.error('[LSP Transport] Error stopping server:', e);
  }
}

this.isConnected = false;
this.messageHandlers.clear();
this.errorHandlers.clear();
this.exitHandlers.clear();
this.healthHandlers.clear();
this.pendingRequests.clear();
this.responseTimes = [];
  }

  private async restartFromSavedConfig(): Promise<void> {
    if (this.isRestarting || !this.startMode || !this.startConfig) {
      return;
    }

    this.isRestarting = true;
    const messageHandlers = new Set(this.messageHandlers);
    const errorHandlers = new Set(this.errorHandlers);
    const exitHandlers = new Set(this.exitHandlers);
    const healthHandlers = new Set(this.healthHandlers);

    try {
      await this.stop();
      this.messageHandlers = messageHandlers;
      this.errorHandlers = errorHandlers;
      this.exitHandlers = exitHandlers;
      this.healthHandlers = healthHandlers;

      if (this.startMode === 'sidecar') {
        await this.start(this.startConfig as Omit<LspServerConfig, 'serverId' | 'serverType'>);
      } else {
        await this.startExternal(this.startConfig as Omit<ExternalLspConfig, 'serverId' | 'serverType'>);
      }
    } catch (error) {
      this.notifyError(`Failed to auto-restart server: ${String(error)}`);
    } finally {
      this.isRestarting = false;
    }
  }

/**
 * Dispose the transport (alias for stop)
 */
dispose(): Promise < void> {
  return this.stop();
}
}

/**
 * Create a new LSP transport for a server
 * @param serverId - Unique identifier for the server
 * @param serverType - Type of server (e.g., 'typescript', 'dart')
 * @param healthConfig - Optional health monitoring configuration
 */
export function createTransport(
  serverId: string,
  serverType: string,
  healthConfig?: HealthConfig
): LspTransport {
  return new LspTransport(serverId, serverType, healthConfig);
}

/**
 * List all running LSP servers
 */
export async function listServers(): Promise<LspServerInfo[]> {
  return invoke<LspServerInfo[]>('lsp_list_servers');
}

/**
 * Get info about a specific server
 */
export async function getServerInfo(serverId: string): Promise<LspServerInfo> {
  return invoke<LspServerInfo>('lsp_get_server_info', { serverId });
}

/**
 * Check if a server is running
 */
export async function isServerRunning(serverId: string): Promise<boolean> {
  return invoke<boolean>('lsp_is_server_running', { serverId });
}

/**
 * Stop all running servers
 */
export async function stopAllServers(): Promise<void> {
  return invoke('lsp_stop_all');
}

/**
 * Svelte Monaco Providers
 * 
 * Registers Monaco language providers that use the Svelte LSP sidecar
 * for completions, hover, definition, and other features.
 * 
 * This provides VS Code-level Svelte intelligence by using the real
 * svelte-language-server.
 */

import type * as Monaco from 'monaco-editor';
import { getMonaco } from '$core/services/monaco-loader';
import { editorStore } from '$features/editor/stores/editor.svelte';
import {
  getSvelteCompletions,
  getSvelteHover,
  getSvelteDefinition,
  getSvelteReferences,
  getSvelteSignatureHelp,
  isSvelteLspInitialized,
  type CompletionItem as LspCompletionItem,
  type HoverResult,
  type Location,
  type SignatureHelp
} from './svelte-sidecar';

// Track registered providers for cleanup
const registeredDisposables: Monaco.IDisposable[] = [];

// Svelte language ID
const SVELTE_LANGUAGE = 'svelte';

/**
 * Convert file path from Monaco model URI
 */
function getFilePathFromModel(model: Monaco.editor.ITextModel): string {
  const uri = model.uri;
  // Our URIs are in format: inmemory://model/{encodedPath}
  const path = uri.path;
  if (path.startsWith('/')) {
    return decodeURIComponent(path.slice(1));
  }
  return decodeURIComponent(path);
}

/**
 * Map LSP completion kind to Monaco completion kind
 */
function mapCompletionKind(monaco: typeof Monaco, lspKind?: number): Monaco.languages.CompletionItemKind {
  if (!lspKind) return monaco.languages.CompletionItemKind.Text;
  
  // LSP CompletionItemKind values
  const kindMap: Record<number, Monaco.languages.CompletionItemKind> = {
    1: monaco.languages.CompletionItemKind.Text,
    2: monaco.languages.CompletionItemKind.Method,
    3: monaco.languages.CompletionItemKind.Function,
    4: monaco.languages.CompletionItemKind.Constructor,
    5: monaco.languages.CompletionItemKind.Field,
    6: monaco.languages.CompletionItemKind.Variable,
    7: monaco.languages.CompletionItemKind.Class,
    8: monaco.languages.CompletionItemKind.Interface,
    9: monaco.languages.CompletionItemKind.Module,
    10: monaco.languages.CompletionItemKind.Property,
    11: monaco.languages.CompletionItemKind.Unit,
    12: monaco.languages.CompletionItemKind.Value,
    13: monaco.languages.CompletionItemKind.Enum,
    14: monaco.languages.CompletionItemKind.Keyword,
    15: monaco.languages.CompletionItemKind.Snippet,
    16: monaco.languages.CompletionItemKind.Color,
    17: monaco.languages.CompletionItemKind.File,
    18: monaco.languages.CompletionItemKind.Reference,
    19: monaco.languages.CompletionItemKind.Folder,
    20: monaco.languages.CompletionItemKind.EnumMember,
    21: monaco.languages.CompletionItemKind.Constant,
    22: monaco.languages.CompletionItemKind.Struct,
    23: monaco.languages.CompletionItemKind.Event,
    24: monaco.languages.CompletionItemKind.Operator,
    25: monaco.languages.CompletionItemKind.TypeParameter
  };
  
  return kindMap[lspKind] ?? monaco.languages.CompletionItemKind.Text;
}

/**
 * Convert LSP completion item to Monaco completion item
 */
function convertCompletionItem(
  monaco: typeof Monaco,
  item: LspCompletionItem,
  range: Monaco.IRange
): Monaco.languages.CompletionItem {
  let documentation: Monaco.languages.CompletionItem['documentation'];
  if (item.documentation) {
    if (typeof item.documentation === 'string') {
      documentation = item.documentation;
    } else if (item.documentation.kind === 'markdown') {
      documentation = { value: item.documentation.value };
    } else {
      documentation = item.documentation.value;
    }
  }

  return {
    label: item.label,
    kind: mapCompletionKind(monaco, item.kind),
    detail: item.detail,
    documentation,
    insertText: item.insertText || item.label,
    insertTextRules: item.insertTextFormat === 2 
      ? monaco.languages.CompletionItemInsertTextRule.InsertAsSnippet 
      : undefined,
    range
  };
}

/**
 * Convert LSP hover to Monaco hover
 */
function convertHover(
  _monaco: typeof Monaco,
  hover: HoverResult
): Monaco.languages.Hover {
  const contents: Monaco.IMarkdownString[] = [];
  
  if (typeof hover.contents === 'string') {
    contents.push({ value: hover.contents });
  } else if (Array.isArray(hover.contents)) {
    for (const content of hover.contents) {
      if (typeof content === 'string') {
        contents.push({ value: content });
      } else {
        contents.push({ value: content.value });
      }
    }
  } else {
    contents.push({ value: hover.contents.value });
  }
  
  let range: Monaco.IRange | undefined;
  if (hover.range) {
    range = {
      startLineNumber: hover.range.start.line + 1,
      startColumn: hover.range.start.character + 1,
      endLineNumber: hover.range.end.line + 1,
      endColumn: hover.range.end.character + 1
    };
  }
  
  return { contents, range };
}

/**
 * Convert LSP file:// URI to file path
 */
function lspUriToFilePath(uri: string): string {
  let path = uri.replace('file://', '');
  // Handle Windows paths (file:///C:/...)
  if (path.match(/^\/[a-zA-Z]:/)) {
    path = path.slice(1);
  }
  // Normalize to forward slashes for consistency
  return path.replace(/\\/g, '/');
}

/**
 * Convert file path to our inmemory:// URI scheme
 * This matches the URI scheme used in monaco-models.ts
 */
function filePathToMonacoUri(monaco: typeof Monaco, filepath: string): Monaco.Uri {
  // Normalize path separators
  const normalizedPath = filepath.replace(/\\/g, '/');
  return monaco.Uri.parse(`inmemory://model/${encodeURIComponent(normalizedPath)}`);
}

/**
 * Convert LSP location to Monaco location
 * Uses our inmemory:// URI scheme so Monaco can navigate to the location
 */
function convertLocation(
  monaco: typeof Monaco,
  location: Location
): Monaco.languages.Location {
  const filepath = lspUriToFilePath(location.uri);
  
  return {
    uri: filePathToMonacoUri(monaco, filepath),
    range: {
      startLineNumber: location.range.start.line + 1,
      startColumn: location.range.start.character + 1,
      endLineNumber: location.range.end.line + 1,
      endColumn: location.range.end.character + 1
    }
  };
}

/**
 * Create completion provider for Svelte sidecar
 */
function createCompletionProvider(monaco: typeof Monaco): Monaco.languages.CompletionItemProvider {
  return {
    triggerCharacters: ['.', '"', "'", '/', '<', ':', '@', '$', '{'],
    
    async provideCompletionItems(
      model: Monaco.editor.ITextModel,
      position: Monaco.Position,
      _context: Monaco.languages.CompletionContext,
      _token: Monaco.CancellationToken
    ): Promise<Monaco.languages.CompletionList | null> {
      if (!isSvelteLspInitialized()) {
        return null;
      }
      
      const filepath = getFilePathFromModel(model);
      const line = position.lineNumber - 1; // LSP is 0-based
      const character = position.column - 1;
      
      const items = await getSvelteCompletions(filepath, line, character);
      if (!items || items.length === 0) {
        return null;
      }
      
      // Get word range for replacement
      const word = model.getWordUntilPosition(position);
      const range: Monaco.IRange = {
        startLineNumber: position.lineNumber,
        startColumn: word.startColumn,
        endLineNumber: position.lineNumber,
        endColumn: word.endColumn
      };
      
      const suggestions = items.map(item => convertCompletionItem(monaco, item, range));
      
      return {
        suggestions,
        incomplete: false
      };
    }
  };
}

/**
 * Create hover provider for Svelte sidecar
 */
function createHoverProvider(monaco: typeof Monaco): Monaco.languages.HoverProvider {
  return {
    async provideHover(
      model: Monaco.editor.ITextModel,
      position: Monaco.Position,
      _token: Monaco.CancellationToken
    ): Promise<Monaco.languages.Hover | null> {
      if (!isSvelteLspInitialized()) {
        return null;
      }
      
      const filepath = getFilePathFromModel(model);
      const line = position.lineNumber - 1;
      const character = position.column - 1;
      
      const hover = await getSvelteHover(filepath, line, character);
      if (!hover) {
        return null;
      }
      
      return convertHover(monaco, hover);
    }
  };
}

/**
 * Create definition provider for Svelte sidecar
 */
function createDefinitionProvider(monaco: typeof Monaco): Monaco.languages.DefinitionProvider {
  return {
    async provideDefinition(
      model: Monaco.editor.ITextModel,
      position: Monaco.Position,
      _token: Monaco.CancellationToken
    ): Promise<Monaco.languages.Definition | null> {
      if (!isSvelteLspInitialized()) {
        return null;
      }
      
      const filepath = getFilePathFromModel(model);
      const line = position.lineNumber - 1;
      const character = position.column - 1;
      
      const locations = await getSvelteDefinition(filepath, line, character);
      if (!locations || locations.length === 0) {
        return null;
      }
      
      return locations.map(loc => convertLocation(monaco, loc));
    }
  };
}

/**
 * Create references provider for Svelte sidecar
 */
function createReferencesProvider(monaco: typeof Monaco): Monaco.languages.ReferenceProvider {
  return {
    async provideReferences(
      model: Monaco.editor.ITextModel,
      position: Monaco.Position,
      context: Monaco.languages.ReferenceContext,
      _token: Monaco.CancellationToken
    ): Promise<Monaco.languages.Location[] | null> {
      if (!isSvelteLspInitialized()) {
        return null;
      }
      
      const filepath = getFilePathFromModel(model);
      const line = position.lineNumber - 1;
      const character = position.column - 1;
      
      const locations = await getSvelteReferences(filepath, line, character, context.includeDeclaration);
      if (!locations || locations.length === 0) {
        return null;
      }
      
      return locations.map(loc => convertLocation(monaco, loc));
    }
  };
}

/**
 * Create signature help provider for Svelte sidecar
 */
function createSignatureHelpProvider(monaco: typeof Monaco): Monaco.languages.SignatureHelpProvider {
  return {
    signatureHelpTriggerCharacters: ['(', ','],
    signatureHelpRetriggerCharacters: [','],
    
    async provideSignatureHelp(
      model: Monaco.editor.ITextModel,
      position: Monaco.Position,
      _token: Monaco.CancellationToken,
      _context: Monaco.languages.SignatureHelpContext
    ): Promise<Monaco.languages.SignatureHelpResult | null> {
      if (!isSvelteLspInitialized()) {
        return null;
      }
      
      const filepath = getFilePathFromModel(model);
      const line = position.lineNumber - 1;
      const character = position.column - 1;
      
      const help = await getSvelteSignatureHelp(filepath, line, character);
      if (!help || help.signatures.length === 0) {
        return null;
      }
      
      const signatures: Monaco.languages.SignatureInformation[] = help.signatures.map(sig => {
        let documentation: string | Monaco.IMarkdownString | undefined;
        if (sig.documentation) {
          if (typeof sig.documentation === 'string') {
            documentation = sig.documentation;
          } else {
            documentation = { value: sig.documentation.value };
          }
        }
        
        const parameters: Monaco.languages.ParameterInformation[] = (sig.parameters || []).map(param => {
          let paramDoc: string | Monaco.IMarkdownString | undefined;
          if (param.documentation) {
            if (typeof param.documentation === 'string') {
              paramDoc = param.documentation;
            } else {
              paramDoc = { value: param.documentation.value };
            }
          }
          
          return {
            label: Array.isArray(param.label) ? param.label : param.label,
            documentation: paramDoc
          };
        });
        
        return {
          label: sig.label,
          documentation,
          parameters
        };
      });
      
      return {
        value: {
          signatures,
          activeSignature: help.activeSignature ?? 0,
          activeParameter: help.activeParameter ?? 0
        },
        dispose: () => {}
      };
    }
  };
}

/**
 * Register an editor opener to handle go-to-definition navigation for Svelte files
 * This opens files in the editor when Monaco tries to navigate to a location
 */
function registerEditorOpener(monaco: typeof Monaco): void {
  const openerDisposable = monaco.editor.registerEditorOpener({
    async openCodeEditor(
      _source: Monaco.editor.ICodeEditor,
      resource: Monaco.Uri,
      selectionOrPosition?: Monaco.IRange | Monaco.IPosition
    ): Promise<boolean> {
      // Extract file path from our inmemory:// URI
      // Format: inmemory://model/{encodedPath}
      if (resource.scheme === 'inmemory' && resource.authority === 'model') {
        const filepath = decodeURIComponent(resource.path.slice(1)); // Remove leading /
        
        // Open the file in the editor
        const opened = await editorStore.openFile(filepath);
        if (!opened) {
          console.warn('[Svelte Monaco Providers] Failed to open file:', filepath);
          return false;
        }
        
        // Navigate to the position after a short delay to let the editor load
        if (selectionOrPosition) {
          setTimeout(() => {
            const line = 'startLineNumber' in selectionOrPosition 
              ? selectionOrPosition.startLineNumber 
              : selectionOrPosition.lineNumber;
            const column = 'startColumn' in selectionOrPosition 
              ? selectionOrPosition.startColumn 
              : selectionOrPosition.column;
            
            // Dispatch navigation event for the editor to handle
            window.dispatchEvent(new CustomEvent('volt:navigate-to-position', {
              detail: { file: filepath, line, column }
            }));
          }, 100);
        }
        
        // Return true to indicate we handled the navigation
        return true;
      }
      
      // For other URI schemes, return false to let Monaco handle it
      return false;
    }
  });
  
  registeredDisposables.push(openerDisposable);
  console.log('[Svelte Monaco Providers] Registered editor opener for go-to-definition');
}

/**
 * Register all Svelte Monaco providers
 * Should be called after Monaco is loaded and Svelte LSP is initialized
 */
export function registerSvelteMonacoProviders(): void {
  const monaco = getMonaco();
  if (!monaco) {
    console.warn('[Svelte Monaco Providers] Monaco not loaded');
    return;
  }
  
  // Register editor opener for go-to-definition navigation
  registerEditorOpener(monaco);
  
  // Completion provider
  const completionDisposable = monaco.languages.registerCompletionItemProvider(
    SVELTE_LANGUAGE,
    createCompletionProvider(monaco)
  );
  registeredDisposables.push(completionDisposable);
  
  // Hover provider
  const hoverDisposable = monaco.languages.registerHoverProvider(
    SVELTE_LANGUAGE,
    createHoverProvider(monaco)
  );
  registeredDisposables.push(hoverDisposable);
  
  // Definition provider
  const definitionDisposable = monaco.languages.registerDefinitionProvider(
    SVELTE_LANGUAGE,
    createDefinitionProvider(monaco)
  );
  registeredDisposables.push(definitionDisposable);
  
  // References provider
  const referencesDisposable = monaco.languages.registerReferenceProvider(
    SVELTE_LANGUAGE,
    createReferencesProvider(monaco)
  );
  registeredDisposables.push(referencesDisposable);
  
  // Signature help provider
  const signatureDisposable = monaco.languages.registerSignatureHelpProvider(
    SVELTE_LANGUAGE,
    createSignatureHelpProvider(monaco)
  );
  registeredDisposables.push(signatureDisposable);
  
  console.log('[Svelte Monaco Providers] Registered providers for:', SVELTE_LANGUAGE);
}

/**
 * Dispose all registered providers
 */
export function disposeSvelteMonacoProviders(): void {
  for (const disposable of registeredDisposables) {
    disposable.dispose();
  }
  registeredDisposables.length = 0;
  console.log('[Svelte Monaco Providers] Disposed all providers');
}

/**
 * Svelte LSP Sidecar Service
 * 
 * Provides full Svelte language intelligence using the real svelte-language-server:
 * - Diagnostics (errors, warnings)
 * - Completions (components, props, runes)
 * - Hover information
 * - Go to definition
 * - Find references
 * 
 * Strategy:
 * - Start server when opening a .svelte file in a project
 * - Workspace root = projectStore.rootPath
 * - Must respect workspace svelte.config.js
 */

import { getLspRegistry, type LspTransport, type JsonRpcMessage } from './sidecar';
import { problemsStore, type Problem } from '$shared/stores/problems.svelte';
import { projectStore } from '$shared/stores/project.svelte';
import { readFileQuiet } from '$core/services/file-system';
import { getAllFiles } from '$core/services/file-index';
import { registerSvelteMonacoProviders, disposeSvelteMonacoProviders } from './svelte-monaco-providers';
import {
  getSvelteLanguageId,
  mapSvelteSeverity,
  sveltePathToUri,
  svelteUriToPath,
} from './svelte-sidecar-utils';

// Server instance tracking
let svelteServerTransport: LspTransport | null = null;
let svelteServerInitialized = false;
let initializationPromise: Promise<void> | null = null;
let initializedRootPath: string | null = null;

// Document tracking
const openDocuments = new Map<string, { version: number; content: string }>();

// Debounce timers
const diagnosticDebounceTimers = new Map<string, ReturnType<typeof setTimeout>>();
const DIAGNOSTIC_DEBOUNCE_MS = 150;

/**
 * Check if a file is a Svelte file
 */
export function isSvelteFile(filepath: string): boolean {
  return filepath.toLowerCase().endsWith('.svelte');
}

/**
 * Handle incoming LSP messages
 */
function handleLspMessage(message: JsonRpcMessage): void {
  // Handle server requests that require a response
  if ('id' in message && 'method' in message && message.id !== null) {
    const id = message.id;
    if (message.method === 'workspace/configuration') {
      const items = (message.params as any)?.items || [];
      const result = items.map(() => ({}));
      svelteServerTransport?.sendResponse(id, result);
    } else {
      svelteServerTransport?.sendResponse(id, null);
    }
    return;
  }

  // Handle notifications
  if ('method' in message && !('id' in message)) {
    if (message.method === 'textDocument/publishDiagnostics') {
      handleDiagnostics(message.params as PublishDiagnosticsParams);
    } else if (message.method === 'window/logMessage') {
      const params = message.params as { type: number; message: string };
      console.log(`[Svelte LSP] ${params.message}`);
    }
  }
}

interface Diagnostic {
  range: {
    start: { line: number; character: number };
    end: { line: number; character: number };
  };
  message: string;
  severity?: number;
  code?: number | string;
  source?: string;
}

interface PublishDiagnosticsParams {
  uri: string;
  diagnostics: Diagnostic[];
}

/**
 * Handle diagnostics from the LSP server
 */
function handleDiagnostics(params: PublishDiagnosticsParams): void {
  const filePath = svelteUriToPath(params.uri);
  const fileName = filePath.split(/[/\\]/).pop() || filePath;

  const problems: Problem[] = params.diagnostics.map((diag, index) => ({
    id: `svelte:${filePath}:${diag.range.start.line}:${diag.range.start.character}:${index}`,
    file: filePath,
    fileName,
    line: diag.range.start.line + 1, // LSP is 0-based, we use 1-based
    column: diag.range.start.character + 1,
    endLine: diag.range.end.line + 1,
    endColumn: diag.range.end.character + 1,
    message: diag.message,
    severity: mapSvelteSeverity(diag.severity ?? 1),
    source: diag.source || 'svelte',
    code: diag.code?.toString()
  }));

  problemsStore.setProblemsForFile(filePath, problems, 'svelte');
}

/**
 * Initialize the Svelte language server
 */
async function initializeServer(): Promise<void> {
  if (!projectStore.rootPath) return;

  // If the workspace root changed, the server will reject new documents.
  // Restart to re-bind to the new root.
  if (svelteServerInitialized && initializedRootPath && projectStore.rootPath !== initializedRootPath) {
    await stopSvelteLsp();
  }

  if (svelteServerInitialized) return;

  if (initializationPromise) {
    return initializationPromise;
  }

  initializationPromise = (async () => {
    try {
      const registry = getLspRegistry();

      // Start the Svelte server
      svelteServerTransport = await registry.startServer('svelte', {
        serverId: 'svelte-main',
        cwd: projectStore.rootPath ?? undefined
      });

      // Set up message handler
      svelteServerTransport.onMessage(handleLspMessage);

      // Set up error handler
      svelteServerTransport.onError((error) => {
        console.error('[Svelte LSP] Server error:', error);
      });

      // Set up exit handler
      svelteServerTransport.onExit(() => {
        console.log('[Svelte LSP] Server exited');
        svelteServerTransport = null;
        svelteServerInitialized = false;
        initializationPromise = null;
        initializedRootPath = null;
        openDocuments.clear();
      });

      // Send initialize request
      const rootUri = sveltePathToUri(projectStore.rootPath!);

      const initResult = await svelteServerTransport.sendRequest('initialize', {
        processId: null,
        rootUri,
        rootPath: projectStore.rootPath,
        capabilities: {
          textDocument: {
            synchronization: {
              dynamicRegistration: true,
              willSave: false,
              willSaveWaitUntil: false,
              didSave: true
            },
            completion: {
              dynamicRegistration: true,
              completionItem: {
                snippetSupport: true,
                commitCharactersSupport: true,
                documentationFormat: ['markdown', 'plaintext'],
                deprecatedSupport: true,
                preselectSupport: true,
                insertReplaceSupport: true,
                labelDetailsSupport: true,
                resolveSupport: {
                  properties: ['documentation', 'detail', 'additionalTextEdits']
                }
              },
              contextSupport: true
            },
            hover: {
              dynamicRegistration: true,
              contentFormat: ['markdown', 'plaintext']
            },
            signatureHelp: {
              dynamicRegistration: true,
              signatureInformation: {
                documentationFormat: ['markdown', 'plaintext'],
                parameterInformation: {
                  labelOffsetSupport: true
                }
              }
            },
            definition: {
              dynamicRegistration: true,
              linkSupport: true
            },
            references: {
              dynamicRegistration: true
            },
            documentHighlight: {
              dynamicRegistration: true
            },
            documentSymbol: {
              dynamicRegistration: true,
              hierarchicalDocumentSymbolSupport: true
            },
            codeAction: {
              dynamicRegistration: true,
              codeActionLiteralSupport: {
                codeActionKind: {
                  valueSet: [
                    'quickfix',
                    'refactor',
                    'refactor.extract',
                    'refactor.inline',
                    'refactor.rewrite',
                    'source',
                    'source.organizeImports'
                  ]
                }
              }
            },
            formatting: {
              dynamicRegistration: true
            },
            rangeFormatting: {
              dynamicRegistration: true
            },
            rename: {
              dynamicRegistration: true,
              prepareSupport: true
            },
            publishDiagnostics: {
              relatedInformation: true,
              tagSupport: {
                valueSet: [1, 2]
              },
              codeDescriptionSupport: true
            }
          },
          workspace: {
            applyEdit: true,
            workspaceEdit: {
              documentChanges: true
            },
            didChangeConfiguration: {
              dynamicRegistration: true
            },
            didChangeWatchedFiles: {
              dynamicRegistration: true
            },
            symbol: {
              dynamicRegistration: true
            },
            configuration: true,
            workspaceFolders: true
          }
        },
        workspaceFolders: [
          {
            uri: rootUri,
            name: projectStore.projectName
          }
        ],
        initializationOptions: {
          configuration: {
            svelte: {
              plugin: {
                svelte: {
                  compilerWarnings: {},
                  format: { enable: true }
                },
                css: { enable: true },
                html: { enable: true }
              }
            }
          }
        }
      });

      console.log('[Svelte LSP] Server initialized:', initResult);

      // Send initialized notification
      await svelteServerTransport.sendNotification('initialized', {});

      svelteServerInitialized = true;
      initializedRootPath = projectStore.rootPath ?? null;

      // Register Monaco providers
      registerSvelteMonacoProviders();
    } catch (error) {
      console.error('[Svelte LSP] Failed to initialize server:', error);
      svelteServerTransport = null;
      initializationPromise = null;
      throw error;
    }
  })();

  return initializationPromise;
}

/**
 * Notify the server that a document was opened
 */
export async function notifySvelteDocumentOpened(filepath: string, content: string): Promise<void> {
  if (!isSvelteFile(filepath)) return;
  if (!projectStore.rootPath) return;

  // Initialize server if needed
  await initializeServer();

  // Don't reopen if already open and content is the same
  const existing = openDocuments.get(filepath);
  if (existing && existing.content === content) return;

  if (!svelteServerTransport || !svelteServerInitialized) return;

  const uri = sveltePathToUri(filepath);
  const languageId = getSvelteLanguageId(filepath);

  // Track document
  openDocuments.set(filepath, { version: existing ? existing.version + 1 : 1, content });

  if (existing) {
    // If it's already open but content changed, send didChange instead
    await svelteServerTransport.sendNotification('textDocument/didChange', {
      textDocument: {
        uri,
        version: existing.version + 1
      },
      contentChanges: [{ text: content }]
    });
    return;
  }

  // Send didOpen notification
  await svelteServerTransport.sendNotification('textDocument/didOpen', {
    textDocument: {
      uri,
      languageId,
      version: 1,
      text: content
    }
  });
}

/**
 * Notify the server that a document was changed
 */
export async function notifySvelteDocumentChanged(filepath: string, content: string): Promise<void> {
  if (!isSvelteFile(filepath)) return;
  if (!svelteServerTransport || !svelteServerInitialized) return;

  const doc = openDocuments.get(filepath);
  if (!doc) {
    // Document wasn't opened, open it now
    await notifySvelteDocumentOpened(filepath, content);
    return;
  }

  // Update version
  doc.version++;
  doc.content = content;

  const uri = sveltePathToUri(filepath);

  // Debounce the change notification
  const existingTimer = diagnosticDebounceTimers.get(filepath);
  if (existingTimer) {
    clearTimeout(existingTimer);
  }

  diagnosticDebounceTimers.set(filepath, setTimeout(async () => {
    diagnosticDebounceTimers.delete(filepath);

    if (!svelteServerTransport || !svelteServerInitialized) return;

    // Send didChange notification with full content
    await svelteServerTransport.sendNotification('textDocument/didChange', {
      textDocument: {
        uri,
        version: doc.version
      },
      contentChanges: [{ text: content }]
    });
  }, DIAGNOSTIC_DEBOUNCE_MS));
}

/**
 * Notify the server that a document was saved
 */
export async function notifySvelteDocumentSaved(filepath: string, content: string): Promise<void> {
  if (!isSvelteFile(filepath)) return;
  if (!svelteServerTransport || !svelteServerInitialized) return;

  const uri = sveltePathToUri(filepath);

  await svelteServerTransport.sendNotification('textDocument/didSave', {
    textDocument: { uri },
    text: content
  });
}

/**
 * Notify the server that a document was closed
 */
export async function notifySvelteDocumentClosed(filepath: string): Promise<void> {
  if (!isSvelteFile(filepath)) return;
  if (!svelteServerTransport || !svelteServerInitialized) return;

  openDocuments.delete(filepath);

  const uri = sveltePathToUri(filepath);

  await svelteServerTransport.sendNotification('textDocument/didClose', {
    textDocument: { uri }
  });

  // Clear Svelte problems for this file
  problemsStore.clearProblemsForFile(filepath, 'svelte');
}

/**
 * Request completions at a position
 */
export async function getSvelteCompletions(
  filepath: string,
  line: number,
  character: number
): Promise<CompletionItem[] | null> {
  if (!isSvelteFile(filepath)) return null;
  if (!svelteServerTransport || !svelteServerInitialized) return null;

  const uri = sveltePathToUri(filepath);

  try {
    const result = await svelteServerTransport.sendRequest<CompletionList | CompletionItem[] | null>(
      'textDocument/completion',
      {
        textDocument: { uri },
        position: { line, character }
      }
    );

    if (!result) return null;

    // Handle both CompletionList and CompletionItem[] responses
    if (Array.isArray(result)) {
      return result;
    }
    return result.items || [];
  } catch (error) {
    console.error('[Svelte LSP] Completion error:', error);
    return null;
  }
}

