/**
 * Convert file path from Monaco model URI
 */
function getFilePathFromModel(model: Monaco.editor.ITextModel): string {
  const uri = model.uri;
  // Our URIs are in format: inmemory://model/{encodedPath}
  const path = uri.path;
  if (path.startsWith('/')) {
    return decodeURIComponent(path.slice(1));
  }
  return decodeURIComponent(path);
}


/**
 * Map LSP completion kind to Monaco completion kind
 */
function mapCompletionKind(monaco: typeof Monaco, lspKind?: number): Monaco.languages.CompletionItemKind {
  if (!lspKind) return monaco.languages.CompletionItemKind.Value;
  
  // LSP CompletionItemKind values
  const kindMap: Record<number, Monaco.languages.CompletionItemKind> = {
    1: monaco.languages.CompletionItemKind.Text,
    2: monaco.languages.CompletionItemKind.Method,
    3: monaco.languages.CompletionItemKind.Function,
    4: monaco.languages.CompletionItemKind.Constructor,
    5: monaco.languages.CompletionItemKind.Field,
    6: monaco.languages.CompletionItemKind.Variable,
    7: monaco.languages.CompletionItemKind.Class,
    8: monaco.languages.CompletionItemKind.Interface,
    9: monaco.languages.CompletionItemKind.Module,
    10: monaco.languages.CompletionItemKind.Property,
    11: monaco.languages.CompletionItemKind.Unit,
    12: monaco.languages.CompletionItemKind.Value,
    13: monaco.languages.CompletionItemKind.Enum,
    14: monaco.languages.CompletionItemKind.Keyword,
    15: monaco.languages.CompletionItemKind.Snippet,
    16: monaco.languages.CompletionItemKind.Color,
    17: monaco.languages.CompletionItemKind.File,
    18: monaco.languages.CompletionItemKind.Reference,
    19: monaco.languages.CompletionItemKind.Folder,
    20: monaco.languages.CompletionItemKind.EnumMember,
    21: monaco.languages.CompletionItemKind.Constant,
    22: monaco.languages.CompletionItemKind.Struct,
    23: monaco.languages.CompletionItemKind.Event,
    24: monaco.languages.CompletionItemKind.Operator,
    25: monaco.languages.CompletionItemKind.TypeParameter
  };
  
  return kindMap[lspKind] ?? monaco.languages.CompletionItemKind.Value;
}

/**
 * Convert LSP completion item to Monaco completion item
 */
function convertCompletionItem(
  monaco: typeof Monaco,
  item: LspCompletionItem,
  range: Monaco.IRange
): Monaco.languages.CompletionItem {
  let documentation: Monaco.languages.CompletionItem['documentation'];
  if (item.documentation) {
    if (typeof item.documentation === 'string') {
      documentation = item.documentation;
    } else if (item.documentation.kind === 'markdown') {
      documentation = { value: item.documentation.value };
    } else {
      documentation = item.documentation.value;
    }
  }

  // Handle text edit if present
  let insertText = item.insertText || item.label;
  let itemRange = range;
  
  if (item.textEdit) {
    insertText = item.textEdit.newText;
    itemRange = {
      startLineNumber: item.textEdit.range.start.line + 1,
      startColumn: item.textEdit.range.start.character + 1,
      endLineNumber: item.textEdit.range.end.line + 1,
      endColumn: item.textEdit.range.end.character + 1
    };
  }

  return {
    label: item.label,
    kind: mapCompletionKind(monaco, item.kind),
    detail: item.detail,
    documentation,
    insertText,
    insertTextRules: item.insertTextFormat === 2 
      ? monaco.languages.CompletionItemInsertTextRule.InsertAsSnippet 
      : undefined,
    range: itemRange,
    sortText: item.sortText,
    filterText: item.filterText
  };
}

/**
 * Convert LSP hover to Monaco hover
 */
function convertHover(
  hover: HoverResult
): Monaco.languages.Hover {
  const contents: Monaco.IMarkdownString[] = [];
  
  if (typeof hover.contents === 'string') {
    contents.push({ value: hover.contents });
  } else if (Array.isArray(hover.contents)) {
    for (const content of hover.contents) {
      if (typeof content === 'string') {
        contents.push({ value: content });
      } else {
        contents.push({ value: content.value });
      }
    }
  } else {
    contents.push({ value: hover.contents.value });
  }
  
  let range: Monaco.IRange | undefined;
  if (hover.range) {
    range = {
      startLineNumber: hover.range.start.line + 1,
      startColumn: hover.range.start.character + 1,
      endLineNumber: hover.range.end.line + 1,
      endColumn: hover.range.end.character + 1
    };
  }
  
  return { contents, range };
}


/**
 * Create completion provider for Tailwind sidecar
 */
function createCompletionProvider(monaco: typeof Monaco): Monaco.languages.CompletionItemProvider {
  return {
    // Trigger on common Tailwind class contexts
    triggerCharacters: ['"', "'", ' ', ':', '-', '[', '/'],
    
    async provideCompletionItems(
      model: Monaco.editor.ITextModel,
      position: Monaco.Position,
      _context: Monaco.languages.CompletionContext,
      _token: Monaco.CancellationToken
    ): Promise<Monaco.languages.CompletionList | null> {
      if (!isTailwindLspInitialized()) {
        return null;
      }
      
      const filepath = getFilePathFromModel(model);
      const line = position.lineNumber - 1; // LSP is 0-based
      const character = position.column - 1;
      
      const items = await getTailwindCompletions(filepath, line, character);
      if (!items || items.length === 0) {
        return null;
      }
      
      // Get word range for replacement
      const word = model.getWordUntilPosition(position);
      const range: Monaco.IRange = {
        startLineNumber: position.lineNumber,
        startColumn: word.startColumn,
        endLineNumber: position.lineNumber,
        endColumn: word.endColumn
      };
      
      const suggestions = items.map(item => convertCompletionItem(monaco, item, range));
      
      return {
        suggestions,
        incomplete: true // Tailwind has many classes, mark as incomplete for better UX
      };
    }
  };
}

/**
 * Create hover provider for Tailwind sidecar
 */
function createHoverProvider(): Monaco.languages.HoverProvider {
  return {
    async provideHover(
      model: Monaco.editor.ITextModel,
      position: Monaco.Position,
      _token: Monaco.CancellationToken
    ): Promise<Monaco.languages.Hover | null> {
      if (!isTailwindLspInitialized()) {
        return null;
      }
      
      const filepath = getFilePathFromModel(model);
      const line = position.lineNumber - 1;
      const character = position.column - 1;
      
      const hover = await getTailwindHover(filepath, line, character);
      if (!hover) {
        return null;
      }
      
      return convertHover(hover);
    }
  };
}

/**
 * Create color provider for Tailwind sidecar
 */
function createColorProvider(monaco: typeof Monaco): Monaco.languages.DocumentColorProvider {
  return {
    async provideDocumentColors(
      model: Monaco.editor.ITextModel,
      _token: Monaco.CancellationToken
    ): Promise<Monaco.languages.IColorInformation[] | null> {
      if (!isTailwindLspInitialized()) {
        return null;
      }
      
      const filepath = getFilePathFromModel(model);
      const colors = await getTailwindDocumentColors(filepath);
      
      if (!colors || colors.length === 0) {
        return null;
      }
      
      return colors.map((colorInfo: ColorInformation) => ({
        color: {
          red: colorInfo.color.red,
          green: colorInfo.color.green,
          blue: colorInfo.color.blue,
          alpha: colorInfo.color.alpha
        },
        range: {
          startLineNumber: colorInfo.range.start.line + 1,
          startColumn: colorInfo.range.start.character + 1,
          endLineNumber: colorInfo.range.end.line + 1,
          endColumn: colorInfo.range.end.character + 1
        }
      }));
    },
    
    async provideColorPresentations(
      model: Monaco.editor.ITextModel,
      colorInfo: Monaco.languages.IColorInformation,
      _token: Monaco.CancellationToken
    ): Promise<Monaco.languages.IColorPresentation[] | null> {
      if (!isTailwindLspInitialized()) {
        return null;
      }
      
      const filepath = getFilePathFromModel(model);
      const presentations = await getTailwindColorPresentations(
        filepath,
        {
          red: colorInfo.color.red,
          green: colorInfo.color.green,
          blue: colorInfo.color.blue,
          alpha: colorInfo.color.alpha
        },
        {
          start: {
            line: colorInfo.range.startLineNumber - 1,
            character: colorInfo.range.startColumn - 1
          },
          end: {
            line: colorInfo.range.endLineNumber - 1,
            character: colorInfo.range.endColumn - 1
          }
        }
      );
      
      if (!presentations || presentations.length === 0) {
        return null;
      }
      
      return presentations.map((pres: ColorPresentation) => {
        const result: Monaco.languages.IColorPresentation = {
          label: pres.label
        };
        
        if (pres.textEdit) {
          result.textEdit = {
            range: {
              startLineNumber: pres.textEdit.range.start.line + 1,
              startColumn: pres.textEdit.range.start.character + 1,
              endLineNumber: pres.textEdit.range.end.line + 1,
              endColumn: pres.textEdit.range.end.character + 1
            },
            text: pres.textEdit.newText
          };
        }
        
        return result;
      });
    }
  };
}


/**
 * Register all Tailwind Monaco providers
 * Should be called after Monaco is loaded and Tailwind LSP is initialized
 */
export function registerTailwindMonacoProviders(): void {
  const monaco = getMonaco();
  if (!monaco) {
    console.warn('[Tailwind Monaco Providers] Monaco not loaded');
    return;
  }
  
  // Register providers for all Tailwind-relevant languages
  for (const language of TAILWIND_LANGUAGES) {
    // Completion provider
    const completionDisposable = monaco.languages.registerCompletionItemProvider(
      language,
      createCompletionProvider(monaco)
    );
    registeredDisposables.push(completionDisposable);
    
    // Hover provider
    const hoverDisposable = monaco.languages.registerHoverProvider(
      language,
      createHoverProvider()
    );
    registeredDisposables.push(hoverDisposable);
    
    // Color provider (for color swatches)
    const colorDisposable = monaco.languages.registerColorProvider(
      language,
      createColorProvider(monaco)
    );
    registeredDisposables.push(colorDisposable);
  }
  
  console.log('[Tailwind Monaco Providers] Registered providers for:', TAILWIND_LANGUAGES);
}

/**
 * Dispose all registered providers
 */
export function disposeTailwindMonacoProviders(): void {
  for (const disposable of registeredDisposables) {
    disposable.dispose();
  }
  registeredDisposables.length = 0;
  console.log('[Tailwind Monaco Providers] Disposed all providers');
}

/**
 * Tailwind CSS LSP Sidecar Service
 * 
 * Provides Tailwind IntelliSense using the real @tailwindcss/language-server:
 * - Class completions in className attributes
 * - Hover shows generated CSS
 * - Diagnostics for invalid classes
 * 
 * Strategy:
 * - Start server when opening files that commonly contain Tailwind classes:
 *   .tsx/.jsx/.ts/.js, .css/.scss, .svelte, .html
 * - Must read workspace tailwind.config.*
 */

import { getLspRegistry, type LspTransport, type JsonRpcMessage } from './sidecar';
import { problemsStore, type Problem, type ProblemSeverity } from '$shared/stores/problems.svelte';
import { projectStore } from '$shared/stores/project.svelte';
import { registerTailwindMonacoProviders, disposeTailwindMonacoProviders } from './tailwind-monaco-providers';

// Server instance tracking
let tailwindServerTransport: LspTransport | null = null;
let tailwindServerInitialized = false;
let initializationPromise: Promise<void> | null = null;

// Document tracking
const openDocuments = new Map<string, { version: number; content: string }>();

// Debounce timers
const diagnosticDebounceTimers = new Map<string, ReturnType<typeof setTimeout>>();
const DIAGNOSTIC_DEBOUNCE_MS = 150;

/**
 * File extensions that commonly contain Tailwind classes
 */
const TAILWIND_FILE_EXTENSIONS = [
  'tsx', 'jsx', 'ts', 'js', 'mts', 'cts', 'mjs', 'cjs',
  'css', 'scss', 'less',
  'svelte',
  'html', 'vue'
];

/**
 * Check if a file may contain Tailwind classes
 */
export function isTailwindFile(filepath: string): boolean {
  const ext = filepath.split('.').pop()?.toLowerCase() || '';
  return TAILWIND_FILE_EXTENSIONS.includes(ext);
}

/**
 * Get the language ID for LSP
 */
function getLanguageId(filepath: string): string {
  const ext = filepath.split('.').pop()?.toLowerCase() || '';
  switch (ext) {
    case 'ts':
    case 'mts':
    case 'cts':
      return 'typescript';
    case 'tsx':
      return 'typescriptreact';
    case 'js':
    case 'mjs':
    case 'cjs':
      return 'javascript';
    case 'jsx':
      return 'javascriptreact';
    case 'css':
      return 'css';
    case 'scss':
      return 'scss';
    case 'less':
      return 'less';
    case 'svelte':
      return 'svelte';
    case 'html':
      return 'html';
    case 'vue':
      return 'vue';
    default:
      return 'plaintext';
  }
}


/**
 * Convert file path to URI
 */
function pathToUri(filepath: string): string {
  // Handle Windows paths
  let normalizedPath = filepath.replace(/\\/g, '/');
  // Normalize drive letter to lowercase for consistency
  if (normalizedPath.match(/^[a-zA-Z]:/)) {
    normalizedPath = normalizedPath[0].toLowerCase() + normalizedPath.slice(1);
  }
  const encodedPath = encodeURI(normalizedPath);
  if (normalizedPath.match(/^[a-zA-Z]:/)) {
    return `file:///${encodedPath}`;
  }
  return `file://${encodedPath}`;
}

/**
 * Convert URI to file path (normalized with forward slashes)
 */
function uriToPath(uri: string): string {
  let path = uri.replace('file://', '');
  // Handle Windows paths (file:///C:/...)
  if (path.match(/^\/[a-zA-Z]:/)) {
    path = path.slice(1);
  }
  // Normalize drive letter to lowercase for consistency
  if (path.match(/^[a-zA-Z]:/)) {
    path = path[0].toLowerCase() + path.slice(1);
  }
  // Normalize to forward slashes for consistency with editorStore
  return path.replace(/\\/g, '/');
}

/**
 * Map LSP severity to our severity
 */
function mapSeverity(lspSeverity: number): ProblemSeverity {
  switch (lspSeverity) {
    case 1: return 'error';
    case 2: return 'warning';
    case 3: return 'info';
    case 4: return 'hint';
    default: return 'info';
  }
}

/**
 * Handle incoming LSP messages
 */
function handleLspMessage(message: JsonRpcMessage): void {
  // Handle server requests that require a response
  if ('id' in message && 'method' in message && message.id !== null) {
    const id = message.id;
    if (message.method === 'workspace/configuration') {
      const items = (message.params as any)?.items || [];
      const result = items.map(() => ({}));
      tailwindServerTransport?.sendResponse(id, result);
    } else {
      tailwindServerTransport?.sendResponse(id, null);
    }
    return;
  }

  // Handle notifications
  if ('method' in message && !('id' in message)) {
    if (message.method === 'textDocument/publishDiagnostics') {
      handleDiagnostics(message.params as PublishDiagnosticsParams);
    } else if (message.method === 'window/logMessage') {
      const params = message.params as { type: number; message: string };
      console.log(`[Tailwind LSP] ${params.message}`);
    }
  }
}

interface Diagnostic {
  range: {
    start: { line: number; character: number };
    end: { line: number; character: number };
  };
  message: string;
  severity?: number;
  code?: number | string;
  source?: string;
}

interface PublishDiagnosticsParams {
  uri: string;
  diagnostics: Diagnostic[];
}

/**
 * Handle diagnostics from the LSP server
 */
function handleDiagnostics(params: PublishDiagnosticsParams): void {
  const filePath = uriToPath(params.uri);
  const fileName = filePath.split(/[/\\]/).pop() || filePath;

  const problems: Problem[] = params.diagnostics.map((diag, index) => ({
    id: `tailwind:${filePath}:${diag.range.start.line}:${diag.range.start.character}:${index}`,
    file: filePath,
    fileName,
    line: diag.range.start.line + 1, // LSP is 0-based, we use 1-based
    column: diag.range.start.character + 1,
    endLine: diag.range.end.line + 1,
    endColumn: diag.range.end.character + 1,
    message: diag.message,
    severity: mapSeverity(diag.severity ?? 2), // Default to warning for Tailwind
    source: diag.source || 'tailwindcss',
    code: diag.code?.toString()
  }));

  // Merge with existing problems (don't overwrite TS problems)
  problemsStore.setProblemsForFile(filePath, problems, 'tailwindcss');
}


/**
 * Initialize the Tailwind CSS language server
 */
async function initializeServer(): Promise<void> {
  if (tailwindServerInitialized || !projectStore.rootPath) {
    return;
  }

  if (initializationPromise) {
    return initializationPromise;
  }

  initializationPromise = (async () => {
    try {
      const registry = getLspRegistry();

      // Start the Tailwind server
      tailwindServerTransport = await registry.startServer('tailwind', {
        serverId: 'tailwind-main',
        cwd: projectStore.rootPath ?? undefined
      });

      // Set up message handler
      tailwindServerTransport.onMessage(handleLspMessage);

      // Set up error handler
      tailwindServerTransport.onError((error) => {
        console.error('[Tailwind LSP] Server error:', error);
      });

      // Set up exit handler
      tailwindServerTransport.onExit(() => {
        console.log('[Tailwind LSP] Server exited');
        tailwindServerTransport = null;
        tailwindServerInitialized = false;
        initializationPromise = null;
        openDocuments.clear();
      });

      // Send initialize request
      const rootUri = pathToUri(projectStore.rootPath!);

      const initResult = await tailwindServerTransport.sendRequest('initialize', {
        processId: null,
        rootUri,
        rootPath: projectStore.rootPath,
        capabilities: {
          textDocument: {
            synchronization: {
              dynamicRegistration: true,
              willSave: false,
              willSaveWaitUntil: false,
              didSave: true
            },
            completion: {
              dynamicRegistration: true,
              completionItem: {
                snippetSupport: true,
                commitCharactersSupport: true,
                documentationFormat: ['markdown', 'plaintext'],
                deprecatedSupport: true,
                preselectSupport: true,
                insertReplaceSupport: true,
                labelDetailsSupport: true,
                resolveSupport: {
                  properties: ['documentation', 'detail', 'additionalTextEdits']
                }
              },
              contextSupport: true
            },
            hover: {
              dynamicRegistration: true,
              contentFormat: ['markdown', 'plaintext']
            },
            publishDiagnostics: {
              relatedInformation: true,
              tagSupport: {
                valueSet: [1, 2]
              },
              codeDescriptionSupport: true
            },
            codeAction: {
              dynamicRegistration: true,
              codeActionLiteralSupport: {
                codeActionKind: {
                  valueSet: ['quickfix']
                }
              }
            },
            colorProvider: {
              dynamicRegistration: true
            }
          },
          workspace: {
            applyEdit: true,
            workspaceEdit: {
              documentChanges: true
            },
            didChangeConfiguration: {
              dynamicRegistration: true
            },
            didChangeWatchedFiles: {
              dynamicRegistration: true
            },
            configuration: true,
            workspaceFolders: true
          }
        },
        workspaceFolders: [
          {
            uri: rootUri,
            name: projectStore.projectName
          }
        ],
        initializationOptions: {
          // Tailwind-specific settings
          userLanguages: {
            // Map file extensions to language IDs for Tailwind
            'javascript': 'javascript',
            'javascriptreact': 'javascriptreact',
            'typescript': 'typescript',
            'typescriptreact': 'typescriptreact',
            'svelte': 'html',
            'vue': 'html'
          }
        }
      });

      console.log('[Tailwind LSP] Server initialized:', initResult);

      // Send initialized notification
      await tailwindServerTransport.sendNotification('initialized', {});

      tailwindServerInitialized = true;

      // Register Monaco providers
      registerTailwindMonacoProviders();
    } catch (error) {
      console.error('[Tailwind LSP] Failed to initialize server:', error);
      tailwindServerTransport = null;
      initializationPromise = null;
      throw error;
    }
  })();

  return initializationPromise;
}


/**
 * Notify the server that a document was opened
 */
export async function notifyTailwindDocumentOpened(filepath: string, content: string): Promise<void> {
  if (!isTailwindFile(filepath)) return;
  if (!projectStore.rootPath) return;

  // Initialize server if needed
  await initializeServer();

  // Don't reopen if already open and content is the same
  const existing = openDocuments.get(filepath);
  if (existing && existing.content === content) return;

  if (!tailwindServerTransport || !tailwindServerInitialized) return;

  const uri = pathToUri(filepath);
  const languageId = getLanguageId(filepath);

  // Track document
  openDocuments.set(filepath, { version: existing ? existing.version + 1 : 1, content });

  if (existing) {
    // If it's already open but content changed, send didChange instead
    await tailwindServerTransport.sendNotification('textDocument/didChange', {
      textDocument: {
        uri,
        version: existing.version + 1
      },
      contentChanges: [{ text: content }]
    });
    return;
  }

  // Send didOpen notification
  await tailwindServerTransport.sendNotification('textDocument/didOpen', {
    textDocument: {
      uri,
      languageId,
      version: 1,
      text: content
    }
  });
}

/**
 * Notify the server that a document was changed
 */
export async function notifyTailwindDocumentChanged(filepath: string, content: string): Promise<void> {
  if (!isTailwindFile(filepath)) return;
  if (!tailwindServerTransport || !tailwindServerInitialized) return;

  const doc = openDocuments.get(filepath);
  if (!doc) {
    // Document wasn't opened, open it now
    await notifyTailwindDocumentOpened(filepath, content);
    return;
  }

  // Update version
  doc.version++;
  doc.content = content;

  const uri = pathToUri(filepath);

  // Debounce the change notification
  const existingTimer = diagnosticDebounceTimers.get(filepath);
  if (existingTimer) {
    clearTimeout(existingTimer);
  }

  diagnosticDebounceTimers.set(filepath, setTimeout(async () => {
    diagnosticDebounceTimers.delete(filepath);

    if (!tailwindServerTransport || !tailwindServerInitialized) return;

    // Send didChange notification with full content
    await tailwindServerTransport.sendNotification('textDocument/didChange', {
      textDocument: {
        uri,
        version: doc.version
      },
      contentChanges: [{ text: content }]
    });
  }, DIAGNOSTIC_DEBOUNCE_MS));
}

/**
 * Notify the server that a document was saved
 */
export async function notifyTailwindDocumentSaved(filepath: string, content: string): Promise<void> {
  if (!isTailwindFile(filepath)) return;
  if (!tailwindServerTransport || !tailwindServerInitialized) return;

  const uri = pathToUri(filepath);

  await tailwindServerTransport.sendNotification('textDocument/didSave', {
    textDocument: { uri },
    text: content
  });
}

/**
 * Notify the server that a document was closed
 */
export async function notifyTailwindDocumentClosed(filepath: string): Promise<void> {
  if (!isTailwindFile(filepath)) return;
  if (!tailwindServerTransport || !tailwindServerInitialized) return;

  openDocuments.delete(filepath);

  const uri = pathToUri(filepath);

  await tailwindServerTransport.sendNotification('textDocument/didClose', {
    textDocument: { uri }
  });

  // Clear Tailwind problems for this file
  problemsStore.clearProblemsForFile(filepath, 'tailwindcss');
}


/**
 * Request completions at a position
 */
export async function getTailwindCompletions(
  filepath: string,
  line: number,
  character: number
): Promise<CompletionItem[] | null> {
  if (!isTailwindFile(filepath)) return null;
  if (!tailwindServerTransport || !tailwindServerInitialized) return null;

  const uri = pathToUri(filepath);

  try {
    const result = await tailwindServerTransport.sendRequest<CompletionList | CompletionItem[] | null>(
      'textDocument/completion',
      {
        textDocument: { uri },
        position: { line, character }
      }
    );

    if (!result) return null;

    // Handle both CompletionList and CompletionItem[] responses
    if (Array.isArray(result)) {
      return result;
    }
    return result.items || [];
  } catch (error) {
    console.error('[Tailwind LSP] Completion error:', error);
    return null;
  }
}

export interface CompletionItem {
  label: string;
  kind?: number;
  detail?: string;
  documentation?: string | { kind: string; value: string };
  insertText?: string;
  insertTextFormat?: number;
  textEdit?: TextEdit;
  additionalTextEdits?: TextEdit[];
  sortText?: string;
  filterText?: string;
  data?: unknown;
}

interface CompletionList {
  isIncomplete: boolean;
  items: CompletionItem[];
}

export interface TextEdit {
  range: {
    start: { line: number; character: number };
    end: { line: number; character: number };
  };
  newText: string;
}

/**
 * Request hover information at a position
 */
export async function getTailwindHover(
  filepath: string,
  line: number,
  character: number
): Promise<HoverResult | null> {
  if (!isTailwindFile(filepath)) return null;
  if (!tailwindServerTransport || !tailwindServerInitialized) return null;

  const uri = pathToUri(filepath);

  try {
    const result = await tailwindServerTransport.sendRequest<HoverResult | null>(
      'textDocument/hover',
      {
        textDocument: { uri },
        position: { line, character }
      }
    );

    return result;
  } catch (error) {
    console.error('[Tailwind LSP] Hover error:', error);
    return null;
  }
}

export interface HoverResult {
  contents: string | { kind: string; value: string } | Array<string | { kind: string; value: string }>;
  range?: {
    start: { line: number; character: number };
    end: { line: number; character: number };
  };
}

/**
 * Request document colors (for color swatches)
 */
export async function getTailwindDocumentColors(
  filepath: string
): Promise<ColorInformation[] | null> {
  if (!isTailwindFile(filepath)) return null;
  if (!tailwindServerTransport || !tailwindServerInitialized) return null;

  const uri = pathToUri(filepath);

  try {
    const result = await tailwindServerTransport.sendRequest<ColorInformation[] | null>(
      'textDocument/documentColor',
      {
        textDocument: { uri }
      }
    );

    return result;
  } catch (error) {
    console.error('[Tailwind LSP] Document color error:', error);
    return null;
  }
}

export interface ColorInformation {
  range: {
    start: { line: number; character: number };
    end: { line: number; character: number };
  };
  color: {
    red: number;
    green: number;
    blue: number;
    alpha: number;
  };
}

/**
 * Request color presentations
 */
export async function getTailwindColorPresentations(
  filepath: string,
  color: { red: number; green: number; blue: number; alpha: number },
  range: { start: { line: number; character: number }; end: { line: number; character: number } }
): Promise<ColorPresentation[] | null> {
  if (!isTailwindFile(filepath)) return null;
  if (!tailwindServerTransport || !tailwindServerInitialized) return null;

  const uri = pathToUri(filepath);

  try {
    const result = await tailwindServerTransport.sendRequest<ColorPresentation[] | null>(
      'textDocument/colorPresentation',
      {
        textDocument: { uri },
        color,
        range
      }
    );

    return result;
  } catch (error) {
    console.error('[Tailwind LSP] Color presentation error:', error);
    return null;
  }
}

export interface ColorPresentation {
  label: string;
  textEdit?: TextEdit;
  additionalTextEdits?: TextEdit[];
}


/**
 * Check if the Tailwind LSP is initialized
 */
export function isTailwindLspInitialized(): boolean {
  return tailwindServerInitialized;
}

/**
 * Check if the Tailwind LSP is connected
 */
export function isTailwindLspConnected(): boolean {
  return tailwindServerTransport?.connected ?? false;
}

/**
 * Stop the Tailwind LSP server
 */
export async function stopTailwindLsp(): Promise<void> {
  // Dispose Monaco providers first
  disposeTailwindMonacoProviders();

  if (tailwindServerTransport) {
    try {
      // Send shutdown request
      await tailwindServerTransport.sendRequest('shutdown', null);
      // Send exit notification
      await tailwindServerTransport.sendNotification('exit', null);
    } catch {
      // Ignore errors during shutdown
    }

    await tailwindServerTransport.stop();
    tailwindServerTransport = null;
  }

  tailwindServerInitialized = false;
  initializationPromise = null;
  openDocuments.clear();

  // Clear all diagnostic timers
  for (const timer of diagnosticDebounceTimers.values()) {
    clearTimeout(timer);
  }
  diagnosticDebounceTimers.clear();
}

/**
 * Restart the Tailwind LSP server
 */
export async function restartTailwindLsp(): Promise<void> {
  await stopTailwindLsp();

  // Re-initialize if there's a project open
  if (projectStore.rootPath) {
    await initializeServer();
  }
}

/**
 * TypeScript Monaco Providers
 * 
 * Registers Monaco language providers that use the TypeScript LSP sidecar
 * for completions, hover, definition, and other features.
 * 
 * This provides VS Code-level TypeScript intelligence by using the real
 * typescript-language-server instead of Monaco's built-in TS worker.
 */

import type * as Monaco from 'monaco-editor';
import { getMonaco } from '$core/services/monaco-loader';
import { editorStore } from '$features/editor/stores/editor.svelte';
import {
  getCompletions,
  getHover,
  getDefinition,
  getReferences,
  getSignatureHelp,
  isTsLspInitialized,
  type CompletionItem as LspCompletionItem,
  type HoverResult,
  type Location,
  type SignatureHelp
} from './typescript-sidecar';

// Track registered providers for cleanup
const registeredDisposables: Monaco.IDisposable[] = [];

// Track if editor opener is registered
let editorOpenerRegistered = false;

// Languages to register providers for
const TS_LANGUAGES = ['typescript', 'javascript', 'typescriptreact', 'javascriptreact'];

/**
 * Convert file path from Monaco model URI
 */
function getFilePathFromModel(model: Monaco.editor.ITextModel): string {
  const uri = model.uri;
  // Our URIs are in format: inmemory://model/{encodedPath}
  const path = uri.path;
  if (path.startsWith('/')) {
    return decodeURIComponent(path.slice(1));
  }
  return decodeURIComponent(path);
}

/**
 * Map LSP completion kind to Monaco completion kind
 */
function mapCompletionKind(monaco: typeof Monaco, lspKind?: number): Monaco.languages.CompletionItemKind {
  if (!lspKind) return monaco.languages.CompletionItemKind.Text;
  
  // LSP CompletionItemKind values
  const kindMap: Record<number, Monaco.languages.CompletionItemKind> = {
    1: monaco.languages.CompletionItemKind.Text,
    2: monaco.languages.CompletionItemKind.Method,
    3: monaco.languages.CompletionItemKind.Function,
    4: monaco.languages.CompletionItemKind.Constructor,
    5: monaco.languages.CompletionItemKind.Field,
    6: monaco.languages.CompletionItemKind.Variable,
    7: monaco.languages.CompletionItemKind.Class,
    8: monaco.languages.CompletionItemKind.Interface,
    9: monaco.languages.CompletionItemKind.Module,
    10: monaco.languages.CompletionItemKind.Property,
    11: monaco.languages.CompletionItemKind.Unit,
    12: monaco.languages.CompletionItemKind.Value,
    13: monaco.languages.CompletionItemKind.Enum,
    14: monaco.languages.CompletionItemKind.Keyword,
    15: monaco.languages.CompletionItemKind.Snippet,
    16: monaco.languages.CompletionItemKind.Color,
    17: monaco.languages.CompletionItemKind.File,
    18: monaco.languages.CompletionItemKind.Reference,
    19: monaco.languages.CompletionItemKind.Folder,
    20: monaco.languages.CompletionItemKind.EnumMember,
    21: monaco.languages.CompletionItemKind.Constant,
    22: monaco.languages.CompletionItemKind.Struct,
    23: monaco.languages.CompletionItemKind.Event,
    24: monaco.languages.CompletionItemKind.Operator,
    25: monaco.languages.CompletionItemKind.TypeParameter
  };
  
  return kindMap[lspKind] ?? monaco.languages.CompletionItemKind.Text;
}

/**
 * Convert LSP completion item to Monaco completion item
 */
function convertCompletionItem(
  monaco: typeof Monaco,
  item: LspCompletionItem,
  range: Monaco.IRange
): Monaco.languages.CompletionItem {
  let documentation: Monaco.languages.CompletionItem['documentation'];
  if (item.documentation) {
    if (typeof item.documentation === 'string') {
      documentation = item.documentation;
    } else if (item.documentation.kind === 'markdown') {
      documentation = { value: item.documentation.value };
    } else {
      documentation = item.documentation.value;
    }
  }

  return {
    label: item.label,
    kind: mapCompletionKind(monaco, item.kind),
    detail: item.detail,
    documentation,
    insertText: item.insertText || item.label,
    insertTextRules: item.insertTextFormat === 2 
      ? monaco.languages.CompletionItemInsertTextRule.InsertAsSnippet 
      : undefined,
    range
  };
}

/**
 * Convert LSP hover to Monaco hover
 */
function convertHover(
  monaco: typeof Monaco,
  hover: HoverResult
): Monaco.languages.Hover {
  const contents: Monaco.IMarkdownString[] = [];
  
  if (typeof hover.contents === 'string') {
    contents.push({ value: hover.contents });
  } else if (Array.isArray(hover.contents)) {
    for (const content of hover.contents) {
      if (typeof content === 'string') {
        contents.push({ value: content });
      } else {
        contents.push({ value: content.value });
      }
    }
  } else {
    contents.push({ value: hover.contents.value });
  }
  
  let range: Monaco.IRange | undefined;
  if (hover.range) {
    range = {
      startLineNumber: hover.range.start.line + 1,
      startColumn: hover.range.start.character + 1,
      endLineNumber: hover.range.end.line + 1,
      endColumn: hover.range.end.character + 1
    };
  }
  
  return { contents, range };
}

/**
 * Convert LSP file:// URI to file path
 */
function lspUriToFilePath(uri: string): string {
  let path = uri.replace('file://', '');
  // Handle Windows paths (file:///C:/...)
  if (path.match(/^\/[a-zA-Z]:/)) {
    path = path.slice(1);
  }
  // Normalize to forward slashes for consistency
  return path.replace(/\\/g, '/');
}

/**
 * Convert file path to our inmemory:// URI scheme
 * This matches the URI scheme used in monaco-models.ts
 */
function filePathToMonacoUri(monaco: typeof Monaco, filepath: string): Monaco.Uri {
  // Normalize path separators
  const normalizedPath = filepath.replace(/\\/g, '/');
  return monaco.Uri.parse(`inmemory://model/${encodeURIComponent(normalizedPath)}`);
}

/**
 * Convert LSP location to Monaco location
 * Uses our inmemory:// URI scheme so Monaco can navigate to the location
 */
function convertLocation(
  monaco: typeof Monaco,
  location: Location
): Monaco.languages.Location {
  const filepath = lspUriToFilePath(location.uri);
  
  return {
    uri: filePathToMonacoUri(monaco, filepath),
    range: {
      startLineNumber: location.range.start.line + 1,
      startColumn: location.range.start.character + 1,
      endLineNumber: location.range.end.line + 1,
      endColumn: location.range.end.character + 1
    }
  };
}

/**
 * Create completion provider for TypeScript sidecar
 */
function createCompletionProvider(monaco: typeof Monaco): Monaco.languages.CompletionItemProvider {
  return {
    triggerCharacters: ['.', '"', "'", '/', '@', '<'],
    
    async provideCompletionItems(
      model: Monaco.editor.ITextModel,
      position: Monaco.Position,
      _context: Monaco.languages.CompletionContext,
      _token: Monaco.CancellationToken
    ): Promise<Monaco.languages.CompletionList | null> {
      if (!isTsLspInitialized()) {
        return null; // Fall back to Monaco's built-in
      }
      
      const filepath = getFilePathFromModel(model);
      const line = position.lineNumber - 1; // LSP is 0-based
      const character = position.column - 1;
      
      const items = await getCompletions(filepath, line, character);
      if (!items || items.length === 0) {
        return null;
      }
      
      // Get word range for replacement
      const word = model.getWordUntilPosition(position);
      const range: Monaco.IRange = {
        startLineNumber: position.lineNumber,
        startColumn: word.startColumn,
        endLineNumber: position.lineNumber,
        endColumn: word.endColumn
      };
      
      const suggestions = items.map(item => convertCompletionItem(monaco, item, range));
      
      return {
        suggestions,
        incomplete: false
      };
    }
  };
}

/**
 * Create hover provider for TypeScript sidecar
 */
function createHoverProvider(monaco: typeof Monaco): Monaco.languages.HoverProvider {
  return {
    async provideHover(
      model: Monaco.editor.ITextModel,
      position: Monaco.Position,
      _token: Monaco.CancellationToken
    ): Promise<Monaco.languages.Hover | null> {
      if (!isTsLspInitialized()) {
        return null;
      }
      
      const filepath = getFilePathFromModel(model);
      const line = position.lineNumber - 1;
      const character = position.column - 1;
      
      const hover = await getHover(filepath, line, character);
      if (!hover) {
        return null;
      }
      
      return convertHover(monaco, hover);
    }
  };
}

/**
 * Create definition provider for TypeScript sidecar
 */
function createDefinitionProvider(monaco: typeof Monaco): Monaco.languages.DefinitionProvider {
  return {
    async provideDefinition(
      model: Monaco.editor.ITextModel,
      position: Monaco.Position,
      _token: Monaco.CancellationToken
    ): Promise<Monaco.languages.Definition | null> {
      if (!isTsLspInitialized()) {
        return null;
      }
      
      const filepath = getFilePathFromModel(model);
      const line = position.lineNumber - 1;
      const character = position.column - 1;
      
      const locations = await getDefinition(filepath, line, character);
      if (!locations || locations.length === 0) {
        return null;
      }
      
      return locations.map(loc => convertLocation(monaco, loc));
    }
  };
}

/**
 * Create references provider for TypeScript sidecar
 */
function createReferencesProvider(monaco: typeof Monaco): Monaco.languages.ReferenceProvider {
  return {
    async provideReferences(
      model: Monaco.editor.ITextModel,
      position: Monaco.Position,
      context: Monaco.languages.ReferenceContext,
      _token: Monaco.CancellationToken
    ): Promise<Monaco.languages.Location[] | null> {
      if (!isTsLspInitialized()) {
        return null;
      }
      
      const filepath = getFilePathFromModel(model);
      const line = position.lineNumber - 1;
      const character = position.column - 1;
      
      const locations = await getReferences(filepath, line, character, context.includeDeclaration);
      if (!locations || locations.length === 0) {
        return null;
      }
      
      return locations.map(loc => convertLocation(monaco, loc));
    }
  };
}

/**
 * Create signature help provider for TypeScript sidecar
 */
function createSignatureHelpProvider(monaco: typeof Monaco): Monaco.languages.SignatureHelpProvider {
  return {
    signatureHelpTriggerCharacters: ['(', ','],
    signatureHelpRetriggerCharacters: [','],
    
    async provideSignatureHelp(
      model: Monaco.editor.ITextModel,
      position: Monaco.Position,
      _token: Monaco.CancellationToken,
      _context: Monaco.languages.SignatureHelpContext
    ): Promise<Monaco.languages.SignatureHelpResult | null> {
      if (!isTsLspInitialized()) {
        return null;
      }
      
      const filepath = getFilePathFromModel(model);
      const line = position.lineNumber - 1;
      const character = position.column - 1;
      
      const help = await getSignatureHelp(filepath, line, character);
      if (!help || help.signatures.length === 0) {
        return null;
      }
      
      const signatures: Monaco.languages.SignatureInformation[] = help.signatures.map(sig => {
        let documentation: string | Monaco.IMarkdownString | undefined;
        if (sig.documentation) {
          if (typeof sig.documentation === 'string') {
            documentation = sig.documentation;
          } else {
            documentation = { value: sig.documentation.value };
          }
        }
        
        const parameters: Monaco.languages.ParameterInformation[] = (sig.parameters || []).map(param => {
          let paramDoc: string | Monaco.IMarkdownString | undefined;
          if (param.documentation) {
            if (typeof param.documentation === 'string') {
              paramDoc = param.documentation;
            } else {
              paramDoc = { value: param.documentation.value };
            }
          }
          
          return {
            label: Array.isArray(param.label) ? param.label : param.label,
            documentation: paramDoc
          };
        });
        
        return {
          label: sig.label,
          documentation,
          parameters
        };
      });
      
      return {
        value: {
          signatures,
          activeSignature: help.activeSignature ?? 0,
          activeParameter: help.activeParameter ?? 0
        },
        dispose: () => {}
      };
    }
  };
}

/**
 * Register an editor opener to handle go-to-definition navigation
 * This opens files in the editor when Monaco tries to navigate to a location
 */
function registerEditorOpener(monaco: typeof Monaco): void {
  if (editorOpenerRegistered) return;
  
  const openerDisposable = monaco.editor.registerEditorOpener({
    async openCodeEditor(
      _source: Monaco.editor.ICodeEditor,
      resource: Monaco.Uri,
      selectionOrPosition?: Monaco.IRange | Monaco.IPosition
    ): Promise<boolean> {
      // Extract file path from our inmemory:// URI
      // Format: inmemory://model/{encodedPath}
      if (resource.scheme === 'inmemory' && resource.authority === 'model') {
        const filepath = decodeURIComponent(resource.path.slice(1)); // Remove leading /
        
        // Open the file in the editor
        const opened = await editorStore.openFile(filepath);
        if (!opened) {
          console.warn('[TS Monaco Providers] Failed to open file:', filepath);
          return false;
        }
        
        // Navigate to the position after a short delay to let the editor load
        if (selectionOrPosition) {
          setTimeout(() => {
            const line = 'startLineNumber' in selectionOrPosition 
              ? selectionOrPosition.startLineNumber 
              : selectionOrPosition.lineNumber;
            const column = 'startColumn' in selectionOrPosition 
              ? selectionOrPosition.startColumn 
              : selectionOrPosition.column;
            
            // Dispatch navigation event for the editor to handle
            window.dispatchEvent(new CustomEvent('volt:navigate-to-position', {
              detail: { file: filepath, line, column }
            }));
          }, 100);
        }
        
        // Return true to indicate we handled the navigation
        return true;
      }
      
      // For other URI schemes, return false to let Monaco handle it
      return false;
    }
  });
  
  registeredDisposables.push(openerDisposable);
  editorOpenerRegistered = true;
  console.log('[TS Monaco Providers] Registered editor opener for go-to-definition');
}

/**
 * Register all TypeScript Monaco providers
 * Should be called after Monaco is loaded
 */
export function registerTsMonacoProviders(): void {
  const monaco = getMonaco();
  if (!monaco) {
    console.warn('[TS Monaco Providers] Monaco not loaded');
    return;
  }
  
  // Register editor opener for go-to-definition navigation
  registerEditorOpener(monaco);
  
  // Register providers for all TS/JS languages
  for (const language of TS_LANGUAGES) {
    // Completion provider
    const completionDisposable = monaco.languages.registerCompletionItemProvider(
      language,
      createCompletionProvider(monaco)
    );
    registeredDisposables.push(completionDisposable);
    
    // Hover provider
    const hoverDisposable = monaco.languages.registerHoverProvider(
      language,
      createHoverProvider(monaco)
    );
    registeredDisposables.push(hoverDisposable);
    
    // Definition provider
    const definitionDisposable = monaco.languages.registerDefinitionProvider(
      language,
      createDefinitionProvider(monaco)
    );
    registeredDisposables.push(definitionDisposable);
    
    // References provider
    const referencesDisposable = monaco.languages.registerReferenceProvider(
      language,
      createReferencesProvider(monaco)
    );
    registeredDisposables.push(referencesDisposable);
    
    // Signature help provider
    const signatureDisposable = monaco.languages.registerSignatureHelpProvider(
      language,
      createSignatureHelpProvider(monaco)
    );
    registeredDisposables.push(signatureDisposable);
  }
  
  console.log('[TS Monaco Providers] Registered providers for:', TS_LANGUAGES);
}

/**
 * Dispose all registered providers
 */
export function disposeTsMonacoProviders(): void {
  for (const disposable of registeredDisposables) {
    disposable.dispose();
  }
  registeredDisposables.length = 0;
  editorOpenerRegistered = false;
  console.log('[TS Monaco Providers] Disposed all providers');
}

/**
 * TypeScript LSP Sidecar Service
 * 
 * Provides full-project TypeScript/JavaScript intelligence using the real
 * typescript-language-server (backed by tsserver).
 * 
 * Features:
 * - Project-wide diagnostics (respects tsconfig.json)
 * - Go-to-definition
 * - Hover information
 * - Completions
 * - Find references
 * 
 * Strategy:
 * - Start server when opening a TS/JS file in a project
 * - Workspace root = projectStore.rootPath
 * - Must respect workspace tsconfig.json (paths/baseUrl) for Next.js
 */

import { getLspRegistry, type LspTransport, type JsonRpcMessage } from './sidecar';
import { problemsStore, type Problem, type ProblemSeverity } from '$shared/stores/problems.svelte';
import { projectStore } from '$shared/stores/project.svelte';
import { readFileQuiet } from '$core/services/file-system';
import { getAllFiles } from '$core/services/file-index';
import { registerTsMonacoProviders, disposeTsMonacoProviders } from './typescript-monaco-providers';

// Server instance tracking
let tsServerTransport: LspTransport | null = null;
let tsServerInitialized = false;
let initializationPromise: Promise<void> | null = null;
let initializedRootPath: string | null = null;

// Document tracking
const openDocuments = new Map<string, { version: number; content: string }>();

// Debounce timers
const diagnosticDebounceTimers = new Map<string, ReturnType<typeof setTimeout>>();
const DIAGNOSTIC_DEBOUNCE_MS = 75;

// Pending open operations (to prevent race conditions)
const openingDocuments = new Map<string, Promise<void>>();

// Note: messageId is managed by the transport layer

/**
 * Check if a file is a TypeScript/JavaScript file
 */
export function isTsJsFile(filepath: string): boolean {
  const ext = filepath.split('.').pop()?.toLowerCase() || '';
  return ['ts', 'tsx', 'js', 'jsx', 'mts', 'cts', 'mjs', 'cjs'].includes(ext);
}

/**
 * Get the language ID for LSP
 */
function getLanguageId(filepath: string): string {
  const ext = filepath.split('.').pop()?.toLowerCase() || '';
  switch (ext) {
    case 'ts':
    case 'mts':
    case 'cts':
      return 'typescript';
    case 'tsx':
      return 'typescriptreact';
    case 'js':
    case 'mjs':
    case 'cjs':
      return 'javascript';
    case 'jsx':
      return 'javascriptreact';
    default:
      return 'typescript';
  }
}

/**
 * Convert file path to URI
 */
function pathToUri(filepath: string): string {
  // Handle Windows paths
  let normalizedPath = filepath.replace(/\\/g, '/');
  // Normalize drive letter to lowercase for consistency
  if (normalizedPath.match(/^[a-zA-Z]:/)) {
    normalizedPath = normalizedPath[0].toLowerCase() + normalizedPath.slice(1);
  }
  const encodedPath = encodeURI(normalizedPath);
  if (normalizedPath.match(/^[a-zA-Z]:/)) {
    return `file:///${encodedPath}`;
  }
  return `file://${encodedPath}`;
}

/**
 * Convert URI to file path (normalized with forward slashes)
 */
function uriToPath(uri: string): string {
  let path = uri.replace('file://', '');

  // Decode URI components (fixes encoded drive letters like %3A)
  try {
    path = decodeURIComponent(path);
  } catch (e) {
    console.warn('[TS LSP] Failed to decode URI component:', path);
  }

  // Handle Windows paths (file:///C:/...)
  if (path.match(/^\/[a-zA-Z]:/)) {
    path = path.slice(1);
  }
  // Normalize drive letter to lowercase for consistency
  if (path.match(/^[a-zA-Z]:/)) {
    path = path[0].toLowerCase() + path.slice(1);
  }
  // Normalize to forward slashes for consistency with editorStore
  return path.replace(/\\/g, '/');
}

/**
 * Map LSP severity to our severity
 */
function mapSeverity(lspSeverity: number): ProblemSeverity {
  switch (lspSeverity) {
    case 1: return 'error';
    case 2: return 'warning';
    case 3: return 'info';
    case 4: return 'hint';
    default: return 'info';
  }
}

/**
 * Handle incoming LSP messages
 */
function handleLspMessage(message: JsonRpcMessage): void {
  // Handle server requests that require a response
  if ('id' in message && 'method' in message && message.id !== null) {
    const id = message.id;
    if (message.method === 'workspace/configuration' || message.method === 'client/registerCapability') {
      const items = (message.params as any)?.items || [];
      const result = items.map((item: any) => {
        // Return default configurations for common TS/JS settings
        if (item.section === 'typescript' || item.section === 'javascript') {
          return { format: { enable: true }, suggest: { enabled: true } };
        }
        return {};
      });
      tsServerTransport?.sendResponse(id, result || [{}]);
    } else {
      tsServerTransport?.sendResponse(id, null);
    }
    return;
  }

  // Handle notifications
  if ('method' in message && !('id' in message)) {
    if (message.method === 'textDocument/publishDiagnostics') {
      handleDiagnostics(message.params as PublishDiagnosticsParams);
    } else if (message.method === 'window/logMessage') {
      const params = message.params as { type: number; message: string };
      console.log(`[TS LSP] ${params.message}`);
    }
  }
}

interface Diagnostic {
  range: {
    start: { line: number; character: number };
    end: { line: number; character: number };
  };
  message: string;
  severity?: number;
  code?: number | string;
  source?: string;
}

interface PublishDiagnosticsParams {
  uri: string;
  diagnostics: Diagnostic[];
}

/**
 * Handle diagnostics from the LSP server
 */
function handleDiagnostics(params: PublishDiagnosticsParams): void {
  const filePath = uriToPath(params.uri);
  const fileName = filePath.split(/[/\\]/).pop() || filePath;

  const problems: Problem[] = params.diagnostics.map((diag, index) => ({
    id: `${filePath}:${diag.range.start.line}:${diag.range.start.character}:${index}`,
    file: filePath,
    fileName,
    line: diag.range.start.line + 1, // LSP is 0-based, we use 1-based
    column: diag.range.start.character + 1,
    endLine: diag.range.end.line + 1,
    endColumn: diag.range.end.character + 1,
    message: diag.message,
    severity: mapSeverity(diag.severity ?? 1),
    source: diag.source || 'typescript',
    code: diag.code?.toString()
  }));

  problemsStore.setProblemsForFile(filePath, problems, 'typescript');
}

/**
 * Initialize the TypeScript language server
 */
async function initializeServer(): Promise<void> {
  if (!projectStore.rootPath) return;

  // If the workspace root changed, the server will reject new documents.
  // Restart to re-bind to the new root.
  if (tsServerInitialized && initializedRootPath && projectStore.rootPath !== initializedRootPath) {
    await stopTsLsp();
  }

  if (tsServerInitialized) return;

  if (initializationPromise) {
    return initializationPromise;
  }

  initializationPromise = (async () => {
    try {
      const registry = getLspRegistry();

      // Start the TypeScript server
      tsServerTransport = await registry.startServer('typescript', {
        serverId: 'typescript-main',
        cwd: projectStore.rootPath ?? undefined
      });

      // Set up message handler
      tsServerTransport.onMessage(handleLspMessage);

      // Set up error handler
      tsServerTransport.onError((error) => {
        console.error('[TS LSP] Server error:', error);
      });

      // Set up exit handler
      tsServerTransport.onExit(() => {
        console.log('[TS LSP] Server exited');
        tsServerTransport = null;
        tsServerInitialized = false;
        initializationPromise = null;
        initializedRootPath = null;
        openDocuments.clear();
      });

      // Send initialize request
      const rootUri = pathToUri(projectStore.rootPath!);

      const initResult = await tsServerTransport.sendRequest('initialize', {
        processId: null,
        rootUri,
        rootPath: projectStore.rootPath,
        capabilities: {
          textDocument: {
            synchronization: {
              dynamicRegistration: true,
              willSave: false,
              willSaveWaitUntil: false,
              didSave: true
            },
            completion: {
              dynamicRegistration: true,
              completionItem: {
                snippetSupport: true,
                commitCharactersSupport: true,
                documentationFormat: ['markdown', 'plaintext'],
                deprecatedSupport: true,
                preselectSupport: true,
                insertReplaceSupport: true,
                labelDetailsSupport: true,
                resolveSupport: {
                  properties: ['documentation', 'detail', 'additionalTextEdits']
                }
              },
              contextSupport: true
            },
            hover: {
