/**
 * Chat History Store
 * 
 * Manages persistent chat history using SQLite via Tauri commands.
 * Provides conversation list, search, and CRUD operations.
 */

import { invoke } from '@tauri-apps/api/core';

// ============================================================================
// Types
// ============================================================================

export interface ConversationSummary {
    id: string;
    title: string;
    createdAt: number;
    updatedAt: number;
    messageCount: number;
    firstUserMessage: string | null;
    isPinned: boolean;
    mode: string;
}

export interface ChatMessage {
    id: string;
    role: 'user' | 'assistant' | 'tool' | 'system';
    content: string;
    timestamp: number;
    metadata?: string; // JSON-encoded extra data
}

export interface Conversation {
    id: string;
    title: string;
    createdAt: number;
    updatedAt: number;
    isPinned: boolean;
    mode: string;
    messages: ChatMessage[];
}

// Date grouping for UI
export type DateGroup = 'pinned' | 'today' | 'yesterday' | 'last7days' | 'last30days' | 'older';

export interface GroupedConversations {
    pinned: ConversationSummary[];
    today: ConversationSummary[];
    yesterday: ConversationSummary[];
    last7days: ConversationSummary[];
    last30days: ConversationSummary[];
    older: ConversationSummary[];
}

// ============================================================================
// Store
// ============================================================================

class ChatHistoryStore {
    // State
    conversations = $state<ConversationSummary[]>([]);
    isLoading = $state(false);
    searchQuery = $state('');
    sidebarOpen = $state(false);

    // Current active conversation ID (synced with assistant store)
    activeConversationId = $state<string | null>(null);

    // Selection state for batch operations
    selectedIds = $state<Set<string>>(new Set());
    isSelectionMode = $state(false);
    private onActiveConversationDeleted: (() => void) | null = null;

    setActiveConversationDeletedHandler(handler: (() => void) | null): void {
        this.onActiveConversationDeleted = handler;
    }

    /**
     * Load all conversations from the database
     */
    async loadConversations(): Promise<void> {
        this.isLoading = true;
        try {
            const convos = await invoke<ConversationSummary[]>('chat_list_conversations');
            this.conversations = convos;
        } catch (err) {
            console.error('[ChatHistory] Failed to load conversations:', err);
        } finally {
            this.isLoading = false;
        }
    }

    /**
     * Search conversations by content
     */
    async search(query: string): Promise<void> {
        this.searchQuery = query;
        this.isLoading = true;
        try {
            const convos = await invoke<ConversationSummary[]>('chat_search_conversations', { query });
            this.conversations = convos;
        } catch (err) {
            console.error('[ChatHistory] Search failed:', err);
        } finally {
            this.isLoading = false;
        }
    }

    /**
     * Create a new conversation
     */
    async createConversation(id: string, mode: string): Promise<ConversationSummary> {
        const convo = await invoke<ConversationSummary>('chat_create_conversation', { id, mode });
        this.conversations = [convo, ...this.conversations];
        this.activeConversationId = id;
        return convo;
    }

    /**
     * Load a full conversation with messages
     */
    async getConversation(id: string): Promise<Conversation> {
        return await invoke<Conversation>('chat_get_conversation', { conversationId: id });
    }

    /**
     * Save a message to a conversation
     */
    async saveMessage(conversationId: string, message: ChatMessage): Promise<void> {
        await invoke('chat_save_message', { conversationId, message });

        // Refresh conversation list to update timestamps and titles
        await this.loadConversations();
    }

    /**
     * Update conversation title
     */
    async updateTitle(conversationId: string, title: string): Promise<void> {
        await invoke('chat_update_title', { conversationId, title });

        // Update local state
        this.conversations = this.conversations.map(c =>
            c.id === conversationId ? { ...c, title } : c
        );
    }

    /**
     * Update conversation mode (ask/plan/agent)
     */
    async updateMode(conversationId: string, mode: string): Promise<void> {
        await invoke('chat_update_mode', { conversationId, mode });

        this.conversations = this.conversations.map(c =>
            c.id === conversationId ? { ...c, mode, updatedAt: Date.now() } : c
        );
    }

    /**
     * Toggle pin status
     */
    async togglePin(conversationId: string): Promise<boolean> {
        const isPinned = await invoke<boolean>('chat_toggle_pin', { conversationId });

        // Update local state and re-sort
        this.conversations = this.conversations.map(c =>
            c.id === conversationId ? { ...c, isPinned } : c
        );

        // Re-sort: pinned first, then by updatedAt
        this.conversations = [...this.conversations].sort((a, b) => {
            if (a.isPinned && !b.isPinned) return -1;
            if (!a.isPinned && b.isPinned) return 1;
            return b.updatedAt - a.updatedAt;
        });

        return isPinned;
    }

    /**
     * Delete a conversation
     */
    async deleteConversation(conversationId: string): Promise<void> {
        await invoke('chat_delete_conversation', { conversationId });

        // Check if we're deleting the active conversation BEFORE clearing state
        const deletingActive = this.activeConversationId === conversationId;

        // Remove from local state
        this.conversations = this.conversations.filter(c => c.id !== conversationId);
        this.selectedIds.delete(conversationId);

        // If we deleted the active conversation, clear it from both stores
        if (deletingActive) {
            this.activeConversationId = null;
            this.onActiveConversationDeleted?.();
        }

        if (this.selectedIds.size === 0) {
            this.isSelectionMode = false;
        }
    }

    /**
     * Delete multiple conversations at once
     */
    async deleteMultiple(ids: string[]): Promise<void> {
        this.isLoading = true;
        try {
            // Check if we're deleting the active conversation BEFORE clearing state
            const deletingActive = ids.includes(this.activeConversationId || '');

            // Sequential deletion for safety with SQLite, or we could add a backend command for batch
            for (const id of ids) {
                await invoke('chat_delete_conversation', { conversationId: id });
            }

            // Update local state
            this.conversations = this.conversations.filter(c => !ids.includes(c.id));
            ids.forEach(id => this.selectedIds.delete(id));

            if (deletingActive) {
                this.activeConversationId = null;
                this.onActiveConversationDeleted?.();
            }

            if (this.selectedIds.size === 0) {
                this.isSelectionMode = false;
            }
        } catch (err) {
            console.error('[ChatHistory] Batch delete failed:', err);
        } finally {
            this.isLoading = false;
        }
    }

    /**
     * Clear all chat history (dangerous!)
     */
    async clearAll(): Promise<void> {
        this.isLoading = true;
        try {
            await invoke('chat_clear_all');
            this.conversations = [];
            this.activeConversationId = null;
            this.selectedIds.clear();
            this.isSelectionMode = false;
        } catch (err) {
            console.error('[ChatHistory] Clear all failed:', err);
        } finally {
            this.isLoading = false;
        }
    }

    /**
     * Selection Helpers
     */
    toggleSelection(id: string): void {
        if (this.selectedIds.has(id)) {
            this.selectedIds.delete(id);
        } else {
            this.selectedIds.add(id);
        }
        // Force reactivity for the Set
        this.selectedIds = new Set(this.selectedIds);

        if (this.selectedIds.size > 0) {
            this.isSelectionMode = true;
        } else {
            this.isSelectionMode = false;
        }
    }

    clearSelection(): void {
        this.selectedIds = new Set();
        this.isSelectionMode = false;
    }

    selectAll(): void {
        this.selectedIds = new Set(this.conversations.map(c => c.id));
        this.isSelectionMode = true;
    }

    /**
     * Group conversations by date for UI display
     */
    get groupedConversations(): GroupedConversations {
        const now = Date.now();
        const today = new Date();
        today.setHours(0, 0, 0, 0);
        const todayStart = today.getTime();

        const yesterday = new Date(today);
        yesterday.setDate(yesterday.getDate() - 1);
        const yesterdayStart = yesterday.getTime();

        const last7days = new Date(today);
        last7days.setDate(last7days.getDate() - 7);
        const last7daysStart = last7days.getTime();

        const last30days = new Date(today);
        last30days.setDate(last30days.getDate() - 30);
        const last30daysStart = last30days.getTime();

        const groups: GroupedConversations = {
            pinned: [],
            today: [],
            yesterday: [],
            last7days: [],
            last30days: [],
            older: []
        };

        for (const conv of this.conversations) {
            if (conv.isPinned) {
                groups.pinned.push(conv);
            } else if (conv.updatedAt >= todayStart) {
                groups.today.push(conv);
            } else if (conv.updatedAt >= yesterdayStart) {
                groups.yesterday.push(conv);
            } else if (conv.updatedAt >= last7daysStart) {
                groups.last7days.push(conv);
            } else if (conv.updatedAt >= last30daysStart) {
                groups.last30days.push(conv);
            } else {
                groups.older.push(conv);
            }
        }

        return groups;
    }

    /**
     * Toggle sidebar visibility
     */
    toggleSidebar(): void {
        this.sidebarOpen = !this.sidebarOpen;
        // Refresh list when opening
        if (this.sidebarOpen) {
            this.loadConversations();
        }
    }

    openSidebar(): void {
        this.sidebarOpen = true;
        // Refresh list when opening
        this.loadConversations();
    }

    closeSidebar(): void {
        this.sidebarOpen = false;
    }

    /**
     * Format relative time for display
     */
    formatRelativeTime(timestamp: number): string {
        const now = Date.now();
        const diff = now - timestamp;

        const minutes = Math.floor(diff / 60000);
        const hours = Math.floor(diff / 3600000);
        const days = Math.floor(diff / 86400000);

        if (minutes < 1) return 'now';
        if (minutes < 60) return `${minutes}m`;
        if (hours < 24) return `${hours}h`;
        if (days < 7) return `${days}d`;

        // Show date for older
        const date = new Date(timestamp);
        return date.toLocaleDateString('en-US', { month: 'short', day: 'numeric' });
    }
}

export const chatHistoryStore = new ChatHistoryStore();

/**
 * Context Events Store
 * Tracks real-time context gathering activities for UI display
 */

export interface ContextActivity {
  id: string;
  type: 'search' | 'read' | 'analyze' | 'index';
  message: string;
  status: 'active' | 'done';
  timestamp: number;
}

export interface ContextStats {
  filesFound: number;
  symbolsIndexed: number;
  budgetUsed: number;
}

class ContextEventsStore {
  activities = $state<ContextActivity[]>([]);
  isGathering = $state(false);
  stats = $state<ContextStats>({ filesFound: 0, symbolsIndexed: 0, budgetUsed: 0 });

  private idCounter = 0;

  /** Start a new context gathering session */
  startGathering() {
    this.activities = [];
    this.isGathering = true;
    this.stats = { filesFound: 0, symbolsIndexed: 0, budgetUsed: 0 };
  }

  /** End the context gathering session */
  endGathering(finalStats: ContextStats) {
    this.isGathering = false;
    this.stats = finalStats;
    // Mark all active items as done
    this.activities = this.activities.map(a => ({ ...a, status: 'done' as const }));
  }

  /** Add a new activity */
  addActivity(type: ContextActivity['type'], message: string): string {
    const id = `ctx-${++this.idCounter}`;
    const activity: ContextActivity = {
      id,
      type,
      message,
      status: 'active',
      timestamp: Date.now(),
    };
    this.activities = [...this.activities, activity];
    return id;
  }

  /** Mark an activity as done */
  completeActivity(id: string) {
    this.activities = this.activities.map(a =>
      a.id === id ? { ...a, status: 'done' as const } : a
    );
  }

  /** Update stats during gathering */
  updateStats(partial: Partial<ContextStats>) {
    this.stats = { ...this.stats, ...partial };
  }

  /** Clear all activities */
  clear() {
    this.activities = [];
    this.isGathering = false;
    this.stats = { filesFound: 0, symbolsIndexed: 0, budgetUsed: 0 };
  }

  // Convenience methods for common activities
  searchingWorkspace(query: string): string {
    return this.addActivity('search', `Searching for "${query}"`);
  }

  analyzingIntent(intentType: string): string {
    return this.addActivity('analyze', `Detected intent: ${intentType}`);
  }

  readingFile(filename: string): string {
    return this.addActivity('read', `Reading ${filename}`);
  }

  indexingSymbols(count: number): string {
    return this.addActivity('index', `Found ${count} symbols`);
  }

  foundRelevantFile(filename: string, reason: string): string {
    return this.addActivity('search', `${filename} - ${reason}`);
  }

  analyzingImports(filename: string): string {
    return this.addActivity('analyze', `Analyzing imports in ${filename}`);
  }
}

export const contextEventsStore = new ContextEventsStore();

export type PromptSource = "builtin" | "user" | "server";

export interface PromptTemplate {
  id: string;
  title: string;
  category: string;
  description: string;
  template: string;
  tags: string[];
  author: string;
  source: PromptSource;
  updatedAt: number;
}

interface PromptLibraryPersisted {
  userPrompts: PromptTemplate[];
  favoriteIds: string[];
  recentUsage?: Array<{ id: string; usedAt: number }>;
}

export interface PromptVariable {
  key: string;
  value: string;
}

const STORAGE_KEY = "volt.promptLibrary.v1";

function normalizeToken(value: string): string {
  return value.trim().toLowerCase();
}

function makeSearchIndexText(prompt: PromptTemplate): string {
  return normalizeToken(
    [
      prompt.title,
      prompt.description,
      prompt.category,
      prompt.author,
      ...prompt.tags,
    ].join(" "),
  );
}

function extractTemplateVariables(template: string): string[] {
  const regex = /\{\{\s*([a-zA-Z0-9_]+)\s*\}\}/g;
  const found = new Set<string>();
  let match: RegExpExecArray | null = null;
  while ((match = regex.exec(template)) !== null) {
    const key = match[1]?.trim();
    if (key) found.add(key);
  }
  return [...found];
}

function renderTemplate(
  template: string,
  variables: Record<string, string>,
): string {
  return template.replace(/\{\{\s*([a-zA-Z0-9_]+)\s*\}\}/g, (_full, key) => {
    const v = variables[key];
    return typeof v === "string" ? v : "";
  });
}

class PromptLibraryStore {
  isOpen = $state(false);
  isLoading = $state(false);
  searchQuery = $state("");
  activeCategory = $state("All");
  showFavoritesOnly = $state(false);

  builtinPrompts = $state<PromptTemplate[]>([]);
  userPrompts = $state<PromptTemplate[]>([]);
  favoriteIds = $state<Set<string>>(new Set());
  recentUsage = $state<Map<string, number>>(new Map());

  private searchIndex = $state<Map<string, string>>(new Map());
  private loaded = false;

  get allPrompts(): PromptTemplate[] {
    return [...this.userPrompts, ...this.builtinPrompts];
  }

  get filteredPrompts(): PromptTemplate[] {
    let prompts = this.allPrompts;

    if (this.showFavoritesOnly) {
      prompts = prompts.filter((p) => this.favoriteIds.has(p.id));
    }

    if (this.activeCategory !== "All") {
      prompts = prompts.filter((p) => p.category === this.activeCategory);
    }

    const query = normalizeToken(this.searchQuery);
    if (query.length > 0) {
      prompts = prompts.filter((p) => {
        const indexed = this.searchIndex.get(p.id) ?? makeSearchIndexText(p);
        return indexed.includes(query);
      });
    }

    return prompts.sort((a, b) => {
      if (this.favoriteIds.has(a.id) && !this.favoriteIds.has(b.id)) return -1;
      if (!this.favoriteIds.has(a.id) && this.favoriteIds.has(b.id)) return 1;
      return b.updatedAt - a.updatedAt;
    });
  }

  get recentPrompts(): PromptTemplate[] {
    const allById = new Map(this.allPrompts.map((p) => [p.id, p] as const));
    return [...this.recentUsage.entries()]
      .sort((a, b) => b[1] - a[1])
      .map(([id]) => allById.get(id))
      .filter((p): p is PromptTemplate => Boolean(p))
      .slice(0, 6);
  }

  get categories(): string[] {
    const values = new Set<string>();
    for (const p of this.allPrompts) values.add(p.category);
    return ["All", ...[...values].sort()];
  }

  getCategoryCount(category: string): number {
    if (category === "All") return this.allPrompts.length;
    return this.allPrompts.filter((p) => p.category === category).length;
  }

  async ensureLoaded(): Promise<void> {
    if (this.loaded || this.isLoading) return;
    this.isLoading = true;
    try {
      this.loadPersisted();
      await this.loadBuiltinPrompts();
      this.rebuildSearchIndex();
      this.loaded = true;
    } finally {
      this.isLoading = false;
    }
  }

  open(): void {
    this.isOpen = true;
    void this.ensureLoaded();
  }

  close(): void {
    this.isOpen = false;
  }

  toggleOpen(): void {
    this.isOpen ? this.close() : this.open();
  }

  setSearchQuery(query: string): void {
    this.searchQuery = query;
  }

  setCategory(category: string): void {
    this.activeCategory = category;
  }

  toggleFavoritesOnly(): void {
    this.showFavoritesOnly = !this.showFavoritesOnly;
  }

  isFavorite(id: string): boolean {
    return this.favoriteIds.has(id);
  }

  toggleFavorite(id: string): void {
    if (this.favoriteIds.has(id)) {
      this.favoriteIds.delete(id);
    } else {
      this.favoriteIds.add(id);
    }
    this.favoriteIds = new Set(this.favoriteIds);
    this.persist();
  }

  recordUsage(id: string): void {
    const next = new Map(this.recentUsage);
    next.set(id, Date.now());
    this.recentUsage = next;
    this.persist();
  }

  clearRecentUsage(): void {
    this.recentUsage = new Map();
    this.persist();
  }

  addUserPrompt(input: {
    title: string;
    category: string;
    description: string;
    template: string;
    tags?: string[];
  }): PromptTemplate {
    const prompt: PromptTemplate = {
      id: `user-${crypto.randomUUID()}`,
      title: input.title.trim(),
      category: input.category.trim() || "Custom",
      description: input.description.trim(),
      template: input.template,
      tags: (input.tags ?? []).map((t) => t.trim()).filter(Boolean),
      author: "You",
      source: "user",
      updatedAt: Date.now(),
    };
    this.userPrompts = [prompt, ...this.userPrompts];
    this.upsertSearchIndex(prompt);
    this.persist();
    return prompt;
  }

  deleteUserPrompt(id: string): void {
    const before = this.userPrompts.length;
    this.userPrompts = this.userPrompts.filter((p) => p.id !== id);
    if (this.userPrompts.length !== before) {
      this.favoriteIds.delete(id);
      this.favoriteIds = new Set(this.favoriteIds);
      this.recentUsage.delete(id);
      this.recentUsage = new Map(this.recentUsage);
      this.searchIndex.delete(id);
      this.searchIndex = new Map(this.searchIndex);
      this.persist();
    }
  }

  extractVariables(prompt: PromptTemplate): PromptVariable[] {
    return extractTemplateVariables(prompt.template).map((key) => ({
      key,
      value: "",
    }));
  }

  renderPrompt(prompt: PromptTemplate, values: Record<string, string>): string {
    return renderTemplate(prompt.template, values);
  }

  private async loadBuiltinPrompts(): Promise<void> {
    const loadFrom = async (url: string): Promise<PromptTemplate[] | null> => {
      const response = await fetch(url, { cache: "no-store" });
      if (!response.ok) return null;
      const raw = (await response.json()) as PromptTemplate[];
      return raw.map((p) => ({
        ...p,
        source: p.source ?? "builtin",
        tags: Array.isArray(p.tags) ? p.tags : [],
      }));
    };

    try {
      const fromIndex = await loadFrom("/prompts.index.json");
      if (fromIndex) {
        this.builtinPrompts = fromIndex;
        return;
      }

      // Backward compatibility (legacy single-file catalog)
      const fromLegacy = await loadFrom("/prompts.json");
      if (fromLegacy) {
        this.builtinPrompts = fromLegacy;
        return;
      }

      throw new Error("No prompt catalog found (prompts.index.json / prompts.json)");
    } catch (err) {
      console.error("[PromptLibrary] Failed to load builtin prompts:", err);
      this.builtinPrompts = [];
    }
  }

  private loadPersisted(): void {
    if (typeof window === "undefined") return;
    try {
      const raw = localStorage.getItem(STORAGE_KEY);
      if (!raw) return;
      const parsed = JSON.parse(raw) as PromptLibraryPersisted;
      this.userPrompts = Array.isArray(parsed.userPrompts)
        ? parsed.userPrompts.filter((p) => p?.id && p?.template)
        : [];
      this.favoriteIds = new Set(
        Array.isArray(parsed.favoriteIds) ? parsed.favoriteIds : [],
      );
      this.recentUsage = new Map(
        Array.isArray(parsed.recentUsage)
          ? parsed.recentUsage
              .filter(
                (r): r is { id: string; usedAt: number } =>
                  Boolean(r && typeof r.id === "string" && Number.isFinite(r.usedAt)),
              )
              .map((r) => [r.id, r.usedAt] as const)
          : [],
      );
    } catch (err) {
      console.warn("[PromptLibrary] Failed to load persisted data:", err);
      this.userPrompts = [];
      this.favoriteIds = new Set();
      this.recentUsage = new Map();
    }
  }

  private persist(): void {
    if (typeof window === "undefined") return;
    try {
      const payload: PromptLibraryPersisted = {
        userPrompts: this.userPrompts,
        favoriteIds: [...this.favoriteIds],
        recentUsage: [...this.recentUsage.entries()]
          .sort((a, b) => b[1] - a[1])
          .slice(0, 40)
          .map(([id, usedAt]) => ({ id, usedAt })),
      };
      localStorage.setItem(STORAGE_KEY, JSON.stringify(payload));
    } catch (err) {
      console.warn("[PromptLibrary] Failed to persist data:", err);
    }
  }

  private rebuildSearchIndex(): void {
    const next = new Map<string, string>();
    for (const p of this.allPrompts) {
      next.set(p.id, makeSearchIndexText(p));
    }
    this.searchIndex = next;
  }

  private upsertSearchIndex(prompt: PromptTemplate): void {
    const next = new Map(this.searchIndex);
    next.set(prompt.id, makeSearchIndexText(prompt));
    this.searchIndex = next;
  }
}

export const promptLibraryStore = new PromptLibraryStore();

/**
 * Tool observability store
 * Captures execution telemetry for dashboards and debugging.
 */

export interface ToolExecutionEvent {
  timestamp: number;
  toolName: string;
  signature: string;
  idempotencyKey?: string;
  durationMs: number;
  success: boolean;
  code: string;
  retryable: boolean;
  attempt: number;
  maxAttempts: number;
  replayed: boolean;
  budgetMs?: number;
  latencyStatus?: ToolLatencyStatus;
}

export type ToolLatencyStatus = 'ok' | 'slow' | 'critical';

export interface ToolAggregate {
  toolName: string;
  total: number;
  success: number;
  failed: number;
  retries: number;
  avgLatencyMs: number;
  p95LatencyMs: number;
  errorRate: number;
  slowCount: number;
  criticalCount: number;
  slowRate: number;
}

const MAX_EVENTS = 3000;

const LATENCY_BUDGETS_MS: Record<string, { warn: number; critical: number }> = {
  // Read/search
  list_dir: { warn: 1200, critical: 3000 },
  read_file: { warn: 1200, critical: 3000 },
  read_files: { warn: 1500, critical: 3500 },
  workspace_search: { warn: 1800, critical: 4500 },
  find_files: { warn: 1800, critical: 4500 },
  read_code: { warn: 1800, critical: 4500 },
  file_outline: { warn: 1200, critical: 3000 },
  search_symbols: { warn: 1800, critical: 4500 },
  // Write/edit
  write_file: { warn: 2500, critical: 7000 },
  append_file: { warn: 2500, critical: 7000 },
  str_replace: { warn: 2500, critical: 7000 },
  multi_replace: { warn: 3000, critical: 8000 },
  replace_lines: { warn: 2500, critical: 7000 },
  format_file: { warn: 3500, critical: 9000 },
  // Diagnostics/LSP
  get_diagnostics: { warn: 1800, critical: 5000 },
  get_tool_metrics: { warn: 1000, critical: 2500 },
  // Terminal/process
  run_command: { warn: 7000, critical: 20000 },
  start_process: { warn: 4000, critical: 12000 },
  get_process_output: { warn: 2000, critical: 6000 },
};

const DEFAULT_BUDGET = { warn: 2000, critical: 6000 };

function percentile(values: number[], p: number): number {
  if (values.length === 0) return 0;
  const sorted = [...values].sort((a, b) => a - b);
  const idx = Math.min(sorted.length - 1, Math.floor((p / 100) * sorted.length));
  return sorted[idx] ?? 0;
}

function getBudget(toolName: string): { warn: number; critical: number } {
  if (toolName.startsWith('lsp_')) return { warn: 2200, critical: 6500 };
  if (toolName.startsWith('mcp_')) return { warn: 3000, critical: 9000 };
  return LATENCY_BUDGETS_MS[toolName] ?? DEFAULT_BUDGET;
}

function classifyLatency(durationMs: number, budget: { warn: number; critical: number }): ToolLatencyStatus {
  if (durationMs >= budget.critical) return 'critical';
  if (durationMs >= budget.warn) return 'slow';
  return 'ok';
}

class ToolObservabilityStore {
  events = $state<ToolExecutionEvent[]>([]);

  record(event: ToolExecutionEvent): void {
    const budget = getBudget(event.toolName);
    const normalized: ToolExecutionEvent = {
      ...event,
      budgetMs: event.budgetMs ?? budget.warn,
      latencyStatus: event.latencyStatus ?? classifyLatency(event.durationMs, budget),
    };
    this.events = [...this.events, normalized];
    if (this.events.length > MAX_EVENTS) {
      this.events = this.events.slice(-MAX_EVENTS);
    }
  }

  clear(): void {
    this.events = [];
  }

  get totalExecutions(): number {
    return this.events.length;
  }

  get successRate(): number {
    if (this.events.length === 0) return 1;
    const success = this.events.filter((e) => e.success).length;
    return success / this.events.length;
  }

  get toolAggregates(): ToolAggregate[] {
    const byTool = new Map<string, ToolExecutionEvent[]>();
    for (const event of this.events) {
      const group = byTool.get(event.toolName) ?? [];
      group.push(event);
      byTool.set(event.toolName, group);
    }

    const out: ToolAggregate[] = [];
    for (const [toolName, group] of byTool) {
      const total = group.length;
      const success = group.filter((e) => e.success).length;
      const failed = total - success;
      const retries = group.filter((e) => e.attempt > 1).length;
      const latencies = group.map((e) => e.durationMs);
      const slowCount = group.filter((e) => e.latencyStatus === 'slow').length;
      const criticalCount = group.filter((e) => e.latencyStatus === 'critical').length;
      const avgLatencyMs =
        latencies.reduce((acc, v) => acc + v, 0) / Math.max(1, latencies.length);
      const p95LatencyMs = percentile(latencies, 95);

      out.push({
        toolName,
        total,
        success,
        failed,
        retries,
        avgLatencyMs,
        p95LatencyMs,
        errorRate: failed / Math.max(1, total),
        slowCount,
        criticalCount,
        slowRate: (slowCount + criticalCount) / Math.max(1, total),
      });
    }

    return out.sort((a, b) => b.total - a.total);
  }

  get topFailingSignatures(): Array<{ signature: string; failures: number; lastSeen: number }> {
    const failures = this.events.filter((e) => !e.success);
    const bySignature = new Map<string, { failures: number; lastSeen: number }>();

    for (const event of failures) {
      const current = bySignature.get(event.signature) ?? { failures: 0, lastSeen: 0 };
      current.failures += 1;
      current.lastSeen = Math.max(current.lastSeen, event.timestamp);
      bySignature.set(event.signature, current);
    }

    return Array.from(bySignature.entries())
      .map(([signature, stats]) => ({ signature, ...stats }))
      .sort((a, b) => b.failures - a.failures)
      .slice(0, 20);
  }

  get topSlowTools(): Array<{ toolName: string; slowRate: number; criticalCount: number; p95LatencyMs: number }> {
    return this.toolAggregates
      .filter((x) => x.slowCount + x.criticalCount > 0)
      .sort((a, b) => {
        if (b.slowRate !== a.slowRate) return b.slowRate - a.slowRate;
        return b.p95LatencyMs - a.p95LatencyMs;
      })
      .slice(0, 20)
      .map((x) => ({
        toolName: x.toolName,
        slowRate: x.slowRate,
        criticalCount: x.criticalCount,
        p95LatencyMs: x.p95LatencyMs,
      }));
  }

  get recentSlowEvents(): ToolExecutionEvent[] {
    return this.events
      .filter((e) => e.latencyStatus === 'slow' || e.latencyStatus === 'critical')
      .slice(-50);
  }
}

