  async goForward(): Promise<void> {
    if (!this.canGoForward || this.historyIndex >= this.historyStack.length - 1) return;
    this.historyIndex++;
    this.url = this.historyStack[this.historyIndex];
    this.status = 'loading';
    this.updateNavState();
    try {
