    this.isTogglingSelectMode = true;
    const newMode = this.mode === 'select' ? 'normal' : 'select';
    
    try {
      if (newMode === 'select') {
        // Reset stale picker/highlight state before enabling
        await this.disableSelectModeAfterPick();

        // Try CDP-based element picker first (more reliable)
        try {
          const { connectCdpToBrowser } = await import('$features/browser/services');
          await connectCdpToBrowser(this.url);
          await invoke('cdp_enable_element_picker');
          this.mode = 'select';
        } catch (cdpErr) {
          // Fallback to old JS injection method
          console.warn('[Browser] CDP element picker failed, using fallback:', cdpErr);
          await invoke('browser_set_select_mode', { enabled: true });
          this.mode = 'select';
        }
      } else {
        // Disable element picker
        await this.disableSelectModeAfterPick();
        this.mode = 'normal';
        // DO NOT clear selectedElement here, so it stays visible in the panel
      }
    } catch (err) {
      console.error('[Browser] Toggle select mode failed:', err);
    } finally {
      this.isTogglingSelectMode = false;
    }
  }

  async executeJs(script: string): Promise<void> {
    if (!this.isOpen) return;
    try {
      await invoke('browser_execute_js', { script });
    } catch (err) {
      console.error('[Browser] Execute JS failed:', err);
    }
  }

  clearSelection(): void {
    this.selectedElement = null;
    this.mode = 'normal';
    // Clear the highlight in the browser
    this.clearSelectionHighlight();
    void this.disableSelectModeAfterPick();
  }

  private async disableSelectModeAfterPick(): Promise<void> {
    if (!this.isOpen) return;
    try {
      await invoke('cdp_disable_element_picker');
    } catch { /* ignore */ }
    try {
      await invoke('browser_set_select_mode', { enabled: false });
    } catch { /* ignore */ }
  }

  /** Clear the selection highlight in the browser (without clearing selectedElement state) */
  private async clearSelectionHighlight(): Promise<void> {
    if (!this.isOpen) return;
    try {
      // Try CDP method first
      await invoke('cdp_disable_element_picker');
    } catch {
      // Fallback to JS injection
      try {
        await invoke('browser_execute_js', { 
          script: 'if(window.__voltClearSelectionHighlight) window.__voltClearSelectionHighlight();' 
        });
      } catch { /* ignore */ }
    }
  }

  // ==================== LIVE RELOAD ====================
  
  /**
   * Toggle live reload on/off
   */
  setLiveReload(enabled: boolean): void {
    this.liveReloadEnabled = enabled;
    if (typeof localStorage !== 'undefined') {
      localStorage.setItem(BrowserStore.LIVE_RELOAD_KEY, String(enabled));
    }
    
    if (enabled && this.isOpen) {
      this.startLiveReload();
    } else {
      this.stopLiveReload();
    }
  }

  /**
   * Start watching project files for changes
   * Triggers browser reload when files change
   */
  private async startLiveReload(): Promise<void> {
    if (this.liveReloadUnlisten) return; // Already watching
    
    try {
      // Listen for file change events from Tauri file watcher
      this.liveReloadUnlisten = await listen<{ changes: Array<{ kind: string; paths: string[] }> }>('file-watch://change', (event) => {
        if (!this.liveReloadEnabled || !this.isOpen || !this.isVisible) return;
        
        const { changes } = event.payload;
        
        // Check if any change is a web file we care about
        const webExtensions = ['.html', '.css', '.js', '.ts', '.jsx', '.tsx', '.vue', '.svelte', '.json'];
        
        for (const change of changes) {
          // Only reload on modify or create events
          if (change.kind !== 'modify' && change.kind !== 'create') continue;
          
          for (const path of change.paths) {
            const isWebFile = webExtensions.some(ext => path.toLowerCase().endsWith(ext));
            if (isWebFile) {
              this.triggerLiveReload();
              return; // One reload is enough
            }
          }
        }
      });
    } catch (err) {
      console.error('[Browser] Failed to start live reload:', err);
    }
  }

  /**
   * Stop watching for file changes
   */
  private stopLiveReload(): void {
    if (this.liveReloadUnlisten) {
      this.liveReloadUnlisten();
      this.liveReloadUnlisten = null;
    }
    if (this.reloadDebounceTimer) {
      clearTimeout(this.reloadDebounceTimer);
      this.reloadDebounceTimer = null;
    }
  }

  /**
   * Trigger a debounced reload
   * Prevents multiple rapid reloads and avoids conflict with native HMR
   */
  private triggerLiveReload(): void {
    // skip reload in development mode to prevent recursive window reloads
    if (import.meta.env.DEV) {
      console.log('[Browser] Skipping live reload in dev mode');
      return;
    }

    // Clear any pending reload
    if (this.reloadDebounceTimer) {
      clearTimeout(this.reloadDebounceTimer);
    }
    
    // Debounce: wait 300ms before reloading
    this.reloadDebounceTimer = setTimeout(async () => {
      // Check if we recently reloaded (native HMR might have handled it)
      const now = Date.now();
      if (now - this.lastReloadTime < 1000) {
        return; // Skip - likely native HMR already handled it
      }
      
      this.lastReloadTime = now;
      await this.reload();
    }, 300);
  }

  // ==================== END LIVE RELOAD ====================

  private updateNavState(): void {
    this.canGoBack = this.historyIndex > 0;
    this.canGoForward = this.historyIndex < this.historyStack.length - 1;
  }

  /**
   * Inject devtools capture scripts into the browser
   * Called after navigation to capture console, errors, network
   */
  private async injectDevToolsScripts(): Promise<void> {
    if (!this.isOpen) return;
    
    // Wait a bit for page to start loading
    await new Promise(resolve => setTimeout(resolve, 500));
    
    try {
      // Import dynamically to avoid circular deps
      const { getDevToolsScript } = await import('$features/browser/services/devtools-inject');
      const script = getDevToolsScript();
      await this.executeJs(script);
    } catch (err) {
      console.error('[Browser] Failed to inject devtools:', err);
    }
  }

  async setBounds(bounds: BrowserBounds): Promise<void> {
    if (!this.isOpen) return;

    if (this.lastBounds) {
      const dx = Math.abs(bounds.x - this.lastBounds.x);
      const dy = Math.abs(bounds.y - this.lastBounds.y);
      const dw = Math.abs(bounds.width - this.lastBounds.width);
      const dh = Math.abs(bounds.height - this.lastBounds.height);
      if (dx < 1 && dy < 1 && dw < 1 && dh < 1) return;
    }

    this.pendingBounds = { ...bounds };

    if (this.boundsTimer) {
      clearTimeout(this.boundsTimer);
    }

    this.boundsTimer = setTimeout(async () => {
      if (!this.pendingBounds || !this.isOpen) return;
      
      const b = this.pendingBounds;
      this.lastBounds = { ...b };
      
      if (b.width < 50 || b.height < 50) return;

      try {
        if (!this.webviewCreated) {
          if (this.isCreatingWebview) return;
          this.isCreatingWebview = true;
          await invoke('browser_create', { url: this.url, bounds: b });
          this.status = 'ready';
          this.webviewCreated = true;
          this.isCreatingWebview = false;
        } else {
          await invoke('browser_set_bounds', { bounds: b });
        }
      } catch (err) {
        console.error('[Browser] Set bounds failed:', err);
        this.status = 'error';
        this.error = err instanceof Error ? err.message : String(err);
        this.webviewCreated = false;
        this.isCreatingWebview = false;
      }
    }, 30);
  }

  async hide(): Promise<void> {
    try {
      await invoke('browser_hide');
    } catch { /* ignore */ }
  }

  async show(): Promise<void> {
    try {
      await invoke('browser_show');
    } catch { /* ignore */ }
  }

  private async setupListeners(): Promise<void> {
    const unlistenSelect = await listen<SelectedElement>('browser://element-selected', (event) => {
      const now = Date.now();
      if (now - this.lastSelectAt < 200) return;
      this.lastSelectAt = now;
      this.selectedElement = event.payload;
      this.mode = 'normal'; // Auto-exit select mode when element is picked
      void this.disableSelectModeAfterPick();
    });
    this.unlisteners.push(unlistenSelect);

    const unlistenNav = await listen<string>('browser://navigated', async (event) => {
      this.url = event.payload;
      this.status = 'ready';
      
      // Check if CDP is connected, if not try to connect or fallback to JS injection
      try {
        const { cdp } = await import('$features/browser/services/cdp');
        const status = await cdp.getStatus();
        if (!status.connected) {
          // Try CDP first - pass the browser URL so it attaches to the right page
          const { connectCdpToBrowser } = await import('$features/browser/services');
          const cdpConnected = await connectCdpToBrowser(this.url);
          if (!cdpConnected) {
            this.injectDevToolsScripts();
          }
        }
        // CDP is connected, events will flow through CDP
      } catch {
        // Fallback to JS injection
        this.injectDevToolsScripts();
      }
    });
    this.unlisteners.push(unlistenNav);

    const unlistenCreated = await listen<string>('browser://created', async (event) => {
      this.status = 'ready';
      
      // Try to connect CDP for professional browser automation
      try {
        const { connectCdpToBrowser } = await import('$features/browser/services');
        // Pass the browser URL so CDP attaches to the browser webview, not Volt's main window
        const cdpConnected = await connectCdpToBrowser(this.url);
        if (cdpConnected) {
          // CDP connected - element selection will use CDP
        } else {
          // Fallback to JS injection
          this.injectDevToolsScripts();
        }
      } catch (err) {
        console.warn('[Browser] CDP connection failed, using JS injection:', err);
        this.injectDevToolsScripts();
      }
    });
    this.unlisteners.push(unlistenCreated);

    const unlistenClosed = await listen('browser://closed', () => {
      this.isOpen = false;
      this.status = 'idle';
      this.webviewCreated = false;
    });
    this.unlisteners.push(unlistenClosed);

    const unlistenSelectMode = await listen<boolean>('browser://select-mode', (event) => {
      this.mode = event.payload ? 'select' : 'normal';
    });
    this.unlisteners.push(unlistenSelectMode);

    const unlistenZoom = await listen<number>('browser://zoom-changed', (event) => {
      this.zoomLevel = event.payload;
    });
    this.unlisteners.push(unlistenZoom);

    const unlistenFindResult = await listen<number>('browser://find-result', (event) => {
      this.findCount = event.payload;
    });
    this.unlisteners.push(unlistenFindResult);

    const unlistenContent = await listen<PageContent>('browser://content-extracted', (event) => {
      this.extractedContent = event.payload;
    });
    this.unlisteners.push(unlistenContent);

    const unlistenResponsive = await listen<[number | null, number | null]>('browser://responsive-mode-changed', (event) => {
      const [w, h] = event.payload;
      this.responsiveMode = w && h ? { width: w, height: h } : null;
    });
    this.unlisteners.push(unlistenResponsive);
  }

  async cleanup(): Promise<void> {
    for (const unlisten of this.unlisteners) {
      unlisten();
    }
    this.unlisteners = [];
    
    if (this.boundsTimer) {
      clearTimeout(this.boundsTimer);
      this.boundsTimer = null;
    }
    
    await this.close();
    this.initialized = false;
  }
}

export const browserStore = new BrowserStore();

/**
 * Editor Streaming Service
 * Handles smooth, animated code streaming into Monaco editor
 * Used by AI assistant to show live code generation
 * 
 * Flow:
 * 1. Open file tab in editor (real file, not virtual)
 * 2. Stream content chunk by chunk with visual animation
 * 3. File is saved to disk by the caller after streaming completes
 */

import { loadMonaco, detectLanguage as unifiedDetectLanguage } from '$core/services/monaco-loader';
import { getOrCreateModel, getActiveEditor } from '$core/services/monaco-models';
import { editorStore } from '$features/editor/stores/editor.svelte';
import { projectStore } from '$shared/stores/project.svelte';

export interface StreamingSession {
  id: string;
  path: string;
  content: string;
  position: number;
  active: boolean;
  completed: boolean;
  abortController: AbortController;
  userScrolledAway: boolean; // Track if user manually scrolled
  onProgress?: (progress: StreamingProgress) => void;
  onComplete?: () => void;
  onError?: (error: string) => void;
}

export interface StreamingProgress {
  charsWritten: number;
  totalChars: number;
  linesWritten: number;
  totalLines: number;
  percent: number;
}

export interface StreamingOptions {
  chunkSize?: number;
  chunkDelay?: number;
  autoScroll?: boolean;
  onProgress?: (progress: StreamingProgress) => void;
  onComplete?: () => void;
  onError?: (error: string) => void;
}

const activeSessions = new Map<string, StreamingSession>();

// Fast streaming for good UX
const DEFAULT_CHUNK_SIZE = 100;
const DEFAULT_CHUNK_DELAY = 0;

function generateSessionId(): string {
  return `stream-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`;
}

function countLines(text: string): number {
  if (!text) return 0;
  let count = 1;
  for (let i = 0; i < text.length; i++) {
    if (text.charCodeAt(i) === 10) count++;
  }
  return count;
}


/**
 * Normalize path - convert to workspace-relative with forward slashes
 */
function normalizePath(inputPath: string): string {
  let normalized = inputPath.replace(/\\/g, '/');

  const workspaceRoot = projectStore.rootPath?.replace(/\\/g, '/');
  if (workspaceRoot && normalized.toLowerCase().startsWith(workspaceRoot.toLowerCase())) {
    normalized = normalized.slice(workspaceRoot.length);
    if (normalized.startsWith('/')) {
      normalized = normalized.slice(1);
    }
  }

  return normalized;
}

/**
 * Compare paths - handles both full paths and relative paths
 * Also handles case-insensitivity on Windows
 */
function pathsEqual(a: string, b: string): boolean {
  const normalizedA = a.replace(/\\/g, '/');
  const normalizedB = b.replace(/\\/g, '/');

  // Windows is case-insensitive
  const isWindows = typeof navigator !== 'undefined' &&
    (navigator.userAgent?.toLowerCase().includes('windows') ||
      navigator.userAgent?.toLowerCase().includes('win32'));

  const compare = (x: string, y: string) =>
    isWindows ? x.toLowerCase() === y.toLowerCase() : x === y;

  // Direct match
  if (compare(normalizedA, normalizedB)) {
    return true;
  }

  // Check if one ends with the other (handles full path vs relative path)
  // e.g., "C:/project/src/index.html" should match "src/index.html" or "index.html"
  if (isWindows) {
    const lowerA = normalizedA.toLowerCase();
    const lowerB = normalizedB.toLowerCase();
    return lowerA.endsWith('/' + lowerB) || lowerB.endsWith('/' + lowerA);
  } else {
    return normalizedA.endsWith('/' + normalizedB) || normalizedB.endsWith('/' + normalizedA);
  }
}

/**
 * Start streaming content to an editor
 * Opens the file tab, clears content, and streams character by character
 */
export async function startStreaming(
  path: string,
  content: string,
  options: StreamingOptions = {}
): Promise<StreamingSession> {
  const sessionId = generateSessionId();

  // Normalize the path - keep it as-is if it's already relative
  // Don't strip too much - we need the full relative path
  let normalizedPath = path.replace(/\\/g, '/');

  // If path starts with workspace root, make it relative
  const workspaceRoot = projectStore.rootPath?.replace(/\\/g, '/');
  if (workspaceRoot && normalizedPath.toLowerCase().startsWith(workspaceRoot.toLowerCase())) {
    normalizedPath = normalizedPath.slice(workspaceRoot.length);
    if (normalizedPath.startsWith('/')) {
      normalizedPath = normalizedPath.slice(1);
    }
  }

  // Ensure we have a valid path
  if (!normalizedPath || normalizedPath === 'undefined') {
    throw new Error(`Invalid path for streaming: ${path}`);
  }

  // Cancel any existing session for this path
  const existingSession = Array.from(activeSessions.values()).find(s =>
    pathsEqual(s.path, normalizedPath)
  );
  if (existingSession) {
    existingSession.abortController.abort();
    activeSessions.delete(existingSession.id);
  }

  const session: StreamingSession = {
    id: sessionId,
    path: normalizedPath,
    content,
    position: 0,
    active: true,
    completed: false,
    abortController: new AbortController(),
    userScrolledAway: false,
    onProgress: options.onProgress,
    onComplete: options.onComplete,
    onError: options.onError
  };

  activeSessions.set(sessionId, session);

  try {
    // Load Monaco first
    const monaco = await loadMonaco();

    // Get filename and language
    const filename = normalizedPath.split('/').pop() || 'untitled';
    const language = unifiedDetectLanguage(filename);

    // Build full path for comparison
    const fullPath = workspaceRoot
      ? `${workspaceRoot}/${normalizedPath}`.replace(/\/+/g, '/')
      : normalizedPath;

    // Check if file already exists in editor
    // Try multiple matching strategies since paths can be stored as full or relative
    let existingFile = editorStore.openFiles.find(f => pathsEqual(f.path, normalizedPath)) ??
      editorStore.openFiles.find(f => pathsEqual(f.path, fullPath));

    if (!existingFile) {
      // For streaming, ALWAYS create a virtual file first with empty content
      // This avoids the race condition where we open an empty file from disk
      // The streaming will fill in the content, and the caller saves to disk after
      editorStore.openVirtualFile({
        path: normalizedPath,
        name: filename,
        content: '', // Start empty, we'll stream content
        language,
        readonly: false,
        pinned: false
      });
      existingFile = editorStore.openFiles.find(f => pathsEqual(f.path, normalizedPath));
    } else {
      // Switch to existing file and clear its content for streaming
      editorStore.setActiveFile(existingFile.path);
    }

    // Update session path to match the actual file path in editor store
    const actualPath = existingFile?.path || normalizedPath;
    session.path = actualPath;

    // Wait for editor to be ready - retry a few times
    let editor = getActiveEditor();
    let retries = 0;
    while (!editor && retries < 10) {
      await new Promise(resolve => setTimeout(resolve, 20));
      editor = getActiveEditor();
      retries++;
    }

    if (!editor) {
      throw new Error('Editor not available after waiting');
    }

    // Get or create the Monaco model for this file
    const modelPath = actualPath;
    const model = await getOrCreateModel({
      path: modelPath,
      content: '', // Start empty
      language
    });

    // Clear the model content
    model.setValue('');

    // Make sure this model is set on the editor
    if (editor.getModel() !== model) {
      editor.setModel(model);
    }

    // Start streaming in background (non-blocking)
    streamContentAsync(session, editor, model, monaco, options);

    return session;
  } catch (err) {
    session.active = false;
    const errorMsg = err instanceof Error ? err.message : 'Unknown error';
    session.onError?.(errorMsg);
    activeSessions.delete(sessionId);
    throw err;
  }
}

/**
 * Async streaming loop - writes content chunk by chunk
 */
async function streamContentAsync(
  session: StreamingSession,
  editor: ReturnType<typeof getActiveEditor>,
  model: Awaited<ReturnType<typeof getOrCreateModel>>,
  monaco: Awaited<ReturnType<typeof loadMonaco>>,
  options: StreamingOptions
): Promise<void> {
  const chunkSize = options.chunkSize ?? DEFAULT_CHUNK_SIZE;
  const chunkDelay = options.chunkDelay ?? DEFAULT_CHUNK_DELAY;
  const autoScroll = options.autoScroll ?? true;

  const totalChars = session.content.length;
  const totalLines = countLines(session.content);

  const yieldEveryChunks = chunkDelay === 0 ? 2 : Infinity;
  let chunkCounter = 0;
  let lastProgressAt = 0;
  const progressThrottleMs = 16;

  if (!editor) {
    session.active = false;
    session.onError?.('Editor not available');
    return;
  }

  // Track scroll listener for cleanup
  let scrollListenerDispose: (() => void) | null = null;

  if (autoScroll) {
    // Listen for scroll events to detect when user scrolls away
    const scrollDisposable = editor.onDidScrollChange((e) => {
      if (!session.active) return;

      // Only care about vertical scroll changes initiated by user
      if (e.scrollTopChanged) {
        const visibleRanges = editor.getVisibleRanges();
        if (visibleRanges.length > 0) {
          const lastVisibleLine = visibleRanges[visibleRanges.length - 1].endLineNumber;
          const currentLastLine = model.getLineCount();

          // If user scrolled more than 5 lines away from the bottom, they want to look at something else
          if (currentLastLine - lastVisibleLine > 5) {
            session.userScrolledAway = true;
          } else {
            // User scrolled back to bottom, resume auto-scroll
            session.userScrolledAway = false;
          }
        }
      }
    });

    scrollListenerDispose = () => scrollDisposable.dispose();
  }

  try {
    let linesWritten = 0;

    while (session.position < totalChars && session.active) {
      // Check for abort
      if (session.abortController.signal.aborted) {
        session.active = false;
        session.onError?.('Streaming cancelled');
        return;
      }

      // Calculate chunk end - try to break at natural points
      let chunkEnd = Math.min(session.position + chunkSize, totalChars);

      if (chunkEnd < totalChars) {
        const lookAhead = session.content.slice(session.position, chunkEnd + 15);
        const newlineIdx = lookAhead.indexOf('\n');

        // Prefer breaking at newlines for cleaner streaming
        if (newlineIdx > 0 && newlineIdx <= chunkSize + 5) {
          chunkEnd = session.position + newlineIdx + 1;
        }
      }

      const chunk = session.content.slice(session.position, chunkEnd);

      // Insert chunk at end of document
      const lastLine = model.getLineCount();
      const lastCol = model.getLineMaxColumn(lastLine);

      editor.executeEdits('ai-streaming', [{
        range: new monaco.Range(lastLine, lastCol, lastLine, lastCol),
        text: chunk,
        forceMoveMarkers: true
      }]);

      session.position = chunkEnd;

      // Update line count incrementally (avoid O(n) slice+count each chunk)
      linesWritten += countLines(chunk);

      const now = Date.now();
      if (now - lastProgressAt >= progressThrottleMs) {
        lastProgressAt = now;

        // Auto-scroll to keep cursor visible - but only if user hasn't scrolled away
        if (autoScroll && !session.userScrolledAway) {
          const newLastLine = model.getLineCount();
          editor.revealLine(newLastLine, 1); // Smooth scroll
        }

        // Report progress (throttled)
        session.onProgress?.({
          charsWritten: session.position,
          totalChars,
          linesWritten: Math.min(linesWritten, totalLines),
          totalLines,
          percent: Math.round((session.position / totalChars) * 100)
        });
      }

      // Yield to allow UI paint when delay is 0
      chunkCounter++;
      if (chunkCounter % yieldEveryChunks === 0) {
        await new Promise<void>((resolve) => setTimeout(resolve, 0));
      }

      // Small delay for visual effect (yield to UI)
      if (chunkDelay > 0 && session.position < totalChars) {
        await new Promise(resolve => setTimeout(resolve, chunkDelay));
      }
    }

    // Mark as completed
    session.active = false;
    session.completed = true;

    // Update editor store with final content so it shows as "dirty"
    editorStore.updateContent(session.path, session.content);

    // Final progress update
    session.onProgress?.({
      charsWritten: totalChars,
      totalChars,
      linesWritten: totalLines,
      totalLines,
      percent: 100
    });

    session.onComplete?.();
  } catch (err) {
    session.active = false;
    const errorMsg = err instanceof Error ? err.message : 'Streaming error';
    session.onError?.(errorMsg);
  } finally {
    // Clean up scroll listener
    scrollListenerDispose?.();
    activeSessions.delete(session.id);
  }
}

/**
 * Cancel a streaming session
 */
export function cancelStreaming(sessionId: string): void {
  const session = activeSessions.get(sessionId);
  if (session) {
    session.abortController.abort();
    session.active = false;
    activeSessions.delete(sessionId);
  }
}

/**
 * Cancel all streaming sessions for a path
 */
export function cancelStreamingForPath(path: string): void {
  const normalizedPath = normalizePath(path);
  for (const [id, session] of activeSessions) {
    if (session.path === normalizedPath) {
      session.abortController.abort();
      session.active = false;
      activeSessions.delete(id);
    }
  }
}

/**
 * Check if a path is currently being streamed to
 */
export function isStreaming(path: string): boolean {
  const normalizedPath = normalizePath(path);
  return Array.from(activeSessions.values()).some(
    s => s.path === normalizedPath && s.active
  );
}

/**
 * Get streaming progress for a path
 */
export function getStreamingProgress(path: string): StreamingProgress | null {
  const normalizedPath = normalizePath(path);
  const session = Array.from(activeSessions.values()).find(
    s => s.path === normalizedPath
  );

  if (!session) return null;

  const totalChars = session.content.length;
  const totalLines = countLines(session.content);
  const linesWritten = countLines(session.content.slice(0, session.position));

  return {
    charsWritten: session.position,
    totalChars,
    linesWritten,
    totalLines,
    percent: Math.round((session.position / totalChars) * 100)
  };
}

/**
 * Start streaming a surgical edit to an editor
 * Replaces originalSnippet with newSnippet progressively
 */
export async function startStreamingEdit(
  path: string,
  originalSnippet: string,
  newSnippet: string,
  options: StreamingOptions = {}
): Promise<StreamingSession> {
  const sessionId = generateSessionId();
  let normalizedPath = normalizePath(path);
  const workspaceRoot = projectStore.rootPath?.replace(/\\/g, '/');

  // Normalize logic similar to startStreaming
  if (workspaceRoot && normalizedPath.toLowerCase().startsWith(workspaceRoot.toLowerCase())) {
    normalizedPath = normalizedPath.slice(workspaceRoot.length);
    if (normalizedPath.startsWith('/')) normalizedPath = normalizedPath.slice(1);
  }

  // Cancel existing sessions
  const existingSession = Array.from(activeSessions.values()).find(s =>
    pathsEqual(s.path, normalizedPath)
  );
  if (existingSession) {
    existingSession.abortController.abort();
    activeSessions.delete(existingSession.id);
  }

  const session: StreamingSession = {
    id: sessionId,
    path: normalizedPath,
    content: newSnippet, // We stream the NEW content
    position: 0,
    active: true,
    completed: false,
    abortController: new AbortController(),
    userScrolledAway: false,
    onProgress: options.onProgress,
    onComplete: options.onComplete,
    onError: options.onError
  };

  activeSessions.set(sessionId, session);

  try {
    const monaco = await loadMonaco();

    // Open/Find file (reusing logic from startStreaming is hard without refactoring, duplicating slightly for safety)
    const filename = normalizedPath.split('/').pop() || 'untitled';
    const language = unifiedDetectLanguage(filename);
    const fullPath = workspaceRoot ? `${workspaceRoot}/${normalizedPath}` : normalizedPath;

    let existingFile = editorStore.openFiles.find(f => pathsEqual(f.path, normalizedPath)) ??
      editorStore.openFiles.find(f => pathsEqual(f.path, fullPath));

    if (!existingFile) {
      const opened = await editorStore.openFile(fullPath);
      if (opened) {
        existingFile = editorStore.activeFile ??
          editorStore.openFiles.find(f => pathsEqual(f.path, normalizedPath));
      }
    } else {
      editorStore.setActiveFile(existingFile.path);
    }

    const actualPath = existingFile?.path || normalizedPath;
    session.path = actualPath;

    // Wait for editor
    let editor = getActiveEditor();
    let retries = 0;
    while (!editor && retries < 10) {
      await new Promise(resolve => setTimeout(resolve, 20));
      editor = getActiveEditor();
      retries++;
    }

    if (!editor) throw new Error('Editor not available');

    const model = await getOrCreateModel({ path: actualPath, content: '', language }); // Content ignored if exists

    // Locate the original snippet
    const modelContent = model.getValue();
    // Normalize line endings for search
    const normalizedModelContent = modelContent.replace(/\r\n/g, '\n');
    const normalizedSnippet = originalSnippet.replace(/\r\n/g, '\n');

    const startIndex = normalizedModelContent.indexOf(normalizedSnippet);
    if (startIndex === -1) {
      // Try fuzzy match (trim)
      const trimmedSnippet = normalizedSnippet.trim();
      const trimmedStart = normalizedModelContent.indexOf(trimmedSnippet);
      if (trimmedStart === -1) {
        // Don't fail yet; Monaco regex matching below is more robust.
      }
      // Use the found index
      // Need to map back to Monaco Position. 
      // Monaco's `getPositionAt` works on the model's text (which might be CRLF)
      // If we used normalized search, indices might differ slightly if file matches CRLF.
      // Ideally use model.findMatches() which is safer.
    }

    // Use Monaco's findMatches with Regex to handle CRLF/LF differences
    // Escape the snippet for regex usage
    const escapedSnippet = originalSnippet.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
    // Replace newlines with a pattern that matches any EOL sequence
    const regexPattern = escapedSnippet.replace(/\n/g, '\\r?\\n');

    const matches = model.findMatches(regexPattern, false, true, false, null, true);
    let matchRange: any = null;

    if (matches.length > 0) {
      matchRange = matches[0].range;
    } else {
      // Fallback: try finding trimmed version (also with regex)
      const trimmedSnippet = originalSnippet.trim();
      const escapedTrimmed = trimmedSnippet.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
      const regexTrimmed = escapedTrimmed.replace(/\n/g, '\\r?\\n');

      const trimmedMatches = model.findMatches(regexTrimmed, false, true, false, null, true);
      if (trimmedMatches.length > 0) {
        matchRange = trimmedMatches[0].range;
      } else {
        const normalized = trimmedSnippet.replace(/\r\n/g, '\n').trim();
        const parts = normalized.split(/\s+/).filter(Boolean).map((p) => p.replace(/[.*+?^${}()|[\]\\]/g, '\\$&'));
        const whitespaceRegex = parts.join('\\s+');
        const wsMatches = whitespaceRegex
          ? model.findMatches(whitespaceRegex, false, true, false, null, true)
          : [];

        if (wsMatches.length > 0) {
          matchRange = wsMatches[0].range;
        } else {
          // Debug: log what we tried to find
          console.warn('[startStreamingEdit] Snippet not found via regex:', regexPattern.slice(0, 100));
          throw new Error('Original snippet not found in file (visual match failed)');
        }
      }
    }

    // Delete the original range
    editor.executeEdits('ai-streaming-edit', [{
      range: matchRange,
      text: '', // Delete
      forceMoveMarkers: true
    }]);

    // Set cursor to start of deletion
    const startPos = matchRange.getStartPosition();
    editor.setPosition(startPos);
    editor.revealPositionInCenter(startPos);

    // Start streaming new content at this position
    streamEditContentAsync(session, editor, model, monaco, startPos, originalSnippet, options);

    return session;

  } catch (err) {
    session.active = false;
    const errorMsg = err instanceof Error ? err.message : 'Unknown error';
    session.onError?.(errorMsg);
    activeSessions.delete(sessionId);
    throw err;
  }
}

/**
 * Async loop for streaming edits at a specific position
 */
async function streamEditContentAsync(
  session: StreamingSession,
  editor: ReturnType<typeof getActiveEditor>,
  model: Awaited<ReturnType<typeof getOrCreateModel>>,
  monaco: Awaited<ReturnType<typeof loadMonaco>>,
  startPosition: any, // monaco.Position
  originalSnippet: string,
  options: StreamingOptions
): Promise<void> {
  if (!editor) {
    session.active = false;
    session.onError?.('No active editor available for streaming edit');
    return;
  }

  const chunkSize = options.chunkSize ?? DEFAULT_CHUNK_SIZE;
  const chunkDelay = options.chunkDelay ?? DEFAULT_CHUNK_DELAY;

  const totalChars = session.content.length;
  const totalLines = countLines(session.content);

  const yieldEveryChunks = chunkDelay === 0 ? 2 : Infinity;
  let chunkCounter = 0;
  let lastProgressAt = 0;
  const progressThrottleMs = 16;

  // Track insertion point
  let currentLine = startPosition.lineNumber;
  let currentColumn = startPosition.column;

  let linesWritten = 0;

  const restoreOriginal = (reason: string): void => {
    try {
      const endPos = new monaco.Position(currentLine, currentColumn);
      const range = new monaco.Range(
        startPosition.lineNumber,
        startPosition.column,
        endPos.lineNumber,
        endPos.column
      );
      editor.executeEdits('ai-streaming-edit-restore', [{
        range,
        text: originalSnippet,
        forceMoveMarkers: true
      }]);
      editorStore.updateContent(session.path, model.getValue());
    } catch (err) {
      console.warn('[streamEditContentAsync] Failed to restore original snippet:', err);
    } finally {
      session.onError?.(reason);
    }
  };

  try {
    while (session.position < totalChars && session.active) {
      if (session.abortController.signal.aborted) {
        session.active = false;
        restoreOriginal('Streaming cancelled');
        return;
      }

      let chunkEnd = Math.min(session.position + chunkSize, totalChars);
      // Nice breaking at newlines
      if (chunkEnd < totalChars) {
        const lookAhead = session.content.slice(session.position, chunkEnd + 15);
        const newlineIdx = lookAhead.indexOf('\n');
        if (newlineIdx > 0 && newlineIdx <= chunkSize + 5) {
          chunkEnd = session.position + newlineIdx + 1;
        }
      }

      const chunk = session.content.slice(session.position, chunkEnd);

      // Insert at current cursor position
      const range = new monaco.Range(currentLine, currentColumn, currentLine, currentColumn);

      editor.executeEdits('ai-streaming-edit', [{
        range,
        text: chunk,
        forceMoveMarkers: true
      }]);

      // Update position for next chunk
      // We can rely on Monaco to move the cursor if we set it, or calculate new pos
      // Simplest is to ask model for position after edit? 
      // Actually `executeEdits` doesn't update cursor auto unless we tell it or read back.
      // Better: Update our tracking based on chunk content.
      const chunkLines = chunk.split('\n');
      if (chunkLines.length > 1) {
        currentLine += chunkLines.length - 1;
        currentColumn = chunkLines[chunkLines.length - 1].length + 1;
      } else {
        currentColumn += chunk.length;
      }

      linesWritten += chunkLines.length;

      session.position = chunkEnd;

      const now = Date.now();
      if (now - lastProgressAt >= progressThrottleMs) {
        lastProgressAt = now;

        // Reveal cursor (throttled)
        editor.revealPosition(new monaco.Position(currentLine, currentColumn));

        session.onProgress?.({
          charsWritten: session.position,
          totalChars,
          linesWritten: Math.min(linesWritten, totalLines),
          totalLines,
          percent: Math.round((session.position / totalChars) * 100)
        });
      }

      chunkCounter++;
      if (chunkCounter % yieldEveryChunks === 0) {
        await new Promise<void>((resolve) => setTimeout(resolve, 0));
      }

      if (chunkDelay > 0 && session.position < totalChars) {
        await new Promise(resolve => setTimeout(resolve, chunkDelay));
      }
    }

    session.active = false;
    session.completed = true;
    editorStore.updateContent(session.path, model.getValue());

    session.onProgress?.({
      charsWritten: totalChars,
      totalChars,
      linesWritten: totalLines,
      totalLines,
      percent: 100
    });

    session.onComplete?.();

  } catch (err) {
    session.active = false;
    restoreOriginal(err instanceof Error ? err.message : 'Streaming error');
  } finally {
    activeSessions.delete(session.id);
  }
}

/**
 * Diff View Store - Manages Monaco DiffEditor state
 * Provides proper VS Code-style inline diff with red/green highlighting
 */
import { writeFile } from '$core/services/file-system';
import { editorStore } from './editor.svelte';

export interface DiffState {
  /** Whether diff view is active */
  active: boolean;
  /** Monotonic session id to force remounts when reopening diff */
  sessionId: number;
  /** File path being diffed */
  filePath: string;
  /** Original content (before changes) */
  originalContent: string;
  /** Modified content (after changes) */
  modifiedContent: string;
  /** Language for syntax highlighting */
  language: string;
  /** Title for the diff view */
  title: string;
  /** Tool call ID for tracking (optional) */
  toolCallId?: string;
  /** Whether to use inline mode (vs side-by-side) */
  inlineMode: boolean;
}

class DiffStore {
  /** Current diff state */
  state = $state<DiffState>({
    active: false,
    sessionId: 0,
    filePath: '',
    originalContent: '',
    modifiedContent: '',
    language: 'plaintext',
    title: '',
    inlineMode: true, // Default to inline mode like VS Code Copilot
  });

  /** Whether diff view is currently active */
  get isActive(): boolean {
    return this.state.active;
  }

  /** Get the current diff file path */
  get filePath(): string {
    return this.state.filePath;
  }

  /**
   * Open diff view for a file
   * Shows the difference between original and modified content
   */
  openDiff(options: {
    filePath: string;
    originalContent: string;
    modifiedContent: string;
    language?: string;
    title?: string;
    toolCallId?: string;
    inlineMode?: boolean;
  }): void {
    const fileName = options.filePath.split(/[/\\]/).pop() || 'file';
    const nextSessionId = this.state.sessionId + 1;

    this.state = {
      active: true,
      sessionId: nextSessionId,
      filePath: options.filePath,
      originalContent: options.originalContent,
      modifiedContent: options.modifiedContent,
      language: options.language || this.detectLanguage(options.filePath),
      title: options.title || `Diff: ${fileName}`,
      toolCallId: options.toolCallId,
      inlineMode: options.inlineMode ?? this.state.inlineMode ?? true,
    };
  }

  /**
   * Close diff view and return to normal editor
   */
  closeDiff(): void {
    this.state = {
      active: false,
      sessionId: this.state.sessionId,
      filePath: '',
      originalContent: '',
      modifiedContent: '',
      language: 'plaintext',
      title: '',
      toolCallId: undefined,
      inlineMode: true,
    };
  }

  /**
   * Toggle between inline and side-by-side mode
   */
  toggleInlineMode(): void {
    this.state = { ...this.state, inlineMode: !this.state.inlineMode };
  }

  /**
   * Set inline mode explicitly
   */
  setInlineMode(inline: boolean): void {
    this.state = { ...this.state, inlineMode: inline };
  }

  /**
   * Accept the changes (close diff, sync modified content to editor)
   */
  async acceptChanges(): Promise<void> {
    const { filePath, modifiedContent } = this.state;
    
    // Close the diff first
    this.closeDiff();
    
    // Sync the modified content to the editor if file is open
    if (filePath && modifiedContent) {
      try {
        // Write modified content back to disk
        await writeFile(filePath, modifiedContent);
        await editorStore.updateFileContent(filePath, modifiedContent);
      } catch (err) {
        console.error('[diffStore] Failed to sync accepted changes:', err);
      }
    }
  }

  /**
   * Reject the changes (revert to original content)
   */
  async rejectChanges(): Promise<void> {
    const { filePath, originalContent } = this.state;
    
    // Close the diff first
    this.closeDiff();
    
    // Revert to original content if file is open
    if (filePath && originalContent) {
      try {
        // Write original content back to disk
        await writeFile(filePath, originalContent);
        
        // Sync to editor
        await editorStore.updateFileContent(filePath, originalContent);
      } catch (err) {
        console.error('[diffStore] Failed to revert changes:', err);
      }
    }
  }

  /**
   * Simple language detection from file path
   */
  private detectLanguage(filePath: string): string {
    const ext = filePath.split('.').pop()?.toLowerCase() || '';
    const languageMap: Record<string, string> = {
      ts: 'typescript',
      tsx: 'typescriptreact',
      js: 'javascript',
      jsx: 'javascriptreact',
      json: 'json',
      html: 'html',
      css: 'css',
      scss: 'scss',
      less: 'less',
      md: 'markdown',
      py: 'python',
      rs: 'rust',
      go: 'go',
      java: 'java',
      kt: 'kotlin',
      swift: 'swift',
      c: 'c',
      cpp: 'cpp',
      h: 'c',
      hpp: 'cpp',
      cs: 'csharp',
      rb: 'ruby',
      php: 'php',
      sql: 'sql',
      yaml: 'yaml',
      yml: 'yaml',
      xml: 'xml',
      svelte: 'svelte',
      vue: 'vue',
      dart: 'dart',
      sh: 'shell',
      bash: 'shell',
      zsh: 'shell',
      ps1: 'powershell',
      toml: 'toml',
    };
    return languageMap[ext] || 'plaintext';
  }
}

export const diffStore = new DiffStore();

/**
 * Editor state store using Svelte 5 runes
 * Manages open files, active file, and file content
 */

import { readFile } from '$core/services/file-system';
import {
  clearReviewHighlight,
  disposeAllModels,
  disposeModel,
  setModelValue,
  setSelection,
} from '$core/services/monaco-models';
import { notifyFileClosed } from '$core/lsp/client';
import { activityStore } from '$shared/stores/activity.svelte';
import {
  isTsJsFile,
  notifyDocumentClosed as notifyTsDocumentClosed,
  notifyDocumentSaved as notifyTsDocumentSaved,
  notifyDocumentChanged as notifyTsDocumentChanged
} from '$core/lsp/typescript-sidecar';
import { detectLanguage } from '$core/services/monaco-loader';
import {
  isTailwindFile,
  notifyTailwindDocumentClosed,
  notifyTailwindDocumentSaved,
  notifyTailwindDocumentChanged
} from '$core/lsp/tailwind-sidecar';
import {
  isEslintFile,
  notifyEslintDocumentClosed,
  notifyEslintDocumentSaved,
  notifyEslintDocumentChanged
} from '$core/lsp/eslint-sidecar';
import {
  isSvelteFile,
  notifySvelteDocumentClosed,
  notifySvelteDocumentSaved,
  notifySvelteDocumentChanged
} from '$core/lsp/svelte-sidecar';
import {
  isHtmlFile,
  notifyHtmlDocumentClosed,
  notifyHtmlDocumentChanged
} from '$core/lsp/html-sidecar';
import {
  isCssFile,
  notifyCssDocumentClosed,
  notifyCssDocumentChanged
} from '$core/lsp/css-sidecar';
import {
  isJsonFile,
  notifyJsonDocumentClosed,
  notifyJsonDocumentChanged
} from '$core/lsp/json-sidecar';
import {
  isDartLspFile,
  notifyDocumentClosed as notifyDartDocumentClosed,
  notifyDocumentSaved as notifyDartDocumentSaved,
  notifyDocumentChanged as notifyDartDocumentChanged
} from '$core/lsp/dart-sidecar';
import {
  isYamlFile,
  notifyDocumentClosed as notifyYamlDocumentClosed,
  notifyDocumentChanged as notifyYamlDocumentChanged
} from '$core/lsp/yaml-sidecar';
import {
  isXmlFile,
  notifyDocumentClosed as notifyXmlDocumentClosed,
  notifyDocumentChanged as notifyXmlDocumentChanged
} from '$core/lsp/xml-sidecar';

export interface OpenFile {
  /** Full file path (normalized with forward slashes) */
  path: string;
  /** File name (for display) */
  name: string;
  /** File content */
  content: string;
  /** Original content (for dirty detection) */
  originalContent: string;
  /** Language for syntax highlighting */
  language: string;
  /** Line ending style (LF or CRLF) */
  lineEnding: 'LF' | 'CRLF';
  /** File encoding */
  encoding: string;
  /** Whether this editor is read-only */
  readonly?: boolean;
  /** Whether the tab is pinned */
  pinned?: boolean;
}

export const VOLT_SETTINGS_PATH = 'volt://settings';

export function isVoltVirtualPath(path: string): boolean {
  return path.startsWith('volt://');
}

/** Cursor position info for status bar */
export interface CursorPosition {
  line: number;
  column: number;
  /** Number of selected characters (0 if no selection) */
  selected: number;
}

/** Editor model options for status bar */
export interface EditorOptions {
  /** Tab size */
  tabSize: number;
  /** Whether using spaces for indentation */
  insertSpaces: boolean;
}

/**
 * Normalize file path to use forward slashes consistently.
 * This prevents duplicate tabs when the same file is opened with different slash styles.
 */
function normalizePath(path: string): string {
  return path.replace(/\\/g, '/');
}

function getFileExt(path: string): string {
  const name = path.split('/').pop() ?? path;
  const idx = name.lastIndexOf('.');
  return idx >= 0 ? name.slice(idx + 1).toLowerCase() : '';
}

const BINARY_LIKE_EXTENSIONS = new Set([
  'pdf',
  'png',
  'jpg',
  'jpeg',
  'gif',
  'webp',
  'bmp',
  'ico',
  'avif',
  'tif',
  'tiff',
  'zip',
  '7z',
  'rar',
  'exe',
  'dll',
  'bin',
  'woff',
  'woff2',
  'ttf',
  'otf',
  'mp3',
  'wav',
  'ogg',
  'oga',
  'flac',
  'aac',
  'm4a',
  'mp4',
  'mpeg',
  'mpg',
  'webm',
  'mov',
  'avi',
  'm4v',
  'ogv',
]);

class EditorStore {
  /** List of open files */
  openFiles = $state<OpenFile[]>([]);

  /** Path of the currently active file */
  activeFilePath = $state<string | null>(null);

  /** Current cursor position */
  cursorPosition = $state<CursorPosition>({ line: 1, column: 1, selected: 0 });

  /** Current editor options (indentation) */
  editorOptions = $state<EditorOptions>({ tabSize: 2, insertSpaces: true });

  /** Get the currently active file */
  get activeFile(): OpenFile | null {
    if (!this.activeFilePath) return null;
    return this.openFiles.find((f) => f.path === this.activeFilePath) ?? null;
  }

  /** Update cursor position (called from Monaco editor) */
  setCursorPosition(line: number, column: number, selected = 0): void {
    this.cursorPosition = { line, column, selected };
  }

  /** Update editor options (called from Monaco editor) */
  setEditorOptions(tabSize: number, insertSpaces: boolean): void {
    this.editorOptions = { tabSize, insertSpaces };
  }

  /** Check if a file is dirty (has unsaved changes) */
  isDirty(path: string): boolean {
    const normalizedPath = normalizePath(path);
    const file = this.openFiles.find(f => f.path === normalizedPath);
    if (!file) return false;
    return file.content !== file.originalContent;
  }

  /** Check if any file is dirty */
  get hasUnsavedChanges(): boolean {
    return this.openFiles.some(f => f.content !== f.originalContent);
  }

  /**
   * Open a file in the editor
   * If already open, just switch to it
   */
  async openFile(path: string): Promise<boolean> {
    // Normalize path to prevent duplicate tabs with different slash styles
    const normalizedPath = normalizePath(path);

    // Check if already open
    const existing = this.openFiles.find(f => f.path === normalizedPath);
    if (existing) {
      this.activeFilePath = normalizedPath;
      return true;
    }

    // Extract filename
    const name = normalizedPath.split('/').pop() || normalizedPath;
    const ext = getFileExt(normalizedPath);
    const isBinaryLike = BINARY_LIKE_EXTENSIONS.has(ext);

    // Read file content for text-like files only.
    // Binary files are opened in preview mode and should not fail file open.
    const content = isBinaryLike ? '' : await readFile(path);
    if (!isBinaryLike && content === null) {
      // Error already shown via toast in readFile
      return false;
    }

    // Detect language from extension
    const language = detectLanguage(name);

    // Detect line ending from content
    const lineEnding = content && content.includes('\r\n') ? 'CRLF' : 'LF';

    // Add to open files (race-safe: check again after async read)
    const existingAfterRead = this.openFiles.find(f => f.path === normalizedPath);
    if (existingAfterRead) {
      this.activeFilePath = normalizedPath;
      return true;
    }

    const newFile: OpenFile = {
      path: normalizedPath,
      name,
      content: content ?? '',
      originalContent: content ?? '',
      language,
      lineEnding,
      encoding: 'UTF-8',
      readonly: isBinaryLike || undefined,
    };

    this.openFiles = [...this.openFiles.filter(f => f.path !== normalizedPath), newFile];
    this.activeFilePath = normalizedPath;

    // Reset cursor position for new file
    this.cursorPosition = { line: 1, column: 1, selected: 0 };

    // Record activity
    activityStore.recordActivity(normalizedPath, 'view');

    return true;
  }

  /**
   * Open a virtual document (not backed by the filesystem).
   * Useful for editor UI pages like Settings.
   */
  openVirtualFile(spec: {
    path: string;
    name: string;
    content: string;
    language: string;
    readonly?: boolean;
    pinned?: boolean;
  }): void {
    const normalizedPath = normalizePath(spec.path);

    const existing = this.openFiles.find((f) => f.path === normalizedPath);
    if (existing) {
      this.activeFilePath = normalizedPath;
      return;
    }

    const newFile: OpenFile = {
      path: normalizedPath,
      name: spec.name,
      content: spec.content,
      originalContent: spec.content,
      language: spec.language,
      lineEnding: 'LF',
      encoding: 'UTF-8',
      readonly: spec.readonly ?? true,
      pinned: spec.pinned
    };

    this.openFiles = [...this.openFiles, newFile];
    this.activeFilePath = normalizedPath;
    this.cursorPosition = { line: 1, column: 1, selected: 0 };
  }

  openSettingsTab(): void {
    this.openVirtualFile({
      path: VOLT_SETTINGS_PATH,
      name: 'Settings',
      content: '',
      language: 'volt-settings',
      readonly: true,
      pinned: false
    });
  }

  /**
   * Close a file
   * Returns false if file has unsaved changes and user cancels
   * Selects the nearest neighbor (prefer right, then left) when closing active tab
   */
  closeFile(path: string, force = false): boolean {
    const normalizedPath = normalizePath(path);
    const fileIndex = this.openFiles.findIndex(f => f.path === normalizedPath);
    if (fileIndex === -1) return true;

    const file = this.openFiles[fileIndex];

    // Check for unsaved changes
    if (!force && this.isDirty(normalizedPath)) {
      const confirmed = confirm(`"${file.name}" has unsaved changes. Close anyway?`);
      if (!confirmed) return false;
    }

    // Determine next active file before removing (VS Code behavior: prefer right neighbor, then left)
    let nextActivePath: string | null = null;
    if (this.activeFilePath === normalizedPath && this.openFiles.length > 1) {
      if (fileIndex < this.openFiles.length - 1) {
        // There's a tab to the right - select it
        nextActivePath = this.openFiles[fileIndex + 1].path;
      } else if (fileIndex > 0) {
        // No tab to the right, select the one to the left
        nextActivePath = this.openFiles[fileIndex - 1].path;
      }
    }

    // Remove from open files
    this.openFiles = this.openFiles.filter(f => f.path !== normalizedPath);
    disposeModel(normalizedPath);
    notifyFileClosed(file.language);

    // Notify TypeScript LSP sidecar about the file being closed
    if (isTsJsFile(normalizedPath)) {
      notifyTsDocumentClosed(normalizedPath);
    }

    // Notify Tailwind LSP sidecar about the file being closed
    if (isTailwindFile(normalizedPath)) {
      notifyTailwindDocumentClosed(normalizedPath);
    }

    // Notify ESLint LSP sidecar about the file being closed
    if (isEslintFile(normalizedPath)) {
      notifyEslintDocumentClosed(normalizedPath);
    }

    // Notify Svelte LSP sidecar about the file being closed
    if (isSvelteFile(normalizedPath)) {
      notifySvelteDocumentClosed(normalizedPath);
    }
    if (isHtmlFile(normalizedPath)) {
      notifyHtmlDocumentClosed(normalizedPath);
    }
    if (isCssFile(normalizedPath)) {
      notifyCssDocumentClosed(normalizedPath);
    }
    if (isJsonFile(normalizedPath)) {
      notifyJsonDocumentClosed(normalizedPath);
    }
    if (isDartLspFile(normalizedPath)) {
      notifyDartDocumentClosed(normalizedPath);
    }
    if (isYamlFile(normalizedPath)) {
      notifyYamlDocumentClosed(normalizedPath);
    }
    if (isXmlFile(normalizedPath)) {
      notifyXmlDocumentClosed(normalizedPath);
    }

    // Update active file
    if (this.activeFilePath === normalizedPath) {
      this.activeFilePath = nextActivePath;
    }

    return true;
  }

  /**
   * Close all files
   * Returns false if any file has unsaved changes and user cancels
   */
  closeAllFiles(force = false): boolean {
    if (!force && this.hasUnsavedChanges) {
      const confirmed = confirm('You have unsaved changes. Close all files anyway?');
      if (!confirmed) return false;
    }

    for (const file of this.openFiles) {
      notifyFileClosed(file.language);

      // Notify TypeScript LSP sidecar about the file being closed
      if (isTsJsFile(file.path)) {
        notifyTsDocumentClosed(file.path);
      }

      // Notify Tailwind LSP sidecar about the file being closed
      if (isTailwindFile(file.path)) {
        notifyTailwindDocumentClosed(file.path);
      }

      // Notify ESLint LSP sidecar about the file being closed
      if (isEslintFile(file.path)) {
        notifyEslintDocumentClosed(file.path);
      }

      // Notify Svelte LSP sidecar about the file being closed
      if (isSvelteFile(file.path)) {
        notifySvelteDocumentClosed(file.path);
      }
      if (isHtmlFile(file.path)) {
        notifyHtmlDocumentClosed(file.path);
      }
      if (isCssFile(file.path)) {
        notifyCssDocumentClosed(file.path);
      }
      if (isJsonFile(file.path)) {
        notifyJsonDocumentClosed(file.path);
      }
      if (isDartLspFile(file.path)) {
        notifyDartDocumentClosed(file.path);
      }
      if (isYamlFile(file.path)) {
        notifyYamlDocumentClosed(file.path);
      }
      if (isXmlFile(file.path)) {
        notifyXmlDocumentClosed(file.path);
      }
    }
    this.openFiles = [];
    this.activeFilePath = null;
    disposeAllModels();
    return true;
  }

  /**
   * Set the active file
   */
  setActiveFile(path: string): void {
    const normalizedPath = normalizePath(path);
    if (this.openFiles.some(f => f.path === normalizedPath)) {
      this.activeFilePath = normalizedPath;
      activityStore.recordActivity(normalizedPath, 'view');
    }
  }

  /**
   * Cycle to the next tab (Ctrl+Tab behavior)
   */
  nextTab(): void {
    if (this.openFiles.length <= 1) return;

    const currentIndex = this.openFiles.findIndex(f => f.path === this.activeFilePath);
    const nextIndex = (currentIndex + 1) % this.openFiles.length;
    this.activeFilePath = this.openFiles[nextIndex].path;
    activityStore.recordActivity(this.activeFilePath, 'view');
  }

  /**
   * Cycle to the previous tab (Ctrl+Shift+Tab behavior)
   */
  previousTab(): void {
    if (this.openFiles.length <= 1) return;

    const currentIndex = this.openFiles.findIndex(f => f.path === this.activeFilePath);
    const prevIndex = currentIndex <= 0 ? this.openFiles.length - 1 : currentIndex - 1;
    this.activeFilePath = this.openFiles[prevIndex].path;
    activityStore.recordActivity(this.activeFilePath, 'view');
  }

  /**
   * Pin or unpin a tab
   */
  togglePin(path: string): void {
    const normalizedPath = normalizePath(path);
    const file = this.openFiles.find(f => f.path === normalizedPath);
    if (!file) return;

    file.pinned = !file.pinned;

    // Reorder: pinned tabs go to the left
    this.sortTabs();
  }

  /**
   * Check if a file is pinned
   */
  isPinned(path: string): boolean {
    const normalizedPath = normalizePath(path);
    const file = this.openFiles.find(f => f.path === normalizedPath);
    return file?.pinned ?? false;
  }

  /**
   * Sort tabs: pinned first, then unpinned
   */
  private sortTabs(): void {
    this.openFiles = [
      ...this.openFiles.filter(f => f.pinned),
      ...this.openFiles.filter(f => !f.pinned)
    ];
  }

  /**
   * Reorder tabs by moving a tab from one index to another
   */
  reorderTabs(fromIndex: number, toIndex: number): void {
    if (fromIndex === toIndex) return;
    if (fromIndex < 0 || fromIndex >= this.openFiles.length) return;
    if (toIndex < 0 || toIndex >= this.openFiles.length) return;

    const file = this.openFiles[fromIndex];
    const targetFile = this.openFiles[toIndex];

    // Don't allow moving unpinned tabs before pinned tabs
    if (!file.pinned && targetFile.pinned) return;
    // Don't allow moving pinned tabs after unpinned tabs
    if (file.pinned && !targetFile.pinned && toIndex > fromIndex) return;

    const newFiles = [...this.openFiles];
    newFiles.splice(fromIndex, 1);
    newFiles.splice(toIndex, 0, file);
    this.openFiles = newFiles;
  }

  /**
   * Update file content (called when editor content changes)
   */
  updateContent(path: string, content: string): void {
    const normalizedPath = normalizePath(path);
    const file = this.openFiles.find(f => f.path === normalizedPath);
    if (file) {
      file.content = content;
      activityStore.recordActivity(normalizedPath, 'edit');
    }
  }

  /**
   * Mark file as saved (update original content to match current)
   */
  markSaved(path: string): void {
    const normalizedPath = normalizePath(path);
    const file = this.openFiles.find(f => f.path === normalizedPath);
    if (file) {
      file.originalContent = file.content;

      // Notify TypeScript LSP sidecar about the file being saved
      if (isTsJsFile(normalizedPath)) {
        notifyTsDocumentSaved(normalizedPath, file.content);
      }

      // Notify Tailwind LSP sidecar about the file being saved
      if (isTailwindFile(normalizedPath)) {
        notifyTailwindDocumentSaved(normalizedPath, file.content);
      }

      // Notify ESLint LSP sidecar about the file being saved
      if (isEslintFile(normalizedPath)) {
        notifyEslintDocumentSaved(normalizedPath, file.content);
      }

      // Notify Svelte LSP sidecar about the file being saved
      if (isSvelteFile(normalizedPath)) {
        notifySvelteDocumentSaved(normalizedPath, file.content);
      }
      if (isDartLspFile(normalizedPath)) {
        notifyDartDocumentSaved(normalizedPath, file.content);
      }
    }
  }

  /**
   * Reload file content from disk
   */
  async reloadFile(path: string): Promise<boolean> {
    const normalizedPath = normalizePath(path);
    const fileIndex = this.openFiles.findIndex(f => f.path === normalizedPath);
    if (fileIndex === -1) return false;

    const ext = getFileExt(normalizedPath);
    const isBinaryLike = BINARY_LIKE_EXTENSIONS.has(ext);
    if (isBinaryLike) {
      // Binary previews are loaded by viewer components from disk directly.
      return true;
    }

    // Use original path for file system access
    try {
      const content = await readFile(path);
      if (content === null) return false;

      // Create updated file object and replace in array to trigger Svelte reactivity
      const updatedFile = {
        ...this.openFiles[fileIndex],
        content,
        originalContent: content
      };
      
      // Replace the array to trigger reactivity
      this.openFiles = [
        ...this.openFiles.slice(0, fileIndex),
        updatedFile,
        ...this.openFiles.slice(fileIndex + 1)
      ];

      // Also update the Monaco model so the editor shows the new content
      setModelValue(normalizedPath, content);

      // Clear any AI edit highlights (the green blocks) on reload
      clearReviewHighlight(normalizedPath);

      // Notify LSP servers about the content change to trigger diagnostics
      if (isTsJsFile(normalizedPath)) {
        notifyTsDocumentChanged(normalizedPath, content);
      }
      if (isTailwindFile(normalizedPath)) {
        notifyTailwindDocumentChanged(normalizedPath, content);
      }
      if (isEslintFile(normalizedPath)) {
        notifyEslintDocumentChanged(normalizedPath, content);
      }
      if (isSvelteFile(normalizedPath)) {
        notifySvelteDocumentChanged(normalizedPath, content);
      }
      if (isHtmlFile(normalizedPath)) {
        notifyHtmlDocumentChanged(normalizedPath, content);
      }
      if (isCssFile(normalizedPath)) {
        notifyCssDocumentChanged(normalizedPath, content);
      }
      if (isJsonFile(normalizedPath)) {
        notifyJsonDocumentChanged(normalizedPath, content);
      }
      if (isDartLspFile(normalizedPath)) {
        notifyDartDocumentChanged(normalizedPath, content);
      }
      if (isYamlFile(normalizedPath)) {
        notifyYamlDocumentChanged(normalizedPath, content);
      }
      if (isXmlFile(normalizedPath)) {
        notifyXmlDocumentChanged(normalizedPath, content);
      }

      return true;
    } catch (e) {
      console.error(`[EditorStore] Failed to reload ${path}:`, e);
      return false;
    }
  }

  /**
   * Update internal state when a file is renamed on disk
   */
  async renameFile(oldPath: string, newPath: string): Promise<void> {
    const normOld = normalizePath(oldPath);
    const normNew = normalizePath(newPath);

    const file = this.openFiles.find(f => f.path === normOld);
    if (!file) return;

    // Update metadata
    file.path = normNew;
    file.name = newPath.split(/[/\\]/).pop() || newPath;

    // Refresh content from new location
    await this.reloadFile(newPath);

    if (this.activeFilePath === normOld) {
      this.activeFilePath = normNew;
    }

    // Dispose old model if it exists (reloadFile will create/update the new one)
    disposeModel(normOld);
  }

  /**
   * Set the selection in the active editor
   */
  async setSelection(path: string, range: {
    startLine: number;
    startColumn: number;
    endLine: number;
    endColumn: number;
  }): Promise<void> {
    setSelection(path, range);
  }

  /**
   * Update file content in memory without reading from disk
   * Used for Accept/Discard in diff view and other in-memory updates
   * Triggers Svelte reactivity properly
   */
  async updateFileContent(path: string, content: string): Promise<boolean> {
    const normalizedPath = normalizePath(path);
    const fileIndex = this.openFiles.findIndex(f => f.path === normalizedPath);
    
    if (fileIndex === -1) return false;

    // Create updated file object and replace in array to trigger Svelte reactivity
    const updatedFile = {
      ...this.openFiles[fileIndex],
      content,
      originalContent: content
    };
    
    // Replace the array to trigger reactivity
    this.openFiles = [
      ...this.openFiles.slice(0, fileIndex),
      updatedFile,
      ...this.openFiles.slice(fileIndex + 1)
    ];

    // Also update the Monaco model
    setModelValue(normalizedPath, content);
    clearReviewHighlight(normalizedPath);

    // Notify LSP servers about the content change to trigger diagnostics
    if (isTsJsFile(normalizedPath)) {
      notifyTsDocumentChanged(normalizedPath, content);
    }
    if (isTailwindFile(normalizedPath)) {
      notifyTailwindDocumentChanged(normalizedPath, content);
    }
    if (isEslintFile(normalizedPath)) {
      notifyEslintDocumentChanged(normalizedPath, content);
    }
    if (isSvelteFile(normalizedPath)) {
      notifySvelteDocumentChanged(normalizedPath, content);
    }
    if (isHtmlFile(normalizedPath)) {
      notifyHtmlDocumentChanged(normalizedPath, content);
    }
    if (isCssFile(normalizedPath)) {
      notifyCssDocumentChanged(normalizedPath, content);
    }
    if (isJsonFile(normalizedPath)) {
      notifyJsonDocumentChanged(normalizedPath, content);
    }
    if (isDartLspFile(normalizedPath)) {
      notifyDartDocumentChanged(normalizedPath, content);
    }
    if (isYamlFile(normalizedPath)) {
      notifyYamlDocumentChanged(normalizedPath, content);
    }
    if (isXmlFile(normalizedPath)) {
      notifyXmlDocumentChanged(normalizedPath, content);
    }

    return true;
  }
}

// Singleton instance
export const editorStore = new EditorStore();

/**
 * Git state store using Svelte 5 runes
 * Manages git status, staging, commits, and branches with debouncing and cancellation
 * Auto-refreshes on file changes like VSCode
 */

import { onFileChange, type FileChangeBatchEvent } from '$core/services/file-watch';
import {
	getGitStatus,
	cancelGitOperation,
	stageFile,
	stageAll,
	unstageFile,
	unstageAll,
	commit,
	listBranches,
	switchBranch,
	hasUncommittedChanges,
	getDiff,
	discardFile,
	isGitRepo,
	type GitStatus,
	type GitBranch,
	type GitDiff,
	type GitFileChange
} from '$features/git/services/git';

// Debounce delay for status refresh (ms)
const STATUS_DEBOUNCE_MS = 300;

// Cache duration for status (ms)
const STATUS_CACHE_MS = 1000;

// File watcher debounce (ms) - longer to batch rapid changes
const FILE_WATCH_DEBOUNCE_MS = 200;

class GitStore {
	// Repository state
	isRepo = $state(false);
	rootPath = $state<string | null>(null);

	// Status
	status = $state<GitStatus | null>(null);
	loading = $state(false);
	error = $state<string | null>(null);

	// Branches
	branches = $state<GitBranch[]>([]);
	branchesLoading = $state(false);

	// Diff viewer
	selectedFile = $state<GitFileChange | null>(null);
	diff = $state<GitDiff | null>(null);
	diffLoading = $state(false);

	// Commit message
	commitMessage = $state('');

	// Internal state for debouncing/cancellation
	private refreshTimer: ReturnType<typeof setTimeout> | null = null;
	private lastRefreshTime = 0;
	private isRefreshing = false;
	private statusOpId: string | null = null;
	private diffOpId: string | null = null;

	// File watcher for auto-refresh
	private fileWatchUnsubscribe: (() => void) | null = null;
	private fileWatchDebounceTimer: ReturnType<typeof setTimeout> | null = null;

	// Derived values using $derived for proper Svelte 5 reactivity
	stagedCount = $derived(this.status?.staged.length ?? 0);
	unstagedCount = $derived(this.status?.unstaged.length ?? 0);
	untrackedCount = $derived(this.status?.untracked.length ?? 0);
	conflictedCount = $derived(this.status?.conflicted.length ?? 0);
	totalChanges = $derived(
		(this.status?.staged.length ?? 0) +
		(this.status?.unstaged.length ?? 0) +
		(this.status?.untracked.length ?? 0) +
		(this.status?.conflicted.length ?? 0)
	);
	currentBranch = $derived(this.status?.branch ?? null);
	hasConflicts = $derived(this.status?.hasConflicts ?? false);
	canCommit = $derived(
		(this.status?.staged.length ?? 0) > 0 &&
		this.commitMessage.trim().length > 0 &&
		!(this.status?.hasConflicts ?? false)
	);

	/**
	 * Initialize git store for a project
	 */
	async init(projectPath: string): Promise<void> {
		this.rootPath = projectPath;
		this.reset();

		// Check if it's a git repo
		this.isRepo = await isGitRepo(projectPath);

		if (this.isRepo) {
			await this.refresh();
			// Start watching for file changes
			this.startFileWatcher();
		}
	}

	/**
	 * Start file watcher for auto-refresh (like VSCode)
	 */
	private startFileWatcher(): void {
		// Clean up existing watcher
		if (this.fileWatchUnsubscribe) {
			this.fileWatchUnsubscribe();
			this.fileWatchUnsubscribe = null;
		}

		// Register handler for file changes using the file-watch service
		this.fileWatchUnsubscribe = onFileChange((batch: FileChangeBatchEvent) => {
			if (!this.isRepo || !this.rootPath) return;

			// Check if any changed file is relevant for git status
			let shouldRefresh = false;

			for (const change of batch.changes) {
				for (const changedPath of change.paths) {
					// Handle .git internal files
					if (changedPath.includes('.git/') || changedPath.includes('.git\\')) {
						// Refresh for:
						// - index (staging changes)
						// - HEAD (branch switch)
						// - refs/ (branch/tag updates)
						// - packed-refs (git gc / remote updates)
						if (
							changedPath.includes('index') ||
							changedPath.includes('HEAD') ||
							changedPath.includes('refs/') ||
							changedPath.includes('packed-refs')
						) {
							shouldRefresh = true;
							break;
						}
						continue;
					}

					// Any other file change should trigger git status refresh
					shouldRefresh = true;
					break;
				}
				if (shouldRefresh) break;
			}

			if (!shouldRefresh) return;

			// Debounce rapid file changes
			if (this.fileWatchDebounceTimer) {
				clearTimeout(this.fileWatchDebounceTimer);
			}

			this.fileWatchDebounceTimer = setTimeout(() => {
				this.fileWatchDebounceTimer = null;
				// Force refresh bypassing cache
				this.lastRefreshTime = 0;
				this.refresh(true);
			}, FILE_WATCH_DEBOUNCE_MS);
		});
	}

	/**
	 * Reset store state
	 */
	reset(): void {
		this.cancelPendingRefresh();

		// Clean up file watcher
		if (this.fileWatchUnsubscribe) {
			this.fileWatchUnsubscribe();
			this.fileWatchUnsubscribe = null;
		}
		if (this.fileWatchDebounceTimer) {
			clearTimeout(this.fileWatchDebounceTimer);
			this.fileWatchDebounceTimer = null;
		}

		this.status = null;
		this.branches = [];
		this.selectedFile = null;
		this.diff = null;
		this.commitMessage = '';
		this.error = null;
		this.loading = false;
		this.branchesLoading = false;
		this.diffLoading = false;
	}

	/**
	 * Cancel any pending refresh operations
	 */
	private cancelPendingRefresh(): void {
		if (this.refreshTimer) {
			clearTimeout(this.refreshTimer);
			this.refreshTimer = null;
		}
		if (this.statusOpId) {
			void cancelGitOperation(this.statusOpId);
			this.statusOpId = null;
		}
	}

	/**
	 * Refresh git status with debouncing
	 */
	async refresh(force = false): Promise<void> {
		if (!this.rootPath || !this.isRepo) return;

		// Cancel any pending refresh
		this.cancelPendingRefresh();

		// Check cache (unless forced)
		const now = Date.now();
		if (!force && now - this.lastRefreshTime < STATUS_CACHE_MS) {
			return;
		}

		// Debounce rapid refreshes
		return new Promise((resolve) => {
			this.refreshTimer = setTimeout(async () => {
				await this.doRefresh();
				resolve();
			}, STATUS_DEBOUNCE_MS);
		});
	}

	/**
	 * Immediate refresh (no debounce)
	 */
	async refreshNow(): Promise<void> {
		if (!this.rootPath || !this.isRepo) return;
		this.cancelPendingRefresh();
		await this.doRefresh();
	}

	/**
	 * Internal refresh implementation
	 */
	private async doRefresh(): Promise<void> {
		if (!this.rootPath) return;

		// If already refreshing, wait for it to complete instead of skipping
		if (this.isRefreshing) {
			// Wait a bit and check again
			await new Promise((resolve) => setTimeout(resolve, 100));
			if (this.isRefreshing) return; // Still refreshing, skip
		}

		this.isRefreshing = true;
		this.loading = true;
		this.error = null;

		// Cancel any previous in-flight status command and start a new op.
		if (this.statusOpId) {
			void cancelGitOperation(this.statusOpId);
		}
		this.statusOpId = crypto.randomUUID();
		const opId = this.statusOpId;

		try {
			const result = await getGitStatus(this.rootPath, opId);

			// Ignore stale responses
			if (this.statusOpId !== opId) return;

			if (result.status) {
				// Use assignment to trigger Svelte reactivity
				this.status = { ...result.status };
				this.lastRefreshTime = Date.now();
				this.error = null;
			} else {
				this.error = result.error || 'Failed to get git status';
			}
		} catch (e) {
			if (this.statusOpId === opId) {
				this.error = e instanceof Error ? e.message : 'Unknown error';
			}
		} finally {
			if (this.statusOpId === opId) {
				this.statusOpId = null;
				this.loading = false;
				this.isRefreshing = false;
			}
		}
	}

	/**
	 * Load branches
	 */
	async loadBranches(): Promise<void> {
		if (!this.rootPath || !this.isRepo) return;

		this.branchesLoading = true;
		try {
			this.branches = await listBranches(this.rootPath);
		} finally {
			this.branchesLoading = false;
		}
	}

	/**
	 * Stage a file
	 */
	async stage(filePath: string): Promise<boolean> {
		if (!this.rootPath) return false;

		const success = await stageFile(this.rootPath, filePath);
		if (success) {
			await this.refreshNow();
		}
		return success;
	}

	/**
	 * Stage all changes
	 */
	async stageAllChanges(): Promise<boolean> {
		if (!this.rootPath) return false;

		const success = await stageAll(this.rootPath);
		if (success) {
			await this.refreshNow();
		}
		return success;
	}

	/**
	 * Unstage a file
	 */
	async unstage(filePath: string): Promise<boolean> {
		if (!this.rootPath) return false;

		const success = await unstageFile(this.rootPath, filePath);
		if (success) {
			await this.refreshNow();
		}
		return success;
	}

	/**
	 * Unstage all changes
	 */
	async unstageAllChanges(): Promise<boolean> {
		if (!this.rootPath) return false;

		const success = await unstageAll(this.rootPath);
		if (success) {
			await this.refreshNow();
		}
		return success;
	}

	/**
	 * Commit staged changes
	 */
	async commitChanges(): Promise<boolean> {
		if (!this.rootPath || !this.canCommit) return false;

		const hash = await commit(this.rootPath, this.commitMessage);
		if (hash) {
			this.commitMessage = '';
			// Force immediate refresh bypassing cache and isRefreshing guard
			this.lastRefreshTime = 0;
			this.isRefreshing = false;
			await this.doRefresh();
			return true;
		}
		return false;
	}

	/**
	 * Switch branch (with uncommitted changes check)
	 */
	async switchToBranch(branch: string): Promise<{ success: boolean; hasChanges: boolean }> {
		if (!this.rootPath) return { success: false, hasChanges: false };

		// Check for uncommitted changes first
		const hasChanges = await hasUncommittedChanges(this.rootPath);
		if (hasChanges) {
			return { success: false, hasChanges: true };
		}

		const success = await switchBranch(this.rootPath, branch);
		if (success) {
			await this.refreshNow();
			await this.loadBranches();
		}
		return { success, hasChanges: false };
	}

	/**
	 * Select a file to view diff
	 */
	async selectFile(file: GitFileChange): Promise<void> {
		if (!this.rootPath) return;

		// Cancel any in-flight diff request
		if (this.diffOpId) {
			void cancelGitOperation(this.diffOpId);
			this.diffOpId = null;
		}

		this.selectedFile = file;
		this.diffLoading = true;
		this.diffOpId = crypto.randomUUID();
		const opId = this.diffOpId;

		try {
			this.diff = await getDiff(this.rootPath, file.path, file.staged, opId);
		} finally {
			if (this.diffOpId === opId) {
				this.diffLoading = false;
				this.diffOpId = null;
			}
		}
	}

	/**
	 * Clear selected file
	 */
	clearSelection(): void {
		if (this.diffOpId) {
			void cancelGitOperation(this.diffOpId);
			this.diffOpId = null;
		}
		this.selectedFile = null;
		this.diff = null;
	}

	/**
	 * Discard changes to a file
	 */
	async discard(filePath: string): Promise<boolean> {
		if (!this.rootPath) return false;

		const success = await discardFile(this.rootPath, filePath);
		if (success) {
			await this.refreshNow();
			// Clear selection if discarded file was selected
			if (this.selectedFile?.path === filePath) {
				this.clearSelection();
			}
		}
		return success;
	}

	/**
	 * Set commit message
	 */
	setCommitMessage(message: string): void {
		this.commitMessage = message;
	}
}

// Singleton instance
export const gitStore = new GitStore();

/**
 * MCP (Model Context Protocol) Store
 * Manages MCP server connections, tools, and configuration
 */

import { invoke } from '@tauri-apps/api/core';
import { listen, type UnlistenFn } from '@tauri-apps/api/event';
import { homeDir, join } from '@tauri-apps/api/path';
import { readTextFile, watch } from '@tauri-apps/plugin-fs';
import { showToast } from '$shared/stores/toast.svelte';
import { logOutput } from '$features/terminal/stores/output.svelte';
import { registerCleanup } from '$core/services/hmr-cleanup';

// Types matching Rust structs
export interface McpServerConfig {
  command: string;
  args?: string[];
  env?: Record<string, string>;
  disabled?: boolean;
  autoApprove?: string[];
}

export interface McpTool {
  name: string;
  description?: string;
  inputSchema?: Record<string, unknown>;
}

export interface McpServerState {
  id: string;
  name: string;
  status: 'connecting' | 'connected' | 'error' | 'stopped';
  tools: McpTool[];
  error?: string;
}

export interface McpConfig {
  mcpServers?: Record<string, McpServerConfig>;
}

interface McpServerEvent {
  server_id: string;
  state: McpServerState;
}

class McpStore {
  // Server states
  servers = $state<Map<string, McpServerState>>(new Map());

  // All available tools (server_id, tool)
  tools = $state<Array<{ serverId: string; tool: McpTool }>>([]);

  // Retry tracking for failed servers
  private retryAttempts = new Map<string, number>();
  private retryTimers = new Map<string, ReturnType<typeof setTimeout>>();
  private startPromises = new Map<string, Promise<void>>();
  private initializePromise: Promise<void> | null = null;
  private reloading = false;
  private reloadQueued = false;
  private static readonly MAX_RETRY_ATTEMPTS = 3;
  private static readonly RETRY_DELAY_MS = 30000; // 30 seconds

  // Config
  userConfig = $state<McpConfig | null>(null);
  workspaceConfig = $state<McpConfig | null>(null);

  // Loading state
  loading = $state(false);
  initialized = $state(false);

  // File watchers
  private userConfigWatcher: (() => void) | null = null;
  private workspaceConfigWatcher: (() => void) | null = null;
  private eventUnlisteners: UnlistenFn[] = [];
  private listenersInitialized = false;

  // Paths
  private userConfigPath: string | null = null;
  private workspaceConfigPath: string | null = null;

  /** Get merged config (workspace overrides user) */
  get mergedConfig(): McpConfig {
    const merged: McpConfig = { mcpServers: {} };

    if (this.userConfig?.mcpServers) {
      Object.assign(merged.mcpServers!, this.userConfig.mcpServers);
    }

    if (this.workspaceConfig?.mcpServers) {
      Object.assign(merged.mcpServers!, this.workspaceConfig.mcpServers);
    }

    return merged;
  }

  /** Get all servers as array */
  get serverList(): McpServerState[] {
    return Array.from(this.servers.values());
  }

  /** Get connected server count */
  get connectedCount(): number {
    return this.serverList.filter(s => s.status === 'connected').length;
  }

  /** Get total tool count */
  get toolCount(): number {
    return this.tools.length;
  }

  /** Update a server's state immediately (for instant UI feedback) */
  updateServerState(serverId: string, updates: Partial<McpServerState>): void {
    const current = this.servers.get(serverId);
    if (current) {
      this.servers.set(serverId, { ...current, ...updates });
    } else {
      // Create new server entry if it doesn't exist
      this.servers.set(serverId, {
        id: serverId,
        name: serverId,
        status: 'stopped',
        tools: [],
        error: undefined,
        ...updates,
      });
    }
    // Force Svelte 5 reactivity by creating new Map
    this.servers = new Map(this.servers);
    this.updateTools();
  }

  // Track current workspace
  private currentWorkspace: string | null = null;

  /** Initialize MCP system (call once on app startup) */
  async initialize(workspacePath?: string): Promise<void> {
    if (this.initializePromise) {
      await this.initializePromise;
      if (workspacePath && workspacePath !== this.currentWorkspace) {
        await this.updateWorkspaceConfig(workspacePath);
      }
      return;
    }

    if (this.initialized) {
      // Already initialized - just update workspace config if provided
      if (workspacePath && workspacePath !== this.currentWorkspace) {
        await this.updateWorkspaceConfig(workspacePath);
      }
      return;
    }

    this.initializePromise = this.initializeInternal(workspacePath);
    try {
      await this.initializePromise;
    } finally {
      this.initializePromise = null;
    }
  }

  private async initializeInternal(workspacePath?: string): Promise<void> {
    logOutput('MCP', 'Initializing MCP system...');
    this.loading = true;
    this.currentWorkspace = workspacePath || null;

    try {
      // Clean up any stale servers from previous session
      try {
        await invoke('stop_all_mcp_servers');
      } catch {
        // Ignore - might not have any
      }

      // Set up event listeners
      await this.setupEventListeners();

      // Determine config paths
      const home = await homeDir();
      this.userConfigPath = await join(home, '.volt', 'settings', 'mcp.json');
      logOutput('MCP', `User config: ${this.userConfigPath}`);

      if (workspacePath) {
        this.workspaceConfigPath = await join(workspacePath, '.volt', 'mcp.json');
        logOutput('MCP', `Workspace config: ${this.workspaceConfigPath}`);
      }

      // Load configs
      await this.loadConfigs();

      // Watch for config changes
      await this.watchConfigs();

      // Start enabled servers
      await this.startEnabledServers();

      this.initialized = true;
      logOutput('MCP', `MCP initialized. ${this.connectedCount} servers connected, ${this.toolCount} tools available`);
    } catch (error) {
      logOutput('MCP', `[ERROR] Initialize failed: ${error}`);
      console.error('[MCP] Initialize error:', error);
    } finally {
      this.loading = false;
    }
  }

  /** Update workspace config when project changes */
  private async updateWorkspaceConfig(workspacePath: string): Promise<void> {
    const mergedBefore = JSON.stringify(this.mergedConfig);
    this.currentWorkspace = workspacePath;

    // Stop watching old workspace config
    if (this.workspaceConfigWatcher) {
      this.workspaceConfigWatcher();
      this.workspaceConfigWatcher = null;
    }

    // Set new workspace config path
    this.workspaceConfigPath = await join(workspacePath, '.volt', 'mcp.json');

    // Load new workspace config
    try {
      const content = await readTextFile(this.workspaceConfigPath);
      this.workspaceConfig = JSON.parse(content);
    } catch {
      this.workspaceConfig = null;
    }

    // Watch new workspace config
    try {
      this.workspaceConfigWatcher = await watch(
        this.workspaceConfigPath,
        async () => {
          console.log('[MCP] Workspace config changed, reloading...');
          await this.reload();
        },
        { recursive: false }
      );
    } catch {
      // File might not exist yet
    }

    // Reload only when merged config actually changed.
    // This avoids stop/start thrash when opening a project that has no workspace MCP config.
    const mergedAfter = JSON.stringify(this.mergedConfig);
    if (mergedAfter !== mergedBefore) {
      await this.reload();
    } else {
      logOutput('MCP', 'Workspace changed but MCP config unchanged, skipping reload');
    }
  }

  /** Clean up on shutdown */
  async cleanup(): Promise<void> {
    for (const timer of this.retryTimers.values()) {
      clearTimeout(timer);
    }
    this.retryTimers.clear();
    this.retryAttempts.clear();
    this.startPromises.clear();

    // Stop all servers
    try {
      await invoke('stop_all_mcp_servers');
    } catch (error) {
      console.error('[MCP] Cleanup error:', error);
    }

    // Remove event listeners
    for (const unlisten of this.eventUnlisteners) {
      unlisten();
    }
    this.eventUnlisteners = [];
    this.listenersInitialized = false;

    // Stop file watchers
    if (this.userConfigWatcher) {
      this.userConfigWatcher();
      this.userConfigWatcher = null;
    }
    if (this.workspaceConfigWatcher) {
      this.workspaceConfigWatcher();
      this.workspaceConfigWatcher = null;
    }

    this.servers.clear();
    this.tools = [];
    this.initialized = false;
  }

  /** Reload all servers (after config change) */
  async reload(): Promise<void> {
    if (this.reloading) {
      this.reloadQueued = true;
      logOutput('MCP', 'Reload already running, queued one follow-up reload');
      return;
    }

    this.reloading = true;
    logOutput('MCP', 'Reloading MCP servers...');
    this.loading = true;

    try {
      // Stop all current servers
      await invoke('stop_all_mcp_servers');
      this.servers.clear();
      this.tools = [];

      // Reload configs
      await this.loadConfigs();

      // Start enabled servers
      await this.startEnabledServers();

      logOutput('MCP', `Reload complete. ${this.connectedCount} servers connected, ${this.toolCount} tools available`);
      showToast({ message: 'MCP servers reloaded', type: 'success' });
    } catch (error) {
      logOutput('MCP', `[ERROR] Reload failed: ${error}`);
      console.error('[MCP] Reload error:', error);
      showToast({ message: 'Failed to reload MCP servers', type: 'error' });
    } finally {
      this.reloading = false;
      this.loading = false;
      if (this.reloadQueued) {
        this.reloadQueued = false;
        void this.reload();
      }
    }
  }

  /** Start a specific server */
  async startServer(serverId: string): Promise<void> {
    const existing = this.startPromises.get(serverId);
    if (existing) {
      return existing;
    }

    const startPromise = this.startServerInternal(serverId).finally(() => {
      this.startPromises.delete(serverId);
    });
    this.startPromises.set(serverId, startPromise);
    return startPromise;
  }

  private async startServerInternal(serverId: string): Promise<void> {
    const config = this.mergedConfig.mcpServers?.[serverId];
    if (!config) {
      logOutput('MCP', `[ERROR] Server '${serverId}' not found in config`);
      showToast({ message: `Server '${serverId}' not found in config`, type: 'error' });
      return;
    }

    logOutput('MCP', `Starting server: ${serverId}`);
    logOutput('MCP', `  Command: ${config.command} ${(config.args || []).join(' ')}`);

    // Set initial connecting state in UI immediately
    this.servers.set(serverId, {
      id: serverId,
      name: serverId,
      status: 'connecting',
      tools: [],
    });
    this.servers = new Map(this.servers);

    try {
      const state = await invoke<McpServerState>('start_mcp_server', {
        serverId,
        config: {
          command: config.command,
          args: config.args || [],
          env: config.env || {},
          disabled: config.disabled || false,
          auto_approve: config.autoApprove || [],
        },
      });

      console.log('[MCP] Server started:', serverId, state.status);
      this.servers.set(serverId, state);
      this.servers = new Map(this.servers);
      this.updateTools();

      // Clear retry state on successful connection
      this.retryAttempts.delete(serverId);
      const existingTimer = this.retryTimers.get(serverId);
      if (existingTimer) {
        clearTimeout(existingTimer);
        this.retryTimers.delete(serverId);
      }

      logOutput('MCP', `Server '${serverId}' connected with ${state.tools.length} tools`);
      for (const tool of state.tools) {
        logOutput('MCP', `  - ${tool.name}${tool.description ? `: ${tool.description.slice(0, 60)}...` : ''}`);
      }

    } catch (error) {
      const errorMsg = String(error);
      const isTimeout = errorMsg.includes('timed out') || errorMsg.includes('timeout');
      const attempt = (this.retryAttempts.get(serverId) || 0) + 1;
      
      logOutput('MCP', `[ERROR] Failed to start '${serverId}': ${errorMsg}`);
      
      // Only show error in console, not spam user
      if (attempt === 1) {
        console.error(`[MCP] Failed to start server '${serverId}':`, error);
      }

      // Update state to show error
      this.servers.set(serverId, {
        id: serverId,
        name: serverId,
        status: 'error',
        tools: [],
        error: isTimeout ? `Connection timeout (attempt ${attempt}/${McpStore.MAX_RETRY_ATTEMPTS})` : errorMsg,
      });
      this.servers = new Map(this.servers);

      // Schedule retry for timeout errors (network issues, slow servers)
      if (isTimeout && attempt < McpStore.MAX_RETRY_ATTEMPTS) {
        this.retryAttempts.set(serverId, attempt);
        
        // Clear any existing retry timer
        const existingTimer = this.retryTimers.get(serverId);
        if (existingTimer) clearTimeout(existingTimer);
        
        logOutput('MCP', `  Will retry in ${McpStore.RETRY_DELAY_MS / 1000}s (attempt ${attempt + 1}/${McpStore.MAX_RETRY_ATTEMPTS})`);
        
        const timer = setTimeout(() => {
          this.retryTimers.delete(serverId);
          logOutput('MCP', `Retrying connection to '${serverId}'...`);
          this.startServer(serverId).catch(() => {
            // Error already handled in startServer
          });
        }, McpStore.RETRY_DELAY_MS);
        
        this.retryTimers.set(serverId, timer);
      } else if (attempt >= McpStore.MAX_RETRY_ATTEMPTS) {
        // Max retries reached - show toast once
        this.retryAttempts.delete(serverId);
        showToast({ message: `${serverId} failed after ${attempt} attempts. Check connection.`, type: 'error' });
      } else {
        // Non-timeout error - show immediately
        showToast({ message: `Failed to start ${serverId}: ${errorMsg}`, type: 'error' });
      }
    }
  }

  /** Stop a specific server */
  async stopServer(serverId: string): Promise<void> {
    logOutput('MCP', `Stopping server: ${serverId}`);
    try {
      await invoke('stop_mcp_server', { serverId });

      const server = this.servers.get(serverId);
      if (server) {
        this.servers.set(serverId, { ...server, status: 'stopped' });
        this.servers = new Map(this.servers);
      }

      this.updateTools();
      logOutput('MCP', `Server '${serverId}' stopped`);
    } catch (error) {
      logOutput('MCP', `[ERROR] Failed to stop '${serverId}': ${error}`);
      console.error(`[MCP] Failed to stop server '${serverId}':`, error);
    }
  }

  /** Call an MCP tool */
  async callTool(serverId: string, toolName: string, args: Record<string, unknown>): Promise<unknown> {
    logOutput('MCP', `Tool call: ${serverId}/${toolName}`);
    logOutput('MCP', `  Arguments: ${JSON.stringify(args).slice(0, 200)}`);
    try {
      const result = await invoke('call_mcp_tool', {
        serverId,
        toolName,
        arguments: args,
      });
      logOutput('MCP', `  Result: ${JSON.stringify(result).slice(0, 300)}${JSON.stringify(result).length > 300 ? '...' : ''}`);
      return result;
    } catch (error) {
      logOutput('MCP', `  [ERROR] ${error}`);
      console.error(`[MCP] Tool call failed:`, error);
      throw error;
    }
  }

  /** Check if a tool should be auto-approved */
  isAutoApproved(serverId: string, toolName: string): boolean {
    const config = this.mergedConfig.mcpServers?.[serverId];
    if (!config?.autoApprove) return false;
    return config.autoApprove.includes(toolName) || config.autoApprove.includes('*');
  }

  // Private methods

  private async setupEventListeners(): Promise<void> {
    if (this.listenersInitialized) {
      return;
    }

    for (const unlisten of this.eventUnlisteners) {
      try {
        unlisten();
      } catch {
        // ignore stale listeners
      }
    }
    this.eventUnlisteners = [];

    // Server state changes
    const unlistenState = await listen<McpServerEvent>('mcp://server-state', (event) => {
      const { server_id, state } = event.payload;
      const prev = this.servers.get(server_id);
      const prevTools = prev?.tools?.map((t) => t.name).join('|') ?? '';
      const nextTools = state.tools?.map((t) => t.name).join('|') ?? '';
      const unchanged =
        prev?.status === state.status &&
        (prev?.error ?? '') === (state.error ?? '') &&
        prevTools === nextTools;
      if (unchanged) return;
      console.log('[MCP] State event:', server_id, state.status);
      this.servers.set(server_id, state);
      // Force reactivity by creating new Map
      this.servers = new Map(this.servers);
      this.updateTools();
    });
    this.eventUnlisteners.push(unlistenState);

    // Server stopped
    const unlistenStopped = await listen<string>('mcp://server-stopped', (event) => {
      const serverId = event.payload;
      console.log('[MCP] Stopped event:', serverId);
      const server = this.servers.get(serverId);
      if (server) {
        this.servers.set(serverId, { ...server, status: 'stopped' });
        // Force reactivity
        this.servers = new Map(this.servers);
        this.updateTools();
      }
    });
    this.eventUnlisteners.push(unlistenStopped);

    // Server logs (stderr output)
    const unlistenLog = await listen<{ server_id: string; message: string; level: string }>('mcp://server-log', (event) => {
      const { server_id, message } = event.payload;
      logOutput('MCP', `[${server_id}] ${message}`);
    });
    this.eventUnlisteners.push(unlistenLog);
    this.listenersInitialized = true;
  }

  private async loadConfigs(): Promise<void> {
    // Load user config using Rust command (bypasses Tauri FS scope)
    if (this.userConfigPath) {
      try {
        const content = await invoke<string>('read_mcp_config');
        this.userConfig = JSON.parse(content);
        logOutput('MCP', `Loaded user config with ${Object.keys(this.userConfig?.mcpServers || {}).length} servers`);
      } catch (err) {
        // File doesn't exist or invalid JSON - that's ok
        logOutput('MCP', `No user config found: ${err}`);
        this.userConfig = null;
      }
    }

    // Load workspace config (this one is in workspace so FS plugin works)
    if (this.workspaceConfigPath) {
      try {
        const content = await readTextFile(this.workspaceConfigPath);
        this.workspaceConfig = JSON.parse(content);
        logOutput('MCP', `Loaded workspace config with ${Object.keys(this.workspaceConfig?.mcpServers || {}).length} servers`);
      } catch {
        this.workspaceConfig = null;
      }
    }
  }

  private async watchConfigs(): Promise<void> {
    // Note: User config (~/.volt/settings/mcp.json) cannot be watched due to Tauri security scope
    // User must click Reload button after editing the config file
    // Only workspace config can be auto-watched

    // Watch workspace config (if in workspace, it can be watched)
    if (this.workspaceConfigPath) {
      try {
        this.workspaceConfigWatcher = await watch(
          this.workspaceConfigPath,
          async () => {
            logOutput('MCP', 'Workspace config changed, reloading...');
            await this.reload();
          },
          { recursive: false }
        );
      } catch {
        // File might not exist yet
      }
    }
  }

  private async startEnabledServers(): Promise<void> {
    const config = this.mergedConfig;
    if (!config.mcpServers) return;

    const isDefaultDisabledServer = (serverId: string, serverConfig: McpServerConfig): boolean =>
      serverId === 'brave-search' && serverConfig.disabled === undefined;

    // First, populate all servers from config (including disabled ones)
    for (const [serverId, serverConfig] of Object.entries(config.mcpServers)) {
      if (!this.servers.has(serverId)) {
        this.servers.set(serverId, {
          id: serverId,
          name: serverId,
          status: serverConfig.disabled || isDefaultDisabledServer(serverId, serverConfig) ? 'stopped' : 'connecting',
          tools: [],
          error: undefined,
        });
      }
    }

    const enabledServers = Object.entries(config.mcpServers).filter(
      ([serverId, cfg]) => !(cfg.disabled || isDefaultDisabledServer(serverId, cfg))
    );

    if (enabledServers.length === 0) {
      logOutput('MCP', 'No enabled servers to start');
      return;
    }

    logOutput('MCP', `Starting ${enabledServers.length} enabled server(s)...`);

    // Start all servers with a stagger to avoid resource contention
    for (const [serverId] of enabledServers) {
      // Fire and forget - don't block initialization
      this.startServer(serverId).catch(err => {
        logOutput('MCP', `[ERROR] Failed to start '${serverId}': ${err}`);
      });
      // Small stagger to prevent CPU spikes
      await new Promise(resolve => setTimeout(resolve, 200));
    }
  }

  private updateTools(): void {
    const allTools: Array<{ serverId: string; tool: McpTool }> = [];

    for (const [serverId, server] of this.servers) {
      if (server.status === 'connected') {
        for (const tool of server.tools) {
          allTools.push({ serverId, tool });
        }
      }
    }

    this.tools = allTools;
  }
}

// Singleton instance
export const mcpStore = new McpStore();

// Register HMR cleanup to prevent orphaned event listeners
registerCleanup('mcp-store', () => mcpStore.cleanup());

/**
 * Search state store using Svelte 5 runes
 * Manages workspace search state and results
 */

import {
  workspaceSearchStream,
  cancelWorkspaceSearch,
  replaceInFile,
  replaceOneInFile,
  type SearchOptions,
  type SearchResults,
  type FileSearchResult,
  type SearchMatch
} from '$features/search/services/search';
import { getSemanticStatus } from '$core/ai/retrieval/semantic-index';
import type { UnlistenFn } from '@tauri-apps/api/event';
import { setModelValue } from '$core/services/monaco-models';
import { editorStore } from '$features/editor/stores/editor.svelte';
import { showToast } from '$shared/stores/toast.svelte';

export type { SearchResults, FileSearchResult, SearchMatch };
export type FileMatches = FileSearchResult;
export type SearchEngineStatus = 'unknown' | 'rg-bundled' | 'rg-system' | 'legacy-fallback';
export type SemanticBackendStatus =
  | 'unknown'
  | 'local-onnx'
  | 'local-onnx-fallback'
  | 'disabled'
  | 'error';

class SearchStore {
  // Search query
  query = $state('');
  
  // Search options
  caseSensitive = $state(false);
  useRegex = $state(false);
  wholeWord = $state(false);
  
  // Replace text
  replaceText = $state('');
  
  // Include/exclude patterns
  includePatterns = $state('');
  excludePatterns = $state('');
  
  // Search state
  searching = $state(false);
  results = $state<SearchResults | null>(null);
  lastSearchCancelled = $state(false);
  searchEngineStatus = $state<SearchEngineStatus>('unknown');
  semanticBackendStatus = $state<SemanticBackendStatus>('unknown');
  searchEngineHint = $state<string | null>(null);
  
  // Expanded files in results (for collapsible file groups)
  expandedFiles = $state<Set<string>>(new Set());
  
  // Currently selected result for highlighting
  selectedFile = $state<string | null>(null);
  selectedMatch = $state<SearchMatch | null>(null);

  private searchSeq = 0;
  private requestId = 0;
  private inFlightRequestId: number | null = null;
  private unlistenStream: UnlistenFn | null = null;

  private streamFileMap: Map<string, FileSearchResult> | null = null;
  private streamPendingFiles: FileSearchResult[] = [];
  private streamLatestTotalMatches = 0;
  private streamLatestTruncated = false;
  private streamFlushTimer: ReturnType<typeof setTimeout> | null = null;

  private mapSearchEngineStatus(telemetry?: {
    engine: string;
    fallbackUsed: boolean;
    rgSource: string;
  }): SearchEngineStatus {
    if (!telemetry) return this.searchEngineStatus;
    if (telemetry.engine === 'legacy') return 'legacy-fallback';
    if (telemetry.rgSource === 'bundled') return 'rg-bundled';
    if (telemetry.rgSource === 'system') return 'rg-system';
    return 'legacy-fallback';
  }

  private mapSemanticStatus(backend: string): SemanticBackendStatus {
    if (backend === 'local-onnx') return 'local-onnx';
    if (backend === 'local-onnx-fallback') return 'local-onnx-fallback';
    if (backend === 'disabled') return 'disabled';
    return 'error';
  }

  private async refreshSemanticStatus(rootPath: string): Promise<void> {
    const status = await getSemanticStatus(rootPath);
    if (!status) return;
    this.semanticBackendStatus = this.mapSemanticStatus(status.backend);
  }

  private normalizePath(path: string): string {
    return path.replace(/\\/g, '/');
  }

  private parsePatternList(input: string): string[] {
    // Accept comma-separated, whitespace-separated, or newline-separated lists.
    // (VS Code commonly uses one pattern per line, but users often paste space-separated too.)
    return input
      .split(/[\s,]+/)
      .map((p) => p.trim())
      .filter(Boolean);
  }

  /**
   * Perform search with current options
   */
  async search(rootPath: string): Promise<void> {
    if (!this.query.trim() || !rootPath) {
      this.results = null;
      this.lastSearchCancelled = false;
      return;
    }

    const seq = ++this.searchSeq;

    // Cancel any in-flight search to keep UI responsive.
    if (this.inFlightRequestId) {
      void cancelWorkspaceSearch(this.inFlightRequestId);
    }
    if (this.unlistenStream) {
      this.unlistenStream();
      this.unlistenStream = null;
    }
    if (this.streamFlushTimer) {
      clearTimeout(this.streamFlushTimer);
      this.streamFlushTimer = null;
    }

    const requestId = ++this.requestId;
    this.inFlightRequestId = requestId;

    this.searching = true;
    this.lastSearchCancelled = false;
    this.results = {
      files: [],
      totalMatches: 0,
      totalFiles: 0,
      truncated: false
    };

    // Incremental merge state for this search
    this.streamFileMap = new Map();
    this.streamPendingFiles = [];
    this.streamLatestTotalMatches = 0;
    this.streamLatestTruncated = false;

    const flushStream = (): void => {
      this.streamFlushTimer = null;
      if (seq !== this.searchSeq || requestId !== this.inFlightRequestId) return;
      if (!this.results) return;
      if (!this.streamFileMap) return;

      if (this.streamPendingFiles.length === 0) {
        // Still update totals while searching
        this.results = {
          files: this.results.files,
          totalMatches: this.streamLatestTotalMatches,
          totalFiles: this.results.files.length,
          truncated: this.streamLatestTruncated
        };
        return;
      }

      const expanded = new Set(this.expandedFiles);

      for (const file of this.streamPendingFiles) {
        const key = file.path;
        const isNew = !this.streamFileMap.has(key);
        this.streamFileMap.set(key, file);

        if (isNew) {
          const count = this.streamFileMap.size;
          if (count <= 10) {
            expanded.add(key);
          } else if (expanded.size < 3) {
            expanded.add(key);
          }
        }
      }

      this.streamPendingFiles = [];

      const files = Array.from(this.streamFileMap.values()).sort((a, b) =>
        a.path.localeCompare(b.path, undefined, { sensitivity: 'base' })
      );

      this.expandedFiles = expanded;
      this.results = {
        files,
        totalMatches: this.streamLatestTotalMatches,
        totalFiles: files.length,
        truncated: this.streamLatestTruncated
      };
    };

    const options: SearchOptions = {
      query: this.query,
      rootPath,
      caseSensitive: this.caseSensitive,
      useRegex: this.useRegex,
      wholeWord: this.wholeWord,
      includePatterns: this.includePatterns ? this.parsePatternList(this.includePatterns) : [],
      excludePatterns: this.excludePatterns ? this.parsePatternList(this.excludePatterns) : [],
      maxResults: 5000,
      requestId
    };

    this.unlistenStream = await workspaceSearchStream(options, {
      onChunk: (chunk) => {
        if (seq !== this.searchSeq || requestId !== this.inFlightRequestId) return;

        this.streamLatestTotalMatches = chunk.totalMatches;
        this.streamLatestTruncated = chunk.truncated;
        this.streamPendingFiles.push(...chunk.files);

        if (!this.streamFlushTimer) {
          this.streamFlushTimer = setTimeout(flushStream, 50);
        }
      },
      onDone: (done) => {
        if (seq !== this.searchSeq || done.requestId !== requestId) return;

        if (this.streamFlushTimer) {
          clearTimeout(this.streamFlushTimer);
          this.streamFlushTimer = null;
        }
        // Flush any pending files immediately
        flushStream();

        this.searching = false;
        this.lastSearchCancelled = done.cancelled;
        if (!done.cancelled) {
          const files = this.results?.files ?? [];
          this.results = {
            files,
            totalMatches: done.totalMatches,
            totalFiles: done.totalFiles,
            truncated: done.truncated,
            telemetry: done.telemetry
          };
          this.searchEngineStatus = this.mapSearchEngineStatus(done.telemetry);
          this.searchEngineHint = done.telemetry?.fallbackReason ?? null;
        }

        if (this.inFlightRequestId === requestId) {
          this.inFlightRequestId = null;
        }

        if (this.unlistenStream) {
          this.unlistenStream();
          this.unlistenStream = null;
        }

        this.streamFileMap = null;
        this.streamPendingFiles = [];
      },
      onError: (evt) => {
        if (seq !== this.searchSeq || evt.requestId !== requestId) return;
        // Errors here are unexpected (cancel is handled separately).
        showToast({ message: `Search error: ${evt.error.message || evt.error.type}`, type: 'error' });
      }
    });

    await this.refreshSemanticStatus(rootPath);
  }

  /**
   * Clear search results
   */
  clear(): void {
    this.query = '';
    this.results = null;
    this.lastSearchCancelled = false;
    this.expandedFiles = new Set();
    this.selectedFile = null;
    this.selectedMatch = null;
    this.searchEngineHint = null;
    if (this.inFlightRequestId) {
      void cancelWorkspaceSearch(this.inFlightRequestId);
      this.inFlightRequestId = null;
    }
    if (this.unlistenStream) {
      this.unlistenStream();
      this.unlistenStream = null;
    }
    if (this.streamFlushTimer) {
      clearTimeout(this.streamFlushTimer);
      this.streamFlushTimer = null;
    }
    this.streamFileMap = null;
    this.streamPendingFiles = [];
  }

  /**
   * Toggle file expansion in results
   */
  toggleFileExpanded(path: string): void {
    const newSet = new Set(this.expandedFiles);
    if (newSet.has(path)) {
      newSet.delete(path);
    } else {
      newSet.add(path);
    }
    this.expandedFiles = newSet;
  }

  /**
   * Expand all files in results
   */
  expandAll(): void {
    if (this.results) {
      this.expandedFiles = new Set(this.results.files.map(f => f.path));
    }
  }

  /**
   * Collapse all files in results
   */
  collapseAll(): void {
    this.expandedFiles = new Set();
  }

  /**
   * Select a match for highlighting
   */
  selectMatch(file: string, match: SearchMatch): void {
    this.selectedFile = file;
    this.selectedMatch = match;
  }

  /**
   * Replace in a single file
   */
  async replaceInSingleFile(path: string): Promise<boolean> {
    if (!this.query.trim()) {
      return false;
    }

    const normalizedPath = this.normalizePath(path);

    // Safety: avoid overwriting unsaved edits.
    if (editorStore.isDirty(normalizedPath)) {
      const confirmed = confirm(
        `"${normalizedPath.split('/').pop() || normalizedPath}" has unsaved changes. Replace will overwrite them. Continue?`
      );
      if (!confirmed) return false;
    }

    const result = await replaceInFile({
      path,
      search: this.query,
      replace: this.replaceText,
      caseSensitive: this.caseSensitive,
      useRegex: this.useRegex,
      wholeWord: this.wholeWord
    });

    if (result) {
      // If the file is open, sync Monaco model + editor store so we don't re-save old content.
      const updated = setModelValue(normalizedPath, result.content);
      if (updated) {
        editorStore.updateContent(normalizedPath, result.content);
        editorStore.markSaved(normalizedPath);
      }

      showToast({
        message: `Replaced ${result.replacements} occurrence${result.replacements === 1 ? '' : 's'} in file`,
        type: 'success'
      });
      return true;
    }

    return false;
  }

  private getNextMatch(): { filePath: string; match: SearchMatch } | null {
    if (this.selectedFile && this.selectedMatch) {
      return { filePath: this.selectedFile, match: this.selectedMatch };
    }

    const firstFile = this.results?.files?.[0];
    const firstMatch = firstFile?.matches?.[0];
    if (!firstFile || !firstMatch) return null;
    return { filePath: firstFile.path, match: firstMatch };
  }

  /**
   * Replace the currently selected match, or the next match if none selected.
   */
  async replaceNext(rootPath: string): Promise<boolean> {
    if (!this.query.trim() || !this.results) {
      return false;
    }

    const target = this.getNextMatch();
    if (!target) return false;

    const normalizedPath = this.normalizePath(target.filePath);

    // Safety: avoid overwriting unsaved edits.
    if (editorStore.isDirty(normalizedPath)) {
      const confirmed = confirm(
        `"${normalizedPath.split('/').pop() || normalizedPath}" has unsaved changes. Replace will overwrite them. Continue?`
      );
      if (!confirmed) return false;
    }

    const result = await replaceOneInFile({
      path: target.filePath,
      line: target.match.line,
      columnStart: target.match.columnStart,
      columnEnd: target.match.columnEnd,
      expected: target.match.matchText,
      replace: this.replaceText
    });

    if (result) {
      const updated = setModelValue(normalizedPath, result.content);
      if (updated) {
        editorStore.updateContent(normalizedPath, result.content);
        editorStore.markSaved(normalizedPath);
      }

      showToast({ message: 'Replaced 1 occurrence', type: 'success' });

      await this.search(rootPath);
      return true;
    }

    return false;
  }

  /**
   * Replace all matches in all files
   */
  async replaceAll(rootPath: string): Promise<void> {
    if (!this.results || !this.query.trim()) {
      return;
    }

    let totalReplacements = 0;
    let filesModified = 0;

    for (const file of this.results.files) {
      const normalizedPath = this.normalizePath(file.path);

      // Safety: avoid overwriting unsaved edits.
      if (editorStore.isDirty(normalizedPath)) {
        const confirmed = confirm(
          `"${normalizedPath.split('/').pop() || normalizedPath}" has unsaved changes. Replace will overwrite them. Continue?`
        );
        if (!confirmed) {
          continue;
        }
      }

      const result = await replaceInFile({
        path: file.path,
        search: this.query,
        replace: this.replaceText,
        caseSensitive: this.caseSensitive,
        useRegex: this.useRegex,
        wholeWord: this.wholeWord
      });

      if (result && result.replacements > 0) {
        totalReplacements += result.replacements;
        filesModified++;

        // Sync Monaco/editor state for open files.
        const updated = setModelValue(normalizedPath, result.content);
        if (updated) {
          editorStore.updateContent(normalizedPath, result.content);
          editorStore.markSaved(normalizedPath);
        }
      }
    }

    showToast({
      message: `Replaced ${totalReplacements} occurrence${totalReplacements === 1 ? '' : 's'} in ${filesModified} file${filesModified === 1 ? '' : 's'}`,
      type: 'success'
    });

    // Re-run search to update results
    await this.search(rootPath);
  }

  /**
   * Toggle case sensitive option
   */
  toggleCaseSensitive(): void {
    this.caseSensitive = !this.caseSensitive;
  }

  /**
   * Toggle regex option
   */
  toggleRegex(): void {
    this.useRegex = !this.useRegex;
  }

  /**
   * Toggle whole word option
   */
  toggleWholeWord(): void {
    this.wholeWord = !this.wholeWord;
  }
}

// Singleton instance
export const searchStore = new SearchStore();

