import { invoke } from '@tauri-apps/api/core';
import { listen, type UnlistenFn } from '@tauri-apps/api/event';
import { registerCleanup } from '$core/services/hmr-cleanup';

/**
 * Terminal session info returned from Rust backend
 */
export interface TerminalInfo {
	terminalId: string;
	shell: string;
	cwd: string;
	cols: number;
	rows: number;
}

/**
 * Terminal data event payload
 */
export interface TerminalDataEvent {
	terminalId: string;
	data: string;
}

/**
 * Terminal exit event payload
 */
export interface TerminalExitEvent {
	terminalId: string;
	code: number | null;
}

/**
 * Terminal ready event payload
 */
export interface TerminalReadyEvent {
	terminalId: string;
}

/**
 * Create a new raw terminal via Tauri invoke
 */
export async function createTerminal(
	cwd?: string,
	cols?: number,
	rows?: number
): Promise<TerminalInfo | null> {
	try {
		return await invoke<TerminalInfo>('terminal_create', { cwd, cols, rows });
	} catch (error) {
		console.error('Terminal create error:', error);
		return null;
	}
}

/**
 * Write data to a terminal via Tauri invoke
 */
export async function writeTerminal(terminalId: string, data: string): Promise<boolean> {
	try {
		await invoke('terminal_write', { terminalId, data });
		return true;
	} catch (error) {
		console.error('Terminal write error:', error);
		return false;
	}
}

/**
 * Resize a terminal via Tauri invoke
 */
export async function resizeTerminal(terminalId: string, cols: number, rows: number): Promise<boolean> {
	try {
		await invoke('terminal_resize', { terminalId, cols, rows });
		return true;
	} catch (error) {
		console.error('Terminal resize error:', error);
		return false;
	}
}

/**
 * Kill a terminal via Tauri invoke
 */
export async function killTerminal(terminalId: string): Promise<boolean> {
	try {
		await invoke('terminal_kill', { terminalId });
		return true;
	} catch (error) {
		console.error('Terminal kill error:', error);
		return false;
	}
}

/**
 * List all active terminals via Tauri invoke
 */
export async function listTerminals(): Promise<TerminalInfo[]> {
	try {
		return await invoke<TerminalInfo[]>('terminal_list');
	} catch (error) {
		console.error('Terminal list error:', error);
		return [];
	}
}

/**
 * Read backend scrollback for an active terminal.
 * Used to rehydrate terminal output after frontend reload/HMR.
 */
export async function getTerminalScrollback(
	terminalId: string,
	maxChars = 250_000
): Promise<string> {
	try {
		return await invoke<string>('terminal_get_scrollback', { terminalId, maxChars });
	} catch (error) {
		console.error('Terminal scrollback error:', error);
		return '';
	}
}

/**
 * Kill all terminals via Tauri invoke
 */
export async function killAllTerminals(): Promise<boolean> {
	try {
		await invoke('terminal_kill_all');
		return true;
	} catch (error) {
		console.error('Terminal kill all error:', error);
		return false;
	}
}

// Global event dispatcher to prevent race conditions
const sessionRegistry = new Map<string, TerminalSession>();
const pendingEvents = new Map<string, Array<{ type: string; payload: any }>>();

/**
 * Start global listeners immediately to capture all terminal events
 */
type TerminalListenerState = {
	started: boolean;
	startPromise: Promise<void> | null;
	unlisteners: UnlistenFn[];
};

const globalScope = globalThis as typeof globalThis & {
	__voltTerminalListeners?: TerminalListenerState;
};

function getTerminalListenerState(): TerminalListenerState {
	if (!globalScope.__voltTerminalListeners) {
		globalScope.__voltTerminalListeners = {
			started: false,
			startPromise: null,
			unlisteners: []
		};
	}
	return globalScope.__voltTerminalListeners;
}

async function startGlobalListeners() {
	const state = getTerminalListenerState();
	if (state.started) return;
	if (state.startPromise) return state.startPromise;

	state.startPromise = (async () => {
		const [unlistenData, unlistenExit, unlistenReady] = await Promise.all([
			listen<TerminalDataEvent>('terminal://data', (event) => {
				const session = sessionRegistry.get(event.payload.terminalId);
				if (session) {
					session.handleDataEvent(event.payload);
				} else {
					const events = pendingEvents.get(event.payload.terminalId) || [];
					events.push({ type: 'data', payload: event.payload });
					pendingEvents.set(event.payload.terminalId, events);
				}
			}),
			listen<TerminalExitEvent>('terminal://exit', (event) => {
				const session = sessionRegistry.get(event.payload.terminalId);
				if (session) {
					session.handleExitEvent(event.payload);
				} else {
					const events = pendingEvents.get(event.payload.terminalId) || [];
					events.push({ type: 'exit', payload: event.payload });
					pendingEvents.set(event.payload.terminalId, events);
				}
			}),
			listen<TerminalReadyEvent>('terminal://ready', (event) => {
				const session = sessionRegistry.get(event.payload.terminalId);
				if (session) {
					session.handleReadyEvent(event.payload);
				} else {
					const events = pendingEvents.get(event.payload.terminalId) || [];
					events.push({ type: 'ready', payload: event.payload });
					pendingEvents.set(event.payload.terminalId, events);
				}
			})
		]);

		state.unlisteners = [unlistenData, unlistenExit, unlistenReady];
		state.started = true;
		state.startPromise = null;
	})().catch((error) => {
		state.startPromise = null;
		state.started = false;
		console.error('[TerminalClient] Failed to start global listeners:', error);
	});

	return state.startPromise;
}

async function stopGlobalListeners(): Promise<void> {
	const state = getTerminalListenerState();
	for (const unlisten of state.unlisteners) {
		try {
			unlisten();
		} catch {
			// ignore
		}
	}
	state.unlisteners = [];
	state.started = false;
	state.startPromise = null;
}

// Kick off global listeners
void startGlobalListeners();
registerCleanup('terminal-client-events', () => stopGlobalListeners());

export async function onTerminalData(
	callback: (event: TerminalDataEvent) => void
): Promise<UnlistenFn> {
	return listen<TerminalDataEvent>('terminal://data', (event) => callback(event.payload));
}

export async function onTerminalExit(
	callback: (event: TerminalExitEvent) => void
): Promise<UnlistenFn> {
	return listen<TerminalExitEvent>('terminal://exit', (event) => callback(event.payload));
}

export async function onTerminalReady(
	callback: (event: TerminalReadyEvent) => void
): Promise<UnlistenFn> {
	return listen<TerminalReadyEvent>('terminal://ready', (event) => callback(event.payload));
}

// ============================================================================
// OSC 633 Shell Integration
// ============================================================================

export interface ShellIntegrationEvent {
	type: 'prompt-start' | 'prompt-end' | 'command-start' | 'command-finish' | 'command-line' | 'property';
	exitCode?: number;
	command?: string;
	property?: { key: string; value: string };
}

export interface CommandCompletion {
	exitCode: number;
	output: string;
	cwd?: string;
	timedOut: boolean;
}

const OSC_633_REGEX = /\x1b\]633;([A-Z])(?:;([^\x07\x1b]*))?\x07|\x1b\]633;([A-Z])(?:;([^\x07\x1b]*))?\x1b\\/g;
const OSC_GENERIC_REGEX = /\x1b\][^\x07\x1b]*(?:\x07|\x1b\\)/g;

function stripTerminalArtifacts(data: string): string {
	if (!data) return '';
	let cleaned = data;

	// Remove OSC control sequences (633 + any other OSC payload)
	cleaned = cleaned.replace(OSC_633_REGEX, '');
	cleaned = cleaned.replace(OSC_GENERIC_REGEX, '');

	// Remove fallback sentinels and helper variable noise
	cleaned = cleaned
		.replace(/__VOLT_EXIT_CODE_\d+__/g, '')
		.replace(/__VOLT_DONE_[A-Za-z0-9]+__/g, '')
		.replace(/^\s*\$voltExit\s*=.*$/gm, '');

	// Remove leaked plain-text cursor query marker while preserving real ESC[6n control queries.
	// Stripping ESC[6n would prevent xterm from answering DSR and can freeze prompt rendering.
	cleaned = cleaned.replace(/(?<!\x1b)\[6n/g, '');

	// Remove any line that still contains raw shell integration markers
	cleaned = cleaned
		.replace(/^.*\]633;.*$/gm, '')
		.replace(/^.*ShellIntegration=Volt.*$/gmi, '');

	return cleaned;
}

function parseOscSequences(data: string): { events: ShellIntegrationEvent[]; cleanData: string } {
	const events: ShellIntegrationEvent[] = [];
	let cleanData = data;

	let match;
	while ((match = OSC_633_REGEX.exec(data)) !== null) {
		const code = match[1] || match[3];
		const params = match[2] || match[4] || '';

		switch (code) {
			case 'A': events.push({ type: 'prompt-start' }); break;
			case 'B': events.push({ type: 'prompt-end' }); break;
			case 'C': events.push({ type: 'command-start' }); break;
			case 'D': events.push({ type: 'command-finish', exitCode: params ? parseInt(params, 10) : undefined }); break;
			case 'E': events.push({ type: 'command-line', command: decodeOscString(params) }); break;
			case 'P':
				const parts = params.split('=');
				if (parts.length >= 2) {
					events.push({ type: 'property', property: { key: parts[0], value: decodeOscString(parts.slice(1).join('=')) } });
				}
				break;
		}
	}

	cleanData = data.replace(OSC_633_REGEX, '');
	return { events, cleanData };
}

function decodeOscString(str: string): string {
	if (!str) return '';
	return str.replace(/\\x([0-9A-Fa-f]{2})/g, (_, hex) => String.fromCharCode(parseInt(hex, 16)));
}

// Universal PowerShell prompt script (works in 5.1 and Core)
export const POWERSHELL_SHELL_INTEGRATION = [
	'function prompt {',
	'  try {',
	'    $e = [char]27; $a = [char]7; $c = (Get-Location).Path;',
	'    Write-Host -NoNewline "$e]633;P;Cwd=$c$a";',
	'    Write-Host -NoNewline "$e]633;A$a";',
	'    $p = "PS $c> ";',
	'    Write-Host -NoNewline "$e]633;B$a";',
	'    if ($null -ne $LASTEXITCODE) { Write-Host -NoNewline "$e]633;D;$LASTEXITCODE$a" };',
	'    return $p;',
	'  } catch { return "PS > " }',
	'};',
	'Write-Host -NoNewline "$([char]27)]633;P;ShellIntegration=Volt$([char]7)";',
	'Clear-Host'
].join(' ');

/**
 * Terminal session manager
 */
export class TerminalSession {
	public info: TerminalInfo;
	private dataUnlisten: UnlistenFn | null = null;
	private exitUnlisten: UnlistenFn | null = null;
	private readyUnlisten: UnlistenFn | null = null;
	private onDataCallback: ((data: string) => void) | null = null;
	private onExitCallback: ((code: number | null) => void) | null = null;

	private dataBuffer: string[] = [];
	private dataBufferChars = 0;
	private static readonly MAX_BUFFER_CHARS = 1_000_000;

	private outputHistory: string[] = [];
	private outputHistoryChars = 0;
	private static readonly MAX_OUTPUT_HISTORY_CHARS = 1_000_000;

	private cleanOutputHistory: string[] = [];
	private cleanOutputHistoryChars = 0;
	private cleanOutputStartOffset = 0;
	private cleanOutputEndOffset = 0;

	private backendReady = false;
	private readyPromise: Promise<void>;
	private resolveReady: (() => void) | null = null;

	private shellIntegrationEnabled = false;
	private currentCwd: string | null = null;
	private commandCompletionCallbacks: Array<{
		resolve: (result: CommandCompletion) => void;
		startTime: number;
		outputBuffer: string[];
		startOffset: number;
	}> = [];

	constructor(info: TerminalInfo) {
		this.info = info;
		this.currentCwd = info.cwd;
		this.readyPromise = new Promise((resolve) => {
			this.resolveReady = resolve;
		});
	}

	public get id(): string { return this.info.terminalId; }

	public get hasShellIntegration(): boolean {
		return this.shellIntegrationEnabled;
	}

	public get cwd(): string | null {
		return this.currentCwd;
	}

	public async startListening(): Promise<void> {
		// Register with global dispatcher
		sessionRegistry.set(this.id, this);

		// Flush any pending events that arrived before we started listening
		const events = pendingEvents.get(this.id);
		if (events) {
			pendingEvents.delete(this.id);
			for (const event of events) {
				if (event.type === 'data') this.handleDataEvent(event.payload);
				else if (event.type === 'exit') this.handleExitEvent(event.payload);
				else if (event.type === 'ready') this.handleReadyEvent(event.payload);
			}
		}
	}

	public handleDataEvent(payload: TerminalDataEvent): void {
		this.markReady();
		const { events, cleanData } = parseOscSequences(payload.data);
		for (const ev of events) this.handleShellIntegrationEvent(ev);

		this.captureToHistory(payload.data);
		if (cleanData) {
			const sanitized = stripTerminalArtifacts(cleanData);
			if (sanitized) {
				this.captureToCleanHistory(sanitized);
				for (const cb of this.commandCompletionCallbacks) cb.outputBuffer.push(sanitized);
			}
		}

		const filteredDisplay = stripTerminalArtifacts(cleanData);

		if (filteredDisplay) {
			if (this.onDataCallback) this.onDataCallback(filteredDisplay);
			else this.bufferData(filteredDisplay);
		}
	}

	/**
	 * Rehydrate in-memory buffers from backend scrollback after reload/HMR.
	 */
	public hydrateScrollback(rawData: string): void {
		if (!rawData) return;
		this.handleDataEvent({ terminalId: this.id, data: rawData });
	}

	public handleExitEvent(payload: TerminalExitEvent): void {
		if (this.onExitCallback) this.onExitCallback(payload.code);
	}

	public handleReadyEvent(payload: TerminalReadyEvent): void {
		this.markReady();
	}

	private markReady(): void {
		if (this.backendReady) return;
		this.backendReady = true;
		this.resolveReady?.();
	}

	public async waitForReady(timeoutMs = 5000): Promise<boolean> {
		if (this.backendReady) return true;
		const timeout = new Promise<boolean>((resolve) => setTimeout(() => resolve(this.backendReady), timeoutMs));
		return Promise.race([this.readyPromise.then(() => true), timeout]);
	}

	public async write(data: string): Promise<boolean> {
		return writeTerminal(this.id, data);
	}

	public async resize(cols: number, rows: number): Promise<boolean> {
		const success = await resizeTerminal(this.id, cols, rows);
		if (success) {
			this.info.cols = cols;
			this.info.rows = rows;
		}
		return success;
	}

	public onData(callback: ((data: string) => void) | null): void {
		this.onDataCallback = callback;
		if (callback && this.dataBuffer.length > 0) {
			callback(this.dataBuffer.join(''));
			this.dataBuffer = [];
			this.dataBufferChars = 0;
		}
	}

	public onExit(callback: (code: number | null) => void): void {
		this.onExitCallback = callback;
	}

	private handleShellIntegrationEvent(event: ShellIntegrationEvent): void {
		switch (event.type) {
			case 'property':
				if (event.property?.key === 'ShellIntegration') {
					this.shellIntegrationEnabled = true;
				} else if (event.property?.key === 'Cwd') {
					this.currentCwd = event.property.value;
				}
				break;
			case 'command-finish':
				const exitCode = event.exitCode ?? 0;
				const callbacks = [...this.commandCompletionCallbacks];
				this.commandCompletionCallbacks = [];
				for (const cb of callbacks) {
					cb.resolve({
						exitCode,
						output: this.cleanCommandOutput(cb.outputBuffer.join('')),
						cwd: this.currentCwd ?? undefined,
						timedOut: false
					});
				}
				break;
		}
	}

	private cleanCommandOutput(output: string): string {
		const ansiRegex = /[\u001b\u009b][[()#;?]*(?:[0-9]{1,4}(?:;[0-9]{0,4})*)?[0-9A-ORZcf-nqry=><]/g;
		let cleaned = output.replace(ansiRegex, '');
		cleaned = stripTerminalArtifacts(cleaned).trim();
		cleaned = cleaned.replace(/\nPS [^\n]+>\s*$/, '');
		cleaned = cleaned.replace(/\n\$\s*$/, '');
		return cleaned;
	}

	private captureToHistory(data: string): void {
		this.outputHistory.push(data);
		this.outputHistoryChars += data.length;
		while (this.outputHistoryChars > TerminalSession.MAX_OUTPUT_HISTORY_CHARS) {
			const removed = this.outputHistory.shift();
			this.outputHistoryChars -= (removed?.length ?? 0);
		}
	}

	private captureToCleanHistory(data: string): void {
		this.cleanOutputHistory.push(data);
		this.cleanOutputHistoryChars += data.length;
		this.cleanOutputEndOffset += data.length;
		while (this.cleanOutputHistoryChars > TerminalSession.MAX_OUTPUT_HISTORY_CHARS) {
			const removed = this.cleanOutputHistory.shift();
			const removedLen = removed?.length ?? 0;
			this.cleanOutputHistoryChars -= removedLen;
			this.cleanOutputStartOffset += removedLen;
		}
	}

	private bufferData(data: string): void {
		this.dataBuffer.push(data);
		this.dataBufferChars += data.length;
		while (this.dataBufferChars > TerminalSession.MAX_BUFFER_CHARS) {
			const removed = this.dataBuffer.shift();
			this.dataBufferChars -= (removed?.length ?? 0);
		}
	}

	public getRecentOutput(maxChars = 20000): string {
		const full = this.outputHistory.join('');
		return full.length <= maxChars ? full : full.slice(-maxChars);
	}

	public getRecentCleanOutput(maxChars = 10000): string {
		const full = this.cleanOutputHistory.join('');
		return full.length <= maxChars ? full : full.slice(-maxChars);
	}

	public getCleanOutputCursor(): number {
		return this.cleanOutputEndOffset;
	}

	public readCleanOutputSince(
		offset: number,
		maxChars = 200_000
	): { text: string; nextOffset: number; truncatedBeforeOffset: boolean } {
		const normalizedOffset = Number.isFinite(offset) ? Math.max(0, offset) : 0;
		const startOffset = Math.max(normalizedOffset, this.cleanOutputStartOffset);
		const localStart = startOffset - this.cleanOutputStartOffset;
		const full = this.cleanOutputHistory.join('');
		let text = full.slice(localStart);
		if (text.length > maxChars) {
			text = text.slice(-maxChars);
		}
		return {
			text,
			nextOffset: this.cleanOutputEndOffset,
			truncatedBeforeOffset: normalizedOffset < this.cleanOutputStartOffset
		};
	}

	public getCleanOutputSince(offset: number): string {
		return this.readCleanOutputSince(offset, Number.POSITIVE_INFINITY).text;
	}

	public async waitForOutput(predicate: (text: string) => boolean, timeoutMs = 10000, startOffset = 0): Promise<string> {
		const startTime = Date.now();
		return new Promise((resolve, reject) => {
			const check = () => {
				const recent = this.outputHistory.join('').slice(startOffset);
				if (predicate(recent)) resolve(recent);
				else if (Date.now() - startTime > timeoutMs) reject(new Error('Timeout'));
				else setTimeout(check, 100);
			};
			check();
		});
	}

	public async enableShellIntegration(): Promise<boolean> {
		if (this.shellIntegrationEnabled) return true;
		if (!this.info.shell.toLowerCase().match(/powershell|pwsh/)) return false;

		// Send the complete integration script in a single line to be safe
		await this.write(POWERSHELL_SHELL_INTEGRATION + '\r\n');

		const start = Date.now();
		while (!this.shellIntegrationEnabled && Date.now() - start < 3000) {
			await new Promise(r => setTimeout(r, 100));
		}
		return this.shellIntegrationEnabled;
	}

	public async executeCommand(command: string, timeoutMs = 300000): Promise<CommandCompletion> {
		if (!this.shellIntegrationEnabled) return this.executeCommandFallback(command, timeoutMs);
		return new Promise((resolve) => {
			const startOffset = this.getCleanOutputCursor();
			let tid: ReturnType<typeof setTimeout> | null = null;
			if (timeoutMs > 0) {
				tid = setTimeout(() => {
					this.commandCompletionCallbacks = this.commandCompletionCallbacks.filter(c => c.resolve !== resolve);
					resolve({ exitCode: -1, output: this.getCleanOutputSince(startOffset), cwd: this.currentCwd ?? undefined, timedOut: true });
				}, timeoutMs);
			}
			this.commandCompletionCallbacks.push({
				resolve: (res) => { if (tid) clearTimeout(tid); resolve(res); },
				startTime: Date.now(),
				outputBuffer: [],
				startOffset
			});
			this.write(`\x1b]633;C\x07${command}\r`);
		});
	}

	private async executeCommandFallback(command: string, timeoutMs: number): Promise<CommandCompletion> {
		const sentinel = Math.random().toString(36).substring(2, 12);
		const startOffset = this.outputHistoryChars;
		const capture = `$voltExit = if ($?) { if ($null -ne $LASTEXITCODE) { $LASTEXITCODE } else { 0 } } else { if ($null -ne $LASTEXITCODE) { $LASTEXITCODE } else { 1 } }`;
		await this.write(`${command}; ${capture}; echo "__VOLT_EXIT_CODE_$voltExit__"; echo "__VOLT_DONE_${sentinel}__"\r`);

		try {
			const effectiveTimeout = timeoutMs > 0 ? timeoutMs : Number.POSITIVE_INFINITY;
			const raw = await this.waitForOutput(t => t.includes(`__VOLT_DONE_${sentinel}__`), effectiveTimeout, startOffset);
			const exitMatch = raw.match(/__VOLT_EXIT_CODE_(\d+)__/);
			const exitCode = exitMatch ? parseInt(exitMatch[1], 10) : 0;
			const ansiRegex = /[\u001b\u009b][[()#;?]*(?:[0-9]{1,4}(?:;[0-9]{0,4})*)?[0-9A-ORZcf-nqry=><]/g;
			let cleaned = raw.replace(ansiRegex, '');
			cleaned = stripTerminalArtifacts(cleaned);
			const lines = cleaned.split(/\r?\n/).map(l => l.trim()).filter(Boolean);
			let startIdx = 0;
			for (let i = 0; i < Math.min(lines.length, 5); i++) {
				if (lines[i].includes('$voltExit') || lines[i].includes('__VOLT_DONE_') || lines[i].includes(command.slice(0, 20))) startIdx = i + 1;
			}
			const final = lines.slice(startIdx).filter(l => !l.includes('__VOLT_') && !l.includes('$voltExit') && !l.includes('PS ')).join('\n').trim();
			return { exitCode, output: final || '[Done]', cwd: this.currentCwd ?? undefined, timedOut: false };
		} catch {
			return { exitCode: -1, output: '[Timeout]', timedOut: true };
		}
	}

	public async kill(): Promise<void> {
		await killTerminal(this.id);
		this.dispose();
	}

	public dispose(): void {
		sessionRegistry.delete(this.id);
		pendingEvents.delete(this.id);
		this.dataUnlisten?.();
		this.exitUnlisten?.();
		this.readyUnlisten?.();
	}
}

export async function createTerminalSession(cwd?: string, cols?: number, rows?: number): Promise<TerminalSession | null> {
	const info = await createTerminal(cwd, cols, rows);
	if (!info) return null;
	const session = new TerminalSession(info);
	await session.startListening();
	return session;
}

/**
 * Rehydrate a session object from an already-running backend terminal.
 * Used after frontend reload/HMR so existing terminals remain visible/controllable.
 */
export async function createTerminalSessionFromInfo(info: TerminalInfo): Promise<TerminalSession> {
	const session = new TerminalSession(info);
	await session.startListening();
	const scrollback = await getTerminalScrollback(info.terminalId);
	if (scrollback) {
		session.hydrateScrollback(scrollback);
	}
	return session;
}

import { problemsStore, type Problem } from '$shared/stores/problems.svelte';
import { onTerminalData, onTerminalExit } from './terminal-client';

let resolveProjectRootPath: (() => string | null) | null = null;

export function setTerminalProblemMatcherProjectRootResolver(
  resolver: (() => string | null) | null
): void {
  resolveProjectRootPath = resolver;
}

/**
 * TerminalProblemMatcher - Parses terminal output for errors and warnings
 * Pipes matched problems to the problemsStore
 */
class TerminalProblemMatcher {
    private unlisten: (() => void) | null = null;
    private unlistenExit: (() => void) | null = null;
    private buffer = new Map<string, string>(); // terminalId -> partial line buffer
    private bufferFlushTimers = new Map<string, ReturnType<typeof setTimeout>>();
    private problemsByKey = new Map<string, { filePath: string; source: string; problems: Problem[] }>();
    private static readonly BUFFER_FLUSH_MS = 100;

    // Common error patterns
    private patterns = [
        // Flutter/Dart Error: lib/main.dart:45:13: Error: Message
        {
            regex: /^(.+?):(\d+):(\d+): (Error|Warning): (.+)$/,
            source: 'terminal (flutter)',
            map: (match: RegExpMatchArray) => ({
                file: match[1],
                line: parseInt(match[2]),
                column: parseInt(match[3]),
                severity: match[4].toLowerCase() === 'error' ? 'error' : 'warning',
                message: match[5]
            })
        },
        // Dart Analysis style: error: Message (code at lib/main.dart:45)
        {
            regex: /^(error|warning|info): (.+?) \((.+?) at (.+?):(\d+)\)$/,
            source: 'terminal (dart)',
            map: (match: RegExpMatchArray) => ({
                file: match[4],
                line: parseInt(match[5]),
                column: 1,
                severity: match[1] === 'error' ? 'error' : (match[1] === 'warning' ? 'warning' : 'info'),
                message: match[2],
                code: match[3]
            })
        },
        // Standard GCC/Clang style: path/to/file:line:col: error: message
        {
            regex: /^(.+?):(\d+):(\d+): (error|warning): (.+)$/,
            source: 'terminal',
            map: (match: RegExpMatchArray) => ({
                file: match[1],
                line: parseInt(match[2]),
                column: parseInt(match[3]),
                severity: match[4] as any,
                message: match[5]
            })
        }
    ];

    /**
     * Start listening to terminal data
     */
    async start(): Promise<void> {
        if (this.unlisten) return;

        const unlistenFn = await onTerminalData((event) => {
            this.handleData(event.terminalId, event.data);
        });

        const unlistenExitFn = await onTerminalExit((event) => {
            this.flushBuffer(event.terminalId);
            this.clearBuffer(event.terminalId);
        });

        this.unlisten = () => {
            unlistenFn();
        };
        this.unlistenExit = () => {
            unlistenExitFn();
        };
    }

    /**
     * Stop listening
     */
    stop(): void {
        if (this.unlisten) {
            this.unlisten();
            this.unlisten = null;
        }
        if (this.unlistenExit) {
            this.unlistenExit();
            this.unlistenExit = null;
        }
    }

    private async handleData(terminalId: string, data: string): Promise<void> {
        // Concatenate with existing buffer for this terminal
        let currentBuffer = (this.buffer.get(terminalId) || '') + data;

        // Split by lines
        const lines = currentBuffer.split(/\r?\n/);

        // Keep the last partial line in the buffer
        if (!data.endsWith('\n') && !data.endsWith('\r')) {
            this.buffer.set(terminalId, lines.pop() || '');
            this.scheduleBufferFlush(terminalId);
        } else {
            this.clearBuffer(terminalId);
        }

        // Process completed lines
        for (const line of lines) {
            await this.processLine(line.trim());
        }
    }

    private async processLine(line: string): Promise<boolean> {
        // Strip ANSI escape codes
        const cleanLine = line.replace(/\x1B\[[0-9;]*[mK]/g, '');

        for (const pattern of this.patterns) {
            const match = cleanLine.match(pattern.regex);
            if (match) {
                const info = pattern.map(match);
                await this.addProblem(info, pattern.source);
                return true;
            }
        }

        return false;
    }

    private scheduleBufferFlush(terminalId: string): void {
        const existing = this.bufferFlushTimers.get(terminalId);
        if (existing) clearTimeout(existing);

        const timer = setTimeout(() => {
            void this.flushBuffer(terminalId);
        }, TerminalProblemMatcher.BUFFER_FLUSH_MS);

        this.bufferFlushTimers.set(terminalId, timer);
    }

    private async flushBuffer(terminalId: string): Promise<void> {
        const buffered = this.buffer.get(terminalId);
        if (!buffered) return;
        const matched = await this.processLine(buffered.trim());
        if (matched) {
            this.clearBuffer(terminalId);
        }
    }

    private clearBuffer(terminalId: string): void {
        this.buffer.delete(terminalId);
        const timer = this.bufferFlushTimers.get(terminalId);
        if (timer) clearTimeout(timer);
        this.bufferFlushTimers.delete(terminalId);
    }

    private async addProblem(info: any, source: string): Promise<void> {
        const rootPath = resolveProjectRootPath?.() ?? null;
        if (!rootPath) return;

        // Resolve absolute path if relative
        let filePath = info.file;
        if (!filePath.startsWith('/') && !/^[a-zA-Z]:/.test(filePath)) {
            filePath = `${rootPath}/${filePath.replace(/\\/g, '/')}`;
        }
        filePath = filePath.replace(/\\/g, '/');

        const fileName = filePath.split(/[/\\]/).pop() || filePath;

        const problem: Problem = {
            id: `terminal-${filePath}-${info.line}-${info.column}-${info.message.substring(0, 20)}`,
            file: filePath,
            fileName,
            line: info.line,
            column: info.column,
            endLine: info.line,
            endColumn: info.column + 1,
            message: info.message,
            severity: info.severity,
            source: source,
            code: info.code
        };

        const key = `${source}::${filePath}`;
        const existing = this.problemsByKey.get(key) || { filePath, source, problems: [] };

        if (!existing.problems.some((p) => p.id === problem.id)) {
            existing.problems = [...existing.problems, problem];
            this.problemsByKey.set(key, existing);
            problemsStore.setProblemsForFile(filePath, existing.problems, source);
        }
    }
    /**
     * Clear all tracked problems and buffers
     */
    clear(): void {
        this.buffer.clear();
        for (const timer of this.bufferFlushTimers.values()) {
            clearTimeout(timer);
        }
        this.bufferFlushTimers.clear();

        for (const entry of this.problemsByKey.values()) {
            problemsStore.clearProblemsForFile(entry.filePath, entry.source);
        }
        this.problemsByKey.clear();
    }
}

export const terminalProblemMatcher = new TerminalProblemMatcher();

/**
 * Output store for managing log channels
 * Provides real log output for Volt, Terminal, and File System channels
 */

export type OutputChannel = 'Volt' | 'Terminal' | 'File System' | 'Prettier' | 'MCP';

interface OutputLine {
  timestamp: Date;
  message: string;
}

interface ChannelData {
  lines: OutputLine[];
}

const MAX_LINES_PER_CHANNEL = 1000;

class OutputStore {
  private channels = $state<Record<OutputChannel, ChannelData>>({
    'Volt': { lines: [] },
    'Terminal': { lines: [] },
    'File System': { lines: [] },
    'Prettier': { lines: [] },
    'MCP': { lines: [] }
  });

  activeChannel = $state<OutputChannel>('Volt');

  /**
   * Get all available channel names
   */
  get channelNames(): OutputChannel[] {
    return ['Volt', 'Terminal', 'File System', 'Prettier', 'MCP'];
  }

  /**
   * Get lines for the active channel
   */
  get activeLines(): OutputLine[] {
    return this.channels[this.activeChannel].lines;
  }

  /**
   * Get lines for a specific channel
   */
  getLines(channel: OutputChannel): OutputLine[] {
    return this.channels[channel].lines;
  }

  /**
   * Append a line to a channel
   */
  append(channel: OutputChannel, message: string): void {
    const channelData = this.channels[channel];
    channelData.lines.push({
      timestamp: new Date(),
      message
    });

    // Trim old lines if exceeding max
    if (channelData.lines.length > MAX_LINES_PER_CHANNEL) {
      channelData.lines = channelData.lines.slice(-MAX_LINES_PER_CHANNEL);
    }
  }

  /**
   * Set the active channel
   */
  setActiveChannel(channel: OutputChannel): void {
    this.activeChannel = channel;
  }

  /**
   * Clear a specific channel
   */
  clear(channel: OutputChannel): void {
    this.channels[channel].lines = [];
  }

  /**
   * Clear all channels
   */
  clearAll(): void {
    for (const channel of this.channelNames) {
      this.channels[channel].lines = [];
    }
  }
}

// Singleton instance
export const outputStore = new OutputStore();

// Helper function for easy logging
export function logOutput(channel: OutputChannel, message: string): void {
  outputStore.append(channel, message);
}

import {
	createTerminalSession,
	createTerminalSessionFromInfo,
	listTerminals,
	killAllTerminals,
	TerminalSession
} from '$features/terminal/services/terminal-client';
import { terminalProblemMatcher } from '$features/terminal/services/terminal-problem-matcher';
import { registerCleanup } from '$core/services/hmr-cleanup';
import { projectStore } from '$shared/stores/project.svelte';

/**
 * Terminal store for managing terminal sessions
 */
class TerminalStore {
	sessions = $state<TerminalSession[]>([]);
	activeTerminalId = $state<string | null>(null);
	lastError = $state<{ terminalId: string; command: string; output: string } | null>(null);
	private createPromise: Promise<TerminalSession | null> | null = null;
	private aiCreatePromise: Promise<TerminalSession | null> | null = null;
	private sessionLabels = $state<Record<string, string>>({});
	private aiTerminalId = $state<string | null>(null);
	private syncPromise: Promise<void> | null = null;
	private startupSyncComplete = false;

	constructor() {
		void this.syncWithBackendRetry(5, 250);
		// Start terminal problem matcher (background service)
		void terminalProblemMatcher.start();
	}

	private async syncWithBackendRetry(
		maxAttempts = 3,
		baseDelayMs = 200,
	): Promise<void> {
		if (this.syncPromise) {
			await this.syncPromise;
			return;
		}

		this.syncPromise = (async () => {
			for (let attempt = 1; attempt <= maxAttempts; attempt++) {
				try {
					await this.syncWithBackend();
					// If we found sessions, no need for more retries.
					if (this.sessions.length > 0) break;
				} catch (err) {
					console.warn('[TerminalStore] syncWithBackend attempt failed:', attempt, err);
				}

				if (attempt < maxAttempts) {
					const delay = baseDelayMs * attempt;
					await new Promise((resolve) => setTimeout(resolve, delay));
				}
			}
		})();

		try {
			await this.syncPromise;
		} finally {
			this.syncPromise = null;
			this.startupSyncComplete = true;
		}
	}

	async ensureSynced(): Promise<void> {
		if (this.startupSyncComplete) {
			await this.syncWithBackend();
			return;
		}
		await this.syncWithBackendRetry(4, 250);
	}

	private attachSession(session: TerminalSession, makeActive = false): void {
		// Avoid duplicate attachment
		if (this.sessions.some((s) => s.id === session.id)) {
			if (makeActive) this.activeTerminalId = session.id;
			return;
		}

		// Set up exit handler to remove session when terminal exits
		session.onExit(() => {
			console.log('[TerminalStore] Terminal exited:', session.id);
			session.dispose();
			this.removeSession(session.id);
		});

		this.sessions = [...this.sessions, session];
		if (makeActive || !this.activeTerminalId) {
			this.activeTerminalId = session.id;
		}
	}

	/**
	 * Get the active terminal session
	 */
	get activeSession(): TerminalSession | null {
		if (!this.activeTerminalId) return null;
		return this.sessions.find((s) => s.id === this.activeTerminalId) ?? null;
	}

	/**
	 * Create a new terminal session
	 */
	async createTerminal(cwd?: string): Promise<TerminalSession | null> {
		// If a terminal creation is already in-flight, await it.
		// This prevents races where callers see `null` and assume terminal creation failed.
		if (this.createPromise) {
			return await this.createPromise;
		}

		this.createPromise = (async () => {
			// Before creating a new session, reconcile with backend in case we are
			// just after reload and missed rehydration.
			await this.ensureSynced();

			// Wait for project restoration to finish if it's currently loading
			// and no explicit cwd was provided.
			if (!cwd) {
				await projectStore.initialized;
			}

			const workingDir = cwd ?? projectStore.rootPath ?? undefined;
			console.log('[TerminalStore] Creating terminal in:', workingDir || '(default)');

			const session = await createTerminalSession(workingDir);
			if (!session) {
				console.error('[TerminalStore] createTerminalSession returned null');
				return null;
			}

			console.log('[TerminalStore] Terminal created:', session.id);
			this.attachSession(session, true);

			return session;
		})();

		try {
			return await this.createPromise;
		} finally {
			this.createPromise = null;
		}
	}

	/**
	 * Assign a user-visible label to a session
	 */
	setSessionLabel(terminalId: string, label: string): void {
		if (!terminalId) return;
		this.sessionLabels = { ...this.sessionLabels, [terminalId]: label };
	}

	getSessionLabel(terminalId: string): string | undefined {
		return this.sessionLabels[terminalId];
	}

	/**
	 * Get or create the dedicated AI terminal session.
	 * This avoids running AI commands in a user's interactive terminal state.
	 */
	async getOrCreateAiTerminal(cwd?: string): Promise<TerminalSession | null> {
		// If AI terminal creation is already in-flight, await it
		if (this.aiCreatePromise) {
			console.log('[TerminalStore] AI terminal creation in progress, waiting...');
			return await this.aiCreatePromise;
		}

		// Check for existing AI terminal first
		const existingId = this.aiTerminalId;
		if (existingId) {
			const existing = this.sessions.find((s) => s.id === existingId) ?? null;
			if (existing) {
				console.log('[TerminalStore] Reusing existing AI terminal:', existingId);
				console.log('[TerminalStore] AI terminal output history chars:', existing.getRecentOutput().length);
				this.activeTerminalId = existing.id;
				return existing;
			}
			// AI terminal ID exists but session is gone, clear it
			console.log('[TerminalStore] AI terminal ID exists but session gone, clearing');
			this.aiTerminalId = null;
		}

		// Create new AI terminal with mutex protection
		this.aiCreatePromise = (async () => {
			console.log('[TerminalStore] Creating new AI terminal');
			const session = await this.createTerminal(cwd);
			if (!session) {
				console.error('[TerminalStore] Failed to create AI terminal');
				return null;
			}

			// Wait for terminal to be ready before enabling shell integration
			await session.waitForReady(3000);
			// Extra safety delay for slow shell initialization
			await new Promise((resolve) => setTimeout(resolve, 500));
			await session.enableShellIntegration();

			this.aiTerminalId = session.id;
			this.setSessionLabel(session.id, 'Volt AI');
			console.log('[TerminalStore] AI terminal created and initialized:', session.id);
			return session;
		})();

		try {
			return await this.aiCreatePromise;
		} finally {
			this.aiCreatePromise = null;
		}
	}

	/**
	 * Detach the AI terminal so the next AI command uses a fresh terminal.
	 * Keeps the existing session alive for inspection/cleanup.
	 */
	detachAiTerminal(terminalId: string, label?: string): void {
		if (this.aiTerminalId === terminalId) {
			this.aiTerminalId = null;
		}
		if (label) {
			this.setSessionLabel(terminalId, label);
		}
	}

	/**
	 * Stop terminal sessions whose cwd is inside the target path.
	 * Helps Windows release file handles before deleting large folders.
	 */
	async stopSessionsInPath(targetPath: string): Promise<number> {
		if (!targetPath) return 0;
		const normalize = (p: string): string => {
			const n = p.replace(/\\/g, '/').replace(/\/+$/, '');
			return /^[A-Za-z]:/.test(n) ? n.toLowerCase() : n;
		};
		const target = normalize(targetPath);
		let stopped = 0;
		const snapshot = [...this.sessions];

		for (const session of snapshot) {
			const cwdRaw = session.cwd || session.info.cwd || '';
			if (!cwdRaw) continue;
			const cwd = normalize(cwdRaw);
			if (cwd === target || cwd.startsWith(target + '/')) {
				try {
					await this.killTerminal(session.id);
					stopped++;
				} catch (err) {
					console.warn('[TerminalStore] Failed to stop terminal in path:', cwdRaw, err);
				}
			}
		}

		return stopped;
	}

	/**
	 * Set the active terminal
	 */
	setActive(terminalId: string): void {
		const session = this.sessions.find((s) => s.id === terminalId);
		if (session) {
			this.activeTerminalId = terminalId;
		}
	}

	/**
	 * Kill and remove a terminal session
	 */
	async killTerminal(terminalId: string): Promise<void> {
		const session = this.sessions.find((s) => s.id === terminalId);
		if (!session) return;

		await session.kill();
		this.removeSession(terminalId);
	}

	/**
	 * Remove a session from the store (internal)
	 */
	private removeSession(terminalId: string): void {
		// Use filter to trigger reactivity (Svelte 5 $state)
		this.sessions = this.sessions.filter((s) => s.id !== terminalId);
		if (this.sessionLabels[terminalId]) {
			const next = { ...this.sessionLabels };
			delete next[terminalId];
			this.sessionLabels = next;
		}
		if (this.aiTerminalId === terminalId) {
			this.aiTerminalId = null;
		}

		// Update active terminal if needed
		if (this.activeTerminalId === terminalId) {
			this.activeTerminalId = this.sessions.length > 0 ? this.sessions[0].id : null;
		}
	}

	/**
	 * Kill all terminals
	 */
	async killAll(): Promise<void> {
		const didKillAll = await killAllTerminals();
		if (!didKillAll) {
			const promises = this.sessions.map(async (session) => {
				await session.kill();
			});
			await Promise.all(promises);
		}
		for (const session of this.sessions) {
			session.dispose();
		}
		this.sessions = [];
		this.activeTerminalId = null;
	}

	/**
	 * Sync with backend terminal list (useful on app startup)
	 */
	async syncWithBackend(): Promise<void> {
		const backendTerminals = await listTerminals();
		const backendIds = new Set(backendTerminals.map((t) => t.terminalId));

		// Remove sessions that no longer exist in backend
		for (const session of [...this.sessions]) {
			if (!backendIds.has(session.id)) {
				session.dispose();
				this.removeSession(session.id);
			}
		}

		// Rehydrate missing backend terminals after reload/HMR.
		const knownIds = new Set(this.sessions.map((s) => s.id));
		for (const info of backendTerminals) {
			if (knownIds.has(info.terminalId)) continue;
			try {
				const restored = await createTerminalSessionFromInfo(info);
				this.attachSession(restored, this.sessions.length === 0);
			} catch (err) {
				console.warn('[TerminalStore] Failed to rehydrate terminal:', info.terminalId, err);
			}
		}
	}
}

