export const settingsStore = new SettingsStore();

/**
 * Theme store using Svelte 5 runes
 * Manages theme selection with localStorage persistence and system preference detection
 */

import { darkThemeVars, voltDarkMonacoTheme } from '$shared/themes/dark';
import { lightThemeVars, voltLightMonacoTheme } from '$shared/themes/light';
import { midnightThemeVars, voltMidnightMonacoTheme } from '$shared/themes/midnight';
import { darkModernThemeVars, voltDarkModernMonacoTheme } from '$shared/themes/dark-modern';

import { solarizedDarkThemeVars, voltSolarizedDarkMonacoTheme } from '$shared/themes/solarized-dark';

const STORAGE_KEY = 'volt.theme';

export type ThemeMode = 'dark' | 'light' | 'midnight' | 'dark-modern' | 'solarized-dark';
export type ResolvedTheme = 'dark' | 'light' | 'midnight' | 'dark-modern' | 'solarized-dark';

class ThemeStore {
  /** User's theme preference (dark, light, midnight, or dark-modern) */
  mode = $state<ThemeMode>('dark-modern');

  /** The actual resolved theme based on mode */
  resolvedTheme = $state<ResolvedTheme>('dark-modern');

  constructor() {
    if (typeof window !== 'undefined') {
      this.loadFromStorage();
      this.updateResolvedTheme();
      this.applyTheme();
    }
  }

  /**
   * Set theme mode
   */
  setMode(mode: ThemeMode): void {
    this.mode = mode;
    this.updateResolvedTheme();
    this.applyTheme();
    this.saveToStorage();
  }

  /**
   * Toggle between themes (cycling behavior)
   */
  toggle(): void {
    this.cycle();
  }

  /**
   * Cycle through themes
   */
  cycle(): void {
    const order: ThemeMode[] = ['dark-modern', 'dark', 'midnight', 'solarized-dark', 'light'];
    const currentIndex = order.indexOf(this.mode);
    const nextIndex = (currentIndex + 1) % order.length;
    this.setMode(order[nextIndex]);
  }

  /**
   * Check if dark modern mode is active
   */
  get isDarkModern(): boolean {
    return this.resolvedTheme === 'dark-modern';
  }

  /**
   * Check if dark mode (anysphere) is active
   */
  get isDark(): boolean {
    return this.resolvedTheme === 'dark';
  }

  /**
   * Check if midnight mode (classic dark) is active
   */
  get isMidnight(): boolean {
    return this.resolvedTheme === 'midnight';
  }

  /**
   * Check if light mode is active
   */
  get isLight(): boolean {
    return this.resolvedTheme === 'light';
  }

  /**
   * Get display name for current theme mode
   */
  get displayName(): string {
    switch (this.mode) {
      case 'dark-modern': return 'Dark Modern';
      case 'dark': return 'Dark';
      case 'midnight': return 'Midnight';
      case 'solarized-dark': return 'Solarized Dark';
      case 'light': return 'Light';
    }
  }

  /**
   * Update resolved theme based on mode
   */
  private updateResolvedTheme(): void {
    this.resolvedTheme = this.mode;
  }

  /**
   * Apply theme CSS variables to document
   */
  private applyTheme(): void {
    if (typeof document === 'undefined') return;

    let vars: Record<string, string>;
    switch (this.resolvedTheme) {
      case 'dark-modern': vars = darkModernThemeVars; break;
      case 'dark': vars = darkThemeVars; break;
      case 'midnight': vars = midnightThemeVars; break;
      case 'solarized-dark': vars = solarizedDarkThemeVars; break;
      case 'light': vars = lightThemeVars; break;
    }

    const root = document.documentElement;

    // Apply all CSS variables
    for (const [key, value] of Object.entries(vars)) {
      root.style.setProperty(key, value);
    }

    // Set data attribute for potential CSS selectors
    root.setAttribute('data-theme', this.resolvedTheme);

    // Update Monaco theme if loaded
    this.updateMonacoTheme();
  }

  /**
   * Update Monaco editor theme
   */
  private updateMonacoTheme(): void {
    // Dynamically import to avoid loading Monaco unnecessarily
    void import('$core/services/monaco-loader').then(({ getMonaco }) => {
      const monaco = getMonaco();
      if (!monaco) return;

      let themeName;
      switch (this.resolvedTheme) {
        case 'dark-modern': themeName = 'volt-dark-modern'; break;
        case 'dark': themeName = 'volt-dark'; break;
        case 'midnight': themeName = 'volt-midnight'; break;
        case 'solarized-dark': themeName = 'volt-solarized-dark'; break;
        case 'light': themeName = 'volt-light'; break;
      }

      // Define themes if not already defined
      try {
        monaco.editor.defineTheme('volt-dark-modern', voltDarkModernMonacoTheme);
        monaco.editor.defineTheme('volt-dark', voltDarkMonacoTheme);
        monaco.editor.defineTheme('volt-midnight', voltMidnightMonacoTheme);
        monaco.editor.defineTheme('volt-solarized-dark', voltSolarizedDarkMonacoTheme);
        monaco.editor.defineTheme('volt-light', voltLightMonacoTheme);
      } catch {
        // Themes may already be defined
      }

      // Set the active theme
      monaco.editor.setTheme(themeName);
    }).catch(() => {
      // Monaco not loaded yet, theme will be applied when it loads
    });
  }

  /**
   * Load theme preference from localStorage
   */
  private loadFromStorage(): void {
    if (typeof window === 'undefined') return;

    try {
      const stored = localStorage.getItem(STORAGE_KEY);
      if (stored && ['dark', 'midnight', 'light', 'dark-modern', 'solarized-dark'].includes(stored)) {
        this.mode = stored as ThemeMode;
      }
    } catch {
      // Ignore storage errors
    }
  }

  /**
   * Save theme preference to localStorage
   */
  private saveToStorage(): void {
    if (typeof window === 'undefined') return;

    try {
      localStorage.setItem(STORAGE_KEY, this.mode);
    } catch {
      // Ignore storage errors
    }
  }
}

// Singleton instance
export const themeStore = new ThemeStore();

/**
 * Get the current Monaco theme name based on resolved theme
 */
export function getMonacoThemeName(): string {
  switch (themeStore.resolvedTheme) {
    case 'dark-modern': return 'volt-dark-modern';
    case 'dark': return 'volt-dark';
    case 'midnight': return 'volt-midnight';
    case 'solarized-dark': return 'volt-solarized-dark';
    case 'light': return 'volt-light';
  }
}

/**
 * Toast notification store using Svelte 5 runes
 * Provides showToast() function for displaying notifications
 */

export type ToastType = 'success' | 'error' | 'warning' | 'info';

export interface ToastAction {
  label: string;
  onClick: () => void;
}

export interface ToastOptions {
  message: string;
  type: ToastType;
  duration?: number;
  action?: ToastAction;
}

export interface Toast {
  id: string;
  message: string;
  type: ToastType;
  duration: number;
  action?: ToastAction;
  count: number;
  createdAt: number;
}

const MAX_VISIBLE_TOASTS = 5;
const DEFAULT_DURATION = 5000;
const RATE_LIMIT_MS = 500;
const DUPLICATE_WINDOW_MS = 2000;

class ToastStore {
  toasts = $state<Toast[]>([]);
  private lastToastTime = 0;
  private lastToastMessage = '';

  /**
   * Show a toast notification
   */
  show(options: ToastOptions): string | null {
    const now = Date.now();
    const { message, type, duration = DEFAULT_DURATION, action } = options;

    // Rate limiting: max 1 toast per 500ms for same message
    if (
      message === this.lastToastMessage &&
      now - this.lastToastTime < RATE_LIMIT_MS
    ) {
      return null;
    }

    // Check for duplicate messages within 2s - increment counter instead
    const existingToast = this.toasts.find(
      (t) =>
        t.message === message &&
        t.type === type &&
        now - t.createdAt < DUPLICATE_WINDOW_MS
    );

    if (existingToast) {
      existingToast.count += 1;
      existingToast.createdAt = now; // Reset timer
      this.lastToastTime = now;
      this.lastToastMessage = message;
      return existingToast.id;
    }

    const id = crypto.randomUUID();
    const toast: Toast = {
      id,
      message,
      type,
      duration,
      action,
      count: 1,
      createdAt: now
    };

    // Add new toast at the end (bottom of stack)
    this.toasts = [...this.toasts, toast];

    // Limit visible toasts
    if (this.toasts.length > MAX_VISIBLE_TOASTS) {
      this.toasts = this.toasts.slice(-MAX_VISIBLE_TOASTS);
    }

    this.lastToastTime = now;
    this.lastToastMessage = message;

    // Auto-dismiss
    if (duration > 0) {
      setTimeout(() => {
        this.dismiss(id);
      }, duration);
    }

    return id;
  }

  /**
   * Dismiss a toast by ID
   */
  dismiss(id: string): void {
    this.toasts = this.toasts.filter((t) => t.id !== id);
  }

  /**
   * Dismiss all toasts
   */
  dismissAll(): void {
    this.toasts = [];
  }
}

// Singleton instance
export const toastStore = new ToastStore();

/**
 * Convenience function to show a toast
 */
export function showToast(options: ToastOptions): string | null {
  return toastStore.show(options);
}

/**
 * Convenience function to dismiss a toast
 */
export function dismissToast(id: string): void {
  toastStore.dismiss(id);
}

/**
 * Convenience function to dismiss all toasts
 */
export function dismissAllToasts(): void {
  toastStore.dismissAll();
}

/**
 * UI state store using Svelte 5 runes
 * Manages layout state: sidebar, panels, menus
 */

import { bottomPanelStore, type BottomPanelTab } from './bottom-panel.svelte';

export type SidebarPanel =
  | 'explorer'
  | 'search'
  | 'git'
  | 'extensions'
  | 'settings'
  | 'mcp'
  | 'browser'
  | 'prompts'
  | null;

const ZOOM_MIN_PERCENT = 50;
const ZOOM_MAX_PERCENT = 200;
const ZOOM_STEP_PERCENT = 10;
const ZOOM_STORAGE_KEY = 'volt.zoomPercent';
const SIDEBAR_OPEN_KEY = 'volt.sidebarOpen';
const SIDEBAR_PANEL_KEY = 'volt.sidebarPanel';
const BOTTOM_PANEL_OPEN_KEY = 'volt.bottomPanelOpen';
const SIDEBAR_MIN_WIDTH = 150;
const SIDEBAR_MAX_WIDTH = 900;

class UIStore {
  // Sidebar state
  sidebarOpen = $state(true);
  activeSidebarPanel = $state<SidebarPanel>('explorer');
  sidebarWidth = $state(250);

  // Bottom panel (terminal) state
  bottomPanelOpen = $state(false);
  bottomPanelHeight = $state(200);

  // Menu state
  activeMenu = $state<string | null>(null);

  // Modal state
  aboutModalOpen = $state(false);

  // Zoom
  zoomPercent = $state(100);

  constructor() {
    this.loadPersistedZoom();
    this.loadPersistedUI();
  }

  /**
   * Toggle sidebar visibility
   */
  toggleSidebar(): void {
    this.sidebarOpen = !this.sidebarOpen;
    this.persistUI();
  }

  /**
   * Set active sidebar panel
   * If same panel clicked, close sidebar
   */
  setActiveSidebarPanel(panel: SidebarPanel): void {
    if (this.activeSidebarPanel === panel && this.sidebarOpen) {
      this.sidebarOpen = false;
    } else {
      this.activeSidebarPanel = panel;
      this.sidebarOpen = true;
    }
    this.persistUI();
  }

  /**
   * Toggle bottom panel (terminal)
   */
  toggleBottomPanel(): void {
    this.bottomPanelOpen = !this.bottomPanelOpen;
    this.persistUI();
  }

  /**
   * Open bottom panel with a specific tab
   */
  openBottomPanelTab(tab: BottomPanelTab): void {
    bottomPanelStore.setActiveTab(tab);
    this.bottomPanelOpen = true;
    this.persistUI();
  }

  /**
   * Open a menu
   */
  openMenu(menuId: string): void {
    this.activeMenu = menuId;
  }

  /**
   * Close all menus
   */
  closeMenus(): void {
    this.activeMenu = null;
  }

  /**
   * Toggle a specific menu
   */
  toggleMenu(menuId: string): void {
    if (this.activeMenu === menuId) {
      this.activeMenu = null;
    } else {
      this.activeMenu = menuId;
    }
  }

  /**
   * Open about modal
   */
  openAboutModal(): void {
    this.aboutModalOpen = true;
    this.closeMenus();
  }

  /**
   * Close about modal
   */
  closeAboutModal(): void {
    this.aboutModalOpen = false;
  }

  /**
   * Set sidebar width (for resizing)
   */
  setSidebarWidth(width: number): void {
    this.sidebarWidth = Math.max(SIDEBAR_MIN_WIDTH, Math.min(SIDEBAR_MAX_WIDTH, width));
  }

  /**
   * Set bottom panel height (for resizing)
   */
  setBottomPanelHeight(height: number): void {
    this.bottomPanelHeight = Math.max(100, Math.min(500, height));
  }

  /**
   * Set UI zoom in percent (e.g., 100 = 100%)
   */
  setZoomPercent(percent: number): void {
    if (!Number.isFinite(percent)) return;
    const rounded = Math.round(percent);
    const next = Math.max(ZOOM_MIN_PERCENT, Math.min(ZOOM_MAX_PERCENT, rounded));
    this.zoomPercent = next;
    this.persistZoom();
  }

  zoomIn(): void {
    this.setZoomPercent(this.zoomPercent + ZOOM_STEP_PERCENT);
  }

  zoomOut(): void {
    this.setZoomPercent(this.zoomPercent - ZOOM_STEP_PERCENT);
  }

  resetZoom(): void {
    this.setZoomPercent(100);
  }

  private loadPersistedZoom(): void {
    if (typeof window === 'undefined') return;
    try {
      const raw = localStorage.getItem(ZOOM_STORAGE_KEY);
      if (!raw) return;
      const parsed = Number(raw);
      if (Number.isFinite(parsed)) {
        const rounded = Math.round(parsed);
        this.zoomPercent = Math.max(ZOOM_MIN_PERCENT, Math.min(ZOOM_MAX_PERCENT, rounded));
      }
    } catch {
      // ignore
    }
  }

  private persistZoom(): void {
    if (typeof window === 'undefined') return;
    try {
      localStorage.setItem(ZOOM_STORAGE_KEY, String(this.zoomPercent));
    } catch {
      // ignore
    }
  }

  private loadPersistedUI(): void {
    if (typeof window === 'undefined') return;
    try {
      const sidebarOpen = localStorage.getItem(SIDEBAR_OPEN_KEY);
      if (sidebarOpen !== null) this.sidebarOpen = sidebarOpen === 'true';

      const sidebarPanel = localStorage.getItem(SIDEBAR_PANEL_KEY);
      if (sidebarPanel) this.activeSidebarPanel = sidebarPanel as SidebarPanel;

      const bottomPanelOpen = localStorage.getItem(BOTTOM_PANEL_OPEN_KEY);
      if (bottomPanelOpen !== null) this.bottomPanelOpen = bottomPanelOpen === 'true';
    } catch {
      // ignore
    }
  }

  private persistUI(): void {
    if (typeof window === 'undefined') return;
    try {
      localStorage.setItem(SIDEBAR_OPEN_KEY, String(this.sidebarOpen));
      if (this.activeSidebarPanel) {
        localStorage.setItem(SIDEBAR_PANEL_KEY, this.activeSidebarPanel);
      }
      localStorage.setItem(BOTTOM_PANEL_OPEN_KEY, String(this.bottomPanelOpen));
    } catch {
      // ignore
    }
  }
}

// Singleton instance
export const uiStore = new UIStore();
